--
-- Name: bulk_import_templates("jsonb"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."bulk_import_templates"("templates_json" "jsonb") RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    template JSONB;
    inserted_count INTEGER := 0;
BEGIN
    FOR template IN SELECT * FROM jsonb_array_elements(templates_json)
    LOOP
        INSERT INTO sms_templates (
            template_name,
            conversation_stage,
            agent_persona,
            language,
            template_body,
            variables
        ) VALUES (
            template->>'template_name',
            template->>'conversation_stage',
            template->>'agent_persona',
            template->>'language',
            template->>'template_body',
            COALESCE((template->'variables')::jsonb, '[]'::jsonb)
        )
        ON CONFLICT (template_name, conversation_stage, agent_persona, language, version)
        DO UPDATE SET
            template_body = EXCLUDED.template_body,
            variables = EXCLUDED.variables,
            updated_at = NOW();
        
        inserted_count := inserted_count + 1;
    END LOOP;
    
    RETURN inserted_count;
END;
$$;


--
-- Name: calc_deal_grade(numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."calc_deal_grade"("margin" numeric, "spread" numeric, "confidence" numeric) RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select case
    when coalesce(confidence,0) >= 85 and coalesce(margin,0) >= 25 and coalesce(spread,0) >= 50000 then 'A+'
    when coalesce(confidence,0) >= 75 and coalesce(margin,0) >= 20 and coalesce(spread,0) >= 35000 then 'A'
    when coalesce(confidence,0) >= 65 and coalesce(margin,0) >= 15 and coalesce(spread,0) >= 20000 then 'B'
    when coalesce(confidence,0) >= 50 and coalesce(margin,0) >= 10 then 'C'
    else 'Watchlist'
  end;
$$;


--
-- Name: calc_rehab_level(numeric, numeric, "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."calc_rehab_level"("repair_cost" numeric, "sqft" numeric, "condition" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select case
    when coalesce(repair_cost,0) = 0 and lower(coalesce(condition,'')) in ('excellent','good','average') then 'Light'
    when public.safe_divide(repair_cost, nullif(sqft,0)) is null then coalesce(nullif(condition,''),'Unknown')
    when public.safe_divide(repair_cost, nullif(sqft,0)) < 15 then 'Light'
    when public.safe_divide(repair_cost, nullif(sqft,0)) < 35 then 'Cosmetic'
    when public.safe_divide(repair_cost, nullif(sqft,0)) < 60 then 'Moderate'
    when public.safe_divide(repair_cost, nullif(sqft,0)) < 90 then 'Heavy'
    else 'Structural'
  end;
$$;


--
-- Name: calc_sqft_range(numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."calc_sqft_range"("sqft" numeric) RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select case
    when sqft is null or sqft <= 0 then 'Unknown'
    when sqft < 1000 then '<1000'
    when sqft < 1500 then '1000–1499'
    when sqft < 2000 then '1500–1999'
    when sqft < 2500 then '2000–2499'
    when sqft < 3000 then '2500–2999'
    when sqft < 4000 then '3000–3999'
    else '4000+'
  end;
$$;


--
-- Name: calc_year_bucket(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."calc_year_bucket"("y" integer) RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select case
    when y is null or y <= 0 then 'Unknown'
    when y < 1940 then '<1940'
    when y < 1960 then '1940–1959'
    when y < 1980 then '1960–1979'
    when y < 2000 then '1980–1999'
    when y < 2010 then '2000–2009'
    when y < 2020 then '2010–2019'
    else '2020+'
  end;
$$;


--
-- Name: campaign_age_bucket_from_mob("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."campaign_age_bucket_from_mob"("p_mob" "text") RETURNS "text"
    LANGUAGE "sql" STABLE
    AS $$
  WITH raw AS (
    SELECT NULLIF(regexp_replace(COALESCE(p_mob, ''), '[^0-9]', '', 'g'), '') AS digits
  ),
  resolved AS (
    SELECT
      CASE
        WHEN digits IS NULL THEN NULL
        WHEN length(digits) <= 3 AND digits::integer BETWEEN 1 AND 120 THEN digits::integer
        WHEN length(digits) >= 4 AND left(digits, 4)::integer BETWEEN 1900 AND EXTRACT(YEAR FROM now())::integer
          THEN EXTRACT(YEAR FROM age(make_date(left(digits, 4)::integer, 1, 1)))::integer
        ELSE NULL
      END AS age
    FROM raw
  )
  SELECT
    CASE
      WHEN age IS NULL THEN NULL
      WHEN age < 35 THEN 'Under 35'
      WHEN age <= 44 THEN '35-44'
      WHEN age <= 54 THEN '45-54'
      WHEN age <= 64 THEN '55-64'
      WHEN age <= 74 THEN '65-74'
      ELSE '75+'
    END
  FROM resolved;
$$;


--
-- Name: campaign_enqueue_next_touch("text", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."campaign_enqueue_next_touch"("p_podio_master_owner_id" "text", "p_campaign_key" "text") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
declare
  v_state public.contact_outreach_state;
  v_touch public.campaign_touch_plan;
  v_next_touch_number integer;
  v_allowed record;

  v_template_id text;
  v_channel text;
  v_delay_total interval;
  v_queue_ts timestamptz := now();

  v_to_phone text;
  v_to_email text;

  v_touch_metadata jsonb;
begin
  -- Lock state row to make "next-touch selection" race-safe.
  select *
  into v_state
  from public.contact_outreach_state
  where podio_master_owner_id = p_podio_master_owner_id
  for update;

  if v_state.id is null then
    raise exception 'missing contact_outreach_state for podio_master_owner_id=%', p_podio_master_owner_id;
  end if;

  if v_state.dnc then
    return;
  end if;
  if v_state.is_paused then
    return;
  end if;

  -- Determine next touch number from state
  v_next_touch_number := coalesce(v_state.current_touch_number, 0) + 1;

  -- Find the plan row for that touch number and pick the configured channel.
  select *
  into v_touch
  from public.campaign_touch_plan
  where campaign_key = p_campaign_key
    and touch_number = v_next_touch_number
    and is_active = true
  order by touch_number
  limit 1;

  if v_touch.id is null then
    -- Campaign complete or missing plan rows.
    return;
  end if;

  v_channel := v_touch.channel;
  v_touch_metadata := v_touch.metadata;

  -- Anti-overlap gate BEFORE we enqueue.
  select *
  into v_allowed
  from public.campaign_touch_allowed(
    p_channel => v_channel,
    p_campaign_key => p_campaign_key,
    p_touch_number => v_next_touch_number,
    p_podio_master_owner_id => p_podio_master_owner_id
  );

  if v_allowed.is_allowed is not true then
    -- Optionally pause campaign? Your rule says "pause campaign touches" on reply recently.
    -- We already block via gating; you can also persist a pause_reason here if desired.
    return;
  end if;

  -- Select recipients from state.
  v_to_phone := v_state.to_phone_number;
  v_to_email := v_state.to_email;

  -- Compute delay (so orchestration can be time-based, not just state-based).
  v_delay_total :=
    (coalesce(v_touch.delay_days, 0) || ' days')::interval +
    (coalesce(v_touch.delay_hours, 0) || ' hours')::interval;

  -- Resolve template_id.
  -- We use template_type from the touch plan; map to sms_templates/some templates table.
  -- Adjust this if your templates are stored differently.
  if v_channel = 'sms' then
    -- Example lookup:
    select st.id::text
    into v_template_id
    from public.sms_templates st
    where st.template_type = v_touch.template_type
    limit 1;

    if v_template_id is null then
      raise exception 'sms_templates not found for template_type=%', v_touch.template_type;
    end if;

    if v_to_phone is null then
      raise exception 'Missing to_phone_number in outreach_state for=%', p_podio_master_owner_id;
    end if;

    insert into public.send_queue (
      channel,
      to_phone_number,
      template_id,
      campaign_key,
      touch_number,
      podio_master_owner_id,
      metadata,
      created_at
    )
    values (
      'sms',
      v_to_phone,
      v_template_id,
      p_campaign_key,
      v_next_touch_number,
      p_podio_master_owner_id,
      jsonb_build_object(
        'stage_code', v_touch.stage_code,
        'use_case', v_touch.use_case,
        'delay_total', v_delay_total,
        'campaign_touch_plan_id', v_touch.id
      ) || v_touch_metadata,
      v_queue_ts
    );

  elsif v_channel = 'email' then
    -- If you have a dedicated email templates table, adapt similarly.
    -- For now, we assume sms_templates is also used for template lookup by template_type.
    select st.id::text
    into v_template_id
    from public.sms_templates st
    where st.template_type = v_touch.template_type
    limit 1;

    if v_template_id is null then
      raise exception 'email template not found for template_type=% (looked up in sms_templates; adjust needed)', v_touch.template_type;
    end if;

    if v_to_email is null then
      raise exception 'Missing to_email in outreach_state for=%', p_podio_master_owner_id;
    end if;

    insert into public.email_queue (
      channel,
      to_email,
      template_id,
      campaign_key,
      touch_number,
      podio_master_owner_id,
      metadata,
      created_at
    )
    values (
      'email',
      v_to_email,
      v_template_id,
      p_campaign_key,
      v_next_touch_number,
      p_podio_master_owner_id,
      jsonb_build_object(
        'stage_code', v_touch.stage_code,
        'use_case', v_touch.use_case,
        'delay_total', v_delay_total,
        'campaign_touch_plan_id', v_touch.id
      ) || v_touch_metadata,
      v_queue_ts
    );
  else
    raise exception 'Unsupported channel=%', v_channel;
  end if;

  -- Update outreach state after enqueue
  if v_channel = 'sms' then
    v_state.last_sms_at := v_queue_ts;
    v_state.next_allowed_sms_at := v_queue_ts + interval '0 hours'; -- immediate for next channel rules;
  elsif v_channel = 'email' then
    v_state.last_email_at := v_queue_ts;
    v_state.next_allowed_email_at := v_queue_ts + interval '0 hours';
  end if;

  v_state.last_outbound_at := v_queue_ts;
  v_state.current_campaign_key := p_campaign_key;
  v_state.current_touch_number := v_next_touch_number;
  v_state.current_stage := v_touch.stage_code;

  -- After any outbound, block further touches until at least next_allowed_any_contact_at.
  -- Rule: no more than 1 outbound per day => set next_allowed_any_contact_at to tomorrow start.
  v_state.next_allowed_any_contact_at := date_trunc('day', v_queue_ts) + interval '1 day';

  update public.contact_outreach_state
  set
    last_sms_at = case when v_channel='sms' then v_queue_ts else last_sms_at end,
    last_email_at = case when v_channel='email' then v_queue_ts else last_email_at end,
    last_outbound_at = v_queue_ts,
    current_campaign_key = p_campaign_key,
    current_touch_number = v_next_touch_number,
    current_stage = v_touch.stage_code,
    next_allowed_any_contact_at = v_state.next_allowed_any_contact_at,
    updated_at = now()
  where id = v_state.id;

  -- Log message event (outbound touch recorded here)
  perform public.log_message_event(
    p_channel => v_channel,
    p_campaign_key => p_campaign_key,
    p_touch_number => v_next_touch_number,
    p_podio_master_owner_id => p_podio_master_owner_id,
    p_template_id => v_template_id,
    p_source => 'campaign_orchestrator'
  );
end;
$$;


--
-- Name: campaign_target_graph_apply_filter_columns(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."campaign_target_graph_apply_filter_columns"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_property jsonb := COALESCE(NEW.extra_data->'property', '{}'::jsonb);
  v_master_owner jsonb := COALESCE(NEW.extra_data->'master_owner', '{}'::jsonb);
  v_prospect jsonb := COALESCE(NEW.extra_data->'prospect', '{}'::jsonb);
BEGIN
  NEW.units_count := COALESCE(
    NEW.units_count,
    public.campaign_target_graph_text_to_numeric(v_property->>'units_count'),
    public.campaign_target_graph_text_to_numeric(v_property->>'units'),
    public.campaign_target_graph_text_to_numeric(v_property->>'number_of_units')
  );
  NEW.tax_delinquent := COALESCE(
    NEW.tax_delinquent,
    public.campaign_target_graph_text_to_bool(v_property->>'tax_delinquent'),
    public.campaign_target_graph_text_to_bool(v_property->>'property_tax_delinquent'),
    (public.campaign_target_graph_text_to_numeric(v_property->>'tax_delinquent_year') IS NOT NULL)
  );
  NEW.active_lien := COALESCE(
    NEW.active_lien,
    public.campaign_target_graph_text_to_bool(v_property->>'active_lien'),
    public.campaign_target_graph_text_to_bool(v_property->>'property_active_lien')
  );
  NEW.property_flags_text := COALESCE(
    NULLIF(NEW.property_flags_text, ''),
    NULLIF(v_property->>'property_flags_text', ''),
    NULLIF(v_property->>'flags_text', ''),
    NULLIF(v_property->>'seller_tags_text', ''),
    NULLIF(NEW.podio_tags, '')
  );
  NEW.building_condition := COALESCE(
    NULLIF(NEW.building_condition, ''),
    NULLIF(v_property->>'building_condition', ''),
    NULLIF(v_property->>'condition', ''),
    NULLIF(v_property->>'rehab_level', ''),
    NULLIF(NEW.rehab_level, '')
  );
  NEW.owner_type := COALESCE(
    NULLIF(NEW.owner_type, ''),
    NULLIF(v_property->>'owner_type', ''),
    NULLIF(v_property->>'owner_type_guess', ''),
    NULLIF(v_master_owner->>'owner_type_guess', ''),
    NULLIF(NEW.owner_type_guess, '')
  );
  NEW.is_corporate_owner := COALESCE(
    NEW.is_corporate_owner,
    public.campaign_target_graph_text_to_bool(v_property->>'is_corporate_owner'),
    CASE
      WHEN lower(COALESCE(NEW.owner_type, NEW.owner_type_guess, '')) ~ '(llc|inc|corp|trust|company|partners|holdings)' THEN true
      ELSE NULL
    END
  );
  NEW.out_of_state_owner := COALESCE(
    NEW.out_of_state_owner,
    public.campaign_target_graph_text_to_bool(v_property->>'out_of_state_owner')
  );
  NEW.gender := COALESCE(NULLIF(NEW.gender, ''), NULLIF(v_prospect->>'gender', ''));
  NEW.marital_status := COALESCE(NULLIF(NEW.marital_status, ''), NULLIF(v_prospect->>'marital_status', ''));
  NEW.net_asset_value := COALESCE(NULLIF(NEW.net_asset_value, ''), NULLIF(v_prospect->>'net_asset_value', ''));
  NEW.buying_power := COALESCE(NULLIF(NEW.buying_power, ''), NULLIF(v_prospect->>'buying_power', ''));
  NEW.email_eligible := COALESCE(
    NEW.email_eligible,
    public.campaign_target_graph_text_to_bool(v_prospect->>'email_eligible')
  );
  RETURN NEW;
END;
$$;


--
-- Name: campaign_target_graph_text_to_bool("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."campaign_target_graph_text_to_bool"("p_value" "text") RETURNS boolean
    LANGUAGE "sql" IMMUTABLE
    AS $$
  SELECT CASE
    WHEN p_value IS NULL THEN NULL
    WHEN lower(trim(p_value)) IN ('true', 't', '1', 'yes', 'y', 'on', 'active', 'delinquent', 'lien') THEN true
    WHEN lower(trim(p_value)) IN ('false', 'f', '0', 'no', 'n', 'off', 'clear', 'none') THEN false
    ELSE NULL
  END;
$$;


--
-- Name: campaign_target_graph_text_to_numeric("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."campaign_target_graph_text_to_numeric"("p_value" "text") RETURNS numeric
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
DECLARE
  v_clean text;
BEGIN
  v_clean := NULLIF(regexp_replace(COALESCE(p_value, ''), '[^0-9.\-]+', '', 'g'), '');
  IF v_clean IS NULL OR v_clean IN ('-', '.', '-.') THEN
    RETURN NULL;
  END IF;
  RETURN v_clean::numeric;
EXCEPTION WHEN OTHERS THEN
  RETURN NULL;
END;
$$;


--
-- Name: campaign_touch_allowed("text", "text", integer, "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."campaign_touch_allowed"("p_channel" "text", "p_campaign_key" "text", "p_touch_number" integer, "p_podio_master_owner_id" "text") RETURNS TABLE("is_allowed" boolean, "block_reason" "text")
    LANGUAGE "plpgsql"
    AS $$
declare
  v_state public.contact_outreach_state;
  v_now timestamptz := now();
  v_touch_delay_interval interval;
  v_other_channel text;
  v_next_contact_allowed timestamptz;
  v_next_channel_allowed timestamptz;
  v_last_inbound_at timestamptz;
  v_last_outbound_at timestamptz;
begin
  -- Fetch state row (and fail closed if missing)
  select *
  into v_state
  from public.contact_outreach_state
  where podio_master_owner_id = p_podio_master_owner_id
  for update;

  if v_state.id is null then
    is_allowed := false;
    block_reason := 'missing contact_outreach_state row';
    return next;
  end if;

  -- Rule 1: DNC
  if v_state.dnc then
    is_allowed := false;
    block_reason := 'DNC=true';
    return next;
  end if;

  -- Rule 2: paused
  if v_state.is_paused then
    is_allowed := false;
    block_reason := coalesce(v_state.pause_reason, 'is_paused=true');
    return next;
  end if;

  -- Rule 3: global next allowed any contact
  if v_state.next_allowed_any_contact_at is not null
     and v_now < v_state.next_allowed_any_contact_at then
    is_allowed := false;
    block_reason := 'waiting for next_allowed_any_contact_at';
    return next;
  end if;

  -- Determine channel-specific next allowed
  if p_channel = 'sms' then
    v_next_channel_allowed := v_state.next_allowed_sms_at;
  elsif p_channel = 'email' then
    v_next_channel_allowed := v_state.next_allowed_email_at;
  else
    is_allowed := false;
    block_reason := 'invalid channel';
    return next;
  end if;

  -- Rule 4/5: channel-specific window
  if v_next_channel_allowed is not null and v_now < v_next_channel_allowed then
    is_allowed := false;
    block_reason := format('waiting for %s window', p_channel);
    return next;
  end if;

  -- Rule 8: Do not send SMS and email within 12 hours of each other unless seller replied
  -- We approximate "seller replied recently" using last_inbound_at.
  -- Set "recently" window to 12 hours per your rule.
  v_last_inbound_at := v_state.last_inbound_at;
  if v_last_inbound_at is null then
    -- ok: treat as no reply
    v_last_inbound_at := 'epoch'::timestamptz;
  end if;

  if p_channel = 'sms' then
    -- If email was sent within last 12h AND seller did not reply since then -> block
    if v_state.last_email_at is not null
       and v_now < (v_state.last_email_at + interval '12 hours') then
      if v_last_inbound_at < v_state.last_email_at then
        is_allowed := false;
        block_reason := 'email within 12h and no reply since';
        return next;
      end if;
    end if;
  elsif p_channel = 'email' then
    if v_state.last_sms_at is not null
       and v_now < (v_state.last_sms_at + interval '12 hours') then
      if v_last_inbound_at < v_state.last_sms_at then
        is_allowed := false;
        block_reason := 'sms within 12h and no reply since';
        return next;
      end if;
    end if;
  end if;

  -- Rule 6: If seller replied recently → pause campaign touches
  -- Interpretation: if last inbound was in the last 12h, block new outbound touches.
  -- (You can tune this window later.)
  if v_state.last_inbound_at is not null
     and v_now < (v_state.last_inbound_at + interval '12 hours') then
    is_allowed := false;
    block_reason := 'seller replied recently (within 12h)';
    return next;
  end if;

  -- Rule 7: do not send more than 1 outbound touch per seller per day
  if v_state.last_outbound_at is not null
     and date(v_state.last_outbound_at) = date(v_now) then
    is_allowed := false;
    block_reason := 'already sent an outbound touch today';
    return next;
  end if;

  is_allowed := true;
  block_reason := null;
  return next;
end;
$$;


--
-- Name: campaign_touch_updated_at(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."campaign_touch_updated_at"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$;


--
-- Name: claim_queue_jobs(integer, "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."claim_queue_jobs"("batch_size" integer DEFAULT 50, "lock_token_param" "text" DEFAULT ("gen_random_uuid"())::"text") RETURNS TABLE("id" "uuid", "queue_key" "text", "message_body" "text", "to_phone_number" character varying, "from_phone_number" character varying, "lock_token" "text", "retry_count" integer)
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    RETURN QUERY
    WITH claimed AS (
        SELECT sq.id
        FROM send_queue sq
        WHERE sq.is_locked = false
          AND sq.queue_status IN ('queued', 'retry')
          AND (sq.scheduled_for IS NULL OR sq.scheduled_for <= NOW())
          AND (sq.next_retry_at IS NULL OR sq.next_retry_at <= NOW())
        ORDER BY sq.send_priority DESC, sq.scheduled_for ASC
        LIMIT batch_size
        FOR UPDATE SKIP LOCKED
    )
    UPDATE send_queue sq
    SET is_locked = true,
        locked_at = NOW(),
        lock_token = lock_token_param,
        queue_status = 'sending',
        updated_at = NOW()
    FROM claimed
    WHERE sq.id = claimed.id
    RETURNING 
        sq.id,
        sq.queue_key,
        sq.message_body,
        sq.to_phone_number,
        sq.from_phone_number,
        sq.lock_token,
        sq.retry_count;
END;
$$;


--
-- Name: generate_buyer_key_etl("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."generate_buyer_key_etl"("normalized_name" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
BEGIN
  RETURN 'bk_' || encode(digest(lower(trim(coalesce(normalized_name, 'unknown'))), 'md5'), 'hex');
END;
$$;


--
-- Name: get_auto_reply_template_id("text", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_auto_reply_template_id"("in_intent" "text", "in_language" "text") RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  target_use_case text;
  result_id text;
BEGIN
  -- Intent mapping
  target_use_case := CASE in_intent
    WHEN 'ownership_confirmed' THEN 'ownership_check'
    WHEN 'price_request' THEN 'seller_asking_price'
    WHEN 'info_request' THEN 'who_is_this'
    WHEN 'positive_interest' THEN 'price_works_confirm_basics'
    ELSE 'ownership_check'
  END;

  -- Select a general-purpose template for the use case (allow 'sfr')
  SELECT id INTO result_id FROM public.sms_templates 
  WHERE use_case = target_use_case 
  AND language = in_language 
  AND is_active = true 
  AND (allowed_property_groups IS NULL OR allowed_property_groups @> ARRAY['sfr'])
  ORDER BY random() 
  LIMIT 1;

  RETURN result_id;
END;
$$;


--
-- Name: get_available_numbers_count(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_available_numbers_count"() RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    available_count INT;
BEGIN
    SELECT COUNT(*)
    INTO available_count
    FROM textgrid_numbers
    WHERE status = 'active'
      AND messages_sent_today < daily_limit;
    
    RETURN available_count;
END;
$$;


--
-- Name: get_buyer_match_candidates("text", double precision, double precision, "text", "text", "text", "text", "text", numeric, numeric, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_buyer_match_candidates"("p_property_id" "text" DEFAULT NULL::"text", "p_lat" double precision DEFAULT NULL::double precision, "p_lng" double precision DEFAULT NULL::double precision, "p_zip" "text" DEFAULT NULL::"text", "p_market" "text" DEFAULT NULL::"text", "p_state" "text" DEFAULT NULL::"text", "p_county" "text" DEFAULT NULL::"text", "p_asset_class" "text" DEFAULT NULL::"text", "p_estimated_value" numeric DEFAULT NULL::numeric, "p_radius_miles" numeric DEFAULT 25, "p_limit" integer DEFAULT 25) RETURNS TABLE("buyer_entity_id" "uuid", "buyer_key" "text", "buyer_name" "text", "buyer_type" "text", "is_corporate_buyer" boolean, "is_repeat_buyer" boolean, "mailing_city" "text", "mailing_state" "text", "mailing_zip" "text", "markets_active" "text"[], "zips_active" "text"[], "counties_active" "text"[], "preferred_asset_classes" "text"[], "purchase_count" integer, "purchase_count_180d" integer, "purchase_count_365d" integer, "first_purchase_date" "date", "last_purchase_date" "date", "avg_purchase_price" numeric, "median_purchase_price" numeric, "preferred_price_min" numeric, "preferred_price_max" numeric, "avg_ppsf" numeric, "velocity_score" numeric, "dispo_priority_score" numeric, "investor_score" numeric, "avg_potential_spread" numeric, "distance_miles" numeric, "matched_purchase_count" integer, "zip_purchase_count" integer, "market_purchase_count" integer, "statewide_purchase_count" integer, "max_purchase_price" numeric, "likely_exit_low" numeric, "likely_exit_high" numeric, "market_match_score" numeric, "asset_match_score" numeric, "price_match_score" numeric, "recency_score" numeric, "repeat_buyer_score" numeric, "spread_fit_score" numeric, "institutional_score" numeric, "volume_score" numeric, "total_match_score" numeric, "match_grade" "text", "fallback_level" "text", "reason_for_match" "text")
    LANGUAGE "plpgsql" STABLE
    AS $$
DECLARE
  n_zip    text := public.intel_normalize_zip(p_zip);
  n_state  text := public.intel_normalize_state(p_state);
  n_market text := NULLIF(btrim(coalesce(p_market,'')),'');
  n_county text := NULLIF(lower(btrim(coalesce(p_county,''))),'');
  n_asset  text := public.intel_normalize_asset_class(p_asset_class);
  v_radius numeric := COALESCE(p_radius_miles, 25);
BEGIN
  RETURN QUERY
  WITH matched_events AS (
    SELECT
      e.buyer_key,
      public.intel_haversine_miles(p_lat, p_lng, e.latitude::double precision, e.longitude::double precision) AS dist,
      CASE
        WHEN n_zip IS NOT NULL AND public.intel_normalize_zip(e.property_zip) = n_zip THEN 5
        WHEN p_lat IS NOT NULL AND e.latitude IS NOT NULL
             AND public.intel_haversine_miles(p_lat, p_lng, e.latitude::double precision, e.longitude::double precision) <= v_radius THEN 4
        WHEN n_market IS NOT NULL AND public.intel_normalize_market(e.market, e.property_city, e.property_state) = n_market THEN 3
        WHEN n_county IS NOT NULL AND lower(btrim(e.county_name)) = n_county THEN 2
        WHEN n_state IS NOT NULL AND public.intel_normalize_state(e.property_state) = n_state THEN 1
        ELSE 0
      END AS tier,
      public.intel_clean_price(e.purchase_price, e.estimated_value) AS eff_price,
      e.purchase_date,
      public.intel_normalize_asset_class(e.normalized_asset_class) AS evt_asset
    FROM public.buyer_purchase_events_v2 e
    WHERE e.buyer_key IS NOT NULL
      AND (
        (n_zip IS NOT NULL AND e.property_zip = n_zip)
        OR (p_lat IS NOT NULL AND e.latitude BETWEEN p_lat - 0.6 AND p_lat + 0.6
                              AND e.longitude BETWEEN p_lng - 0.6 AND p_lng + 0.6)
        OR (n_state IS NOT NULL AND upper(btrim(e.property_state)) = n_state)
      )
  ),
  related AS ( SELECT * FROM matched_events WHERE tier > 0 ),
  per_buyer AS (
    SELECT
      r.buyer_key,
      max(r.tier)                                               AS best_tier,
      min(r.dist) FILTER (WHERE r.dist IS NOT NULL)             AS nearest_dist,
      count(*)                                                  AS matched_cnt,
      count(*) FILTER (WHERE r.tier = 5)                        AS zip_cnt,
      count(*) FILTER (WHERE r.tier >= 3)                       AS market_cnt,
      count(*)                                                  AS statewide_cnt,
      avg(r.eff_price) FILTER (WHERE r.eff_price > 0)           AS avg_matched_price,
      max(r.eff_price)                                          AS max_matched_price,
      (percentile_cont(0.5) WITHIN GROUP (ORDER BY r.eff_price))::numeric AS median_matched_price,
      max(r.purchase_date)                                      AS last_matched_date,
      mode() WITHIN GROUP (ORDER BY r.evt_asset)                AS dominant_asset
    FROM related r
    GROUP BY r.buyer_key
  ),
  meta AS ( SELECT COALESCE(max(best_tier), 0) AS global_tier FROM per_buyer ),
  scored AS (
    SELECT
      be.id AS buyer_entity_id, be.buyer_key, be.buyer_name, be.buyer_type,
      be.is_corporate_buyer, be.is_repeat_buyer,
      be.mailing_city, be.mailing_state, be.mailing_zip,
      be.markets_active, be.zips_active, be.counties_active, be.preferred_asset_classes,
      be.purchase_count, be.purchase_count_180d, be.purchase_count_365d,
      be.first_purchase_date,
      be.preferred_price_min, be.preferred_price_max, be.avg_ppsf,
      be.velocity_score, be.dispo_priority_score, be.investor_score, be.avg_potential_spread,
      pb.best_tier, pb.nearest_dist, pb.matched_cnt, pb.zip_cnt, pb.market_cnt, pb.statewide_cnt,
      pb.avg_matched_price, pb.max_matched_price, pb.median_matched_price,
      pb.last_matched_date, pb.dominant_asset,
      CASE pb.best_tier
        WHEN 5 THEN 100
        WHEN 4 THEN CASE
            WHEN pb.nearest_dist <= 2  THEN 92 WHEN pb.nearest_dist <= 5  THEN 82
            WHEN pb.nearest_dist <= 10 THEN 70 WHEN pb.nearest_dist <= 25 THEN 58 ELSE 50 END
        WHEN 3 THEN 48 WHEN 2 THEN 38 WHEN 1 THEN 25 ELSE 10
      END::numeric AS geo_score,
      CASE
        WHEN pb.last_matched_date IS NULL THEN 10
        WHEN pb.last_matched_date >= CURRENT_DATE - 90  THEN 100
        WHEN pb.last_matched_date >= CURRENT_DATE - 180 THEN 82
        WHEN pb.last_matched_date >= CURRENT_DATE - 365 THEN 60
        WHEN pb.last_matched_date >= CURRENT_DATE - 730 THEN 35 ELSE 15
      END::numeric AS recency_val,
      CASE
        WHEN pb.matched_cnt >= 10 THEN 100 WHEN pb.matched_cnt >= 5 THEN 82
        WHEN pb.matched_cnt >= 3 THEN 65 WHEN pb.matched_cnt >= 2 THEN 48 ELSE 30
      END::numeric AS volume_val,
      CASE
        WHEN p_estimated_value IS NULL OR pb.avg_matched_price IS NULL OR pb.avg_matched_price = 0 THEN 45
        WHEN abs(p_estimated_value - pb.avg_matched_price)/greatest(pb.avg_matched_price,1) <= 0.15 THEN 100
        WHEN abs(p_estimated_value - pb.avg_matched_price)/greatest(pb.avg_matched_price,1) <= 0.30 THEN 78
        WHEN abs(p_estimated_value - pb.avg_matched_price)/greatest(pb.avg_matched_price,1) <= 0.60 THEN 55
        WHEN abs(p_estimated_value - pb.avg_matched_price)/greatest(pb.avg_matched_price,1) <= 1.00 THEN 35 ELSE 18
      END::numeric AS price_val,
      CASE
        WHEN n_asset IS NULL THEN 50
        WHEN pb.dominant_asset = n_asset THEN 100
        WHEN EXISTS (SELECT 1 FROM unnest(be.preferred_asset_classes) pac
                     WHERE public.intel_normalize_asset_class(pac) = n_asset) THEN 80
        ELSE 30
      END::numeric AS asset_val,
      CASE
        WHEN be.purchase_count >= 10 THEN 100 WHEN be.purchase_count >= 5 THEN 80
        WHEN be.purchase_count >= 3 THEN 60 WHEN be.purchase_count >= 2 THEN 40 ELSE 18
      END::numeric AS repeat_val,
      CASE
        WHEN be.avg_potential_spread IS NULL OR be.avg_potential_spread = 0 THEN 30
        WHEN be.avg_potential_spread >= 50000 THEN 100 WHEN be.avg_potential_spread >= 25000 THEN 75
        WHEN be.avg_potential_spread >= 10000 THEN 50 ELSE 25
      END::numeric AS spread_val,
      CASE be.buyer_type WHEN 'institutional' THEN 100 WHEN 'trust' THEN 70 WHEN 'corporate' THEN 40 ELSE 25 END::numeric AS inst_val
    FROM per_buyer pb
    JOIN public.buyer_entities_v2 be ON be.buyer_key = pb.buyer_key
  )
  SELECT
    s.buyer_entity_id, s.buyer_key, s.buyer_name, s.buyer_type,
    s.is_corporate_buyer, s.is_repeat_buyer,
    s.mailing_city, s.mailing_state, s.mailing_zip,
    s.markets_active, s.zips_active, s.counties_active, s.preferred_asset_classes,
    s.purchase_count, s.purchase_count_180d, s.purchase_count_365d,
    s.first_purchase_date, s.last_matched_date AS last_purchase_date,
    round(s.avg_matched_price, 0)    AS avg_purchase_price,
    round(s.median_matched_price, 0) AS median_purchase_price,
    s.preferred_price_min, s.preferred_price_max, s.avg_ppsf,
    s.velocity_score, s.dispo_priority_score, s.investor_score, s.avg_potential_spread,
    round(s.nearest_dist::numeric, 2)        AS distance_miles,
    s.matched_cnt::integer                   AS matched_purchase_count,
    s.zip_cnt::integer                       AS zip_purchase_count,
    s.market_cnt::integer                    AS market_purchase_count,
    s.statewide_cnt::integer                 AS statewide_purchase_count,
    round(s.max_matched_price, 0)            AS max_purchase_price,
    round(COALESCE(s.avg_matched_price,0) * 0.95, 0) AS likely_exit_low,
    round(COALESCE(s.avg_matched_price,0) * 1.12, 0) AS likely_exit_high,
    round(s.geo_score,1)    AS market_match_score,
    round(s.asset_val,1)    AS asset_match_score,
    round(s.price_val,1)    AS price_match_score,
    round(s.recency_val,1)  AS recency_score,
    round(s.repeat_val,1)   AS repeat_buyer_score,
    round(s.spread_val,1)   AS spread_fit_score,
    round(s.inst_val,1)     AS institutional_score,
    round(s.volume_val,1)   AS volume_score,
    LEAST(100, round(
      s.geo_score*0.30 + s.asset_val*0.15 + s.price_val*0.15 + s.recency_val*0.15
      + s.repeat_val*0.10 + s.spread_val*0.10
      + GREATEST(0, s.inst_val - 40)*0.05
      + GREATEST(0, s.volume_val - 30)*0.05
    , 1))::numeric AS total_match_score,
    CASE
      WHEN (s.geo_score*0.30 + s.asset_val*0.15 + s.price_val*0.15 + s.recency_val*0.15 + s.repeat_val*0.10 + s.spread_val*0.10) >= 88 THEN 'A+'
      WHEN (s.geo_score*0.30 + s.asset_val*0.15 + s.price_val*0.15 + s.recency_val*0.15 + s.repeat_val*0.10 + s.spread_val*0.10) >= 76 THEN 'A'
      WHEN (s.geo_score*0.30 + s.asset_val*0.15 + s.price_val*0.15 + s.recency_val*0.15 + s.repeat_val*0.10 + s.spread_val*0.10) >= 62 THEN 'B'
      WHEN (s.geo_score*0.30 + s.asset_val*0.15 + s.price_val*0.15 + s.recency_val*0.15 + s.repeat_val*0.10 + s.spread_val*0.10) >= 48 THEN 'C'
      ELSE 'D'
    END AS match_grade,
    (SELECT CASE m.global_tier WHEN 5 THEN 'zip' WHEN 4 THEN 'radius' WHEN 3 THEN 'market'
                               WHEN 2 THEN 'county' WHEN 1 THEN 'state' ELSE 'none' END FROM meta m) AS fallback_level,
    (
      CASE WHEN s.zip_cnt > 0 THEN s.zip_cnt || ' purchase(s) in zip ' || coalesce(n_zip,'') || '; ' ELSE '' END ||
      CASE WHEN s.nearest_dist IS NOT NULL THEN 'nearest buy ' || round(s.nearest_dist::numeric,1) || 'mi away; ' ELSE '' END ||
      CASE WHEN s.matched_cnt >= 3 THEN 'active local buyer (' || s.matched_cnt || ' nearby purchases); ' ELSE '' END ||
      CASE WHEN s.buyer_type = 'institutional' THEN 'institutional capital; '
           WHEN s.buyer_type = 'trust' THEN 'trust entity; ' ELSE '' END ||
      CASE WHEN s.last_matched_date >= CURRENT_DATE - 180 THEN 'bought in last 6mo; ' ELSE '' END
    ) AS reason_for_match
  FROM scored s
  ORDER BY total_match_score DESC, s.matched_cnt DESC
  LIMIT p_limit;
END;
$$;


--
-- Name: get_buyers_for_property("text", integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_buyers_for_property"("p_property_id" "text", "p_limit" integer DEFAULT 25) RETURNS TABLE("buyer_entity_key" "text", "buyer_display_name" "text", "buyer_grade" "text", "buyer_confidence_score" integer, "match_score" integer, "purchase_count_6mo" bigint, "purchase_count_12mo" bigint, "avg_purchase_price" numeric, "median_purchase_price" numeric, "top_markets" "text"[], "top_zips" "text"[], "asset_classes_bought" "text"[], "last_purchase_date" "date", "buyer_signal_summary" "text", "reason_matched" "text")
    LANGUAGE "sql" STABLE
    AS $_$
  with subject as (
    select
      p.property_id::text as property_id,
      coalesce(nullif(trim(p.market), ''), nullif(trim(concat_ws(', ', p.property_address_city, p.property_address_state)), '')) as market,
      nullif(trim(p.property_address_state), '') as property_state,
      nullif(trim(p.property_address_zip), '') as property_zip,
      nullif(trim(p.property_type), '') as property_type,
      p.building_square_feet::numeric as building_square_feet,
      p.total_bedrooms::numeric as total_bedrooms,
      p.total_baths::numeric as total_baths,
      p.year_built::numeric as year_built,
      p.estimated_value::numeric as target_price,
      case
        when lower(coalesce(p.property_type, '')) like '%single%' then 'single_family'
        when lower(coalesce(p.property_type, '')) like any (array['%duplex%', '%triplex%', '%quad%', '%multi%']) then 'multifamily'
        when lower(coalesce(p.property_type, '')) like any (array['%condo%', '%townhome%', '%townhouse%']) then 'attached_residential'
        when lower(coalesce(p.property_type, '')) like '%mobile%' then 'manufactured'
        else null
      end as normalized_asset_class
    from public.properties p
    where p.property_id::text = p_property_id
    limit 1
  ),
  candidate_stats as (
    select
      l.buyer_entity_key,
      l.buyer_display_name,
      l.buyer_grade,
      l.buyer_confidence_score,
      l.purchase_count_6mo,
      l.purchase_count_12mo,
      l.avg_purchase_price,
      l.median_purchase_price,
      l.avg_sqft,
      l.avg_beds,
      l.avg_baths,
      l.top_markets,
      l.top_zips,
      l.asset_classes_bought,
      l.last_purchase_date,
      l.buyer_signal_summary,
      l.off_market_purchase_count,
      count(*) filter (where p.market = s.market and s.market is not null) as same_market_purchase_count,
      count(*) filter (where p.property_address_state = s.property_state and s.property_state is not null) as same_state_purchase_count,
      count(*) filter (where p.property_address_zip = s.property_zip and s.property_zip is not null) as same_zip_purchase_count,
      count(*) filter (where p.normalized_asset_class = s.normalized_asset_class and s.normalized_asset_class is not null) as same_asset_class_count,
      count(*) filter (where p.property_type = s.property_type and s.property_type is not null) as same_property_type_count
    from public.v_buyer_entity_leaderboard l
    cross join subject s
    join public.v_buyer_entity_purchases p
      on p.buyer_entity_key = l.buyer_entity_key
    where l.buyer_grade <> 'Noise'
    group by
      l.buyer_entity_key,
      l.buyer_display_name,
      l.buyer_grade,
      l.buyer_confidence_score,
      l.purchase_count_6mo,
      l.purchase_count_12mo,
      l.avg_purchase_price,
      l.median_purchase_price,
      l.avg_sqft,
      l.avg_beds,
      l.avg_baths,
      l.top_markets,
      l.top_zips,
      l.asset_classes_bought,
      l.last_purchase_date,
      l.buyer_signal_summary,
      l.off_market_purchase_count
  ),
  scored as (
    select
      c.*,
      s.market,
      s.property_state,
      s.property_zip,
      s.property_type,
      s.target_price,
      s.building_square_feet,
      s.total_bedrooms,
      s.total_baths,
      greatest(
        0,
        least(
          100,
          round(
            case
              when c.same_zip_purchase_count > 0 then 26
              when c.same_market_purchase_count > 0 then 20
              when c.same_state_purchase_count > 0 then 12
              else 0
            end
            + case when c.same_asset_class_count > 0 then 14 else 0 end
            + case when c.same_property_type_count > 0 then 10 else 0 end
            + case
                when s.target_price is null or c.median_purchase_price is null or c.median_purchase_price = 0 then 6
                else greatest(0, 16 - (abs(s.target_price - c.median_purchase_price) / c.median_purchase_price) * 20)
              end
            + case
                when s.building_square_feet is null or c.avg_sqft is null then 4
                when c.avg_sqft is not null and c.avg_sqft > 0 then
                  greatest(
                    0,
                    12 - (
                      abs(s.building_square_feet - c.avg_sqft) / greatest(s.building_square_feet, 1)
                    ) * 14
                  )
                else 4
              end
            + case
                when s.total_bedrooms is null then 3
                else greatest(
                  0,
                  6 - abs(s.total_bedrooms - coalesce(c.avg_beds, s.total_bedrooms)) * 3
                )
              end
            + case
                when s.total_baths is null then 3
                else greatest(
                  0,
                  6 - abs(s.total_baths - coalesce(c.avg_baths, s.total_baths)) * 3
                )
              end
            + least(8, c.purchase_count_6mo * 2)
            + least(12, c.buyer_confidence_score * 0.12)
            + case c.buyer_grade
                when 'A+' then 8
                when 'A' then 6
                when 'B' then 3
                else 0
              end
            + case when c.off_market_purchase_count > 0 then 4 else 0 end
          )::numeric
        )
      )::integer as match_score
    from candidate_stats c
    cross join subject s
  )
  select
    buyer_entity_key,
    buyer_display_name,
    buyer_grade,
    buyer_confidence_score,
    match_score,
    purchase_count_6mo,
    purchase_count_12mo,
    avg_purchase_price,
    median_purchase_price,
    top_markets,
    top_zips,
    asset_classes_bought,
    last_purchase_date,
    buyer_signal_summary,
    concat_ws(
      ' • ',
      case
        when same_zip_purchase_count > 0 then 'Repeat buyer in subject ZIP'
        when same_market_purchase_count > 0 then 'Active in subject market'
        when same_state_purchase_count > 0 then 'Active in subject state'
        else null
      end,
      case when same_asset_class_count > 0 then 'Asset class match' else null end,
      case when same_property_type_count > 0 then 'Property type match' else null end,
      case
        when target_price is not null and median_purchase_price is not null
          then 'Median buy ' || to_char(median_purchase_price, 'FM$999,999,999')
        else null
      end,
      case when purchase_count_6mo > 0 then purchase_count_6mo::text || ' buys in 6mo' else null end,
      case when off_market_purchase_count > 0 then off_market_purchase_count::text || ' off-market purchases' else null end
    ) as reason_matched
  from scored
  order by
    match_score desc,
    buyer_confidence_score desc,
    purchase_count_6mo desc,
    purchase_count_12mo desc,
    last_purchase_date desc nulls last
  limit greatest(coalesce(p_limit, 25), 1);
$_$;


--
-- Name: get_canonical_property_group("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_canonical_property_group"("property_type" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
DECLARE
  pt text := lower(COALESCE(property_type, ''));
BEGIN
  IF pt IN ('single family', 'sfr', 'residential', 'single-family') THEN RETURN 'sfr';
  ELSIF pt IN ('duplex') THEN RETURN 'duplex';
  ELSIF pt IN ('triplex') THEN RETURN 'triplex';
  ELSIF pt IN ('fourplex') THEN RETURN 'fourplex';
  ELSIF pt ILIKE '%multifamily%' AND pt ILIKE '%small%' THEN RETURN 'small_multifamily';
  ELSIF pt ILIKE '%multifamily%' THEN RETURN 'multifamily_5_plus';
  ELSIF pt ILIKE '%retail%' OR pt ILIKE '%strip%' THEN RETURN 'retail';
  ELSIF pt ILIKE '%office%' THEN RETURN 'office';
  ELSIF pt ILIKE '%industrial%' OR pt ILIKE '%warehouse%' THEN RETURN 'industrial';
  ELSIF pt ILIKE '%storage%' THEN RETURN 'self_storage';
  ELSIF pt ILIKE '%hotel%' OR pt ILIKE '%motel%' THEN RETURN 'hotel_motel';
  ELSIF pt ILIKE '%mobile home%' THEN RETURN 'mobile_home_park';
  ELSIF pt ILIKE '%land%' OR pt ILIKE '%lot%' OR pt ILIKE '%parcel%' THEN RETURN 'land';
  ELSE RETURN 'other_commercial';
  END IF;
END;
$$;


