--
-- Name: v_seller_work_items; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_seller_work_items" AS
 SELECT "p"."property_id",
    "p"."master_owner_id",
    COALESCE("lt"."thread_key", ('property:'::"text" || "p"."property_id")) AS "thread_key",
    ("lt"."thread_key" IS NOT NULL) AS "has_conversation",
    ("lq"."queue_id" IS NOT NULL) AS "has_queue",
    ("lm"."message_id" IS NOT NULL) AS "has_message_event",
    (("lm"."message_id" IS NULL) AND ("lq"."queue_id" IS NULL) AND ("lt"."thread_key" IS NULL)) AS "is_uncontacted",
    COALESCE(NULLIF("lt"."status", ''::"text"), 'not_contacted'::"text") AS "status",
    COALESCE(NULLIF("lt"."stage", ''::"text"), 'not_contacted'::"text") AS "stage",
        CASE
            WHEN (COALESCE("lt"."is_suppressed", false) OR COALESCE("lm"."is_opt_out", false)) THEN 'blocked'::"text"
            WHEN ("lq"."failed_reason" IS NOT NULL) THEN 'issue'::"text"
            WHEN (("lt"."latest_direction" = 'inbound'::"text") AND (COALESCE("lt"."is_read", false) = false)) THEN 'new_reply'::"text"
            WHEN (COALESCE("lt"."is_hot_lead", false) OR COALESCE("lt"."is_urgent", false)) THEN 'hot'::"text"
            WHEN ("lt"."last_intent" = ANY (ARRAY['seller_interested'::"text", 'positive_interest'::"text", 'interested'::"text", 'asking_price_provided'::"text"])) THEN 'positive_intent'::"text"
            WHEN ("lt"."stage" = ANY (ARRAY['negotiating'::"text", 'underwriting'::"text", 'offer_sent'::"text", 'price_discovery'::"text", 'condition_details'::"text"])) THEN 'negotiating'::"text"
            WHEN (("lm"."message_id" IS NOT NULL) OR ("lq"."sent_at" IS NOT NULL)) THEN 'contacted'::"text"
            ELSE 'not_contacted'::"text"
        END AS "seller_state",
        CASE
            WHEN ("lq"."queue_status" = ANY (ARRAY['sending'::"text", 'processing'::"text"])) THEN 'active'::"text"
            WHEN (("lq"."queue_status" = ANY (ARRAY['queued'::"text", 'pending'::"text", 'approved'::"text"])) AND (COALESCE("lq"."scheduled_for", "now"()) <= "now"())) THEN 'ready'::"text"
            WHEN (("lq"."queue_status" = ANY (ARRAY['queued'::"text", 'pending'::"text", 'approved'::"text"])) AND ("lq"."scheduled_for" > "now"())) THEN 'scheduled'::"text"
            WHEN ("lq"."queue_status" = 'sent'::"text") THEN 'sent'::"text"
            WHEN ("lq"."queue_status" = 'delivered'::"text") THEN 'delivered'::"text"
            WHEN ("lq"."queue_status" = ANY (ARRAY['failed'::"text", 'error'::"text", 'blocked'::"text", 'cancelled'::"text"])) THEN 'issue'::"text"
            ELSE 'none'::"text"
        END AS "execution_state",
        CASE
            WHEN (("lt"."thread_key" IS NULL) AND ("lq"."queue_id" IS NULL)) THEN 'not_contacted'::"text"
            WHEN COALESCE("lt"."is_hot_lead", false) THEN 'hot_leads'::"text"
            WHEN (COALESCE("lt"."is_suppressed", false) OR COALESCE("lm"."is_opt_out", false)) THEN 'dnc_opt_out'::"text"
            WHEN ("lt"."automation_state" = 'active'::"text") THEN 'automated'::"text"
            WHEN (("lt"."latest_direction" = 'inbound'::"text") AND (("lt"."stage" = 'needs_response'::"text") OR (NOT COALESCE("lt"."is_read", false)))) THEN 'new_inbound'::"text"
            WHEN ("lq"."queue_status" = ANY (ARRAY['queued'::"text", 'pending'::"text", 'approved'::"text"])) THEN 'outbound_active'::"text"
            WHEN (("lt"."latest_direction" = 'outbound'::"text") AND ("lt"."stage" = ANY (ARRAY['sent_waiting'::"text", 'waiting'::"text"]))) THEN 'outbound_active'::"text"
            ELSE 'cold_no_response'::"text"
        END AS "inbox_category",
    "lt"."latest_message_at",
    "lt"."latest_direction",
    "lt"."latest_message_body",
    "lt"."last_inbound_at",
    "lt"."last_outbound_at",
    COALESCE("lt"."pending_queue_count", 0) AS "pending_queue_count",
    "lt"."follow_up_at",
    "lt"."agent_id",
    "lt"."persona_id",
    COALESCE("lt"."is_starred", false) AS "is_starred",
    COALESCE("lt"."is_pinned", false) AS "is_pinned",
    COALESCE("lt"."is_read", true) AS "is_read",
    COALESCE("lt"."is_hot_lead", false) AS "is_hot_lead",
    COALESCE("lt"."is_suppressed", false) AS "is_suppressed",
    "p"."property_address_full",
    "p"."property_type",
    "p"."estimated_value",
    "p"."cash_offer",
    "p"."final_acquisition_score",
    "p"."structured_motivation_score" AS "priority_score",
    "p"."property_address_city" AS "city",
    "p"."property_address_state" AS "state",
    "p"."property_address_zip" AS "zip",
    "p"."latitude",
    "p"."longitude",
    "mo"."display_name" AS "owner_display_name",
    "mo"."priority_tier" AS "owner_priority_tier",
    "mo"."portfolio_total_value",
    "mo"."property_count" AS "owner_property_count",
    COALESCE("lt"."prospect_id", "bp"."prospect_id") AS "prospect_id",
    COALESCE("bp"."full_name", "mo"."display_name") AS "prospect_full_name",
    COALESCE("lt"."canonical_e164", "bp"."best_phone") AS "prospect_best_phone",
    COALESCE("bp"."sms_eligible", false) AS "sms_eligible",
    COALESCE(NULLIF("lt"."latest_message_body", ''::"text"), NULLIF("bp"."full_name", ''::"text"), NULLIF("mo"."display_name", ''::"text"), ('Lead: '::"text" || "p"."property_id")) AS "display_name",
    COALESCE(NULLIF("p"."property_address_full", ''::"text"), 'Unknown Property'::"text") AS "display_address",
    COALESCE(NULLIF("lt"."canonical_e164", ''::"text"), NULLIF("bp"."best_phone", ''::"text"), 'No Phone'::"text") AS "display_phone",
    COALESCE("p"."market", 'Unknown'::"text") AS "display_market"
   FROM ((((("public"."properties" "p"
     LEFT JOIN LATERAL ( SELECT "ts"."thread_key",
            "ts"."stage",
            "ts"."status",
            "ts"."priority",
            "ts"."is_read",
            "ts"."is_pinned",
            "ts"."is_starred",
            "ts"."is_urgent",
            "ts"."is_hot_lead",
            "ts"."is_suppressed",
            "ts"."last_intent",
            "ts"."next_action",
            "ts"."automation_state",
            "ts"."latest_message_body",
            "ts"."latest_message_at",
            "ts"."latest_direction",
            "ts"."last_inbound_at",
            "ts"."last_outbound_at",
            "ts"."pending_queue_count",
            "ts"."agent_id",
            "ts"."persona_id",
            "ts"."follow_up_at",
            "ts"."master_owner_id",
            "ts"."prospect_id",
            "ts"."canonical_e164"
           FROM "public"."inbox_thread_state" "ts"
          WHERE ("ts"."property_id" = "p"."property_id")
          ORDER BY "ts"."latest_message_at" DESC NULLS LAST, "ts"."updated_at" DESC NULLS LAST
         LIMIT 1) "lt" ON (true))
     LEFT JOIN LATERAL ( SELECT "sq"."id" AS "queue_id",
            "sq"."queue_status",
            "sq"."scheduled_for",
            "sq"."sent_at",
            "sq"."delivered_at",
            "sq"."failed_reason"
           FROM "public"."send_queue" "sq"
          WHERE ("sq"."property_id" = "p"."property_id")
          ORDER BY "sq"."created_at" DESC
         LIMIT 1) "lq" ON (true))
     LEFT JOIN LATERAL ( SELECT "me"."id" AS "message_id",
            "me"."direction",
            "me"."message_body",
            "me"."delivery_status",
            "me"."event_timestamp",
            "me"."is_opt_out"
           FROM "public"."message_events" "me"
          WHERE ("me"."property_id" = "p"."property_id")
          ORDER BY "me"."event_timestamp" DESC NULLS LAST, "me"."created_at" DESC NULLS LAST
         LIMIT 1) "lm" ON (true))
     LEFT JOIN "public"."master_owners" "mo" ON (("mo"."master_owner_id" = "p"."master_owner_id")))
     LEFT JOIN LATERAL ( SELECT "pr"."prospect_id",
            "pr"."full_name",
            "pr"."first_name",
            "pr"."best_phone",
            "pr"."sms_eligible"
           FROM "public"."prospects" "pr"
          WHERE ("pr"."master_owner_id" = "p"."master_owner_id")
          ORDER BY "pr"."contact_score_final" DESC NULLS LAST, "pr"."created_at" DESC
         LIMIT 1) "bp" ON (true));


--
-- Name: v_command_map_seller_pin_feed; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_command_map_seller_pin_feed" AS
 WITH "queue_stats" AS (
         SELECT "sq"."property_id",
            ("count"(*) FILTER (WHERE (("sq"."queue_status" = ANY (ARRAY['queued'::"text", 'pending'::"text", 'approved'::"text"])) AND (COALESCE("sq"."scheduled_for", "now"()) <= "now"()))))::integer AS "ready_count",
            ("count"(*) FILTER (WHERE (("sq"."queue_status" = ANY (ARRAY['queued'::"text", 'pending'::"text", 'approved'::"text"])) AND ("sq"."scheduled_for" > "now"()))))::integer AS "scheduled_count",
            ("count"(*) FILTER (WHERE ("sq"."queue_status" = ANY (ARRAY['queued'::"text", 'pending'::"text", 'approved'::"text"]))))::integer AS "queued_count",
            ("count"(*) FILTER (WHERE ("sq"."queue_status" = ANY (ARRAY['sending'::"text", 'processing'::"text", 'active'::"text"]))))::integer AS "active_count",
            ("count"(*) FILTER (WHERE ("sq"."queue_status" = 'sent'::"text")))::integer AS "sent_count",
            ("count"(*) FILTER (WHERE ("sq"."queue_status" = 'delivered'::"text")))::integer AS "delivered_count",
            "min"("sq"."scheduled_for") FILTER (WHERE (("sq"."queue_status" = ANY (ARRAY['queued'::"text", 'pending'::"text", 'approved'::"text"])) AND ("sq"."scheduled_for" > "now"()))) AS "next_scheduled_for"
           FROM "public"."send_queue" "sq"
          WHERE ("sq"."property_id" IS NOT NULL)
          GROUP BY "sq"."property_id"
        ), "message_stats" AS (
         SELECT "me"."property_id",
            ("count"(*) FILTER (WHERE ("me"."direction" = 'inbound'::"text")))::integer AS "inbound_count",
            ("count"(*) FILTER (WHERE ("me"."direction" = 'outbound'::"text")))::integer AS "outbound_count"
           FROM "public"."message_events" "me"
          WHERE ("me"."property_id" IS NOT NULL)
          GROUP BY "me"."property_id"
        )
 SELECT "p"."property_id",
    COALESCE("swi"."master_owner_id", "p"."master_owner_id") AS "master_owner_id",
    "swi"."prospect_id",
    COALESCE(NULLIF("swi"."thread_key", ''::"text"), ('property:'::"text" || "p"."property_id")) AS "thread_key",
    COALESCE(NULLIF("swi"."prospect_full_name", ''::"text"), NULLIF("swi"."owner_display_name", ''::"text"), NULLIF("mo"."display_name", ''::"text"), NULLIF("pr"."full_name", ''::"text"), NULLIF("pr"."first_name", ''::"text")) AS "seller_display_name",
    COALESCE(NULLIF("swi"."owner_display_name", ''::"text"), NULLIF("mo"."display_name", ''::"text")) AS "owner_display_name",
    COALESCE(NULLIF("p"."owner_name", ''::"text"), NULLIF("mo"."display_name", ''::"text")) AS "owner_name",
    COALESCE(NULLIF("pr"."full_name", ''::"text"), NULLIF("pr"."first_name", ''::"text")) AS "owner_full_name",
    NULL::"text" AS "entity_name",
    COALESCE(NULLIF("swi"."prospect_full_name", ''::"text"), NULLIF("pr"."full_name", ''::"text"), NULLIF("pr"."first_name", ''::"text"), NULLIF("mo"."display_name", ''::"text")) AS "seller_name",
    COALESCE(NULLIF("p"."property_address", ''::"text"), NULLIF("p"."property_address_full", ''::"text")) AS "property_address",
    COALESCE(NULLIF("swi"."property_address_full", ''::"text"), NULLIF("p"."property_address_full", ''::"text"), NULLIF("p"."property_address", ''::"text")) AS "property_address_full",
    COALESCE(NULLIF("p"."property_address_city", ''::"text"), NULLIF("swi"."city", ''::"text")) AS "property_address_city",
    COALESCE(NULLIF("p"."property_address_state", ''::"text"), NULLIF("swi"."state", ''::"text")) AS "property_address_state",
    COALESCE(NULLIF("p"."property_address_zip", ''::"text"), NULLIF("swi"."zip", ''::"text")) AS "property_address_zip",
    COALESCE(NULLIF("p"."market", ''::"text"), NULLIF("swi"."display_market", 'Unknown'::"text")) AS "market",
    COALESCE(NULLIF("p"."market", ''::"text"), NULLIF("swi"."display_market", 'Unknown'::"text")) AS "filter_market",
    COALESCE(NULLIF("p"."property_type", ''::"text"), NULLIF("p"."property_class", ''::"text")) AS "property_type",
    COALESCE(NULLIF("p"."property_class", ''::"text"), NULLIF("p"."property_type", ''::"text")) AS "asset_class",
    "p"."total_bedrooms",
    "p"."total_baths",
    "p"."building_square_feet",
    "p"."units_count",
    "p"."year_built",
    "p"."lot_square_feet",
    "p"."lot_acreage",
    "p"."estimated_value",
    "p"."equity_amount",
    "p"."equity_percent",
    "p"."estimated_repair_cost",
    "p"."final_acquisition_score",
    COALESCE("p"."structured_motivation_score", "swi"."priority_score", ("mo"."priority_score")::numeric) AS "motivation_score",
    COALESCE("p"."final_acquisition_score", "p"."structured_motivation_score", "swi"."priority_score", ("mo"."priority_score")::numeric) AS "priority_score",
    COALESCE("p"."podio_tags", "p"."seller_tags_text", "mo"."seller_tags_text") AS "podio_tags",
    COALESCE("p"."property_flags_text", "p"."seller_tags_text", "mo"."seller_tags_text") AS "property_flags_text",
    COALESCE("p"."property_flags_json", "p"."seller_tags_json", "mo"."seller_tags_json") AS "property_flags_json",
    COALESCE("p"."property_flags_text", "p"."seller_tags_text", "mo"."seller_tags_text") AS "property_tags_text",
    COALESCE("p"."property_flags_json", "p"."seller_tags_json", "mo"."seller_tags_json") AS "property_tags_json",
    COALESCE(NULLIF("mo"."owner_type_guess", ''::"text"),
        CASE
            WHEN "p"."is_corporate_owner" THEN 'Corporate'::"text"
            ELSE 'Individual'::"text"
        END) AS "owner_type",
    COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") AS "seller_state",
    COALESCE(NULLIF("swi"."status", ''::"text"), 'not_contacted'::"text") AS "seller_status",
    COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") AS "execution_state",
    COALESCE(NULLIF("swi"."inbox_category", ''::"text"), 'not_contacted'::"text") AS "inbox_category",
    "swi"."latest_message_at",
    "swi"."latest_direction",
    COALESCE("ms"."inbound_count", 0) AS "inbound_count",
    COALESCE("ms"."outbound_count", 0) AS "outbound_count",
    COALESCE("qs"."queued_count", 0) AS "queued_count",
    COALESCE("qs"."scheduled_count", 0) AS "scheduled_count",
    COALESCE("qs"."ready_count", 0) AS "ready_count",
    COALESCE("qs"."sent_count", 0) AS "sent_count",
    COALESCE("qs"."delivered_count", 0) AS "delivered_count",
    "qs"."next_scheduled_for",
    "p"."latitude",
    "p"."longitude",
    "p"."latitude" AS "lat",
    "p"."longitude" AS "lng",
        CASE
            WHEN ((COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = ANY (ARRAY['blocked'::"text", 'issue'::"text"])) OR (COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") = 'issue'::"text")) THEN '#ff6b63'::"text"
            WHEN (COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = 'hot'::"text") THEN '#f59e0b'::"text"
            WHEN (COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = 'positive_intent'::"text") THEN '#30d5c8'::"text"
            WHEN (COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = 'negotiating'::"text") THEN '#b188ff'::"text"
            WHEN (COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = 'new_reply'::"text") THEN '#62d3ff'::"text"
            WHEN (COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = 'contacted'::"text") THEN '#4d8fff'::"text"
            ELSE '#94a3b8'::"text"
        END AS "pin_color",
    'circle'::"text" AS "pin_shape",
        CASE
            WHEN (COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = ANY (ARRAY['hot'::"text", 'positive_intent'::"text", 'new_reply'::"text"])) THEN 'pulse_soft'::"text"
            WHEN (COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") = ANY (ARRAY['ready'::"text", 'active'::"text", 'scheduled'::"text"])) THEN 'pulse_warning'::"text"
            ELSE 'none'::"text"
        END AS "pulse_style",
        CASE
            WHEN (COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") = 'queued'::"text") THEN '#4d8fff'::"text"
            WHEN (COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") = 'scheduled'::"text") THEN '#38bdf8'::"text"
            WHEN (COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") = ANY (ARRAY['ready'::"text", 'active'::"text"])) THEN '#22d3ee'::"text"
            WHEN (COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") = 'sent'::"text") THEN '#4d8fff'::"text"
            WHEN (COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") = 'delivered'::"text") THEN '#22c55e'::"text"
            WHEN (COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") = 'issue'::"text") THEN '#ff6b63'::"text"
            ELSE 'transparent'::"text"
        END AS "execution_ring_color",
    GREATEST((COALESCE("p"."final_acquisition_score", (0)::numeric))::integer, (COALESCE("p"."structured_motivation_score", "swi"."priority_score", (0)::numeric))::integer,
        CASE
            WHEN (COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = 'new_reply'::"text") THEN 98
            WHEN (COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = 'positive_intent'::"text") THEN 92
            WHEN (COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = 'negotiating'::"text") THEN 88
            WHEN (COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = 'hot'::"text") THEN 85
            WHEN (COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") = ANY (ARRAY['ready'::"text", 'active'::"text"])) THEN 78
            WHEN (COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") = 'scheduled'::"text") THEN 68
            WHEN (COALESCE(NULLIF("swi"."execution_state", ''::"text"), 'none'::"text") = 'queued'::"text") THEN 60
            WHEN (COALESCE(NULLIF("swi"."seller_state", ''::"text"), 'not_contacted'::"text") = 'contacted'::"text") THEN 52
            ELSE 35
        END) AS "render_priority"
   FROM ((((("public"."properties" "p"
     LEFT JOIN "public"."v_seller_work_items" "swi" ON (("swi"."property_id" = "p"."property_id")))
     LEFT JOIN "public"."master_owners" "mo" ON (("mo"."master_owner_id" = COALESCE("swi"."master_owner_id", "p"."master_owner_id"))))
     LEFT JOIN "public"."prospects" "pr" ON (("pr"."prospect_id" = "swi"."prospect_id")))
     LEFT JOIN "queue_stats" "qs" ON (("qs"."property_id" = "p"."property_id")))
     LEFT JOIN "message_stats" "ms" ON (("ms"."property_id" = "p"."property_id")))
  WHERE (("p"."latitude" IS NOT NULL) AND ("p"."longitude" IS NOT NULL));


--
-- Name: get_command_map_seller_pins(double precision, double precision, double precision, double precision, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_command_map_seller_pins"("min_lat" double precision, "min_lng" double precision, "max_lat" double precision, "max_lng" double precision, "zoom_level" integer DEFAULT 10, "max_rows" integer DEFAULT 1000) RETURNS SETOF "public"."v_command_map_seller_pin_feed"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  l_max_rows integer := least(greatest(coalesce(max_rows, 1000), 100), 5000);
  l_inventory_limit integer;
  l_priority_limit integer;
BEGIN
  -- We now use a more balanced sampling at all zoom levels to prevent uncontacted
  -- inventory from being completely starved by high-priority activity.
  IF coalesce(zoom_level, 10) < 11 THEN
    l_inventory_limit := floor(l_max_rows * 0.5)::integer;
    l_priority_limit := l_max_rows - l_inventory_limit;
  ELSE
    -- At high zoom, we can show more, but we still split to ensure diversity.
    l_inventory_limit := floor(l_max_rows * 0.7)::integer;
    l_priority_limit := l_max_rows;
  END IF;

  RETURN QUERY
  WITH bounds_filtered AS (
    SELECT *
    FROM public.v_command_map_seller_pin_feed p
    WHERE p.latitude BETWEEN least(min_lat, max_lat)::numeric AND greatest(min_lat, max_lat)::numeric
      AND p.longitude BETWEEN least(min_lng, max_lng)::numeric AND greatest(min_lng, max_lng)::numeric
  ),
  high_priority AS (
    SELECT *
    FROM bounds_filtered
    WHERE seller_state <> 'not_contacted'
       OR execution_state <> 'none'
       OR render_priority >= 45
    ORDER BY render_priority DESC, coalesce(priority_score, 0) DESC, latest_message_at DESC NULLS LAST
    LIMIT l_priority_limit
  ),
  inventory AS (
    SELECT *
    FROM bounds_filtered
    WHERE seller_state = 'not_contacted'
      AND execution_state = 'none'
      AND render_priority < 45
    ORDER BY render_priority DESC, coalesce(priority_score, 0) DESC, estimated_value DESC NULLS LAST
    LIMIT l_inventory_limit
  ),
  combined AS (
    SELECT * FROM high_priority
    UNION ALL
    SELECT * FROM inventory
  )
  SELECT * FROM (
    SELECT DISTINCT ON (property_id) *
    FROM combined
    ORDER BY property_id, render_priority DESC, coalesce(priority_score, 0) DESC, latest_message_at DESC NULLS LAST
  ) sub
  ORDER BY render_priority DESC, coalesce(priority_score, 0) DESC, latest_message_at DESC NULLS LAST
  LIMIT l_max_rows;
END;
$$;


--
-- Name: get_comp_candidates_for_subject("text", numeric, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_comp_candidates_for_subject"("p_subject_property_id" "text", "p_radius_miles" numeric DEFAULT 1.0, "p_months_back" integer DEFAULT 6, "p_limit" integer DEFAULT 25) RETURNS TABLE("comp_id" "uuid", "property_id" "text", "address" "text", "city" "text", "state" "text", "zip" "text", "latitude" numeric, "longitude" numeric, "sale_price" numeric, "sale_date" "date", "mls_sold_price" numeric, "mls_sold_date" "date", "estimated_value" numeric, "price_off_value" numeric, "percent_off" numeric, "ppsf" numeric, "ppu" numeric, "ppbd" numeric, "asset_class" "text", "property_type" "text", "building_condition" "text", "construction_type" "text", "beds" numeric, "baths" numeric, "sqft" numeric, "units_count" numeric, "year_built" numeric, "distance_miles" numeric, "similarity_score" numeric, "comp_confidence_score" numeric, "deal_grade" "text", "streetview_image" "text")
    LANGUAGE "sql" STABLE
    AS $$
with subject as (
  -- Try to find in sold comps first (might have more specific comp data)
  select
    property_id,
    latitude,
    longitude,
    normalized_asset_class,
    property_type,
    total_bedrooms,
    total_baths,
    building_square_feet,
    year_built,
    units_count
  from public.v_recent_sold_comps
  where property_id = p_subject_property_id
  
  union all
  
  -- Fallback to properties table
  select
    property_id,
    latitude,
    longitude,
    case 
      when property_type in ('Single Family', 'Residential') then 'single_family'
      when property_type in ('Multi-Family', 'Apartment', 'Duplex', 'Triplex', 'Quadruplex') then 'multifamily'
      else 'single_family' 
    end as normalized_asset_class,
    property_type,
    total_bedrooms,
    total_baths,
    building_square_feet,
    year_built::numeric,
    units_count::numeric
  from public.properties
  where property_id = p_subject_property_id
    and not exists (select 1 from public.v_recent_sold_comps where property_id = p_subject_property_id)
  
  limit 1
),
candidates as (
  select
    c.*,
    (
      3958.8 * acos(
        least(1, greatest(-1,
          cos(radians(s.latitude)) * cos(radians(c.latitude)) *
          cos(radians(c.longitude) - radians(s.longitude)) +
          sin(radians(s.latitude)) * sin(radians(c.latitude))
        ))
      )
    ) as distance_miles,

    (
      100::numeric
      - least(35::numeric, abs(coalesce(c.building_square_feet, 0) - coalesce(s.building_square_feet, 0)) / greatest(coalesce(s.building_square_feet, 1), 1) * 35)
      - least(15::numeric, abs(coalesce(c.total_bedrooms, 0) - coalesce(s.total_bedrooms, 0)) * 5)
      - least(15::numeric, abs(coalesce(c.total_baths, 0) - coalesce(s.total_baths, 0)) * 5)
      - least(20::numeric, abs(coalesce(c.year_built, 0) - coalesce(s.year_built, 0)) / 5)
      - case when c.normalized_asset_class = s.normalized_asset_class then 0::numeric else 20::numeric end
    ) as similarity_score
  from public.v_recent_sold_comps c
  cross join subject s
  where c.is_usable_comp = true
    and c.property_id is distinct from s.property_id
    and c.sale_date >= current_date - make_interval(months => p_months_back)
    and c.latitude is not null
    and c.longitude is not null
)
select
  id as comp_id,
  property_id,
  property_address_full as address,
  property_address_city as city,
  property_address_state as state,
  property_address_zip as zip,
  latitude,
  longitude,
  sale_price,
  sale_date,
  mls_sold_price,
  mls_sold_date,
  estimated_value,
  price_off_value,
  percent_off,
  computed_ppsf as ppsf,
  ppu,
  ppbd,
  normalized_asset_class as asset_class,
  property_type,
  building_condition,
  construction_type,
  total_bedrooms as beds,
  total_baths as baths,
  building_square_feet as sqft,
  units_count,
  year_built,
  round(distance_miles::numeric, 2) as distance_miles,
  greatest(0::numeric, round(similarity_score::numeric, 2)) as similarity_score,
  comp_confidence_score,
  deal_grade,
  streetview_image
from candidates
where distance_miles <= p_radius_miles
order by
  similarity_score desc nulls last,
  sale_date desc nulls last,
  distance_miles asc
limit least(greatest(p_limit, 1), 100);
$$;


--
-- Name: nexus_inbox_priority_classify("text", "text", bigint, boolean, boolean, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."nexus_inbox_priority_classify"("latest_direction" "text", "latest_message_body" "text", "pending_queue_count" bigint DEFAULT 0, "is_archived" boolean DEFAULT false, "is_suppressed" boolean DEFAULT false, "has_opt_out" boolean DEFAULT false) RETURNS TABLE("ui_intent" "text", "priority_bucket" "text", "show_in_priority_inbox" boolean)
    LANGUAGE "sql" STABLE
    AS $_$
WITH normalized AS (
  SELECT
    LOWER(TRIM(REGEXP_REPLACE(COALESCE(latest_message_body, ''), '[^a-zA-Z0-9áéíóúüñÁÉÍÓÚÜÑ]+', ' ', 'g'))) as body_norm,
    (' ' || LOWER(TRIM(REGEXP_REPLACE(COALESCE(latest_message_body, ''), '[^a-zA-Z0-9áéíóúüñÁÉÍÓÚÜÑ]+', ' ', 'g'))) || ' ') as body_pad
),
classify AS (
  SELECT
    CASE
      -- 1. Non-inbound
      WHEN LOWER(COALESCE(latest_direction, '')) IS DISTINCT FROM 'inbound' THEN 'outbound_waiting'
      
      -- 2. Opt Out
      WHEN COALESCE(has_opt_out, false) OR body_pad LIKE '% stop %' OR body_pad LIKE '% remove %' OR body_pad LIKE '% unsubscribe %' THEN 'opt_out'
        
      -- 3. Wrong Number
      WHEN body_pad LIKE '% wrong number %' OR body_pad LIKE '% wrong person %' OR body_pad LIKE '% not the owner %' THEN 'wrong_number'
        
      -- 4. Not Interested
      WHEN body_norm IN ('no', 'nope', 'nah') OR body_pad LIKE '% not interested %' OR body_pad LIKE '% not for sale %' THEN 'not_interested'
      
      -- 5. Tenant Occupancy
      WHEN body_pad LIKE '% tenant %' OR body_pad LIKE '% rented %' OR body_pad LIKE '% lease %' THEN 'tenant_occupancy'
      
      -- 6. Condition Disclosed
      WHEN body_pad LIKE '% needs work %' OR body_pad LIKE '% fixer %' OR body_pad LIKE '% bad shape %' OR body_pad LIKE '% roof %' THEN 'condition_disclosed'

      -- 7. Asks Offer
      WHEN body_pad LIKE '% make me an offer %' OR body_pad LIKE '% your offer %' OR body_pad LIKE '% what you pay %' THEN 'asks_offer'

      -- 8. Asking Price (Improved Regex)
      WHEN latest_message_body ~* '(\$?\d{1,3}([.,]\d{3})+( |$))|(\d+ *(k|m|million))|(\d{6,8})' THEN 'asking_price_provided'

      -- 9. Ownership Confirmed
      WHEN body_pad LIKE '% i own it %' OR body_pad LIKE '% it is mine %' OR body_pad LIKE '% yes it is %' THEN 'ownership_confirmed'
        
      -- 10. Needs Call
      WHEN body_pad LIKE '% call me %' OR body_pad LIKE '% give me a call %' OR body_pad LIKE '% phone number %' THEN 'needs_call'

      -- 11. Needs Email
      WHEN body_pad LIKE '% email me %' OR body_pad LIKE '% send email %' OR body_pad LIKE '% what is your email %' THEN 'needs_email'

      -- 12. Who Is This
      WHEN body_pad LIKE '% who is this %' OR body_pad LIKE '% who are you %' OR body_pad LIKE '% what company %' THEN 'who_is_this'

      -- 13. Seller Interested
      WHEN body_norm IN ('yes', 'si', 'ok', 'okay') 
        OR body_pad LIKE '% interested in selling %' 
        OR body_pad LIKE '% i am interested %' THEN 'seller_interested'
        
      -- Fallback
      ELSE 'unclear'
    END as ui_intent
  FROM normalized
)
SELECT
  c.ui_intent,
  CASE
    WHEN c.ui_intent = 'outbound_waiting' THEN (CASE WHEN pending_queue_count > 0 THEN 'queued' ELSE 'normal' END)
    WHEN c.ui_intent IN ('opt_out') THEN 'suppressed'
    WHEN c.ui_intent IN ('wrong_number', 'not_interested', 'tenant_occupancy') THEN 'hidden'
    ELSE 'priority'
  END as priority_bucket,
  (
    NOT is_archived AND NOT is_suppressed AND NOT has_opt_out 
    AND LOWER(latest_direction) = 'inbound'
    AND c.ui_intent NOT IN ('opt_out', 'wrong_number', 'not_interested')
  ) as show_in_priority_inbox
FROM classify c;
$_$;


--
-- Name: deduped_message_events; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."deduped_message_events" AS
 WITH "ranked" AS (
         SELECT "message_events"."id",
            "message_events"."message_event_key",
            "message_events"."provider_message_sid",
            "message_events"."direction",
            "message_events"."event_type",
            "message_events"."message_body",
            "message_events"."to_phone_number",
            "message_events"."from_phone_number",
            "message_events"."phone_number_id",
            "message_events"."queue_id",
            "message_events"."metadata",
            "message_events"."created_at",
            "message_events"."sent_at",
            "message_events"."received_at",
            "message_events"."delivered_at",
            "message_events"."failed_at",
            "message_events"."error_message",
            "message_events"."property_address",
            "message_events"."message_id",
            "message_events"."event_timestamp",
            "message_events"."message_variant",
            "message_events"."master_owner_id",
            "message_events"."prospect_id",
            "message_events"."property_id",
            "message_events"."textgrid_number_id",
            "message_events"."sms_agent_id",
            "message_events"."template_id",
            "message_events"."conversation_brain_id",
            "message_events"."market_id",
            "message_events"."ai_route",
            "message_events"."processed_by",
            "message_events"."source_app",
            "message_events"."trigger_name",
            "message_events"."ai_output",
            "message_events"."character_count",
            "message_events"."delivery_status",
            "message_events"."raw_carrier_status",
            "message_events"."is_final_failure",
            "message_events"."failure_bucket",
            "message_events"."latency_ms",
            "message_events"."processing_delay_seconds",
            "message_events"."provider_delivery_status",
            "message_events"."failure_code",
            "message_events"."failure_reason",
            "message_events"."is_opt_out",
            "message_events"."opt_out_keyword",
            "message_events"."opt_out_message",
            "message_events"."segment_count",
            "message_events"."prior_message_id",
            "message_events"."triggered_by",
            "message_events"."response_to_message_id",
            "message_events"."stage_before",
            "message_events"."stage_after",
            "message_events"."stage_changed_by",
            "message_events"."stage_change_reason",
            "message_events"."podio_sync_status",
            "message_events"."podio_message_event_id",
            "message_events"."podio_synced_at",
            "message_events"."podio_sync_error",
            "message_events"."podio_sync_attempts",
            "message_events"."updated_at",
            "message_events"."thread_key",
            "message_events"."seller_display_name",
            "message_events"."market",
            "message_events"."detected_intent",
            "message_events"."routing_allowed",
            "message_events"."safety_status",
            "message_events"."priority",
            "message_events"."risk",
            "message_events"."type",
            "message_events"."language",
            "message_events"."classification_confidence",
            "message_events"."current_stage",
            "row_number"() OVER (PARTITION BY COALESCE(("message_events"."queue_id")::"text", "message_events"."provider_message_sid", "message_events"."message_id", "message_events"."message_event_key", ("message_events"."id")::"text") ORDER BY
                CASE
                    WHEN ("message_events"."delivery_status" = ANY (ARRAY['delivered'::"text", 'sent'::"text"])) THEN 1
                    WHEN ("message_events"."delivery_status" = ANY (ARRAY['queued'::"text", 'pending'::"text", 'scheduled'::"text"])) THEN 2
                    WHEN ("message_events"."delivery_status" = ANY (ARRAY['failed'::"text", 'undelivered'::"text"])) THEN 3
                    ELSE 4
                END, COALESCE("message_events"."delivered_at", "message_events"."sent_at", "message_events"."received_at", "message_events"."event_timestamp", "message_events"."created_at") DESC) AS "rn"
           FROM "public"."message_events"
          WHERE ("message_events"."thread_key" IS NOT NULL)
        )
 SELECT "id",
    "message_event_key",
    "provider_message_sid",
    "direction",
    "event_type",
    "message_body",
    "to_phone_number",
    "from_phone_number",
    "phone_number_id",
    "queue_id",
    "metadata",
    "created_at",
    "sent_at",
    "received_at",
    "delivered_at",
    "failed_at",
    "error_message",
    "property_address",
    "message_id",
    "event_timestamp",
    "message_variant",
    "master_owner_id",
    "prospect_id",
    "property_id",
    "textgrid_number_id",
    "sms_agent_id",
    "template_id",
    "conversation_brain_id",
