--
-- Name: nexus_inbox_threads_v; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."nexus_inbox_threads_v" AS
 WITH "message_base" AS (
         SELECT "me"."id",
            COALESCE("me"."event_timestamp", "me"."created_at") AS "message_ts",
            "me"."direction",
            COALESCE("me"."message_body", ''::"text") AS "message_body",
            "me"."delivery_status",
            "me"."delivered_at",
            "me"."sent_at",
            "me"."provider_message_sid",
            "me"."is_opt_out",
            "me"."master_owner_id",
            "me"."prospect_id",
            "me"."property_id",
            "me"."market",
            "me"."thread_key",
            "me"."property_address",
            "me"."seller_display_name"
           FROM "public"."deduped_message_events" "me"
        ), "thread_rollup" AS (
         SELECT "message_base"."thread_key",
            "count"(*) AS "message_count",
            "count"(*) FILTER (WHERE ("message_base"."direction" = 'inbound'::"text")) AS "inbound_count",
            "count"(*) FILTER (WHERE ("message_base"."direction" = 'outbound'::"text")) AS "outbound_count",
            "count"(*) FILTER (WHERE (("message_base"."direction" = 'outbound'::"text") AND ("message_base"."delivery_status" = ANY (ARRAY['queued'::"text", 'pending'::"text", 'scheduled'::"text"])))) AS "pending_queue_count",
            "max"("message_base"."message_ts") AS "latest_message_at",
            "max"("message_base"."message_ts") FILTER (WHERE ("message_base"."direction" = 'inbound'::"text")) AS "last_inbound_at",
            "max"("message_base"."message_ts") FILTER (WHERE ("message_base"."direction" = 'outbound'::"text")) AS "last_outbound_at",
            "max"("message_base"."delivered_at") AS "last_delivered_at"
           FROM "message_base"
          GROUP BY "message_base"."thread_key"
        ), "latest_msg" AS (
         SELECT DISTINCT ON ("message_base"."thread_key") "message_base"."id",
            "message_base"."message_ts",
            "message_base"."direction",
            "message_base"."message_body",
            "message_base"."delivery_status",
            "message_base"."delivered_at",
            "message_base"."sent_at",
            "message_base"."provider_message_sid",
            "message_base"."is_opt_out",
            "message_base"."master_owner_id",
            "message_base"."prospect_id",
            "message_base"."property_id",
            "message_base"."market",
            "message_base"."thread_key",
            "message_base"."property_address",
            "message_base"."seller_display_name"
           FROM "message_base"
          ORDER BY "message_base"."thread_key", "message_base"."message_ts" DESC, "message_base"."id" DESC
        )
 SELECT "l"."thread_key",
    "tr"."latest_message_at",
    "l"."direction" AS "latest_direction",
    "l"."message_body" AS "latest_message_body",
    "l"."master_owner_id",
    "l"."prospect_id",
    "l"."property_id",
    COALESCE("l"."market", 'unknown'::"text") AS "market",
    "tr"."message_count",
    "tr"."inbound_count",
    "tr"."outbound_count",
    "tr"."pending_queue_count",
    "tr"."last_inbound_at",
    "tr"."last_outbound_at",
    "l"."property_address" AS "event_property_address",
    "l"."seller_display_name" AS "event_seller_display_name",
    "c"."ui_intent",
    "c"."priority_bucket",
    COALESCE(NULLIF("ts"."status", ''::"text"), 'open'::"text") AS "status",
    COALESCE(NULLIF("ts"."stage", ''::"text"), 'needs_response'::"text") AS "stage",
    "c"."show_in_priority_inbox",
    COALESCE("ts"."is_archived", false) AS "is_archived",
    COALESCE("ts"."is_read", false) AS "is_read",
    COALESCE("ts"."is_pinned", false) AS "is_pinned",
    COALESCE("ts"."is_hot_lead", false) AS "is_hot_lead",
    "l"."delivery_status" AS "latest_delivery_status",
    "l"."delivered_at" AS "latest_delivered_at",
    "l"."sent_at" AS "latest_sent_at",
    "l"."provider_message_sid" AS "latest_provider_sid",
    "tr"."last_delivered_at"
   FROM ((("latest_msg" "l"
     JOIN "thread_rollup" "tr" ON (("tr"."thread_key" = "l"."thread_key")))
     LEFT JOIN "public"."inbox_thread_state" "ts" ON (("ts"."thread_key" = "l"."thread_key")))
     CROSS JOIN LATERAL "public"."nexus_inbox_priority_classify"("l"."direction", "l"."message_body", "tr"."pending_queue_count", COALESCE("ts"."is_archived", false), COALESCE("ts"."is_suppressed", false), COALESCE("l"."is_opt_out", false)) "c"("ui_intent", "priority_bucket", "show_in_priority_inbox"));


