     LEFT JOIN "public"."properties" "p" ON (("p"."property_id" = COALESCE("r"."res_property_id", "lp"."property_id"))))
     LEFT JOIN "public"."master_owners" "mo" ON (("mo"."master_owner_id" = "r"."res_owner_id")))
     LEFT JOIN "public"."prospects" "pr" ON (("pr"."prospect_id" = "r"."res_prospect_id")));


--
-- Name: get_inbox_thread_dossier("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_inbox_thread_dossier"("thread_key_param" "text") RETURNS SETOF "public"."inbox_threads_hydrated"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY SELECT * FROM public.inbox_threads_hydrated WHERE thread_key = thread_key_param LIMIT 1;
END;
$$;


--
-- Name: get_next_queued_message(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_next_queued_message"() RETURNS TABLE("id" "uuid", "contact_id" "uuid", "phone_number" character varying, "message_body" "text", "scheduled_for" timestamp with time zone)
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    RETURN QUERY
    SELECT mq.id, mq.contact_id, mq.phone_number, mq.message_body, mq.scheduled_for
    FROM message_queue mq
    WHERE mq.status = 'queued'
      AND (mq.scheduled_for IS NULL OR mq.scheduled_for <= NOW())
    ORDER BY mq.priority DESC, mq.created_at ASC
    LIMIT 1
    FOR UPDATE SKIP LOCKED;
END;
$$;


--
-- Name: get_number_rotation_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_number_rotation_stats"() RETURNS TABLE("phone_number" "text", "status" "text", "messages_sent_today" integer, "daily_limit" integer, "remaining_capacity" integer, "usage_percentage" double precision, "last_used_at" timestamp with time zone)
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        tn.phone_number,
        tn.status,
        tn.messages_sent_today,
        tn.daily_limit,
        tn.daily_limit - tn.messages_sent_today as remaining_capacity,
        ROUND((tn.messages_sent_today::FLOAT / tn.daily_limit::FLOAT * 100)::numeric, 2)::FLOAT as usage_percentage,
        tn.last_used_at
    FROM textgrid_numbers tn
    ORDER BY tn.messages_sent_today DESC;
END;
$$;


--
-- Name: get_or_create_conversation("uuid", character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_or_create_conversation"("p_contact_id" "uuid", "p_stage" character varying DEFAULT 'initial_contact'::character varying, "p_persona" character varying DEFAULT 'professional'::character varying, "p_language" character varying DEFAULT 'en'::character varying) RETURNS "uuid"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    v_conversation_id UUID;
BEGIN
    -- Try to get existing conversation
    SELECT id INTO v_conversation_id
    FROM conversations
    WHERE contact_id = p_contact_id;
    
    -- If not found, create new
    IF v_conversation_id IS NULL THEN
        INSERT INTO conversations (contact_id, conversation_stage, agent_persona, language)
        VALUES (p_contact_id, p_stage, p_persona, p_language)
        RETURNING id INTO v_conversation_id;
    END IF;
    
    RETURN v_conversation_id;
END;
$$;


--
-- Name: get_ownership_check_template_stats(timestamp with time zone, timestamp with time zone, "text", "text", "text", integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_ownership_check_template_stats"("p_start_date" timestamp with time zone DEFAULT ("now"() - '30 days'::interval), "p_end_date" timestamp with time zone DEFAULT "now"(), "p_market" "text" DEFAULT NULL::"text", "p_agent_id" "text" DEFAULT NULL::"text", "p_language" "text" DEFAULT NULL::"text", "p_min_sent" integer DEFAULT 1) RETURNS TABLE("template_id" "text", "template_uuid" "uuid", "template_name" "text", "use_case" "text", "stage_code" "text", "stage_label" "text", "language" "text", "agent_persona" "text", "template_text" "text", "is_active" boolean, "total_queued" bigint, "total_sent" bigint, "total_delivered" bigint, "total_failed" bigint, "total_pending" bigint, "total_paused" bigint, "total_blocked" bigint, "first_sent_at" timestamp with time zone, "last_sent_at" timestamp with time zone, "delivery_rate" numeric, "failure_rate" numeric, "pending_rate" numeric, "total_inbound_replies" bigint, "unique_seller_replies" bigint, "reply_rate" numeric, "same_day_reply_count" bigint, "same_day_reply_rate" numeric, "reply_within_1hr_count" bigint, "reply_within_4hr_count" bigint, "reply_within_24hr_count" bigint, "avg_minutes_to_first_reply" numeric, "median_minutes_to_first_reply" numeric, "positive_interest_count" bigint, "positive_interest_rate" numeric, "ownership_confirmed_count" bigint, "ownership_confirmed_rate" numeric, "info_request_count" bigint, "info_request_rate" numeric, "not_interested_count" bigint, "not_interested_rate" numeric, "wrong_number_count" bigint, "wrong_number_rate" numeric, "opt_out_count" bigint, "opt_out_rate" numeric, "hostile_or_legal_count" bigint, "hostile_or_legal_rate" numeric, "unclear_count" bigint, "unclear_rate" numeric, "advanced_to_consider_selling_count" bigint, "advanced_to_consider_selling_rate" numeric, "advanced_to_price_count" bigint, "advanced_to_price_rate" numeric, "advanced_to_offer_count" bigint, "advanced_to_offer_rate" numeric, "advanced_to_contract_count" bigint, "advanced_to_contract_rate" numeric, "suppressed_after_template_count" bigint, "suppressed_after_template_rate" numeric, "delivery_score" numeric, "reply_score" numeric, "positive_intent_score" numeric, "progression_score" numeric, "compliance_safety_score" numeric, "revenue_score" numeric, "overall_template_score" numeric, "recommendation" "text", "risk_flags" "text"[], "top_markets" "jsonb", "sample_replies" "jsonb")
    LANGUAGE "sql" STABLE
    AS $_$
with template_base as (
  select st.id template_uuid,
         coalesce(nullif(st.template_id,''), nullif(st.podio_template_id,''), st.id::text) template_id,
         coalesce(nullif(st.template_name,''), nullif(st.stage_label,''), nullif(st.use_case,''), st.id::text) template_name,
         st.use_case, st.stage_code, st.stage_label, coalesce(nullif(st.language,''),'en') language,
         st.agent_persona, st.template_body template_text, coalesce(st.is_active,true) is_active
  from public.sms_templates st
  where lower(coalesce(st.use_case,''))='ownership_check'
     or lower(coalesce(st.stage_code,''))='ownership_check'
     or lower(coalesce(st.metadata->>'use_case',''))='ownership_check'
),
queue_base as (
  select q.*, coalesce(nullif(q.selected_template_id,''), nullif(q.template_id,''), nullif(q.metadata->>'template_id',''), nullif(q.metadata->>'selected_template_id','')) resolved_template_id
  from public.send_queue q
  where coalesce(q.created_at,q.scheduled_for,q.scheduled_for_utc) between p_start_date and p_end_date
    and (p_market is null or q.market=p_market or q.market_id=p_market or q.metadata->>'market'=p_market)
    and (p_agent_id is null or q.sms_agent_id=p_agent_id or q.selected_agent_id=p_agent_id or q.metadata->>'agent_id'=p_agent_id)
    and (p_language is null or q.language=p_language or q.metadata->>'language'=p_language)
),
outbound_events as (
  select me.id event_id, me.thread_key, coalesce(me.event_timestamp,me.sent_at,me.created_at) outbound_at,
         coalesce(nullif(me.template_id,''),nullif(q.selected_template_id,''),nullif(q.template_id,''),nullif(me.metadata->>'template_id',''),nullif(q.metadata->>'template_id','')) resolved_template_id,
         coalesce(me.to_phone_number,q.to_phone_number) seller_phone, coalesce(me.market,q.market) market, me.delivery_status, me.stage_after, q.id queue_id
  from public.message_events me left join public.send_queue q on q.id=me.queue_id
  where lower(coalesce(me.direction,''))='outbound'
    and coalesce(me.event_timestamp,me.sent_at,me.created_at) between p_start_date and p_end_date
    and (p_market is null or coalesce(me.market,q.market,me.market_id,q.market_id)=p_market)
),
inbound_events as (
  select me.id event_id, me.thread_key, coalesce(me.event_timestamp,me.received_at,me.created_at) inbound_at,
         coalesce(me.from_phone_number,me.to_phone_number) seller_phone,
         lower(coalesce(me.detected_intent,me.metadata->>'intent',me.event_type,'unclear')) intent,
         lower(coalesce(me.stage_after,me.current_stage,me.metadata->>'stage_after','')) stage_after,
         lower(coalesce(me.safety_status,me.metadata->>'safety_status','')) safety_status,
         coalesce(me.is_opt_out,false) is_opt_out, me.message_body, me.market
  from public.message_events me
  where lower(coalesce(me.direction,''))='inbound'
    and coalesce(me.event_timestamp,me.received_at,me.created_at) between p_start_date and p_end_date
    and (p_market is null or me.market=p_market or me.market_id=p_market)
),
attributed_replies as (
  select i.*, o.resolved_template_id attributed_template_id, o.outbound_at, extract(epoch from (i.inbound_at-o.outbound_at))/60.0 minutes_to_reply
  from inbound_events i
  join lateral (
    select o.* from outbound_events o
    where o.resolved_template_id is not null and o.outbound_at<=i.inbound_at and o.outbound_at>=i.inbound_at-interval '14 days'
      and ((i.thread_key is not null and o.thread_key=i.thread_key) or (i.thread_key is null and i.seller_phone is not null and o.seller_phone=i.seller_phone))
    order by o.outbound_at desc limit 1
  ) o on true
),
queue_metrics as (
  select tb.template_id,
    count(q.id)::bigint total_queued,
    count(*) filter (where q.queue_status in ('sent','sent_waiting_delivery','delivered') or q.sent_at is not null or q.provider_message_id is not null or q.textgrid_message_id is not null)::bigint total_sent,
    count(*) filter (where q.queue_status='delivered' or q.delivered_at is not null or lower(coalesce(q.delivery_confirmed,''))='delivered')::bigint total_delivered,
    count(*) filter (where q.queue_status in ('failed','send_failed') or q.failed_reason is not null)::bigint total_failed,
    count(*) filter (where q.queue_status in ('queued','scheduled','pending','sending'))::bigint total_pending,
    count(*) filter (where q.queue_status ilike '%paused%')::bigint total_paused,
    count(*) filter (where q.queue_status in ('blocked','cancelled') or q.blocked_reason is not null or q.guard_reason is not null)::bigint total_blocked,
    min(q.sent_at) filter (where q.sent_at is not null) first_sent_at, max(q.sent_at) filter (where q.sent_at is not null) last_sent_at
  from template_base tb left join queue_base q on q.resolved_template_id in (tb.template_id,tb.template_uuid::text)
  group by tb.template_id
),
reply_metrics as (
  select tb.template_id,
    count(ar.event_id)::bigint total_inbound_replies,
    count(distinct coalesce(ar.thread_key,ar.seller_phone))::bigint unique_seller_replies,
    count(*) filter (where ar.inbound_at::date=ar.outbound_at::date)::bigint same_day_reply_count,
    count(*) filter (where ar.minutes_to_reply<=60)::bigint reply_within_1hr_count,
    count(*) filter (where ar.minutes_to_reply<=240)::bigint reply_within_4hr_count,
    count(*) filter (where ar.minutes_to_reply<=1440)::bigint reply_within_24hr_count,
    avg(ar.minutes_to_reply)::numeric avg_minutes_to_first_reply,
    percentile_cont(0.5) within group (order by ar.minutes_to_reply)::numeric median_minutes_to_first_reply,
    count(*) filter (where ar.intent ~ '(positive|interested|yes|ask_offer|price_given|seller_open|open_to_offer)' or ar.stage_after ~ '(ownership_confirmed|seller_open|price|offer|negotiat)')::bigint positive_interest_count,
    count(*) filter (where ar.intent ~ '(ownership|yes_confirmed|owner_confirmed)' or ar.stage_after ~ 'ownership_confirmed')::bigint ownership_confirmed_count,
    count(*) filter (where ar.intent ~ '(info|who|how_got_number|send_info|ask_info)')::bigint info_request_count,
    count(*) filter (where ar.intent ~ '(not_interested|no_interest|dead)')::bigint not_interested_count,
    count(*) filter (where ar.intent ~ '(wrong_number|wrong_person|not_owner)' or ar.message_body ilike '%wrong number%')::bigint wrong_number_count,
    count(*) filter (where ar.is_opt_out or ar.intent ~ '(opt_out|stop|unsubscribe)' or ar.message_body ~* '(^|\s)(stop|unsubscribe|remove me)(\s|$)')::bigint opt_out_count,
    count(*) filter (where ar.intent ~ '(hostile|legal|attorney|lawsuit|sue|angry)' or ar.message_body ~* '(attorney|lawyer|lawsuit|sue|legal)')::bigint hostile_or_legal_count,
    count(*) filter (where ar.intent ~ '(unclear|unknown)' or ar.intent is null)::bigint unclear_count,
    count(*) filter (where ar.stage_after ~ '(consider_selling|seller_open|interest_probe)')::bigint advanced_to_consider_selling_count,
    count(*) filter (where ar.stage_after ~ '(price|asking|price_discovery)')::bigint advanced_to_price_count,
    count(*) filter (where ar.stage_after ~ '(offer|offer_ready|offer_sent|offer_reveal|offer_stage)')::bigint advanced_to_offer_count,
    count(*) filter (where ar.stage_after ~ '(contract|under_contract)')::bigint advanced_to_contract_count,
    count(*) filter (where ar.safety_status ~ '(suppressed|blocked)' or ar.intent ~ '(opt_out|stop|wrong_number|hostile|legal)')::bigint suppressed_after_template_count,
    jsonb_agg(jsonb_build_object('at',ar.inbound_at,'intent',ar.intent,'body',left(coalesce(ar.message_body,''),220)) order by ar.inbound_at desc) filter (where ar.event_id is not null) sample_replies
  from template_base tb left join attributed_replies ar on ar.attributed_template_id in (tb.template_id,tb.template_uuid::text)
  group by tb.template_id
),
market_rollup as (
  select q.resolved_template_id template_id, jsonb_agg(jsonb_build_object('market',q.market,'sent',q.cnt) order by q.cnt desc) top_markets
  from (select resolved_template_id, market, count(*) cnt from queue_base where resolved_template_id is not null and market is not null group by resolved_template_id, market) q
  group by q.resolved_template_id
),
final as (
  select tb.template_id,tb.template_uuid,tb.template_name,tb.use_case,tb.stage_code,tb.stage_label,tb.language,tb.agent_persona,tb.template_text,tb.is_active,
    coalesce(qm.total_queued,0)::bigint total_queued, coalesce(qm.total_sent,0)::bigint total_sent, coalesce(qm.total_delivered,0)::bigint total_delivered, coalesce(qm.total_failed,0)::bigint total_failed,
    coalesce(qm.total_pending,0)::bigint total_pending, coalesce(qm.total_paused,0)::bigint total_paused, coalesce(qm.total_blocked,0)::bigint total_blocked,
    qm.first_sent_at,qm.last_sent_at,
    round(100.0*coalesce(qm.total_delivered,0)/nullif(qm.total_sent,0),2) delivery_rate,
    round(100.0*coalesce(qm.total_failed,0)/nullif(qm.total_sent,0),2) failure_rate,
    round(100.0*coalesce(qm.total_pending,0)/nullif(qm.total_queued,0),2) pending_rate,
    coalesce(rm.total_inbound_replies,0)::bigint total_inbound_replies, coalesce(rm.unique_seller_replies,0)::bigint unique_seller_replies,
    round(100.0*coalesce(rm.unique_seller_replies,0)/nullif(qm.total_delivered,0),2) reply_rate,
    coalesce(rm.same_day_reply_count,0)::bigint same_day_reply_count, round(100.0*coalesce(rm.same_day_reply_count,0)/nullif(rm.total_inbound_replies,0),2) same_day_reply_rate,
    coalesce(rm.reply_within_1hr_count,0)::bigint reply_within_1hr_count, coalesce(rm.reply_within_4hr_count,0)::bigint reply_within_4hr_count, coalesce(rm.reply_within_24hr_count,0)::bigint reply_within_24hr_count,
    round(rm.avg_minutes_to_first_reply,2) avg_minutes_to_first_reply, round(rm.median_minutes_to_first_reply,2) median_minutes_to_first_reply,
    coalesce(rm.positive_interest_count,0)::bigint positive_interest_count, round(100.0*coalesce(rm.positive_interest_count,0)/nullif(rm.total_inbound_replies,0),2) positive_interest_rate,
    coalesce(rm.ownership_confirmed_count,0)::bigint ownership_confirmed_count, round(100.0*coalesce(rm.ownership_confirmed_count,0)/nullif(qm.total_delivered,0),2) ownership_confirmed_rate,
    coalesce(rm.info_request_count,0)::bigint info_request_count, round(100.0*coalesce(rm.info_request_count,0)/nullif(rm.total_inbound_replies,0),2) info_request_rate,
    coalesce(rm.not_interested_count,0)::bigint not_interested_count, round(100.0*coalesce(rm.not_interested_count,0)/nullif(rm.total_inbound_replies,0),2) not_interested_rate,
    coalesce(rm.wrong_number_count,0)::bigint wrong_number_count, round(100.0*coalesce(rm.wrong_number_count,0)/nullif(rm.total_inbound_replies,0),2) wrong_number_rate,
    coalesce(rm.opt_out_count,0)::bigint opt_out_count, round(100.0*coalesce(rm.opt_out_count,0)/nullif(qm.total_delivered,0),2) opt_out_rate,
    coalesce(rm.hostile_or_legal_count,0)::bigint hostile_or_legal_count, round(100.0*coalesce(rm.hostile_or_legal_count,0)/nullif(qm.total_delivered,0),2) hostile_or_legal_rate,
    coalesce(rm.unclear_count,0)::bigint unclear_count, round(100.0*coalesce(rm.unclear_count,0)/nullif(rm.total_inbound_replies,0),2) unclear_rate,
    coalesce(rm.advanced_to_consider_selling_count,0)::bigint advanced_to_consider_selling_count, round(100.0*coalesce(rm.advanced_to_consider_selling_count,0)/nullif(qm.total_delivered,0),2) advanced_to_consider_selling_rate,
    coalesce(rm.advanced_to_price_count,0)::bigint advanced_to_price_count, round(100.0*coalesce(rm.advanced_to_price_count,0)/nullif(qm.total_delivered,0),2) advanced_to_price_rate,
    coalesce(rm.advanced_to_offer_count,0)::bigint advanced_to_offer_count, round(100.0*coalesce(rm.advanced_to_offer_count,0)/nullif(qm.total_delivered,0),2) advanced_to_offer_rate,
    coalesce(rm.advanced_to_contract_count,0)::bigint advanced_to_contract_count, round(100.0*coalesce(rm.advanced_to_contract_count,0)/nullif(qm.total_delivered,0),2) advanced_to_contract_rate,
    coalesce(rm.suppressed_after_template_count,0)::bigint suppressed_after_template_count, round(100.0*coalesce(rm.suppressed_after_template_count,0)/nullif(qm.total_delivered,0),2) suppressed_after_template_rate,
    least(100,greatest(0,coalesce(round(100.0*qm.total_delivered/nullif(qm.total_sent,0),2),0))) delivery_score,
    least(100,greatest(0,coalesce(round(100.0*rm.unique_seller_replies/nullif(qm.total_delivered,0),2),0)*4)) reply_score,
    least(100,greatest(0,coalesce(round(100.0*rm.positive_interest_count/nullif(rm.total_inbound_replies,0),2),0))) positive_intent_score,
    least(100,greatest(0,coalesce(round(100.0*rm.ownership_confirmed_count/nullif(qm.total_delivered,0),2),0)*5)) progression_score,
    least(100,greatest(0,100-(coalesce(round(100.0*rm.opt_out_count/nullif(qm.total_delivered,0),2),0)*12)-(coalesce(round(100.0*rm.hostile_or_legal_count/nullif(qm.total_delivered,0),2),0)*20)-(coalesce(round(100.0*rm.wrong_number_count/nullif(rm.total_inbound_replies,0),2),0)*2))) compliance_safety_score,
    0::numeric revenue_score,
    coalesce(mr.top_markets,'[]'::jsonb) top_markets,
    coalesce((select jsonb_agg(x) from (select value x from jsonb_array_elements(coalesce(rm.sample_replies,'[]'::jsonb)) limit 8) ss),'[]'::jsonb) sample_replies
  from template_base tb left join queue_metrics qm on qm.template_id=tb.template_id left join reply_metrics rm on rm.template_id=tb.template_id left join market_rollup mr on mr.template_id in (tb.template_id,tb.template_uuid::text)
), scored as (
  select f.*, round((f.delivery_score*.15)+(f.reply_score*.20)+(f.positive_intent_score*.25)+(f.progression_score*.20)+(f.compliance_safety_score*.15)+(f.revenue_score*.05),2) overall_template_score,
  array_remove(array[
    case when f.total_sent<25 then 'LOW_DATA' end, case when f.opt_out_rate>=3 then 'OPT_OUT_WATCH' end, case when f.opt_out_rate>=5 then 'HIGH_OPT_OUT' end,
    case when f.hostile_or_legal_rate>=1 then 'LEGAL_WATCH' end, case when f.failure_rate>=10 then 'DELIVERY_RISK' end,
    case when f.reply_rate is not null and f.reply_rate<2 and f.total_sent>=25 then 'LOW_REPLY' end, case when f.wrong_number_rate>=15 then 'WRONG_NUMBER_SPIKE' end
  ],null) risk_flags
  from final f
)
select
  s.template_id,s.template_uuid,s.template_name,s.use_case,s.stage_code,s.stage_label,s.language,s.agent_persona,s.template_text,s.is_active,
  s.total_queued,s.total_sent,s.total_delivered,s.total_failed,s.total_pending,s.total_paused,s.total_blocked,s.first_sent_at,s.last_sent_at,s.delivery_rate,s.failure_rate,s.pending_rate,
  s.total_inbound_replies,s.unique_seller_replies,s.reply_rate,s.same_day_reply_count,s.same_day_reply_rate,s.reply_within_1hr_count,s.reply_within_4hr_count,s.reply_within_24hr_count,s.avg_minutes_to_first_reply,s.median_minutes_to_first_reply,
  s.positive_interest_count,s.positive_interest_rate,s.ownership_confirmed_count,s.ownership_confirmed_rate,s.info_request_count,s.info_request_rate,s.not_interested_count,s.not_interested_rate,s.wrong_number_count,s.wrong_number_rate,s.opt_out_count,s.opt_out_rate,s.hostile_or_legal_count,s.hostile_or_legal_rate,s.unclear_count,s.unclear_rate,
  s.advanced_to_consider_selling_count,s.advanced_to_consider_selling_rate,s.advanced_to_price_count,s.advanced_to_price_rate,s.advanced_to_offer_count,s.advanced_to_offer_rate,s.advanced_to_contract_count,s.advanced_to_contract_rate,s.suppressed_after_template_count,s.suppressed_after_template_rate,
  s.delivery_score,s.reply_score,s.positive_intent_score,s.progression_score,s.compliance_safety_score,s.revenue_score,s.overall_template_score,
  case when s.total_sent<greatest(coalesce(p_min_sent,1),25) then 'LOW_DATA' when coalesce(s.opt_out_rate,0)>=5 or coalesce(s.hostile_or_legal_rate,0)>=2 then 'PAUSE' when s.overall_template_score>=75 and coalesce(s.opt_out_rate,0)<3 and coalesce(s.hostile_or_legal_rate,0)<1 then 'SCALE' when s.overall_template_score>=40 then 'TESTING' else 'PAUSE' end recommendation,
  s.risk_flags,s.top_markets,s.sample_replies
from scored s
where s.total_sent>=coalesce(p_min_sent,1)
order by s.overall_template_score desc nulls last, s.total_sent desc;
$_$;


--
-- Name: get_ownership_check_template_stats_v2(timestamp with time zone, timestamp with time zone, "text", "text", "text", integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_ownership_check_template_stats_v2"("p_start_date" timestamp with time zone DEFAULT ("now"() - '30 days'::interval), "p_end_date" timestamp with time zone DEFAULT "now"(), "p_market" "text" DEFAULT NULL::"text", "p_agent_id" "text" DEFAULT NULL::"text", "p_language" "text" DEFAULT NULL::"text", "p_min_sent" integer DEFAULT 1) RETURNS TABLE("template_id" "text", "template_uuid" "uuid", "template_name" "text", "use_case" "text", "stage_code" "text", "stage_label" "text", "language" "text", "agent_persona" "text", "template_text" "text", "is_active" boolean, "total_queued" bigint, "total_sent" bigint, "total_delivered" bigint, "total_failed" bigint, "total_pending" bigint, "total_paused" bigint, "total_blocked" bigint, "first_sent_at" timestamp with time zone, "last_sent_at" timestamp with time zone, "delivery_rate" numeric, "failure_rate" numeric, "pending_rate" numeric, "total_inbound_replies" bigint, "unique_seller_replies" bigint, "reply_rate" numeric, "same_day_reply_count" bigint, "same_day_reply_rate" numeric, "reply_within_1hr_count" bigint, "reply_within_4hr_count" bigint, "reply_within_24hr_count" bigint, "avg_minutes_to_first_reply" numeric, "median_minutes_to_first_reply" numeric, "positive_interest_count" bigint, "positive_interest_rate" numeric, "ownership_confirmed_count" bigint, "ownership_confirmed_rate" numeric, "info_request_count" bigint, "info_request_rate" numeric, "not_interested_count" bigint, "not_interested_rate" numeric, "wrong_number_count" bigint, "wrong_number_rate" numeric, "opt_out_count" bigint, "opt_out_rate" numeric, "hostile_or_legal_count" bigint, "hostile_or_legal_rate" numeric, "unclear_count" bigint, "unclear_rate" numeric, "advanced_to_consider_selling_count" bigint, "advanced_to_consider_selling_rate" numeric, "advanced_to_price_count" bigint, "advanced_to_price_rate" numeric, "advanced_to_offer_count" bigint, "advanced_to_offer_rate" numeric, "advanced_to_contract_count" bigint, "advanced_to_contract_rate" numeric, "suppressed_after_template_count" bigint, "suppressed_after_template_rate" numeric, "delivery_score" numeric, "reply_score" numeric, "positive_intent_score" numeric, "progression_score" numeric, "compliance_safety_score" numeric, "revenue_score" numeric, "overall_template_score" numeric, "recommendation" "text", "risk_flags" "text"[], "top_markets" "jsonb", "sample_replies" "jsonb")
    LANGUAGE "sql" STABLE
    AS $$
  select * from public.get_ownership_check_template_stats(p_start_date,p_end_date,p_market,p_agent_id,p_language,p_min_sent);
$$;


--
-- Name: get_property_coordinates("text"[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_property_coordinates"("p_property_ids" "text"[]) RETURNS TABLE("property_id" "text", "latitude" numeric, "longitude" numeric)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    p.property_id::text,
    p.latitude,
    p.longitude
  from public.properties p
  where p.property_id::text = any(p_property_ids)
    and p.latitude is not null
    and p.longitude is not null
    and p.latitude <> 0
    and p.longitude <> 0;
$$;


--
-- Name: get_recent_sold_comps_in_bounds(numeric, numeric, numeric, numeric, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_recent_sold_comps_in_bounds"("p_min_lat" numeric, "p_min_lng" numeric, "p_max_lat" numeric, "p_max_lng" numeric, "p_months_back" integer DEFAULT 6, "p_limit" integer DEFAULT 1000) RETURNS TABLE("id" "uuid", "property_id" "text", "address" "text", "city" "text", "state" "text", "zip" "text", "latitude" numeric, "longitude" numeric, "sale_price" numeric, "sale_date" "date", "ppsf" numeric, "asset_class" "text", "beds" numeric, "baths" numeric, "sqft" numeric, "year_built" numeric, "confidence" numeric, "deal_grade" "text", "streetview_image" "text")
    LANGUAGE "sql" STABLE
    AS $$
  select
    id,
    property_id,
    property_address_full as address,
    property_address_city as city,
    property_address_state as state,
    property_address_zip as zip,
    latitude,
    longitude,
    sale_price,
    sale_date,
    computed_ppsf as ppsf,
    normalized_asset_class as asset_class,
    total_bedrooms as beds,
    total_baths as baths,
    building_square_feet as sqft,
    year_built,
    comp_confidence_score as confidence,
    deal_grade,
    streetview_image
  from public.v_recent_sold_comps
  where is_usable_comp = true
    and sale_date >= current_date - make_interval(months => p_months_back)
    and latitude between p_min_lat and p_max_lat
    and longitude between p_min_lng and p_max_lng
  order by sale_date desc nulls last
  limit least(greatest(p_limit, 1), 5000);
$$;


--
-- Name: get_sms_template_stats(timestamp with time zone, timestamp with time zone, "text", "text", "text", integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_sms_template_stats"("p_start_date" timestamp with time zone DEFAULT ("now"() - '30 days'::interval), "p_end_date" timestamp with time zone DEFAULT "now"(), "p_use_case" "text" DEFAULT NULL::"text", "p_market" "text" DEFAULT NULL::"text", "p_language" "text" DEFAULT NULL::"text", "p_min_sent" integer DEFAULT 1) RETURNS TABLE("template_id" "text", "template_uuid" "uuid", "template_name" "text", "use_case" "text", "stage_code" "text", "stage_label" "text", "language" "text", "agent_persona" "text", "template_text" "text", "is_active" boolean, "total_queued" bigint, "total_sent" bigint, "total_delivered" bigint, "total_failed" bigint, "total_pending" bigint, "total_paused" bigint, "total_blocked" bigint, "first_sent_at" timestamp with time zone, "last_sent_at" timestamp with time zone, "delivery_rate" numeric, "failure_rate" numeric, "pending_rate" numeric, "total_inbound_replies" bigint, "unique_seller_replies" bigint, "reply_rate" numeric, "same_day_reply_count" bigint, "reply_within_1hr_count" bigint, "reply_within_4hr_count" bigint, "reply_within_24hr_count" bigint, "avg_minutes_to_first_reply" numeric, "median_minutes_to_first_reply" numeric, "positive_interest_count" bigint, "positive_interest_rate" numeric, "ownership_confirmed_count" bigint, "ownership_confirmed_rate" numeric, "info_request_count" bigint, "info_request_rate" numeric, "price_given_count" bigint, "price_given_rate" numeric, "ask_offer_count" bigint, "ask_offer_rate" numeric, "not_interested_count" bigint, "not_interested_rate" numeric, "wrong_number_count" bigint, "wrong_number_rate" numeric, "opt_out_count" bigint, "opt_out_rate" numeric, "hostile_or_legal_count" bigint, "hostile_or_legal_rate" numeric, "unclear_count" bigint, "unclear_rate" numeric, "stage_advanced_count" bigint, "stage_advanced_rate" numeric, "suppressed_after_template_count" bigint, "suppressed_after_template_rate" numeric, "delivery_score" numeric, "reply_score" numeric, "positive_intent_score" numeric, "progression_score" numeric, "compliance_safety_score" numeric, "revenue_score" numeric, "overall_template_score" numeric, "recommendation" "text", "risk_flags" "text"[], "top_markets" "jsonb", "sample_replies" "jsonb")
    LANGUAGE "sql" STABLE
    AS $_$
with template_base as (
  select
    st.id as template_uuid,
    coalesce(nullif(st.template_id,''), nullif(st.podio_template_id,''), st.id::text) as template_id,
    coalesce(nullif(st.template_name,''), nullif(st.stage_label,''), nullif(st.use_case,''), st.id::text) as template_name,
    st.use_case,
    st.stage_code,
    st.stage_label,
    coalesce(nullif(st.language,''),'en') as language,
    st.agent_persona,
    st.template_body as template_text,
    coalesce(st.is_active,true) as is_active
  from public.sms_templates st
  where p_use_case is null
     or lower(coalesce(st.use_case,'')) = lower(p_use_case)
     or lower(coalesce(st.stage_code,'')) = lower(p_use_case)
     or lower(coalesce(st.metadata->>'use_case','')) = lower(p_use_case)
),
queue_base as (
  select q.*,
    coalesce(nullif(q.selected_template_id,''), nullif(q.template_id,''), nullif(q.metadata->>'template_id',''), nullif(q.metadata->>'selected_template_id','')) as resolved_template_id
  from public.send_queue q
  where coalesce(q.created_at,q.scheduled_for,q.scheduled_for_utc) between p_start_date and p_end_date
    and (p_market is null or q.market=p_market or q.market_id=p_market or q.metadata->>'market'=p_market)
    and (p_language is null or q.language=p_language or q.metadata->>'language'=p_language)
),
outbound_events as (
  select
    me.id as event_id,
    me.thread_key,
    coalesce(me.event_timestamp,me.sent_at,me.created_at) as outbound_at,
    coalesce(nullif(me.template_id,''),nullif(q.selected_template_id,''),nullif(q.template_id,''),nullif(me.metadata->>'template_id',''),nullif(q.metadata->>'template_id','')) as resolved_template_id,
    coalesce(me.to_phone_number,q.to_phone_number) as seller_phone,
    coalesce(me.market,q.market) as market,
    me.delivery_status,
    me.stage_after,
    q.id as queue_id
  from public.message_events me
  left join public.send_queue q on q.id=me.queue_id
  where lower(coalesce(me.direction,''))='outbound'
    and coalesce(me.event_timestamp,me.sent_at,me.created_at) between p_start_date and p_end_date
    and (p_market is null or coalesce(me.market,q.market,me.market_id,q.market_id)=p_market)
),
inbound_events as (
  select
    me.id as event_id,
    me.thread_key,
    coalesce(me.event_timestamp,me.received_at,me.created_at) as inbound_at,
    coalesce(me.from_phone_number,me.to_phone_number) as seller_phone,
    lower(coalesce(me.detected_intent,me.metadata->>'intent',me.event_type,'unclear')) as intent,
    lower(coalesce(me.stage_after,me.current_stage,me.metadata->>'stage_after','')) as stage_after,
    lower(coalesce(me.stage_before,me.metadata->>'stage_before','')) as stage_before,
    lower(coalesce(me.safety_status,me.metadata->>'safety_status','')) as safety_status,
    coalesce(me.is_opt_out,false) as is_opt_out,
    me.message_body,
    me.market
  from public.message_events me
  where lower(coalesce(me.direction,''))='inbound'
    and coalesce(me.event_timestamp,me.received_at,me.created_at) between p_start_date and p_end_date
    and (p_market is null or me.market=p_market or me.market_id=p_market)
),
attributed_replies as (
  select i.*, o.resolved_template_id as attributed_template_id, o.outbound_at,
         extract(epoch from (i.inbound_at-o.outbound_at))/60.0 as minutes_to_reply
  from inbound_events i
  join lateral (
    select o.* from outbound_events o
    where o.resolved_template_id is not null
      and o.outbound_at <= i.inbound_at
      and o.outbound_at >= i.inbound_at - interval '14 days'
      and ((i.thread_key is not null and o.thread_key=i.thread_key) or (i.thread_key is null and i.seller_phone is not null and o.seller_phone=i.seller_phone))
    order by o.outbound_at desc
    limit 1
  ) o on true
),
queue_metrics as (
  select tb.template_id,
    count(q.id)::bigint as total_queued,
    count(*) filter (where q.queue_status in ('sent','sent_waiting_delivery','delivered') or q.sent_at is not null or q.provider_message_id is not null or q.textgrid_message_id is not null)::bigint as total_sent,
    count(*) filter (where q.queue_status='delivered' or q.delivered_at is not null or lower(coalesce(q.delivery_confirmed,''))='delivered')::bigint as total_delivered,
    count(*) filter (where q.queue_status in ('failed','send_failed') or q.failed_reason is not null)::bigint as total_failed,
    count(*) filter (where q.queue_status in ('queued','scheduled','pending','sending'))::bigint as total_pending,
    count(*) filter (where q.queue_status ilike '%paused%')::bigint as total_paused,
    count(*) filter (where q.queue_status in ('blocked','cancelled') or q.blocked_reason is not null or q.guard_reason is not null)::bigint as total_blocked,
    min(q.sent_at) filter (where q.sent_at is not null) as first_sent_at,
    max(q.sent_at) filter (where q.sent_at is not null) as last_sent_at
  from template_base tb
  left join queue_base q on q.resolved_template_id in (tb.template_id,tb.template_uuid::text)
  group by tb.template_id
),
reply_metrics as (
  select tb.template_id,
    count(ar.event_id)::bigint as total_inbound_replies,
    count(distinct coalesce(ar.thread_key,ar.seller_phone))::bigint as unique_seller_replies,
    count(*) filter (where ar.inbound_at::date=ar.outbound_at::date)::bigint as same_day_reply_count,
    count(*) filter (where ar.minutes_to_reply<=60)::bigint as reply_within_1hr_count,
    count(*) filter (where ar.minutes_to_reply<=240)::bigint as reply_within_4hr_count,
    count(*) filter (where ar.minutes_to_reply<=1440)::bigint as reply_within_24hr_count,
    avg(ar.minutes_to_reply)::numeric as avg_minutes_to_first_reply,
    percentile_cont(0.5) within group (order by ar.minutes_to_reply)::numeric as median_minutes_to_first_reply,
    count(*) filter (where ar.intent ~ '(positive|interested|yes|ask_offer|price_given|seller_open|open_to_offer)' or ar.stage_after ~ '(ownership_confirmed|seller_open|price|offer|negotiat)')::bigint as positive_interest_count,
    count(*) filter (where ar.intent ~ '(ownership|yes_confirmed|owner_confirmed)' or ar.stage_after ~ 'ownership_confirmed')::bigint as ownership_confirmed_count,
    count(*) filter (where ar.intent ~ '(info|who|how_got_number|send_info|ask_info)')::bigint as info_request_count,
    count(*) filter (where ar.intent ~ '(price_given|asking_price|seller_price)' or ar.message_body ~* '(^|\s)\$?[0-9]{2,3}[kK]?([,0-9]{3})?(\s|$)')::bigint as price_given_count,
    count(*) filter (where ar.intent ~ '(ask_offer|what_offer|how_much|offer_request)' or ar.message_body ~* '(how much|what.*offer|your offer|cash offer)')::bigint as ask_offer_count,
    count(*) filter (where ar.intent ~ '(not_interested|no_interest|dead)')::bigint as not_interested_count,
    count(*) filter (where ar.intent ~ '(wrong_number|wrong_person|not_owner)' or ar.message_body ilike '%wrong number%')::bigint as wrong_number_count,
    count(*) filter (where ar.is_opt_out or ar.intent ~ '(opt_out|stop|unsubscribe)' or ar.message_body ~* '(^|\s)(stop|unsubscribe|remove me)(\s|$)')::bigint as opt_out_count,
    count(*) filter (where ar.intent ~ '(hostile|legal|attorney|lawsuit|sue|angry)' or ar.message_body ~* '(attorney|lawyer|lawsuit|sue|legal)')::bigint as hostile_or_legal_count,
    count(*) filter (where ar.intent ~ '(unclear|unknown)' or ar.intent is null)::bigint as unclear_count,
    count(*) filter (where coalesce(ar.stage_after,'') <> '' and coalesce(ar.stage_before,'') <> '' and ar.stage_after <> ar.stage_before and ar.stage_after not in ('dead','suppressed'))::bigint as stage_advanced_count,
    count(*) filter (where ar.safety_status ~ '(suppressed|blocked)' or ar.intent ~ '(opt_out|stop|wrong_number|hostile|legal)')::bigint as suppressed_after_template_count,
    jsonb_agg(jsonb_build_object('at',ar.inbound_at,'intent',ar.intent,'stage_after',ar.stage_after,'body',left(coalesce(ar.message_body,''),220)) order by ar.inbound_at desc) filter (where ar.event_id is not null) as sample_replies
  from template_base tb
  left join attributed_replies ar on ar.attributed_template_id in (tb.template_id,tb.template_uuid::text)
  group by tb.template_id
),
market_rollup as (
  select q.resolved_template_id as template_id, jsonb_agg(jsonb_build_object('market',q.market,'sent',q.cnt) order by q.cnt desc) as top_markets
  from (select resolved_template_id, market, count(*) cnt from queue_base where resolved_template_id is not null and market is not null group by resolved_template_id, market) q
  group by q.resolved_template_id
),
final as (
  select tb.template_id,tb.template_uuid,tb.template_name,tb.use_case,tb.stage_code,tb.stage_label,tb.language,tb.agent_persona,tb.template_text,tb.is_active,
    coalesce(qm.total_queued,0)::bigint total_queued, coalesce(qm.total_sent,0)::bigint total_sent, coalesce(qm.total_delivered,0)::bigint total_delivered, coalesce(qm.total_failed,0)::bigint total_failed,
    coalesce(qm.total_pending,0)::bigint total_pending, coalesce(qm.total_paused,0)::bigint total_paused, coalesce(qm.total_blocked,0)::bigint total_blocked, qm.first_sent_at, qm.last_sent_at,
    round(100.0*coalesce(qm.total_delivered,0)/nullif(qm.total_sent,0),2) delivery_rate,
    round(100.0*coalesce(qm.total_failed,0)/nullif(qm.total_sent,0),2) failure_rate,
    round(100.0*coalesce(qm.total_pending,0)/nullif(qm.total_queued,0),2) pending_rate,
    coalesce(rm.total_inbound_replies,0)::bigint total_inbound_replies, coalesce(rm.unique_seller_replies,0)::bigint unique_seller_replies,
    round(100.0*coalesce(rm.unique_seller_replies,0)/nullif(qm.total_delivered,0),2) reply_rate,
    coalesce(rm.same_day_reply_count,0)::bigint same_day_reply_count,
    coalesce(rm.reply_within_1hr_count,0)::bigint reply_within_1hr_count, coalesce(rm.reply_within_4hr_count,0)::bigint reply_within_4hr_count, coalesce(rm.reply_within_24hr_count,0)::bigint reply_within_24hr_count,
    round(rm.avg_minutes_to_first_reply,2) avg_minutes_to_first_reply, round(rm.median_minutes_to_first_reply,2) median_minutes_to_first_reply,
    coalesce(rm.positive_interest_count,0)::bigint positive_interest_count, round(100.0*coalesce(rm.positive_interest_count,0)/nullif(rm.total_inbound_replies,0),2) positive_interest_rate,
    coalesce(rm.ownership_confirmed_count,0)::bigint ownership_confirmed_count, round(100.0*coalesce(rm.ownership_confirmed_count,0)/nullif(qm.total_delivered,0),2) ownership_confirmed_rate,
    coalesce(rm.info_request_count,0)::bigint info_request_count, round(100.0*coalesce(rm.info_request_count,0)/nullif(rm.total_inbound_replies,0),2) info_request_rate,
    coalesce(rm.price_given_count,0)::bigint price_given_count, round(100.0*coalesce(rm.price_given_count,0)/nullif(rm.total_inbound_replies,0),2) price_given_rate,
    coalesce(rm.ask_offer_count,0)::bigint ask_offer_count, round(100.0*coalesce(rm.ask_offer_count,0)/nullif(rm.total_inbound_replies,0),2) ask_offer_rate,
    coalesce(rm.not_interested_count,0)::bigint not_interested_count, round(100.0*coalesce(rm.not_interested_count,0)/nullif(rm.total_inbound_replies,0),2) not_interested_rate,
    coalesce(rm.wrong_number_count,0)::bigint wrong_number_count, round(100.0*coalesce(rm.wrong_number_count,0)/nullif(rm.total_inbound_replies,0),2) wrong_number_rate,
    coalesce(rm.opt_out_count,0)::bigint opt_out_count, round(100.0*coalesce(rm.opt_out_count,0)/nullif(qm.total_delivered,0),2) opt_out_rate,
    coalesce(rm.hostile_or_legal_count,0)::bigint hostile_or_legal_count, round(100.0*coalesce(rm.hostile_or_legal_count,0)/nullif(qm.total_delivered,0),2) hostile_or_legal_rate,
    coalesce(rm.unclear_count,0)::bigint unclear_count, round(100.0*coalesce(rm.unclear_count,0)/nullif(rm.total_inbound_replies,0),2) unclear_rate,
    coalesce(rm.stage_advanced_count,0)::bigint stage_advanced_count, round(100.0*coalesce(rm.stage_advanced_count,0)/nullif(qm.total_delivered,0),2) stage_advanced_rate,
    coalesce(rm.suppressed_after_template_count,0)::bigint suppressed_after_template_count, round(100.0*coalesce(rm.suppressed_after_template_count,0)/nullif(qm.total_delivered,0),2) suppressed_after_template_rate,
    least(100,greatest(0,coalesce(round(100.0*qm.total_delivered/nullif(qm.total_sent,0),2),0))) delivery_score,
    least(100,greatest(0,coalesce(round(100.0*rm.unique_seller_replies/nullif(qm.total_delivered,0),2),0)*4)) reply_score,
    least(100,greatest(0,coalesce(round(100.0*rm.positive_interest_count/nullif(rm.total_inbound_replies,0),2),0))) positive_intent_score,
    least(100,greatest(0,coalesce(round(100.0*rm.stage_advanced_count/nullif(qm.total_delivered,0),2),0)*5)) progression_score,
    least(100,greatest(0,100-(coalesce(round(100.0*rm.opt_out_count/nullif(qm.total_delivered,0),2),0)*12)-(coalesce(round(100.0*rm.hostile_or_legal_count/nullif(qm.total_delivered,0),2),0)*20)-(coalesce(round(100.0*rm.wrong_number_count/nullif(rm.total_inbound_replies,0),2),0)*2))) compliance_safety_score,
    0::numeric revenue_score,
    coalesce(mr.top_markets,'[]'::jsonb) top_markets,
    coalesce((select jsonb_agg(x) from (select value x from jsonb_array_elements(coalesce(rm.sample_replies,'[]'::jsonb)) limit 8) ss),'[]'::jsonb) sample_replies
  from template_base tb left join queue_metrics qm on qm.template_id=tb.template_id left join reply_metrics rm on rm.template_id=tb.template_id left join market_rollup mr on mr.template_id in (tb.template_id,tb.template_uuid::text)
),
scored as (
  select f.*,
    round((f.delivery_score*.15)+(f.reply_score*.20)+(f.positive_intent_score*.25)+(f.progression_score*.20)+(f.compliance_safety_score*.15)+(f.revenue_score*.05),2) overall_template_score,
    array_remove(array[
      case when f.total_sent<25 then 'LOW_DATA' end,
      case when f.opt_out_rate>=3 then 'OPT_OUT_WATCH' end,
      case when f.opt_out_rate>=5 then 'HIGH_OPT_OUT' end,
      case when f.hostile_or_legal_rate>=1 then 'LEGAL_WATCH' end,
      case when f.failure_rate>=10 then 'DELIVERY_RISK' end,
      case when f.reply_rate is not null and f.reply_rate<2 and f.total_sent>=25 then 'LOW_REPLY' end,
      case when f.wrong_number_rate>=15 then 'WRONG_NUMBER_SPIKE' end
    ],null) risk_flags
  from final f
)
select
  s.template_id,s.template_uuid,s.template_name,s.use_case,s.stage_code,s.stage_label,s.language,s.agent_persona,s.template_text,s.is_active,
  s.total_queued,s.total_sent,s.total_delivered,s.total_failed,s.total_pending,s.total_paused,s.total_blocked,s.first_sent_at,s.last_sent_at,s.delivery_rate,s.failure_rate,s.pending_rate,
  s.total_inbound_replies,s.unique_seller_replies,s.reply_rate,s.same_day_reply_count,s.reply_within_1hr_count,s.reply_within_4hr_count,s.reply_within_24hr_count,s.avg_minutes_to_first_reply,s.median_minutes_to_first_reply,
  s.positive_interest_count,s.positive_interest_rate,s.ownership_confirmed_count,s.ownership_confirmed_rate,s.info_request_count,s.info_request_rate,s.price_given_count,s.price_given_rate,s.ask_offer_count,s.ask_offer_rate,
  s.not_interested_count,s.not_interested_rate,s.wrong_number_count,s.wrong_number_rate,s.opt_out_count,s.opt_out_rate,s.hostile_or_legal_count,s.hostile_or_legal_rate,s.unclear_count,s.unclear_rate,
  s.stage_advanced_count,s.stage_advanced_rate,s.suppressed_after_template_count,s.suppressed_after_template_rate,
  s.delivery_score,s.reply_score,s.positive_intent_score,s.progression_score,s.compliance_safety_score,s.revenue_score,s.overall_template_score,
  case when s.total_sent<greatest(coalesce(p_min_sent,1),25) then 'LOW_DATA' when coalesce(s.opt_out_rate,0)>=5 or coalesce(s.hostile_or_legal_rate,0)>=2 then 'PAUSE' when s.overall_template_score>=75 and coalesce(s.opt_out_rate,0)<3 and coalesce(s.hostile_or_legal_rate,0)<1 then 'SCALE' when s.overall_template_score>=40 then 'TESTING' else 'PAUSE' end recommendation,
  s.risk_flags,s.top_markets,s.sample_replies
from scored s
where s.total_sent>=coalesce(p_min_sent,1)
order by s.overall_template_score desc nulls last, s.total_sent desc;
$_$;


--
-- Name: get_thread_enrichment("text"[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_thread_enrichment"("p_thread_keys" "text"[]) RETURNS TABLE("thread_key" "text", "property_id" "text", "master_owner_id" "text", "prospect_id" "text", "owner_display_name" "text", "seller_first_name" "text", "seller_last_name" "text", "owner_type" "text", "contact_language" "text", "best_phone" "text", "phone_confidence" "text", "property_address_full" "text", "property_street" "text", "property_city" "text", "property_state" "text", "property_zip" "text", "property_type" "text", "market_name" "text", "beds" numeric, "baths" numeric, "sqft" numeric, "year_built" numeric, "effective_year_built" numeric, "estimated_value" numeric, "cash_offer" numeric, "equity_amount" numeric, "equity_percent" numeric, "estimated_repair_cost" numeric, "final_acquisition_score" numeric, "motivation_score" numeric, "motivation_summary" "text", "deal_next_step" "text", "podio_tags" "text", "is_owner_occupied" boolean, "is_absentee" boolean, "is_vacant" boolean, "has_lien" boolean, "is_probate" boolean, "is_tax_delinquent" boolean, "streetview_image" "text", "zillow_url" "text", "realtor_url" "text")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with thread_ids as (
    select
      tk.thread_key,
      case when tk.thread_key like 'phone:%' then substring(tk.thread_key from 7) end as phone_raw,
      case when tk.thread_key like 'owner:%' then substring(tk.thread_key from 7) end as owner_id_raw,
      case when tk.thread_key like 'prospect:%' then substring(tk.thread_key from 8) end as prospect_id_raw,
      case when tk.thread_key like 'property:%' then substring(tk.thread_key from 11) end as property_id_raw,
      case when tk.thread_key like 'event:%' then substring(tk.thread_key from 7)::uuid end as event_id_raw
    from unnest(p_thread_keys) as tk(thread_key)
  ),
  -- Find latest message_event for each thread
  latest_events as (
    select distinct on (ti.thread_key)
      ti.thread_key,
      me.property_id,
      me.master_owner_id,
      me.prospect_id,
      me.market_id,
      me.property_address
    from thread_ids ti
    left join public.message_events me on (
      (ti.phone_raw is not null and (me.from_phone_number = ti.phone_raw or me.to_phone_number = ti.phone_raw))
      or (ti.owner_id_raw is not null and me.master_owner_id = ti.owner_id_raw)
      or (ti.prospect_id_raw is not null and me.prospect_id = ti.prospect_id_raw)
      or (ti.property_id_raw is not null and me.property_id = ti.property_id_raw)
      or (ti.event_id_raw is not null and me.id = ti.event_id_raw)
    )
    order by ti.thread_key, me.event_timestamp desc nulls last, me.id desc
  ),
  -- Enrich with property data
  property_enriched as (
    select
      le.thread_key,
      coalesce(p.property_id::text, le.property_id) as property_id,
      le.master_owner_id,
      le.prospect_id,
      le.market_id,
      p.property_address_full,
      p.property_address as property_street,
      p.property_address_city as property_city,
      p.property_address_state as property_state,
      p.property_address_zip as property_zip,
      p.property_type,
      p.total_bedrooms as beds,
      p.total_baths as baths,
      p.building_square_feet as sqft,
      p.year_built,
      p.effective_year_built,
      p.estimated_value,
      p.cash_offer,
      p.equity_amount,
      p.equity_percent,
      p.estimated_repair_cost,
      p.final_acquisition_score,
      p.structured_motivation_score as motivation_score,
      null::text as motivation_summary,
      null::text as deal_next_step,
      p.podio_tags,
      p.streetview_image,
      p.tax_delinquent as is_tax_delinquent,
      p.active_lien as has_lien,
      null::boolean as is_owner_occupied,
      null::boolean as is_absentee,
      null::boolean as is_vacant,
      null::boolean as is_probate,
      null::text as zillow_url,
      null::text as realtor_url,
      coalesce(p.market, le.market_id) as market_name,
      p.owner_1_firstname as seller_first_name,
      p.owner_1_lastname as seller_last_name
    from latest_events le
    left join public.properties p on p.property_id::text = coalesce(le.property_id, null)
  ),
  -- Enrich with owner data
  owner_enriched as (
    select
      pe.thread_key,
      pe.property_id,
      pe.master_owner_id,
      pe.prospect_id,
      pe.property_address_full,
      pe.property_street,
      pe.property_city,
      pe.property_state,
      pe.property_zip,
      pe.property_type,
      pe.beds,
      pe.baths,
      pe.sqft,
      pe.year_built,
      pe.effective_year_built,
      pe.estimated_value,
      pe.cash_offer,
      pe.equity_amount,
      pe.equity_percent,
      pe.estimated_repair_cost,
      pe.final_acquisition_score,
      pe.motivation_score,
      pe.motivation_summary,
      pe.deal_next_step,
      pe.podio_tags,
      pe.streetview_image,
      pe.is_tax_delinquent,
      pe.has_lien,
      pe.is_owner_occupied,
      pe.is_absentee,
      pe.is_vacant,
      pe.is_probate,
      pe.zillow_url,
      pe.realtor_url,
      pe.market_name,
      coalesce(pe.seller_first_name, so.owner_name) as seller_first_name,
      pe.seller_last_name,
      mo.display_name as owner_display_name,
      mo.owner_type_guess as owner_type,
      mo.best_language as contact_language,
      mo.best_phone_1 as best_phone,
      mo.best_phone_confidence as phone_confidence
    from property_enriched pe
    left join public.master_owners mo on mo.master_owner_id::text = pe.master_owner_id
    left join public.sub_owners so on so.master_owner_id::text = pe.master_owner_id
  )
  select
    oe.thread_key,
    oe.property_id,
    oe.master_owner_id,
    oe.prospect_id,
    oe.owner_display_name,
    oe.seller_first_name,
    oe.seller_last_name,
    oe.owner_type,
    oe.contact_language,
    oe.best_phone,
    oe.phone_confidence,
    oe.property_address_full,
    oe.property_street,
    oe.property_city,
    oe.property_state,
    oe.property_zip,
    oe.property_type,
    oe.market_name,
    oe.beds,
    oe.baths,
    oe.sqft,
    oe.year_built,
    oe.effective_year_built,
    oe.estimated_value,
    oe.cash_offer,
    oe.equity_amount,
    oe.equity_percent,
    oe.estimated_repair_cost,
    oe.final_acquisition_score,
    oe.motivation_score,
    oe.motivation_summary,
    oe.deal_next_step,
    oe.podio_tags,
    oe.is_owner_occupied,
    oe.is_absentee,
    oe.is_vacant,
    oe.has_lien,
    oe.is_probate,
    oe.is_tax_delinquent,
    oe.streetview_image,
    oe.zillow_url,
    oe.realtor_url
  from owner_enriched oe;
$$;


