--
-- Name: intel_clean_price(numeric, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."intel_clean_price"("pp" numeric, "ev" numeric) RETURNS numeric
    LANGUAGE "sql" IMMUTABLE
    AS $$
  SELECT CASE
    WHEN COALESCE(NULLIF(pp,0), ev) BETWEEN 1000 AND 20000000
      THEN COALESCE(NULLIF(pp,0), ev)
    ELSE NULL
  END;
$$;


--
-- Name: intel_haversine_miles(double precision, double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."intel_haversine_miles"("lat1" double precision, "lng1" double precision, "lat2" double precision, "lng2" double precision) RETURNS double precision
    LANGUAGE "sql" IMMUTABLE
    AS $$
  SELECT CASE
    WHEN lat1 IS NULL OR lng1 IS NULL OR lat2 IS NULL OR lng2 IS NULL THEN NULL
    ELSE 3958.7559 * 2 * asin(least(1, sqrt(
      power(sin(radians(lat2 - lat1) / 2), 2) +
      cos(radians(lat1)) * cos(radians(lat2)) *
      power(sin(radians(lng2 - lng1) / 2), 2)
    )))
  END;
$$;


--
-- Name: intel_normalize_asset_class("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."intel_normalize_asset_class"("p_value" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  -- Canonical buckets shared by events (single_family/multifamily/apartment),
  -- entity preferred_asset_classes (Single Family/Multi-Family/Apartment/…),
  -- and property_type labels. Apartment is unified into multifamily.
  SELECT CASE
    WHEN p_value IS NULL OR btrim(p_value) = '' THEN NULL
    WHEN lower(p_value) ~ 'single|sfr|sfh'                       THEN 'single_family'
    WHEN lower(p_value) ~ 'multi|apartment|duplex|triplex|fourplex|quad' THEN 'multifamily'
    WHEN lower(p_value) ~ 'condo'                                THEN 'condominium'
    WHEN lower(p_value) ~ 'town'                                 THEN 'townhouse'
    WHEN lower(p_value) ~ 'vacant|land|lot'                      THEN 'land'
    WHEN lower(p_value) ~ 'mobile|manufactured'                  THEN 'mobile_home'
    WHEN lower(p_value) ~ 'commercial|office|retail|industrial|hotel' THEN 'commercial'
    ELSE 'other'
  END;
$$;


--
-- Name: intel_normalize_market("text", "text", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."intel_normalize_market"("p_market" "text", "p_city" "text", "p_state" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  -- Prefer a real market label; otherwise derive "City, ST" from city+state;
  -- otherwise fall back to state. Generic for every metro — no hardcoded crosswalk.
  SELECT CASE
    WHEN nullif(btrim(p_market), '') IS NOT NULL AND lower(btrim(p_market)) <> 'other'
      THEN btrim(p_market)
    WHEN nullif(btrim(p_city), '') IS NOT NULL AND public.intel_normalize_state(p_state) IS NOT NULL
      THEN initcap(btrim(p_city)) || ', ' || public.intel_normalize_state(p_state)
    WHEN public.intel_normalize_state(p_state) IS NOT NULL
      THEN public.intel_normalize_state(p_state)
    ELSE NULL
  END;
$$;


--
-- Name: intel_normalize_state("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."intel_normalize_state"("p_state" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  SELECT CASE upper(btrim(coalesce(p_state, '')))
    WHEN ''            THEN NULL
    WHEN 'ALABAMA'     THEN 'AL' WHEN 'ALASKA' THEN 'AK' WHEN 'ARIZONA' THEN 'AZ'
    WHEN 'ARKANSAS'    THEN 'AR' WHEN 'CALIFORNIA' THEN 'CA' WHEN 'COLORADO' THEN 'CO'
    WHEN 'CONNECTICUT' THEN 'CT' WHEN 'DELAWARE' THEN 'DE' WHEN 'FLORIDA' THEN 'FL'
    WHEN 'GEORGIA'     THEN 'GA' WHEN 'HAWAII' THEN 'HI' WHEN 'IDAHO' THEN 'ID'
    WHEN 'ILLINOIS'    THEN 'IL' WHEN 'INDIANA' THEN 'IN' WHEN 'IOWA' THEN 'IA'
    WHEN 'KANSAS'      THEN 'KS' WHEN 'KENTUCKY' THEN 'KY' WHEN 'LOUISIANA' THEN 'LA'
    WHEN 'MAINE'       THEN 'ME' WHEN 'MARYLAND' THEN 'MD' WHEN 'MASSACHUSETTS' THEN 'MA'
    WHEN 'MICHIGAN'    THEN 'MI' WHEN 'MINNESOTA' THEN 'MN' WHEN 'MISSISSIPPI' THEN 'MS'
    WHEN 'MISSOURI'    THEN 'MO' WHEN 'MONTANA' THEN 'MT' WHEN 'NEBRASKA' THEN 'NE'
    WHEN 'NEVADA'      THEN 'NV' WHEN 'NEW HAMPSHIRE' THEN 'NH' WHEN 'NEW JERSEY' THEN 'NJ'
    WHEN 'NEW MEXICO'  THEN 'NM' WHEN 'NEW YORK' THEN 'NY' WHEN 'NORTH CAROLINA' THEN 'NC'
    WHEN 'NORTH DAKOTA' THEN 'ND' WHEN 'OHIO' THEN 'OH' WHEN 'OKLAHOMA' THEN 'OK'
    WHEN 'OREGON'      THEN 'OR' WHEN 'PENNSYLVANIA' THEN 'PA' WHEN 'RHODE ISLAND' THEN 'RI'
    WHEN 'SOUTH CAROLINA' THEN 'SC' WHEN 'SOUTH DAKOTA' THEN 'SD' WHEN 'TENNESSEE' THEN 'TN'
    WHEN 'TEXAS'       THEN 'TX' WHEN 'UTAH' THEN 'UT' WHEN 'VERMONT' THEN 'VT'
    WHEN 'VIRGINIA'    THEN 'VA' WHEN 'WASHINGTON' THEN 'WA' WHEN 'WEST VIRGINIA' THEN 'WV'
    WHEN 'WISCONSIN'   THEN 'WI' WHEN 'WYOMING' THEN 'WY' WHEN 'DISTRICT OF COLUMBIA' THEN 'DC'
    ELSE left(upper(btrim(p_state)), 2)  -- already a 2-letter code, or best-effort
  END;
$$;


--
-- Name: intel_normalize_zip("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."intel_normalize_zip"("p_zip" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  SELECT CASE
    WHEN p_zip IS NULL THEN NULL
    WHEN length(regexp_replace(p_zip, '\D', '', 'g')) >= 5
      THEN left(regexp_replace(p_zip, '\D', '', 'g'), 5)
    ELSE NULL  -- malformed (<5 digits) → unusable, do not pad-guess
  END;
$$;


