--
-- Name: mark_job_failed("uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."mark_job_failed"("job_id" "uuid", "lock_token_param" "text", "error_msg" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    current_retry_count INT;
    current_max_retries INT;
    updated_count INT;
BEGIN
    -- Get current retry info
    SELECT retry_count, max_retries 
    INTO current_retry_count, current_max_retries
    FROM send_queue
    WHERE id = job_id AND lock_token = lock_token_param;
    
    IF NOT FOUND THEN
        RETURN false;
    END IF;
    
    -- Determine if we should retry or fail permanently
    IF current_retry_count + 1 < current_max_retries THEN
        -- Retry with exponential backoff
        UPDATE send_queue
        SET queue_status = 'retry',
            retry_count = retry_count + 1,
            next_retry_at = NOW() + (INTERVAL '1 minute' * POWER(2, retry_count + 1)),
            is_locked = false,
            locked_at = NULL,
            lock_token = NULL,
            metadata = jsonb_set(
                COALESCE(metadata, '{}'::jsonb),
                '{last_error}',
                to_jsonb(error_msg),
                true
            ),
            updated_at = NOW()
        WHERE id = job_id AND lock_token = lock_token_param;
    ELSE
        -- Failed permanently
        UPDATE send_queue
        SET queue_status = 'failed',
            retry_count = retry_count + 1,
            is_locked = false,
            locked_at = NULL,
            lock_token = NULL,
            metadata = jsonb_set(
                COALESCE(metadata, '{}'::jsonb),
                '{final_error}',
                to_jsonb(error_msg),
                true
            ),
            updated_at = NOW()
        WHERE id = job_id AND lock_token = lock_token_param;
    END IF;
    
    GET DIAGNOSTICS updated_count = ROW_COUNT;
    RETURN updated_count > 0;
END;
$$;


--
-- Name: mark_job_sent("uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."mark_job_sent"("job_id" "uuid", "lock_token_param" "text", "provider_sid" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    updated_count INT;
BEGIN
    UPDATE send_queue
    SET queue_status = 'sent',
        is_locked = false,
        locked_at = NULL,
        lock_token = NULL,
        updated_at = NOW()
    WHERE id = job_id 
      AND lock_token = lock_token_param;
    
    GET DIAGNOSTICS updated_count = ROW_COUNT;
    RETURN updated_count > 0;
END;
$$;


--
-- Name: mark_message_sent("uuid", character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."mark_message_sent"("p_queue_id" "uuid", "p_textgrid_message_id" character varying) RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    UPDATE message_queue
    SET status = 'sent',
        sent_at = NOW(),
        textgrid_message_id = p_textgrid_message_id
    WHERE id = p_queue_id;
END;
$$;


--
-- Name: normalize_asset_class_etl("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."normalize_asset_class_etl"("raw_type" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
BEGIN
  CASE lower(trim(coalesce(raw_type, '')))
    WHEN 'single family', 'sfr', 'single-family', 'single family residential', 'residential' THEN RETURN 'single_family';
    WHEN 'multi-family', 'multifamily', 'multi family', 'duplex', 'triplex', 'quadplex', 'fourplex' THEN RETURN 'multifamily';
    WHEN 'apartment', 'apartments', 'apartment complex' THEN RETURN 'apartment';
    ELSE
      IF lower(coalesce(raw_type,'')) LIKE '%multi%' OR lower(coalesce(raw_type,'')) LIKE '%duplex%' THEN
        RETURN 'multifamily';
      ELSIF lower(coalesce(raw_type,'')) LIKE '%apartment%' THEN
        RETURN 'apartment';
      ELSE
        RETURN 'single_family';
      END IF;
  END CASE;
END;
$$;


--
-- Name: normalize_buyer_entity_name("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."normalize_buyer_entity_name"("value" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  with cleaned as (
    select regexp_replace(lower(coalesce(value, '')), '[^a-z0-9\s]+', ' ', 'g') as normalized
  )
  select nullif(
    trim(
      regexp_replace(
        regexp_replace(
          regexp_replace(
            regexp_replace(
              regexp_replace(
                regexp_replace(
                  regexp_replace(normalized, '\m(limited liability company)\M', ' ', 'g'),
                  '\m(llc)\M',
                  ' ',
                  'g'
                ),
                '\m(incorporated)\M|\m(inc)\M',
                ' ',
                'g'
              ),
              '\m(corporation)\M|\m(corp)\M',
              ' ',
              'g'
            ),
            '\m(company)\M|\m(co)\M',
            ' ',
            'g'
          ),
          '\m(limited)\M|\m(ltd)\M',
          ' ',
          'g'
        ),
        '\s+',
        ' ',
        'g'
      )
    ),
    ''
  )
  from cleaned;
$$;


--
-- Name: normalize_buyer_entity_text("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."normalize_buyer_entity_text"("value" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select nullif(
    trim(
      regexp_replace(
        lower(coalesce(value, '')),
        '\s+',
        ' ',
        'g'
      )
    ),
    ''
  );
$$;


--
-- Name: normalize_buyer_name_etl("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."normalize_buyer_name_etl"("raw_name" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $_$
BEGIN
  RETURN trim(
    regexp_replace(
      regexp_replace(
        lower(trim(coalesce(raw_name, ''))),
        '\s+(llc|l\.l\.c\.|inc|incorporated|corp|corporation|ltd|lp|l\.p\.|llp|pllc|holdings?|group|co|company|trust|estate|revocable|realty|properties|investments?|capital|ventures?|enterprises?|solutions?|management|mgmt|partners?|associates?|family)\s*\.?$',
        '', 'gi'
      ),
      '[^a-z0-9\s]', '', 'g'
    )
  );
END;
$_$;


--
-- Name: normalize_phone("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."normalize_phone"("phone" "text") RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  clean_phone text;
BEGIN
  IF phone IS NULL THEN RETURN NULL; END IF;
  -- Remove all non-numeric characters
  clean_phone := regexp_replace(phone, '[^0-9]', '', 'g');
  -- If it starts with 1 and is 11 digits, it's a US number, keep it (or add +)
  -- If it's 10 digits, add 1
  IF length(clean_phone) = 10 THEN
    clean_phone := '1' || clean_phone;
  END IF;
  IF length(clean_phone) >= 11 AND left(clean_phone, 1) = '1' THEN
    RETURN '+' || clean_phone;
  END IF;
  -- Fallback
  RETURN '+' || clean_phone;
END;
$$;


--
-- Name: populate_buyer_entities_from_sold_data(boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."populate_buyer_entities_from_sold_data"("p_dry_run" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_scanned integer := 0;
  v_entities_upserted integer := 0;
  v_events_upserted integer := 0;
  v_repeat_buyers integer := 0;
  v_corporate_buyers integer := 0;
  v_markets_covered integer := 0;
BEGIN
  SELECT count(*) INTO v_scanned FROM public.recently_sold_properties
  WHERE buyer_name IS NOT NULL AND trim(buyer_name) <> '';

  IF p_dry_run THEN
    SELECT count(*) INTO v_entities_upserted FROM (
      SELECT 1 FROM public.recently_sold_properties
      WHERE buyer_name IS NOT NULL AND trim(buyer_name) <> ''
      GROUP BY normalize_buyer_name_etl(coalesce(buyer_name_clean, buyer_name))
      HAVING normalize_buyer_name_etl(coalesce(buyer_name_clean, buyer_name)) IS NOT NULL
         AND trim(normalize_buyer_name_etl(coalesce(buyer_name_clean, buyer_name))) <> ''
    ) x;
    SELECT count(*) INTO v_repeat_buyers FROM (
      SELECT 1 FROM public.recently_sold_properties
      WHERE buyer_name IS NOT NULL AND trim(buyer_name) <> ''
      GROUP BY normalize_buyer_name_etl(coalesce(buyer_name_clean, buyer_name))
      HAVING count(*) >= 2
    ) x;
    SELECT count(*) INTO v_corporate_buyers FROM (
      SELECT 1 FROM public.recently_sold_properties
      WHERE buyer_name IS NOT NULL AND trim(buyer_name) <> ''
        AND (is_corporate_owner = true OR coalesce(buyer_name_clean, buyer_name) ~* '(llc|inc|corp|trust|holdings|group|capital|investments|realty|properties)')
      GROUP BY normalize_buyer_name_etl(coalesce(buyer_name_clean, buyer_name))
      HAVING normalize_buyer_name_etl(coalesce(buyer_name_clean, buyer_name)) IS NOT NULL
    ) x;
    SELECT count(DISTINCT market) INTO v_markets_covered FROM public.recently_sold_properties WHERE market IS NOT NULL;
    RETURN jsonb_build_object(
      'dry_run', true, 'rows_scanned', v_scanned,
      'entities_would_create_or_update', v_entities_upserted, 'events_would_create_or_update', v_scanned,
      'repeat_buyers_found', v_repeat_buyers, 'corporate_buyers_found', v_corporate_buyers, 'markets_covered', v_markets_covered
    );
  END IF;

  -- Phase 1: Upsert buyer entities
  INSERT INTO public.buyer_entities_v2 (
    id, buyer_key, buyer_name, normalized_buyer_name, buyer_type, is_corporate_buyer, is_repeat_buyer,
    mailing_address_full, mailing_city, mailing_state, mailing_zip,
    first_purchase_date, last_purchase_date, purchase_count, purchase_count_180d, purchase_count_365d,
    markets_active, counties_active, zips_active, preferred_asset_classes,
    preferred_price_min, preferred_price_max, avg_purchase_price, median_purchase_price,
    avg_ppsf, avg_units, investor_score, velocity_score, corporate_buyer_score, dispo_priority_score,
    contact_enrichment_status, raw_profile,
    dominant_comp_search_profiles, preferred_sqft_ranges, preferred_year_built_buckets, preferred_renovation_levels,
    avg_potential_spread, avg_ppu, created_at, updated_at
  )
  WITH grouped AS (
    SELECT
      normalize_buyer_name_etl(coalesce(rsp.buyer_name_clean, rsp.buyer_name)) AS norm_name,
      generate_buyer_key_etl(normalize_buyer_name_etl(coalesce(rsp.buyer_name_clean, rsp.buyer_name))) AS bkey,
      bool_or(rsp.is_corporate_owner) OR bool_or(coalesce(rsp.buyer_name_clean, rsp.buyer_name) ~* '(llc|inc|corp|trust|holdings|group|capital|investments|realty|properties)') AS is_corp,
      bool_or(coalesce(rsp.buyer_name_clean, rsp.buyer_name) ~* '\mtrust\M') AS is_trust,
      bool_or(coalesce(rsp.buyer_name_clean, rsp.buyer_name) ~* '(fund|reit|institution|secretary)') AS is_inst,
      count(*) AS cnt,
      count(*) FILTER (WHERE rsp.sale_date >= (CURRENT_DATE - '180 days'::interval)) AS cnt_180d,
      count(*) FILTER (WHERE rsp.sale_date >= (CURRENT_DATE - '365 days'::interval)) AS cnt_365d,
      max(rsp.owner_address_full) AS mail_full, max(rsp.owner_address_city) AS mail_city,
      max(rsp.owner_address_state) AS mail_state, max(rsp.owner_address_zip) AS mail_zip,
      min(rsp.sale_date) AS first_dt, max(rsp.sale_date) AS last_dt,
      array_agg(DISTINCT rsp.market ORDER BY rsp.market) FILTER (WHERE rsp.market IS NOT NULL) AS mkts,
      array_agg(DISTINCT rsp.property_address_county_name ORDER BY rsp.property_address_county_name) FILTER (WHERE rsp.property_address_county_name IS NOT NULL) AS counties,
      array_agg(DISTINCT rsp.property_address_zip ORDER BY rsp.property_address_zip) FILTER (WHERE rsp.property_address_zip IS NOT NULL) AS zips,
      array_agg(DISTINCT coalesce(rsp.property_type, 'Single Family') ORDER BY coalesce(rsp.property_type, 'Single Family')) AS asset_classes,
      min(rsp.sale_price) FILTER (WHERE rsp.sale_price > 0) AS price_min,
      max(rsp.sale_price) FILTER (WHERE rsp.sale_price > 0) AS price_max,
      avg(rsp.sale_price) FILTER (WHERE rsp.sale_price > 0) AS price_avg,
      percentile_cont(0.5) WITHIN GROUP (ORDER BY rsp.sale_price) FILTER (WHERE rsp.sale_price > 0) AS price_med,
      avg(rsp.price_per_sqft) FILTER (WHERE rsp.price_per_sqft > 0) AS avg_ppsf_val,
      avg(rsp.units_count) FILTER (WHERE rsp.units_count > 0) AS avg_units_val,
      avg(rsp.potential_spread) FILTER (WHERE rsp.potential_spread > 0) AS avg_spread,
      avg(rsp.price_per_unit) FILTER (WHERE rsp.price_per_unit > 0) AS avg_ppu_val,
      max(rsp.sale_date) AS latest_sale
    FROM public.recently_sold_properties rsp
    WHERE rsp.buyer_name IS NOT NULL AND trim(rsp.buyer_name) <> ''
      AND normalize_buyer_name_etl(coalesce(rsp.buyer_name_clean, rsp.buyer_name)) <> ''
    GROUP BY 1, 2
    HAVING count(*) > 0
  ),
  display_names AS (
    SELECT DISTINCT ON (generate_buyer_key_etl(normalize_buyer_name_etl(coalesce(buyer_name_clean, buyer_name))))
      generate_buyer_key_etl(normalize_buyer_name_etl(coalesce(buyer_name_clean, buyer_name))) AS bkey,
      buyer_name
    FROM public.recently_sold_properties
    WHERE buyer_name IS NOT NULL AND trim(buyer_name) <> ''
    ORDER BY generate_buyer_key_etl(normalize_buyer_name_etl(coalesce(buyer_name_clean, buyer_name))), length(buyer_name) DESC
  )
  SELECT
    gen_random_uuid(), g.bkey, d.buyer_name, g.norm_name,
    CASE WHEN g.is_inst THEN 'institutional' WHEN g.is_trust THEN 'trust' WHEN g.is_corp THEN 'corporate' ELSE 'individual' END,
    g.is_corp, g.cnt >= 2,
    g.mail_full, g.mail_city, g.mail_state, g.mail_zip, g.first_dt, g.last_dt,
    g.cnt::integer, g.cnt_180d::integer, g.cnt_365d::integer,
    coalesce(g.mkts, ARRAY[]::text[]), coalesce(g.counties, ARRAY[]::text[]),
    coalesce(g.zips, ARRAY[]::text[]), coalesce(g.asset_classes, ARRAY[]::text[]),
    g.price_min, g.price_max, g.price_avg, g.price_med, g.avg_ppsf_val, g.avg_units_val,
    least(100, greatest(0, g.cnt * 10 +
      CASE WHEN g.latest_sale >= (CURRENT_DATE - '180 days'::interval) THEN 20
           WHEN g.latest_sale >= (CURRENT_DATE - '365 days'::interval) THEN 10 ELSE 0 END +
      CASE WHEN g.cnt >= 5 THEN 30 WHEN g.cnt >= 3 THEN 20 WHEN g.cnt >= 2 THEN 10 ELSE 0 END)),
    least(100, greatest(0, CASE WHEN g.cnt >= 2 THEN (g.cnt_180d::numeric / greatest(g.cnt,1)) * 100 ELSE 0 END)),
    CASE WHEN g.is_corp THEN 80 ELSE 20 END,
    least(100, greatest(0, g.cnt * 8 +
      CASE WHEN g.latest_sale >= (CURRENT_DATE - '180 days'::interval) THEN 25
           WHEN g.latest_sale >= (CURRENT_DATE - '365 days'::interval) THEN 12 ELSE 0 END +
      CASE WHEN g.cnt >= 3 THEN 20 WHEN g.cnt >= 2 THEN 10 ELSE 0 END)),
    'not_started',
    jsonb_build_object('source', 'recently_sold_properties_etl', 'purchase_count', g.cnt),
    ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[],
    g.avg_spread, g.avg_ppu_val, now(), now()
  FROM grouped g JOIN display_names d ON d.bkey = g.bkey
  ON CONFLICT (buyer_key) DO UPDATE SET
    buyer_name = EXCLUDED.buyer_name, normalized_buyer_name = EXCLUDED.normalized_buyer_name,
    buyer_type = EXCLUDED.buyer_type, is_corporate_buyer = EXCLUDED.is_corporate_buyer,
    is_repeat_buyer = EXCLUDED.is_repeat_buyer,
    mailing_address_full = coalesce(buyer_entities_v2.mailing_address_full, EXCLUDED.mailing_address_full),
    mailing_city = coalesce(buyer_entities_v2.mailing_city, EXCLUDED.mailing_city),
    mailing_state = coalesce(buyer_entities_v2.mailing_state, EXCLUDED.mailing_state),
    mailing_zip = coalesce(buyer_entities_v2.mailing_zip, EXCLUDED.mailing_zip),
    first_purchase_date = least(buyer_entities_v2.first_purchase_date, EXCLUDED.first_purchase_date),
    last_purchase_date = greatest(buyer_entities_v2.last_purchase_date, EXCLUDED.last_purchase_date),
    purchase_count = EXCLUDED.purchase_count, purchase_count_180d = EXCLUDED.purchase_count_180d,
    purchase_count_365d = EXCLUDED.purchase_count_365d, markets_active = EXCLUDED.markets_active,
    counties_active = EXCLUDED.counties_active, zips_active = EXCLUDED.zips_active,
    preferred_asset_classes = EXCLUDED.preferred_asset_classes,
    preferred_price_min = EXCLUDED.preferred_price_min, preferred_price_max = EXCLUDED.preferred_price_max,
    avg_purchase_price = EXCLUDED.avg_purchase_price, median_purchase_price = EXCLUDED.median_purchase_price,
    avg_ppsf = EXCLUDED.avg_ppsf, avg_units = EXCLUDED.avg_units,
    investor_score = EXCLUDED.investor_score, velocity_score = EXCLUDED.velocity_score,
    corporate_buyer_score = EXCLUDED.corporate_buyer_score, dispo_priority_score = EXCLUDED.dispo_priority_score,
    avg_potential_spread = EXCLUDED.avg_potential_spread, avg_ppu = EXCLUDED.avg_ppu,
    raw_profile = buyer_entities_v2.raw_profile || EXCLUDED.raw_profile, updated_at = now();

  GET DIAGNOSTICS v_entities_upserted = ROW_COUNT;

  -- Phase 2: Upsert purchase events using dedup key
  INSERT INTO public.buyer_purchase_events_v2 (
    id, buyer_entity_id, buyer_key, buyer_name, buyer_type, is_corporate_buyer,
    purchase_date, recording_date, purchase_price, purchase_price_source,
    property_address_full, property_city, property_state, property_zip, county_name,
    market, latitude, longitude, normalized_asset_class, property_type, property_class,
    beds, baths, sqft, units_count, year_built, estimated_value, estimated_repair_cost,
    equity_percent, ppsf, potential_spread, arv_estimate, source, raw_payload,
    source_dedup_key, created_at, updated_at
  )
  SELECT
    gen_random_uuid(), be.id, be.buyer_key,
    coalesce(rsp.buyer_name_clean, rsp.buyer_name),
    CASE WHEN be.buyer_type IN ('corporate','trust','institutional') THEN be.buyer_type ELSE 'individual' END,
    be.is_corporate_buyer,
    rsp.sale_date, rsp.recording_date,
    coalesce(rsp.sale_price, rsp.mls_sold_price),
    CASE WHEN rsp.sale_price IS NOT NULL THEN 'sale_price' ELSE 'mls_sold_price' END,
    rsp.property_address_full, rsp.property_address_city, rsp.property_address_state,
    rsp.property_address_zip, rsp.property_address_county_name, rsp.market,
    rsp.latitude, rsp.longitude,
    normalize_asset_class_etl(rsp.property_type),
    rsp.property_type, rsp.property_class,
    rsp.total_bedrooms, rsp.total_baths, rsp.building_square_feet,
    rsp.units_count, rsp.year_built,
    rsp.estimated_value, rsp.estimated_repair_cost, rsp.equity_percent,
    rsp.price_per_sqft, rsp.potential_spread, rsp.estimated_value,
    'recently_sold_properties_etl',
    coalesce(rsp.raw_payload, jsonb_build_object('etl', true)),
    md5(be.buyer_key || '::' || coalesce(rsp.property_id, rsp.property_address_full, '') || '::' || coalesce(rsp.sale_date::text, '')),
    now(), now()
  FROM public.recently_sold_properties rsp
  JOIN public.buyer_entities_v2 be
    ON be.buyer_key = generate_buyer_key_etl(normalize_buyer_name_etl(coalesce(rsp.buyer_name_clean, rsp.buyer_name)))
  WHERE rsp.buyer_name IS NOT NULL AND trim(rsp.buyer_name) <> ''
    AND normalize_buyer_name_etl(coalesce(rsp.buyer_name_clean, rsp.buyer_name)) <> ''
    AND coalesce(rsp.latitude, 0) <> 0 AND coalesce(rsp.longitude, 0) <> 0
  ON CONFLICT (source_dedup_key) WHERE source_dedup_key IS NOT NULL DO NOTHING;

  GET DIAGNOSTICS v_events_upserted = ROW_COUNT;

  SELECT count(*) INTO v_repeat_buyers FROM public.buyer_entities_v2 WHERE is_repeat_buyer = true;
  SELECT count(*) INTO v_corporate_buyers FROM public.buyer_entities_v2 WHERE is_corporate_buyer = true;
  SELECT count(DISTINCT m) INTO v_markets_covered
  FROM (SELECT unnest(markets_active) AS m FROM public.buyer_entities_v2 WHERE markets_active IS NOT NULL) x
  WHERE m IS NOT NULL;

  RETURN jsonb_build_object(
    'dry_run', false, 'rows_scanned', v_scanned,
    'entities_upserted', v_entities_upserted, 'events_upserted', v_events_upserted,
    'repeat_buyers', v_repeat_buyers, 'corporate_buyers', v_corporate_buyers,
    'markets_covered', v_markets_covered
  );
END;
$$;


--
-- Name: reap_stale_campaign_target_graph_refresh_runs(interval); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."reap_stale_campaign_target_graph_refresh_runs"("p_max_idle" interval DEFAULT '00:10:00'::interval) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_reaped integer := 0;
BEGIN
  WITH activity AS (
    SELECT
      r.id,
      GREATEST(
        r.started_at,
        COALESCE(
          (SELECT max(b.finished_at)
             FROM public.campaign_target_graph_refresh_batches b
            WHERE b.run_id = r.id),
          r.started_at
        )
      ) AS last_activity_at
    FROM public.campaign_target_graph_refresh_runs r
    WHERE r.status = 'started'
  ),
  stale AS (
    SELECT id FROM activity WHERE last_activity_at < now() - p_max_idle
  ),
  updated AS (
    UPDATE public.campaign_target_graph_refresh_runs r
    SET
      status = 'failed',
      finished_at = now(),
      error_message = COALESCE(r.error_message, 'reaped: no batch progress within idle window'),
      metadata = COALESCE(r.metadata, '{}'::jsonb) || jsonb_build_object(
        'failure_reason', 'reaped_stale_started_run',
        'reaped_at', to_jsonb(now()),
        'reap_max_idle', p_max_idle::text
      )
    FROM stale
    WHERE r.id = stale.id
    RETURNING r.id
  )
  SELECT count(*)::integer INTO v_reaped FROM updated;

  RETURN v_reaped;
END;
$$;


--
-- Name: rebuild_buyer_geo_rollups(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."rebuild_buyer_geo_rollups"() RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_rows integer;
BEGIN
  TRUNCATE public.buyer_geo_rollups_v2;

  INSERT INTO public.buyer_geo_rollups_v2 (
    geo_level, geo_key, state, county_name, market, zip, normalized_asset_class, timeframe_days,
    purchase_count, buyer_count, corporate_buyer_count, repeat_buyer_count,
    avg_purchase_price, median_purchase_price, min_purchase_price, max_purchase_price,
    avg_ppsf, avg_units, avg_sqft, centroid_lat, centroid_lng,
    dominant_property_type, dominant_buyer_type, dominant_strategy,
    top_buyers, price_bands,
    liquidity_score, velocity_score, investor_demand_score, retail_exit_score, buyer_heat_score,
    calculated_at, created_at, updated_at
  )
  WITH base AS (
    SELECT
      e.buyer_key,
      public.intel_normalize_zip(e.property_zip)                          AS n_zip,
      public.intel_normalize_market(e.market, e.property_city, e.property_state) AS n_market,
      public.intel_normalize_state(e.property_state)                      AS n_state,
      NULLIF(btrim(e.county_name),'')                                     AS county_name,
      public.intel_normalize_asset_class(e.normalized_asset_class)        AS n_asset,
      public.intel_clean_price(e.purchase_price, e.estimated_value)       AS eff_price,
      e.ppsf, e.sqft, e.units_count, e.latitude, e.longitude,
      e.property_type, e.buyer_type, e.purchase_date, e.likely_strategy
    FROM public.buyer_purchase_events_v2 e
    WHERE e.buyer_key IS NOT NULL
  ),
  exploded AS (
    SELECT 'zip'::text AS geo_level, n_zip AS geo_key, n_state AS r_state, NULL::text AS r_market, n_zip AS r_zip,
           county_name, n_asset, buyer_key, eff_price, ppsf, sqft, units_count, latitude, longitude,
           property_type, buyer_type, purchase_date, likely_strategy
    FROM base WHERE n_zip IS NOT NULL
    UNION ALL
    SELECT 'market', n_market, n_state, n_market, NULL, county_name, n_asset, buyer_key, eff_price, ppsf, sqft,
           units_count, latitude, longitude, property_type, buyer_type, purchase_date, likely_strategy
    FROM base WHERE n_market IS NOT NULL
    UNION ALL
    SELECT 'state', n_state, n_state, NULL, NULL, county_name, n_asset, buyer_key, eff_price, ppsf, sqft,
           units_count, latitude, longitude, property_type, buyer_type, purchase_date, likely_strategy
    FROM base WHERE n_state IS NOT NULL
  ),
  withasset AS (
    SELECT x.geo_level, x.geo_key, x.r_state, x.r_market, x.r_zip, x.county_name,
           a.asset_dim, x.buyer_key, x.eff_price, x.ppsf, x.sqft, x.units_count,
           x.latitude, x.longitude, x.property_type, x.buyer_type, x.purchase_date, x.likely_strategy
    FROM exploded x
    CROSS JOIN LATERAL (VALUES (x.n_asset), ('all')) a(asset_dim)
    WHERE a.asset_dim IS NOT NULL AND x.geo_key IS NOT NULL
  ),
  grp_buyer AS (
    SELECT geo_level, geo_key, asset_dim, buyer_key,
           count(*) AS buys, max(purchase_date) AS last_buy, max(buyer_type) AS btype
    FROM withasset
    GROUP BY geo_level, geo_key, asset_dim, buyer_key
  ),
  ranked_buyers AS (
    SELECT geo_level, geo_key, asset_dim, buyer_key, buys, last_buy, btype,
           row_number() OVER (PARTITION BY geo_level, geo_key, asset_dim ORDER BY buys DESC, last_buy DESC NULLS LAST) AS rn
    FROM grp_buyer
  ),
  top_buyers_agg AS (
    SELECT geo_level, geo_key, asset_dim,
           jsonb_agg(jsonb_build_object('buyer_key', buyer_key, 'buys', buys, 'last_buy', last_buy)
                     ORDER BY buys DESC) FILTER (WHERE rn <= 10) AS top_buyers
    FROM ranked_buyers GROUP BY geo_level, geo_key, asset_dim
  ),
  buyer_metrics AS (
    SELECT gb.geo_level, gb.geo_key, gb.asset_dim,
           count(*)                                          AS buyer_count,
           count(*) FILTER (WHERE gb.buys >= 2)              AS repeat_buyer_count,
           count(*) FILTER (WHERE gb.btype = 'institutional') AS institutional_count,
           mode() WITHIN GROUP (ORDER BY gb.btype)          AS dominant_buyer_type
    FROM grp_buyer gb
    GROUP BY gb.geo_level, gb.geo_key, gb.asset_dim
  ),
  grp_median AS (
    SELECT geo_level, geo_key, asset_dim,
           (percentile_cont(0.5) WITHIN GROUP (ORDER BY eff_price))::numeric AS med
    FROM withasset GROUP BY geo_level, geo_key, asset_dim
  ),
  event_metrics AS (
    SELECT w.geo_level, w.geo_key, w.asset_dim,
           max(w.r_state)                                                   AS state,
           max(w.r_market)                                                  AS market,
           max(w.r_zip)                                                     AS zip,
           mode() WITHIN GROUP (ORDER BY w.county_name)                     AS any_county,
           count(*)                                                          AS purchase_count,
           count(*) FILTER (WHERE w.purchase_date >= CURRENT_DATE - 365)     AS purchases_365d,
           count(*) FILTER (WHERE w.purchase_date >= CURRENT_DATE - 180)     AS purchases_180d,
           round(avg(w.eff_price) FILTER (WHERE w.eff_price > 0 AND w.eff_price <= GREATEST(2000000, 5*gm.med)),0) AS avg_purchase_price,
           round(gm.med,0)                                                   AS median_purchase_price,
           round(min(w.eff_price) FILTER (WHERE w.eff_price > 0),0)          AS min_purchase_price,
           round(max(w.eff_price) FILTER (WHERE w.eff_price <= GREATEST(2000000, 5*gm.med)),0) AS max_purchase_price,
           round(avg(w.ppsf) FILTER (WHERE w.ppsf > 0 AND w.ppsf < 2000),2)  AS avg_ppsf,
           round(avg(w.units_count) FILTER (WHERE w.units_count > 0),2)      AS avg_units,
           round(avg(w.sqft) FILTER (WHERE w.sqft > 0 AND w.sqft < 100000),0) AS avg_sqft,
           round(avg(w.latitude)::numeric,6)                                AS centroid_lat,
           round(avg(w.longitude)::numeric,6)                               AS centroid_lng,
           mode() WITHIN GROUP (ORDER BY w.property_type)                   AS dominant_property_type,
           mode() WITHIN GROUP (ORDER BY w.likely_strategy)                 AS dominant_strategy,
           count(*) FILTER (WHERE w.eff_price < 150000)                     AS pb_u150,
           count(*) FILTER (WHERE w.eff_price >= 150000 AND w.eff_price < 300000) AS pb_150_300,
           count(*) FILTER (WHERE w.eff_price >= 300000 AND w.eff_price < 500000) AS pb_300_500,
           count(*) FILTER (WHERE w.eff_price >= 500000 AND w.eff_price <= GREATEST(2000000, 5*gm.med)) AS pb_o500
    FROM withasset w
    JOIN grp_median gm ON gm.geo_level=w.geo_level AND gm.geo_key=w.geo_key AND coalesce(gm.asset_dim,'')=coalesce(w.asset_dim,'')
    GROUP BY w.geo_level, w.geo_key, w.asset_dim, gm.med
  )
  SELECT
    em.geo_level, em.geo_key, em.state, em.any_county, em.market, em.zip, em.asset_dim, 0,
    em.purchase_count, bm.buyer_count, bm.institutional_count, bm.repeat_buyer_count,
    em.avg_purchase_price, em.median_purchase_price, em.min_purchase_price, em.max_purchase_price,
    em.avg_ppsf, em.avg_units, em.avg_sqft, em.centroid_lat, em.centroid_lng,
    em.dominant_property_type, bm.dominant_buyer_type, em.dominant_strategy,
    tb.top_buyers,
    jsonb_build_object('under_150k', em.pb_u150, '150k_300k', em.pb_150_300, '300k_500k', em.pb_300_500, 'over_500k', em.pb_o500),
    (CASE WHEN bm.buyer_count >= 50 THEN 100 WHEN bm.buyer_count >= 20 THEN 85 WHEN bm.buyer_count >= 10 THEN 70
          WHEN bm.buyer_count >= 5 THEN 55 WHEN bm.buyer_count >= 2 THEN 35 ELSE 15 END)::numeric,
    round(least(100, 100.0 * em.purchases_365d / GREATEST(em.purchase_count,1)),1),
    round(least(100,
      (CASE WHEN bm.buyer_count >= 50 THEN 60 WHEN bm.buyer_count >= 20 THEN 50 WHEN bm.buyer_count >= 10 THEN 40
            WHEN bm.buyer_count >= 5 THEN 28 WHEN bm.buyer_count >= 2 THEN 16 ELSE 6 END)
      + (20.0 * em.purchases_180d / GREATEST(em.purchase_count,1))
      + (20.0 * bm.repeat_buyer_count / GREATEST(bm.buyer_count,1))
    ),1),
    NULL::numeric,
    round(least(100,
      0.40 * least(100, 100.0 * em.purchases_365d / GREATEST(em.purchase_count,1))
      + 0.35 * (CASE WHEN bm.buyer_count >= 50 THEN 100 WHEN bm.buyer_count >= 20 THEN 85 WHEN bm.buyer_count >= 10 THEN 70
                     WHEN bm.buyer_count >= 5 THEN 55 WHEN bm.buyer_count >= 2 THEN 35 ELSE 15 END)
      + 0.25 * least(100, em.purchase_count)
    ),1),
    now(), now(), now()
  FROM event_metrics em
  JOIN buyer_metrics bm ON bm.geo_level=em.geo_level AND bm.geo_key=em.geo_key AND coalesce(bm.asset_dim,'')=coalesce(em.asset_dim,'')
  LEFT JOIN top_buyers_agg tb ON tb.geo_level=em.geo_level AND tb.geo_key=em.geo_key AND coalesce(tb.asset_dim,'')=coalesce(em.asset_dim,'');

  GET DIAGNOSTICS v_rows = ROW_COUNT;
  RETURN v_rows;
END;
$$;


--
-- Name: refresh_campaign_target_graph(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."refresh_campaign_target_graph"() RETURNS TABLE("graph_rows" integer, "facet_rows" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_result record;
BEGIN
  SELECT *
  INTO v_result
  FROM public.refresh_campaign_target_graph_staged(10000, NULL);

  graph_rows := v_result.graph_rows;
  facet_rows := v_result.facet_rows;
  RETURN NEXT;
END;
$$;


--
-- Name: refresh_campaign_target_graph_facets(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."refresh_campaign_target_graph_facets"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count integer := 0;
BEGIN
  TRUNCATE TABLE public.campaign_target_graph_facets;

  WITH base_facets AS (
    SELECT
      g.graph_id,
      g.queue_eligible,
      g.sender_covered,
      g.sms_eligible,
      NOT (g.true_post_contact_suppression OR g.wrong_number) AS clean_path,
      facet.field_key,
      facet.value
    FROM public.campaign_target_graph g
    CROSS JOIN LATERAL (VALUES
      ('properties.market', g.market),
      ('properties.property_state', g.state),
      ('properties.property_address_state', g.state),
      ('properties.property_address_city', g.property_city),
      ('properties.property_zip', g.property_zip),
      ('properties.property_address_zip', g.property_zip),
      ('properties.property_county_name', g.property_county_name),
      ('properties.property_address_county_name', g.property_county_name),
      ('properties.property_type', g.property_type),
      ('properties.property_class', g.property_class),
      ('properties.units_count', g.units_count::text),
      ('properties.tax_delinquent', g.tax_delinquent::text),
      ('properties.active_lien', g.active_lien::text),
      ('properties.building_condition', g.building_condition),
      ('properties.rehab_level', g.rehab_level),
      ('properties.owner_type', g.owner_type),
      ('properties.owner_type_guess', g.owner_type_guess),
      ('properties.is_corporate_owner', g.is_corporate_owner::text),
      ('properties.out_of_state_owner', g.out_of_state_owner::text),
      ('prospects.language_preference', g.language),
      ('prospects.gender', g.gender),
      ('prospects.marital_status', g.marital_status),
      ('prospects.age_bucket', g.age_bucket),
      ('prospects.occupation_group', g.occupation_group),
      ('prospects.education_model', g.education_model),
      ('prospects.est_household_income', g.income),
      ('prospects.net_asset_value', g.net_asset_value),
      ('prospects.buying_power', g.buying_power),
      ('prospects.timezone', g.timezone),
      ('prospects.contact_window', g.contact_window),
      ('prospects.sms_eligible', g.sms_eligible::text),
      ('prospects.email_eligible', g.email_eligible::text),
      ('master_owners.owner_type_guess', g.owner_type_guess),
      ('master_owners.priority_tier', g.priority_tier),
      ('master_owners.follow_up_cadence', g.follow_up_cadence),
      ('phones.phone_owner', g.phone_owner),
      ('phones.activity_status', COALESCE(NULLIF(g.phone_activity_status, ''), CASE WHEN g.wrong_number THEN 'wrong_number' ELSE NULL END)),
      ('phones.usage_12_months', g.usage_12_months),
      ('phones.usage_2_months', g.usage_2_months),
      ('outreach.true_post_contact_suppression', g.true_post_contact_suppression::text),
      ('outreach.pending_prior_touch', g.pending_prior_touch::text),
      ('outreach.duplicate_queue_status', CASE WHEN g.active_queue_item THEN 'active_queue_item' ELSE 'clear' END),
      ('sender_coverage.routing_allowed', g.sender_covered::text),
      ('sender_coverage.routing_tier', g.routing_tier),
      ('sender_coverage.selected_textgrid_market', g.sender_market),
      ('sender_coverage.selected_textgrid_state', g.state),
      ('sender_coverage.sender_coverage_status', CASE WHEN g.sender_covered THEN 'Covered' ELSE 'No Route' END)
    ) AS facet(field_key, value)
  ),
  list_facets AS (
    SELECT
      graph_id,
      queue_eligible,
      sender_covered,
      sms_eligible,
      NOT (true_post_contact_suppression OR wrong_number) AS clean_path,
      'prospects.matching_flags' AS field_key,
      NULLIF(trim(value), '') AS value
    FROM public.campaign_target_graph
    CROSS JOIN LATERAL regexp_split_to_table(COALESCE(matching_flags_text, ''), '[,\n;|]+') AS split_value(value)
    UNION ALL
    SELECT
      graph_id,
      queue_eligible,
      sender_covered,
      sms_eligible,
      NOT (true_post_contact_suppression OR wrong_number) AS clean_path,
      'prospects.person_flags_text' AS field_key,
      NULLIF(trim(value), '') AS value
    FROM public.campaign_target_graph
    CROSS JOIN LATERAL regexp_split_to_table(COALESCE(matching_flags_text, ''), '[,\n;|]+') AS split_value(value)
    UNION ALL
    SELECT
      graph_id,
      queue_eligible,
      sender_covered,
      sms_eligible,
      NOT (true_post_contact_suppression OR wrong_number) AS clean_path,
      'properties.seller_tags_text' AS field_key,
      NULLIF(trim(value), '') AS value
    FROM public.campaign_target_graph
    CROSS JOIN LATERAL regexp_split_to_table(COALESCE(podio_tags, ''), '[,\n;|]+') AS split_value(value)
    UNION ALL
    SELECT
      graph_id,
      queue_eligible,
      sender_covered,
      sms_eligible,
      NOT (true_post_contact_suppression OR wrong_number) AS clean_path,
      'prospects.seller_tags_text' AS field_key,
      NULLIF(trim(value), '') AS value
    FROM public.campaign_target_graph
    CROSS JOIN LATERAL regexp_split_to_table(COALESCE(podio_tags, ''), '[,\n;|]+') AS split_value(value)
    UNION ALL
    SELECT
      graph_id,
      queue_eligible,
      sender_covered,
      sms_eligible,
      NOT (true_post_contact_suppression OR wrong_number) AS clean_path,
      'properties.property_flags_text' AS field_key,
      NULLIF(trim(value), '') AS value
    FROM public.campaign_target_graph
    CROSS JOIN LATERAL regexp_split_to_table(COALESCE(property_flags_text, ''), '[,\n;|]+') AS split_value(value)
  )
  INSERT INTO public.campaign_target_graph_facets (
    field_key,
    value,
    label,
    target_count,
    clean_count,
    queueable_count,
    sender_covered_count,
    sms_eligible_count,
    updated_at
  )
  SELECT
    field_key,
    value,
    value AS label,
    COUNT(*)::integer AS target_count,
    COUNT(*) FILTER (WHERE clean_path)::integer AS clean_count,
    COUNT(*) FILTER (WHERE queue_eligible)::integer AS queueable_count,
    COUNT(*) FILTER (WHERE sender_covered)::integer AS sender_covered_count,
    COUNT(*) FILTER (WHERE sms_eligible)::integer AS sms_eligible_count,
    now() AS updated_at
  FROM (
    SELECT * FROM base_facets
    UNION ALL
    SELECT * FROM list_facets
  ) facets
  WHERE NULLIF(trim(value), '') IS NOT NULL
  GROUP BY field_key, value;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


--
-- Name: refresh_campaign_target_graph_fallback_batch("uuid", integer, integer, "text", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."refresh_campaign_target_graph_fallback_batch"("p_run_id" "uuid", "p_batch_limit" integer DEFAULT 10000, "p_batch_offset" integer DEFAULT 0, "p_state" "text" DEFAULT NULL::"text", "p_market" "text" DEFAULT NULL::"text") RETURNS TABLE("run_id" "uuid", "batch_number" integer, "batch_type" "text", "batch_key" "text", "batch_start" "text", "batch_end" "text", "source_rows" integer, "rows_inserted" integer, "stage_rows" integer, "has_more" boolean, "elapsed_ms" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_started_at timestamptz := clock_timestamp();
  v_batch_id uuid;
  v_batch_number integer;
  v_batch_type text := 'missing_owner_json_property_offset';
  v_batch_key text;
  v_batch_start text;
  v_batch_end text;
  v_source_rows integer := 0;
  v_rows_inserted integer := 0;
  v_stage_rows integer := 0;
  v_has_more boolean := false;
  v_elapsed_ms integer := 0;
  v_limit integer := LEAST(GREATEST(COALESCE(p_batch_limit, 10000), 1), 50000);
  v_offset integer := GREATEST(COALESCE(p_batch_offset, 0), 0);
  v_state text := NULLIF(upper(trim(COALESCE(p_state, ''))), '');
  v_market text := NULLIF(trim(COALESCE(p_market, '')), '');
  v_run_exists boolean := false;
BEGIN
  PERFORM set_config('statement_timeout', '0', true);
  PERFORM set_config('work_mem', '128MB', true);

  SELECT EXISTS (
    SELECT 1
    FROM public.campaign_target_graph_refresh_runs r
    WHERE r.id = p_run_id
      AND r.status = 'started'
  )
  INTO v_run_exists;

  IF NOT v_run_exists THEN
    RAISE EXCEPTION 'campaign target graph refresh run % is not active', p_run_id;
  END IF;

  v_batch_key := concat(
    'fallback_property_offset:', v_offset,
    ':limit:', v_limit,
    CASE WHEN v_state IS NOT NULL THEN concat(':state:', v_state) ELSE '' END,
    CASE WHEN v_market IS NOT NULL THEN concat(':market:', v_market) ELSE '' END
  );

  SELECT COALESCE(MAX(b.batch_number), 0) + 1
  INTO v_batch_number
  FROM public.campaign_target_graph_refresh_batches b
  WHERE b.run_id = p_run_id;

  WITH batch_keys AS (
    SELECT
      COALESCE(NULLIF(p.property_id, ''), NULLIF(p.property_export_id, '')) AS sort_key
    FROM public.properties p
    WHERE (v_state IS NULL OR upper(COALESCE(NULLIF(p.property_state, ''), NULLIF(p.property_address_state, ''))) = v_state)
      AND (v_market IS NULL OR p.market = v_market)
      AND NOT EXISTS (
        SELECT 1
        FROM public.campaign_target_graph_stage s
        WHERE s.property_id = p.property_id
      )
      AND NOT EXISTS (
        SELECT 1
        FROM public.campaign_target_graph_stage s
        WHERE s.property_export_id = p.property_export_id
      )
    ORDER BY
      COALESCE(NULLIF(p.property_id, ''), NULLIF(p.property_export_id, '')) NULLS LAST,
      p.property_export_id NULLS LAST
    LIMIT v_limit OFFSET v_offset
  )
  SELECT
    COUNT(*)::integer,
    (array_agg(sort_key ORDER BY sort_key NULLS LAST))[1],
    (array_agg(sort_key ORDER BY sort_key DESC NULLS LAST))[1]
  INTO v_source_rows, v_batch_start, v_batch_end
  FROM batch_keys;

  SELECT EXISTS (
    SELECT 1
    FROM public.properties p
    WHERE (v_state IS NULL OR upper(COALESCE(NULLIF(p.property_state, ''), NULLIF(p.property_address_state, ''))) = v_state)
      AND (v_market IS NULL OR p.market = v_market)
      AND NOT EXISTS (
        SELECT 1
        FROM public.campaign_target_graph_stage s
        WHERE s.property_id = p.property_id
      )
      AND NOT EXISTS (
        SELECT 1
        FROM public.campaign_target_graph_stage s
        WHERE s.property_export_id = p.property_export_id
      )
    ORDER BY
      COALESCE(NULLIF(p.property_id, ''), NULLIF(p.property_export_id, '')) NULLS LAST,
      p.property_export_id NULLS LAST
    LIMIT 1 OFFSET (v_offset + v_limit)
  )
  INTO v_has_more;

  INSERT INTO public.campaign_target_graph_refresh_batches (
    run_id,
    batch_number,
    batch_type,
    batch_key,
    batch_start,
    batch_end,
    status,
    metadata
  )
  VALUES (
    p_run_id,
    v_batch_number,
    v_batch_type,
    v_batch_key,
    v_batch_start,
    v_batch_end,
    'started',
    jsonb_build_object(
      'batch_limit', v_limit,
      'batch_offset', v_offset,
      'batch_state', v_state,
      'batch_market', v_market,
      'source_rows', v_source_rows,
      'graph_path', 'properties_prospects_json_phones',
      'fallback_enabled', true,
      'direct_core_only', false
    )
  )
  RETURNING id INTO v_batch_id;

  IF v_source_rows = 0 THEN
    v_elapsed_ms := GREATEST(0, floor(EXTRACT(epoch FROM clock_timestamp() - v_started_at) * 1000)::integer);
    SELECT COUNT(*)::integer INTO v_stage_rows FROM public.campaign_target_graph_stage;

    UPDATE public.campaign_target_graph_refresh_batches
    SET
      rows_inserted = 0,
      finished_at = clock_timestamp(),
      elapsed_ms = v_elapsed_ms,
      status = 'completed',
      metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
        'has_more', false,
        'stage_rows_after_batch', v_stage_rows
      )
    WHERE id = v_batch_id;

    run_id := p_run_id;
    batch_number := v_batch_number;
    batch_type := v_batch_type;
    batch_key := v_batch_key;
    batch_start := v_batch_start;
    batch_end := v_batch_end;
    source_rows := v_source_rows;
    rows_inserted := 0;
    stage_rows := v_stage_rows;
    has_more := false;
    elapsed_ms := v_elapsed_ms;
    RETURN NEXT;
    RETURN;
  END IF;

  WITH property_batch AS (
    SELECT p.*
    FROM public.properties p
    WHERE (v_state IS NULL OR upper(COALESCE(NULLIF(p.property_state, ''), NULLIF(p.property_address_state, ''))) = v_state)
      AND (v_market IS NULL OR p.market = v_market)
      AND NOT EXISTS (
        SELECT 1
        FROM public.campaign_target_graph_stage s
        WHERE s.property_id = p.property_id
      )
      AND NOT EXISTS (
        SELECT 1
        FROM public.campaign_target_graph_stage s
        WHERE s.property_export_id = p.property_export_id
      )
    ORDER BY
      COALESCE(NULLIF(p.property_id, ''), NULLIF(p.property_export_id, '')) NULLS LAST,
      p.property_export_id NULLS LAST
    LIMIT v_limit OFFSET v_offset
  ),
  prospect_paths AS (
    SELECT
      ROW(p.*)::public.properties AS p,
      pr.pr_row AS pr,
      pr.link_rank AS prospect_link_rank
    FROM property_batch p
    JOIN LATERAL (
      SELECT candidate.pr_row, candidate.link_rank
      FROM (
        SELECT ROW(pr.*)::public.prospects AS pr_row, 1 AS link_rank
        FROM public.prospects pr
        WHERE NULLIF(p.property_id, '') IS NOT NULL
          AND pr.linked_property_ids_json ? p.property_id
        UNION ALL
        SELECT ROW(pr.*)::public.prospects AS pr_row, 2 AS link_rank
        FROM public.prospects pr
        WHERE NULLIF(p.property_export_id, '') IS NOT NULL
          AND pr.linked_property_ids_json ? p.property_export_id
      ) candidate
      ORDER BY
        candidate.link_rank,
        COALESCE((candidate.pr_row).likely_owner, false) DESC,
        COALESCE((candidate.pr_row).is_primary_prospect, false) DESC,
        (candidate.pr_row).rank_position NULLS LAST,
        (candidate.pr_row).phone_score_final DESC NULLS LAST,
        (candidate.pr_row).contact_score_final DESC NULLS LAST,
        COALESCE((candidate.pr_row).updated_at, (candidate.pr_row).created_at) DESC NULLS LAST
      LIMIT 1
    ) pr ON true
  ),
  target_paths AS (
    SELECT
      md5(concat_ws('|',
        NULLIF(p.property_id, ''),
        NULLIF(p.property_export_id, ''),
        NULLIF(COALESCE(pr.master_owner_id, p.master_owner_id), ''),
        NULLIF(COALESCE(pr.prospect_id::text, ph.primary_prospect_id::text, ph.canonical_prospect_id::text), ''),
        NULLIF(ph.phone_id::text, ''),
        NULLIF(ph.canonical_e164, '')
      )) AS graph_id,
      p.property_id::text AS property_id,
      p.property_export_id::text AS property_export_id,
      COALESCE(pr.master_owner_id, p.master_owner_id)::text AS master_owner_id,
      COALESCE(pr.prospect_id::text, ph.primary_prospect_id::text, ph.canonical_prospect_id::text) AS prospect_id,
      COALESCE(pr.canonical_prospect_id::text, ph.canonical_prospect_id::text) AS canonical_prospect_id,
      ph.phone_id::text AS phone_id,
      ph.canonical_e164::text AS canonical_e164,
      graph_market.market AS market,
      COALESCE(NULLIF(p.property_state, ''), NULLIF(p.property_address_state, '')) AS state,
      p.property_address_city::text AS property_city,
      COALESCE(NULLIF(p.property_zip, ''), NULLIF(p.property_address_zip, '')) AS property_zip,
      COALESCE(NULLIF(p.property_county_name, ''), NULLIF(p.property_address_county_name, '')) AS property_county_name,
      p.property_type::text AS property_type,
      p.property_class::text AS property_class,
      COALESCE(
        NULLIF(to_jsonb(p)->>'canonical_property_group', ''),
        NULLIF(p.property_group, ''),
        NULLIF(p.normalized_asset_class, ''),
        NULLIF(p.asset_type_label, ''),
        NULLIF(p.property_class, ''),
        NULLIF(p.property_type, '')
      ) AS canonical_property_group,
      COALESCE(NULLIF(pr.language_preference, ''), NULLIF(ph.linked_languages_text, '')) AS language,
      public.campaign_age_bucket_from_mob(pr.mob::text) AS age_bucket,
      pr.occupation_group::text AS occupation_group,
      pr.education_model::text AS education_model,
      pr.est_household_income::text AS income,
      COALESCE(NULLIF(pr.owner_type_guess, ''), NULLIF(p.owner_type_guess, ''), NULLIF(p.owner_type, '')) AS owner_type_guess,
      COALESCE(NULLIF(pr.priority_tier, ''), NULLIF(p.priority_tier, '')) AS priority_tier,
      NULL::text AS follow_up_cadence,
      COALESCE(NULLIF(p.rehab_level, ''), NULLIF(p.renovation_level_classification, ''), NULLIF(p.building_condition, '')) AS rehab_level,
      (
        ph.canonical_e164 IS NOT NULL
        AND COALESCE(ph.phone_contact_status, '') IS DISTINCT FROM 'wrong_number'
      ) AS sms_eligible,
      COALESCE(sup.is_suppressed, false) AS true_post_contact_suppression,
      (
        COALESCE(ph.phone_contact_status, '') = 'wrong_number'
        OR ph.wrong_number_at IS NOT NULL
      ) AS wrong_number,
      (
        latest.last_outbound_at IS NOT NULL
        AND latest.last_outbound_at >= now() - interval '30 days'
      ) AS pending_prior_touch,
      COALESCE(aq.active_queue_count, 0) > 0 AS active_queue_item,
      sm.sender_market IS NOT NULL AS sender_covered,
      sm.sender_market,
      COALESCE(NULLIF(ph.timezone, ''), NULLIF(pr.timezone, '')) AS timezone,
      ph.best_phone_score,
      ph.phone_owner,
      ph.activity_status AS phone_activity_status,
      ph.usage_12_months::text AS usage_12_months,
      ph.usage_2_months::text AS usage_2_months,
      'ownership_check'::text AS template_use_case,
      COALESCE(NULLIF(ph.contact_window, ''), NULLIF(pr.contact_window, '')) AS contact_window,
      NULLIF(GREATEST(
        COALESCE(latest.last_outbound_at, 'epoch'::timestamptz),
        COALESCE(latest.last_inbound_at, 'epoch'::timestamptz)
      ), 'epoch'::timestamptz) AS latest_contact_at,
      latest.last_outbound_at,
      latest.last_inbound_at,
      CASE WHEN sm.sender_market IS NOT NULL THEN 'exact_market_match' ELSE 'no_sender_route' END AS routing_tier,
      CASE
        WHEN COALESCE(pr.likely_owner, false) THEN 'verified'
        WHEN COALESCE(pr.likely_renting, false) THEN 'renter_risk'
        WHEN pr.prospect_id IS NOT NULL THEN 'probable_json_fallback'
        ELSE 'unknown'
      END AS identity_alignment,
      COALESCE(p.final_acquisition_score, pr.master_owner_priority_score) AS acquisition_score,
      COALESCE(NULLIF(p.seller_tags_text, ''), NULLIF(p.podio_tags, ''), NULLIF(pr.seller_tags_text, '')) AS podio_tags,
      jsonb_strip_nulls(jsonb_build_object(
        'matching_flags', pr.matching_flags,
        'person_flags_text', pr.person_flags_text,
        'person_flags_json', pr.person_flags_json
      )) AS matching_flags,
      COALESCE(NULLIF(pr.matching_flags, ''), NULLIF(pr.person_flags_text, '')) AS matching_flags_text,
      COALESCE(NULLIF(pr.owner_display_name, ''), NULLIF(p.owner_display_name, ''), NULLIF(p.owner_name, '')) AS owner_name,
      COALESCE(NULLIF(pr.first_name, ''), NULLIF(ph.phone_first_name, ''), split_part(NULLIF(COALESCE(pr.full_name, ph.phone_full_name, pr.owner_display_name), ''), ' ', 1)) AS seller_first_name,
      COALESCE(NULLIF(pr.full_name, ''), NULLIF(ph.phone_full_name, ''), NULLIF(ph.primary_display_name, ''), NULLIF(pr.owner_display_name, '')) AS seller_full_name,
      COALESCE(NULLIF(p.property_address_full, ''), NULLIF(p.property_address, '')) AS property_address_full,
      p.estimated_value,
      p.equity_amount,
      p.equity_percent,
      p.cash_offer,
      CASE WHEN latest.last_outbound_at IS NULL THEN 0 ELSE 1 END AS touch_count,
      CASE WHEN latest.last_outbound_at IS NULL THEN 1 ELSE 2 END AS current_touch_number,
      latest.last_outbound_at IS NULL AS never_contacted,
      jsonb_build_object(
        'property', CASE WHEN p.property_id IS NOT NULL THEN 1 ELSE 0 END,
        'master_owner', 0,
        'prospect', CASE WHEN pr.prospect_id IS NOT NULL THEN 1 ELSE 0 END,
        'phone', CASE WHEN ph.phone_id IS NOT NULL THEN 1 ELSE 0 END,
        'sender_numbers', COALESCE(sm.sender_count, 0),
        'prospect_link_rank', prospect_paths.prospect_link_rank,
        'phone_link_rank', ph.link_rank
      ) AS linkage_counts,
      to_jsonb(p) AS property_data,
      to_jsonb(pr) AS prospect_data,
      to_jsonb(ph) AS phone_data,
      sup.suppression_rows AS suppression_data,
      GREATEST(
        COALESCE(p.updated_at, p.created_at, 'epoch'::timestamptz),
        COALESCE(pr.updated_at, pr.created_at, 'epoch'::timestamptz),
        COALESCE(ph.updated_at, ph.created_at, 'epoch'::timestamptz),
        COALESCE(latest.last_outbound_at, 'epoch'::timestamptz),
        COALESCE(latest.last_inbound_at, 'epoch'::timestamptz),
        COALESCE(sm.latest_sender_update, 'epoch'::timestamptz),
        COALESCE(sup.latest_suppressed_at, 'epoch'::timestamptz)
      ) AS source_updated_at
    FROM prospect_paths
    CROSS JOIN LATERAL (SELECT (prospect_paths.p).*) p
    CROSS JOIN LATERAL (SELECT (prospect_paths.pr).*) pr
    CROSS JOIN LATERAL (
      SELECT COALESCE(NULLIF(p.market, ''), NULLIF(pr.primary_market, '')) AS market
    ) graph_market
    LEFT JOIN LATERAL (
      SELECT linked_ph.*
      FROM (
        SELECT ph.*, 1 AS link_rank
        FROM public.phones ph
        WHERE ph.canonical_e164 IS NOT NULL
          AND (
            ph.phone_type IS NULL
            OR ph.phone_type = ''
            OR lower(ph.phone_type) IN ('w', 'wireless', 'mobile', 'voip', 'unknown')
          )
          AND ph.primary_prospect_id = pr.prospect_id
        UNION ALL
        SELECT ph.*, 2 AS link_rank
        FROM public.phones ph
        WHERE ph.canonical_e164 IS NOT NULL
          AND (
            ph.phone_type IS NULL
            OR ph.phone_type = ''
            OR lower(ph.phone_type) IN ('w', 'wireless', 'mobile', 'voip', 'unknown')
          )
          AND ph.canonical_prospect_id = pr.canonical_prospect_id
        UNION ALL
        SELECT ph.*, 3 AS link_rank
        FROM public.phones ph
        WHERE ph.canonical_e164 IS NOT NULL
          AND (
            ph.phone_type IS NULL
            OR ph.phone_type = ''
            OR lower(ph.phone_type) IN ('w', 'wireless', 'mobile', 'voip', 'unknown')
          )
          AND ph.master_owner_id = COALESCE(pr.master_owner_id, p.master_owner_id)
      ) linked_ph
      ORDER BY
        linked_ph.link_rank,
        COALESCE(linked_ph.is_best_phone_for_slot, false) DESC,
        COALESCE(linked_ph.is_best_phone_for_owner, false) DESC,
        linked_ph.best_phone_score DESC NULLS LAST,
        COALESCE(linked_ph.updated_at, linked_ph.created_at) DESC NULLS LAST
      LIMIT 1
    ) ph ON true
    LEFT JOIN LATERAL (
      SELECT COUNT(*)::integer AS active_queue_count
      FROM public.send_queue sq
      WHERE sq.to_phone_number = ph.canonical_e164
        AND lower(COALESCE(sq.queue_status, '')) IN ('queued', 'scheduled', 'pending', 'ready', 'approved', 'processing', 'sending')
    ) aq ON ph.canonical_e164 IS NOT NULL
    LEFT JOIN LATERAL (
      SELECT
        MAX(last_inbound_at) AS last_inbound_at,
        MAX(last_outbound_at) AS last_outbound_at
      FROM (
        SELECT
          MAX(COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at)) AS last_inbound_at,
          NULL::timestamptz AS last_outbound_at
        FROM public.message_events me
        WHERE me.from_phone_number = ph.canonical_e164
          AND lower(COALESCE(me.direction, '')) LIKE 'in%'
        UNION ALL
        SELECT
          NULL::timestamptz AS last_inbound_at,
          MAX(COALESCE(me.event_timestamp, me.sent_at, me.received_at, me.created_at)) AS last_outbound_at
        FROM public.message_events me
        WHERE me.to_phone_number = ph.canonical_e164
          AND lower(COALESCE(me.direction, '')) LIKE 'out%'
        UNION ALL
        SELECT
          NULL::timestamptz AS last_inbound_at,
          MAX(COALESCE(sq.sent_at, sq.scheduled_for_utc, sq.scheduled_for, sq.created_at)) AS last_outbound_at
        FROM public.send_queue sq
        WHERE sq.to_phone_number = ph.canonical_e164
      ) contact_events
    ) latest ON ph.canonical_e164 IS NOT NULL
    LEFT JOIN LATERAL (
      SELECT
        bool_or(COALESCE(sl.is_active, true)) AS is_suppressed,
        MAX(COALESCE(sl.suppressed_at, sl.created_at)) AS latest_suppressed_at,
        jsonb_agg(to_jsonb(sl) ORDER BY COALESCE(sl.suppressed_at, sl.created_at) DESC NULLS LAST) AS suppression_rows
      FROM (
        SELECT sl.*
        FROM public.sms_suppression_list sl
        WHERE sl.phone_e164 = ph.canonical_e164
        UNION ALL
        SELECT sl.*
        FROM public.sms_suppression_list sl
        WHERE sl.phone_number = ph.canonical_e164
          AND sl.phone_e164 IS DISTINCT FROM ph.canonical_e164
      ) sl
    ) sup ON ph.canonical_e164 IS NOT NULL
    LEFT JOIN LATERAL (
      SELECT
        tn.market AS sender_market,
        COUNT(*)::integer AS sender_count,
        MAX(tn.updated_at) AS latest_sender_update
      FROM public.textgrid_numbers tn
      WHERE tn.market = COALESCE(graph_market.market, ph.primary_market)
        AND NULLIF(tn.phone_number, '') IS NOT NULL
        AND lower(COALESCE(tn.status, 'active')) NOT IN ('disabled', 'inactive', 'failed', 'blocked', 'retired')
      GROUP BY tn.market
    ) sm ON COALESCE(graph_market.market, ph.primary_market) IS NOT NULL
  )
  INSERT INTO public.campaign_target_graph_stage (
    graph_id,
    property_id,
    property_export_id,
    master_owner_id,
    prospect_id,
    canonical_prospect_id,
    phone_id,
    canonical_e164,
    market,
    state,
    property_city,
    property_zip,
    property_county_name,
    property_type,
    property_class,
    canonical_property_group,
    language,
    age_bucket,
    occupation_group,
    education_model,
    income,
    owner_type_guess,
    priority_tier,
    follow_up_cadence,
    rehab_level,
    sms_eligible,
    true_post_contact_suppression,
    wrong_number,
    pending_prior_touch,
    active_queue_item,
    sender_covered,
    sender_market,
    timezone,
    best_phone_score,
    phone_owner,
    phone_activity_status,
    usage_12_months,
    usage_2_months,
    template_use_case,
    contact_window,
    latest_contact_at,
    last_outbound_at,
    last_inbound_at,
    routing_tier,
    identity_alignment,
    acquisition_score,
    podio_tags,
    matching_flags,
    matching_flags_text,
    owner_name,
    seller_first_name,
    seller_full_name,
    property_address_full,
    estimated_value,
    equity_amount,
    equity_percent,
    cash_offer,
    touch_count,
    current_touch_number,
    never_contacted,
    queue_eligible,
    queue_block_reason,
    graph_source,
    linkage_counts,
    blocker_flags,
    extra_data,
    source_updated_at,
    generated_at
  )
  SELECT
    graph_id,
    property_id,
    property_export_id,
    master_owner_id,
    prospect_id,
    canonical_prospect_id,
    phone_id,
    canonical_e164,
    market,
    state,
    property_city,
    property_zip,
    property_county_name,
    property_type,
    property_class,
    canonical_property_group,
    language,
    age_bucket,
    occupation_group,
    education_model,
    income,
    owner_type_guess,
    priority_tier,
    follow_up_cadence,
    rehab_level,
    sms_eligible,
    true_post_contact_suppression,
    wrong_number,
    pending_prior_touch,
    active_queue_item,
    sender_covered,
    sender_market,
    timezone,
    best_phone_score,
    phone_owner,
    phone_activity_status,
    usage_12_months,
    usage_2_months,
    template_use_case,
    contact_window,
    latest_contact_at,
    last_outbound_at,
    last_inbound_at,
    routing_tier,
    identity_alignment,
    acquisition_score,
    podio_tags,
    matching_flags,
    matching_flags_text,
    owner_name,
    seller_first_name,
    seller_full_name,
    property_address_full,
    estimated_value,
    equity_amount,
    equity_percent,
    cash_offer,
    touch_count,
    current_touch_number,
    never_contacted,
    (
      sms_eligible
      AND NOT true_post_contact_suppression
      AND NOT wrong_number
      AND NOT pending_prior_touch
      AND NOT active_queue_item
      AND sender_covered
    ) AS queue_eligible,
    CASE
      WHEN NOT sms_eligible THEN 'sms_ineligible'
      WHEN true_post_contact_suppression THEN 'suppressed'
      WHEN wrong_number THEN 'wrong_number'
      WHEN pending_prior_touch THEN 'pending_prior_touch'
      WHEN active_queue_item THEN 'active_queue_item'
      WHEN NOT sender_covered THEN 'no_sender_coverage'
      ELSE NULL
    END AS queue_block_reason,
    'campaign_target_graph.refresh.missing_owner_json_fallback' AS graph_source,
    linkage_counts,
    jsonb_build_object(
      'sms_eligible', sms_eligible,
      'true_post_contact_suppression', true_post_contact_suppression,
      'wrong_number', wrong_number,
      'pending_prior_touch', pending_prior_touch,
      'active_queue_item', active_queue_item,
      'sender_covered', sender_covered
    ) AS blocker_flags,
    jsonb_strip_nulls(jsonb_build_object(
      'property', property_data,
      'prospect', prospect_data,
      'phone', phone_data,
      'suppression', suppression_data
    )) AS extra_data,
    NULLIF(source_updated_at, 'epoch'::timestamptz) AS source_updated_at,
    now() AS generated_at
  FROM target_paths
  WHERE phone_id IS NOT NULL
    AND canonical_e164 IS NOT NULL
  ON CONFLICT (graph_id) DO UPDATE SET
    graph_source = EXCLUDED.graph_source,
    generated_at = EXCLUDED.generated_at,
    source_updated_at = EXCLUDED.source_updated_at;

  GET DIAGNOSTICS v_rows_inserted = ROW_COUNT;

  SELECT COUNT(*)::integer INTO v_stage_rows FROM public.campaign_target_graph_stage;
  v_elapsed_ms := GREATEST(0, floor(EXTRACT(epoch FROM clock_timestamp() - v_started_at) * 1000)::integer);

  UPDATE public.campaign_target_graph_refresh_batches
  SET
    rows_inserted = v_rows_inserted,
    finished_at = clock_timestamp(),
    elapsed_ms = v_elapsed_ms,
    status = 'completed',
    metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
      'has_more', v_has_more,
      'stage_rows_after_batch', v_stage_rows
    )
  WHERE id = v_batch_id;

  UPDATE public.campaign_target_graph_refresh_runs
  SET metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
    'last_fallback_batch_number', v_batch_number,
    'last_fallback_batch_key', v_batch_key,
    'last_fallback_has_more', v_has_more,
    'stage_rows', v_stage_rows,
    'fallback_enabled', true
  )
  WHERE id = p_run_id;

  run_id := p_run_id;
  batch_number := v_batch_number;
  batch_type := v_batch_type;
  batch_key := v_batch_key;
  batch_start := v_batch_start;
  batch_end := v_batch_end;
  source_rows := v_source_rows;
  rows_inserted := v_rows_inserted;
  stage_rows := v_stage_rows;
  has_more := v_has_more;
  elapsed_ms := v_elapsed_ms;
  RETURN NEXT;
EXCEPTION WHEN OTHERS THEN
  v_elapsed_ms := GREATEST(0, floor(EXTRACT(epoch FROM clock_timestamp() - v_started_at) * 1000)::integer);

  IF v_batch_id IS NOT NULL THEN
    UPDATE public.campaign_target_graph_refresh_batches
    SET
      finished_at = clock_timestamp(),
      elapsed_ms = v_elapsed_ms,
      status = 'failed',
      error_message = SQLERRM,
      metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object('error_sqlstate', SQLSTATE)
    WHERE id = v_batch_id;
  END IF;

  UPDATE public.campaign_target_graph_refresh_runs
  SET
    status = 'failed',
    finished_at = now(),
    error_message = SQLERRM,
    metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
      'last_failed_fallback_batch_key', v_batch_key,
      'last_error_sqlstate', SQLSTATE
    )
  WHERE id = p_run_id;

  RAISE;
END;
$$;


--
-- Name: refresh_campaign_target_graph_stage_batch("uuid", integer, integer, "text", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."refresh_campaign_target_graph_stage_batch"("p_run_id" "uuid", "p_batch_limit" integer DEFAULT 10000, "p_batch_offset" integer DEFAULT 0, "p_state" "text" DEFAULT NULL::"text", "p_market" "text" DEFAULT NULL::"text") RETURNS TABLE("run_id" "uuid", "batch_number" integer, "batch_type" "text", "batch_key" "text", "batch_start" "text", "batch_end" "text", "source_rows" integer, "rows_inserted" integer, "stage_rows" integer, "has_more" boolean, "elapsed_ms" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_started_at timestamptz := clock_timestamp();
  v_batch_id uuid;
  v_batch_number integer;
  v_batch_type text := 'property_offset';
  v_batch_key text;
  v_batch_start text;
  v_batch_end text;
  v_source_rows integer := 0;
  v_rows_inserted integer := 0;
  v_stage_rows integer := 0;
  v_has_more boolean := false;
  v_elapsed_ms integer := 0;
  v_limit integer := LEAST(GREATEST(COALESCE(p_batch_limit, 10000), 1), 50000);
  v_offset integer := GREATEST(COALESCE(p_batch_offset, 0), 0);
  v_state text := NULLIF(upper(trim(COALESCE(p_state, ''))), '');
  v_market text := NULLIF(trim(COALESCE(p_market, '')), '');
  v_run_exists boolean := false;
BEGIN
  PERFORM set_config('statement_timeout', '0', true);
  PERFORM set_config('work_mem', '128MB', true);

  SELECT EXISTS (
    SELECT 1
    FROM public.campaign_target_graph_refresh_runs r
    WHERE r.id = p_run_id
      AND r.status = 'started'
  )
  INTO v_run_exists;

  IF NOT v_run_exists THEN
    RAISE EXCEPTION 'campaign target graph refresh run % is not active', p_run_id;
  END IF;

  IF v_state IS NOT NULL THEN
    v_batch_type := 'state_property_offset';
  ELSIF v_market IS NOT NULL THEN
    v_batch_type := 'market_property_offset';
  END IF;

  v_batch_key := concat(
    'property_offset:', v_offset,
    ':limit:', v_limit,
    CASE WHEN v_state IS NOT NULL THEN concat(':state:', v_state) ELSE '' END,
    CASE WHEN v_market IS NOT NULL THEN concat(':market:', v_market) ELSE '' END
  );

  SELECT COALESCE(MAX(b.batch_number), 0) + 1
  INTO v_batch_number
  FROM public.campaign_target_graph_refresh_batches b
  WHERE b.run_id = p_run_id;

  WITH batch_keys AS (
    SELECT
      COALESCE(NULLIF(p.property_id, ''), NULLIF(p.property_export_id, '')) AS sort_key
    FROM public.properties p
    WHERE NULLIF(p.master_owner_id, '') IS NOT NULL
      AND (v_state IS NULL OR upper(COALESCE(NULLIF(p.property_state, ''), NULLIF(p.property_address_state, ''))) = v_state)
      AND (v_market IS NULL OR p.market = v_market)
    ORDER BY
      COALESCE(NULLIF(p.property_id, ''), NULLIF(p.property_export_id, '')) NULLS LAST,
      p.property_export_id NULLS LAST
    LIMIT v_limit OFFSET v_offset
  )
  SELECT
    COUNT(*)::integer,
    (array_agg(sort_key ORDER BY sort_key NULLS LAST))[1],
    (array_agg(sort_key ORDER BY sort_key DESC NULLS LAST))[1]
  INTO v_source_rows, v_batch_start, v_batch_end
  FROM batch_keys;

  SELECT EXISTS (
    SELECT 1
    FROM public.properties p
    WHERE NULLIF(p.master_owner_id, '') IS NOT NULL
      AND (v_state IS NULL OR upper(COALESCE(NULLIF(p.property_state, ''), NULLIF(p.property_address_state, ''))) = v_state)
      AND (v_market IS NULL OR p.market = v_market)
    ORDER BY
      COALESCE(NULLIF(p.property_id, ''), NULLIF(p.property_export_id, '')) NULLS LAST,
      p.property_export_id NULLS LAST
    LIMIT 1 OFFSET (v_offset + v_limit)
  )
  INTO v_has_more;

  INSERT INTO public.campaign_target_graph_refresh_batches (
    run_id,
    batch_number,
    batch_type,
    batch_key,
    batch_start,
    batch_end,
    status,
    metadata
  )
  VALUES (
    p_run_id,
    v_batch_number,
    v_batch_type,
    v_batch_key,
    v_batch_start,
    v_batch_end,
    'started',
    jsonb_build_object(
      'batch_limit', v_limit,
      'batch_offset', v_offset,
      'batch_state', v_state,
      'batch_market', v_market,
      'source_rows', v_source_rows,
      'graph_path', 'properties_master_owners_prospects_phones',
      'phone_join_strategy', 'primary_prospect_id_then_canonical_prospect_id_then_master_owner_id'
    )
  )
  RETURNING id INTO v_batch_id;

  IF v_source_rows = 0 THEN
    v_elapsed_ms := GREATEST(0, floor(EXTRACT(epoch FROM clock_timestamp() - v_started_at) * 1000)::integer);

    SELECT COUNT(*)::integer INTO v_stage_rows FROM public.campaign_target_graph_stage;

    UPDATE public.campaign_target_graph_refresh_batches
    SET
      rows_inserted = 0,
      finished_at = clock_timestamp(),
      elapsed_ms = v_elapsed_ms,
      status = 'completed',
      metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
        'has_more', false,
        'stage_rows_after_batch', v_stage_rows
      )
    WHERE id = v_batch_id;

    UPDATE public.campaign_target_graph_refresh_runs
    SET metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
      'last_batch_number', v_batch_number,
      'last_batch_key', v_batch_key,
      'last_has_more', false,
      'completed_all_batches', true,
      'stage_rows', v_stage_rows
    )
    WHERE id = p_run_id;

    run_id := p_run_id;
    batch_number := v_batch_number;
    batch_type := v_batch_type;
    batch_key := v_batch_key;
    batch_start := v_batch_start;
    batch_end := v_batch_end;
    source_rows := v_source_rows;
    rows_inserted := 0;
    stage_rows := v_stage_rows;
    has_more := false;
    elapsed_ms := v_elapsed_ms;
    RETURN NEXT;
    RETURN;
  END IF;

  WITH property_batch AS (
    SELECT p.*
    FROM public.properties p
    WHERE NULLIF(p.master_owner_id, '') IS NOT NULL
      AND (v_state IS NULL OR upper(COALESCE(NULLIF(p.property_state, ''), NULLIF(p.property_address_state, ''))) = v_state)
      AND (v_market IS NULL OR p.market = v_market)
    ORDER BY
      COALESCE(NULLIF(p.property_id, ''), NULLIF(p.property_export_id, '')) NULLS LAST,
      p.property_export_id NULLS LAST
    LIMIT v_limit OFFSET v_offset
  ),
  owner_paths AS (
    SELECT
      ROW(p.*)::public.properties AS p,
      ROW(mo.*)::public.master_owners AS mo
    FROM property_batch p
    JOIN public.master_owners mo
      ON mo.master_owner_id = p.master_owner_id
  ),
  prospect_paths AS (
    SELECT
      op.p,
      op.mo,
      pr.pr_row AS pr,
      pr.link_rank AS prospect_link_rank
    FROM owner_paths op
    CROSS JOIN LATERAL (SELECT (op.mo).*) mo
    JOIN LATERAL (
      SELECT candidate.pr_row, candidate.link_rank
      FROM (
        SELECT ROW(pr.*)::public.prospects AS pr_row, 1 AS link_rank
        FROM public.prospects pr
        WHERE mo.best_prospect_id IS NOT NULL
          AND pr.prospect_id = mo.best_prospect_id
        UNION ALL
        SELECT ROW(pr.*)::public.prospects AS pr_row, 2 AS link_rank
        FROM public.prospects pr
        WHERE mo.best_canonical_prospect_id IS NOT NULL
          AND pr.canonical_prospect_id = mo.best_canonical_prospect_id
        UNION ALL
        SELECT ROW(pr.*)::public.prospects AS pr_row, 3 AS link_rank
        FROM public.prospects pr
        WHERE pr.master_owner_id = mo.master_owner_id
      ) candidate
      ORDER BY
        candidate.link_rank,
        COALESCE((candidate.pr_row).is_primary_prospect, false) DESC,
        (candidate.pr_row).rank_position NULLS LAST,
        (candidate.pr_row).phone_score_final DESC NULLS LAST,
        (candidate.pr_row).contact_score_final DESC NULLS LAST,
        COALESCE((candidate.pr_row).updated_at, (candidate.pr_row).created_at) DESC NULLS LAST
      LIMIT 1
    ) pr ON true
  ),
  target_paths AS (
    SELECT
      md5(concat_ws('|',
        NULLIF(p.property_id, ''),
        NULLIF(p.property_export_id, ''),
        NULLIF(COALESCE(mo.master_owner_id, p.master_owner_id), ''),
        NULLIF(COALESCE(pr.prospect_id::text, ph.primary_prospect_id::text, ph.canonical_prospect_id::text), ''),
        NULLIF(ph.phone_id::text, ''),
        NULLIF(ph.canonical_e164, '')
      )) AS graph_id,
      p.property_id::text AS property_id,
      p.property_export_id::text AS property_export_id,
      COALESCE(mo.master_owner_id, p.master_owner_id)::text AS master_owner_id,
      COALESCE(pr.prospect_id::text, ph.primary_prospect_id::text, ph.canonical_prospect_id::text) AS prospect_id,
      COALESCE(pr.canonical_prospect_id::text, ph.canonical_prospect_id::text) AS canonical_prospect_id,
      ph.phone_id::text AS phone_id,
      ph.canonical_e164::text AS canonical_e164,
      graph_market.market AS market,
      COALESCE(NULLIF(p.property_state, ''), NULLIF(p.property_address_state, '')) AS state,
      p.property_address_city::text AS property_city,
      COALESCE(NULLIF(p.property_zip, ''), NULLIF(p.property_address_zip, '')) AS property_zip,
      COALESCE(NULLIF(p.property_county_name, ''), NULLIF(p.property_address_county_name, '')) AS property_county_name,
      p.property_type::text AS property_type,
      p.property_class::text AS property_class,
      COALESCE(
        NULLIF(to_jsonb(p)->>'canonical_property_group', ''),
        NULLIF(p.property_group, ''),
        NULLIF(p.normalized_asset_class, ''),
        NULLIF(p.asset_type_label, ''),
        NULLIF(p.property_class, ''),
        NULLIF(p.property_type, '')
      ) AS canonical_property_group,
      COALESCE(NULLIF(pr.language_preference, ''), NULLIF(mo.best_language, ''), NULLIF(ph.linked_languages_text, '')) AS language,
      public.campaign_age_bucket_from_mob(pr.mob::text) AS age_bucket,
      pr.occupation_group::text AS occupation_group,
      pr.education_model::text AS education_model,
      pr.est_household_income::text AS income,
      COALESCE(NULLIF(mo.owner_type_guess, ''), NULLIF(pr.owner_type_guess, ''), NULLIF(p.owner_type_guess, ''), NULLIF(p.owner_type, '')) AS owner_type_guess,
      COALESCE(NULLIF(mo.priority_tier, ''), NULLIF(pr.priority_tier, ''), NULLIF(p.priority_tier, '')) AS priority_tier,
      mo.follow_up_cadence::text AS follow_up_cadence,
      COALESCE(NULLIF(p.rehab_level, ''), NULLIF(p.renovation_level_classification, ''), NULLIF(p.building_condition, '')) AS rehab_level,
      (
        ph.canonical_e164 IS NOT NULL
        AND COALESCE(ph.phone_contact_status, '') IS DISTINCT FROM 'wrong_number'
      ) AS sms_eligible,
      COALESCE(sup.is_suppressed, false) AS true_post_contact_suppression,
      (
        COALESCE(ph.phone_contact_status, '') = 'wrong_number'
        OR ph.wrong_number_at IS NOT NULL
      ) AS wrong_number,
      (
        latest.last_outbound_at IS NOT NULL
        AND latest.last_outbound_at >= now() - interval '30 days'
      ) AS pending_prior_touch,
      COALESCE(aq.active_queue_count, 0) > 0 AS active_queue_item,
      sm.sender_market IS NOT NULL AS sender_covered,
      sm.sender_market,
      COALESCE(NULLIF(ph.timezone, ''), NULLIF(pr.timezone, ''), NULLIF(mo.routing_timezone, '')) AS timezone,
      ph.best_phone_score,
      ph.phone_owner,
      ph.activity_status AS phone_activity_status,
      ph.usage_12_months::text AS usage_12_months,
      ph.usage_2_months::text AS usage_2_months,
      'ownership_check'::text AS template_use_case,
      COALESCE(NULLIF(ph.contact_window, ''), NULLIF(pr.contact_window, ''), NULLIF(mo.best_contact_window, '')) AS contact_window,
      NULLIF(GREATEST(
        COALESCE(latest.last_outbound_at, 'epoch'::timestamptz),
        COALESCE(latest.last_inbound_at, 'epoch'::timestamptz)
      ), 'epoch'::timestamptz) AS latest_contact_at,
      latest.last_outbound_at,
      latest.last_inbound_at,
      CASE WHEN sm.sender_market IS NOT NULL THEN 'exact_market_match' ELSE 'no_sender_route' END AS routing_tier,
      CASE
        WHEN COALESCE(pr.likely_owner, false) THEN 'verified'
        WHEN COALESCE(pr.likely_renting, false) THEN 'renter_risk'
        WHEN pr.prospect_id IS NOT NULL THEN 'probable'
        ELSE 'unknown'
      END AS identity_alignment,
      COALESCE(p.final_acquisition_score, mo.priority_score, pr.master_owner_priority_score) AS acquisition_score,
      COALESCE(NULLIF(p.seller_tags_text, ''), NULLIF(p.podio_tags, ''), NULLIF(mo.seller_tags_text, ''), NULLIF(pr.seller_tags_text, '')) AS podio_tags,
      jsonb_strip_nulls(jsonb_build_object(
        'matching_flags', pr.matching_flags,
        'person_flags_text', pr.person_flags_text,
        'person_flags_json', pr.person_flags_json
      )) AS matching_flags,
      COALESCE(NULLIF(pr.matching_flags, ''), NULLIF(pr.person_flags_text, '')) AS matching_flags_text,
      COALESCE(NULLIF(mo.display_name, ''), NULLIF(pr.owner_display_name, ''), NULLIF(p.owner_display_name, ''), NULLIF(p.owner_name, '')) AS owner_name,
      COALESCE(NULLIF(pr.first_name, ''), NULLIF(ph.phone_first_name, ''), split_part(NULLIF(COALESCE(pr.full_name, ph.phone_full_name, mo.display_name), ''), ' ', 1)) AS seller_first_name,
      COALESCE(NULLIF(pr.full_name, ''), NULLIF(ph.phone_full_name, ''), NULLIF(ph.primary_display_name, ''), NULLIF(mo.display_name, '')) AS seller_full_name,
      COALESCE(NULLIF(p.property_address_full, ''), NULLIF(p.property_address, '')) AS property_address_full,
      p.estimated_value,
      p.equity_amount,
      p.equity_percent,
      p.cash_offer,
      CASE WHEN latest.last_outbound_at IS NULL THEN 0 ELSE 1 END AS touch_count,
      CASE WHEN latest.last_outbound_at IS NULL THEN 1 ELSE 2 END AS current_touch_number,
      latest.last_outbound_at IS NULL AS never_contacted,
      jsonb_build_object(
        'property', CASE WHEN p.property_id IS NOT NULL THEN 1 ELSE 0 END,
        'master_owner', CASE WHEN mo.master_owner_id IS NOT NULL THEN 1 ELSE 0 END,
        'prospect', CASE WHEN pr.prospect_id IS NOT NULL THEN 1 ELSE 0 END,
        'phone', CASE WHEN ph.phone_id IS NOT NULL THEN 1 ELSE 0 END,
        'sender_numbers', COALESCE(sm.sender_count, 0),
        'prospect_link_rank', prospect_paths.prospect_link_rank,
        'phone_link_rank', ph.link_rank
      ) AS linkage_counts,
      to_jsonb(p) AS property_data,
      to_jsonb(mo) AS master_owner_data,
      to_jsonb(pr) AS prospect_data,
      to_jsonb(ph) AS phone_data,
      sup.suppression_rows AS suppression_data,
      GREATEST(
        COALESCE(p.updated_at, p.created_at, 'epoch'::timestamptz),
        COALESCE(mo.updated_at, mo.created_at, 'epoch'::timestamptz),
        COALESCE(pr.updated_at, pr.created_at, 'epoch'::timestamptz),
        COALESCE(ph.updated_at, ph.created_at, 'epoch'::timestamptz),
        COALESCE(latest.last_outbound_at, 'epoch'::timestamptz),
        COALESCE(latest.last_inbound_at, 'epoch'::timestamptz),
        COALESCE(sm.latest_sender_update, 'epoch'::timestamptz),
        COALESCE(sup.latest_suppressed_at, 'epoch'::timestamptz)
      ) AS source_updated_at
    FROM prospect_paths
    CROSS JOIN LATERAL (SELECT (prospect_paths.p).*) p
    CROSS JOIN LATERAL (SELECT (prospect_paths.mo).*) mo
    CROSS JOIN LATERAL (SELECT (prospect_paths.pr).*) pr
    CROSS JOIN LATERAL (
      SELECT COALESCE(NULLIF(p.market, ''), NULLIF(mo.routing_market, ''), NULLIF(pr.primary_market, '')) AS market
    ) graph_market
    LEFT JOIN LATERAL (
      SELECT linked_ph.*
      FROM (
        SELECT ph.*, 1 AS link_rank
        FROM public.phones ph
        WHERE ph.canonical_e164 IS NOT NULL
          AND (
            ph.phone_type IS NULL
            OR ph.phone_type = ''
            OR lower(ph.phone_type) IN ('w', 'wireless', 'mobile', 'voip', 'unknown')
          )
          AND ph.primary_prospect_id = pr.prospect_id
        UNION ALL
        SELECT ph.*, 2 AS link_rank
        FROM public.phones ph
        WHERE ph.canonical_e164 IS NOT NULL
          AND (
            ph.phone_type IS NULL
            OR ph.phone_type = ''
            OR lower(ph.phone_type) IN ('w', 'wireless', 'mobile', 'voip', 'unknown')
          )
          AND ph.canonical_prospect_id = pr.canonical_prospect_id
        UNION ALL
        SELECT ph.*, 3 AS link_rank
        FROM public.phones ph
        WHERE ph.canonical_e164 IS NOT NULL
          AND (
            ph.phone_type IS NULL
            OR ph.phone_type = ''
            OR lower(ph.phone_type) IN ('w', 'wireless', 'mobile', 'voip', 'unknown')
          )
          AND ph.master_owner_id = mo.master_owner_id
      ) linked_ph
      ORDER BY
        linked_ph.link_rank,
        COALESCE(linked_ph.is_best_phone_for_slot, false) DESC,
        COALESCE(linked_ph.is_best_phone_for_owner, false) DESC,
        linked_ph.best_phone_score DESC NULLS LAST,
        COALESCE(linked_ph.updated_at, linked_ph.created_at) DESC NULLS LAST
      LIMIT 1
    ) ph ON true
    LEFT JOIN LATERAL (
      SELECT COUNT(*)::integer AS active_queue_count
      FROM public.send_queue sq
      WHERE sq.to_phone_number = ph.canonical_e164
        AND lower(COALESCE(sq.queue_status, '')) IN ('queued', 'scheduled', 'pending', 'ready', 'approved', 'processing', 'sending')
    ) aq ON ph.canonical_e164 IS NOT NULL
    LEFT JOIN LATERAL (
      SELECT
        MAX(last_inbound_at) AS last_inbound_at,
        MAX(last_outbound_at) AS last_outbound_at
      FROM (
        SELECT
          MAX(COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at)) AS last_inbound_at,
          NULL::timestamptz AS last_outbound_at
        FROM public.message_events me
        WHERE me.from_phone_number = ph.canonical_e164
          AND lower(COALESCE(me.direction, '')) LIKE 'in%'
        UNION ALL
        SELECT
          NULL::timestamptz AS last_inbound_at,
          MAX(COALESCE(me.event_timestamp, me.sent_at, me.received_at, me.created_at)) AS last_outbound_at
        FROM public.message_events me
        WHERE me.to_phone_number = ph.canonical_e164
          AND lower(COALESCE(me.direction, '')) LIKE 'out%'
        UNION ALL
        SELECT
          NULL::timestamptz AS last_inbound_at,
          MAX(COALESCE(sq.sent_at, sq.scheduled_for_utc, sq.scheduled_for, sq.created_at)) AS last_outbound_at
        FROM public.send_queue sq
        WHERE sq.to_phone_number = ph.canonical_e164
      ) contact_events
    ) latest ON ph.canonical_e164 IS NOT NULL
    LEFT JOIN LATERAL (
      SELECT
        bool_or(COALESCE(sl.is_active, true)) AS is_suppressed,
        MAX(COALESCE(sl.suppressed_at, sl.created_at)) AS latest_suppressed_at,
        jsonb_agg(to_jsonb(sl) ORDER BY COALESCE(sl.suppressed_at, sl.created_at) DESC NULLS LAST) AS suppression_rows
      FROM (
        SELECT sl.*
        FROM public.sms_suppression_list sl
        WHERE sl.phone_e164 = ph.canonical_e164
        UNION ALL
        SELECT sl.*
        FROM public.sms_suppression_list sl
        WHERE sl.phone_number = ph.canonical_e164
          AND sl.phone_e164 IS DISTINCT FROM ph.canonical_e164
      ) sl
    ) sup ON ph.canonical_e164 IS NOT NULL
    LEFT JOIN LATERAL (
      SELECT
        tn.market AS sender_market,
        COUNT(*)::integer AS sender_count,
        MAX(tn.updated_at) AS latest_sender_update
      FROM public.textgrid_numbers tn
      WHERE tn.market = COALESCE(graph_market.market, ph.primary_market)
        AND NULLIF(tn.phone_number, '') IS NOT NULL
        AND lower(COALESCE(tn.status, 'active')) NOT IN ('disabled', 'inactive', 'failed', 'blocked', 'retired')
      GROUP BY tn.market
    ) sm ON COALESCE(graph_market.market, ph.primary_market) IS NOT NULL
  )
  INSERT INTO public.campaign_target_graph_stage (
    graph_id,
    property_id,
    property_export_id,
    master_owner_id,
    prospect_id,
    canonical_prospect_id,
    phone_id,
    canonical_e164,
    market,
    state,
    property_city,
    property_zip,
    property_county_name,
    property_type,
    property_class,
    canonical_property_group,
    language,
    age_bucket,
    occupation_group,
    education_model,
    income,
    owner_type_guess,
    priority_tier,
    follow_up_cadence,
    rehab_level,
    sms_eligible,
    true_post_contact_suppression,
    wrong_number,
    pending_prior_touch,
    active_queue_item,
    sender_covered,
    sender_market,
    timezone,
    best_phone_score,
    phone_owner,
    phone_activity_status,
    usage_12_months,
    usage_2_months,
    template_use_case,
    contact_window,
    latest_contact_at,
    last_outbound_at,
    last_inbound_at,
    routing_tier,
    identity_alignment,
    acquisition_score,
    podio_tags,
    matching_flags,
    matching_flags_text,
    owner_name,
    seller_first_name,
    seller_full_name,
    property_address_full,
    estimated_value,
    equity_amount,
    equity_percent,
    cash_offer,
    touch_count,
    current_touch_number,
    never_contacted,
    queue_eligible,
    queue_block_reason,
    graph_source,
    linkage_counts,
    blocker_flags,
    extra_data,
    source_updated_at,
    generated_at
  )
  SELECT
    graph_id,
    property_id,
    property_export_id,
    master_owner_id,
    prospect_id,
    canonical_prospect_id,
    phone_id,
    canonical_e164,
    market,
    state,
    property_city,
    property_zip,
    property_county_name,
    property_type,
    property_class,
    canonical_property_group,
    language,
    age_bucket,
    occupation_group,
    education_model,
    income,
    owner_type_guess,
    priority_tier,
    follow_up_cadence,
    rehab_level,
    sms_eligible,
    true_post_contact_suppression,
    wrong_number,
    pending_prior_touch,
    active_queue_item,
    sender_covered,
    sender_market,
    timezone,
    best_phone_score,
    phone_owner,
    phone_activity_status,
    usage_12_months,
    usage_2_months,
    template_use_case,
    contact_window,
    latest_contact_at,
    last_outbound_at,
    last_inbound_at,
    routing_tier,
    identity_alignment,
    acquisition_score,
    podio_tags,
    matching_flags,
    matching_flags_text,
    owner_name,
    seller_first_name,
    seller_full_name,
    property_address_full,
    estimated_value,
    equity_amount,
    equity_percent,
    cash_offer,
    touch_count,
    current_touch_number,
    never_contacted,
    (
      sms_eligible
      AND NOT true_post_contact_suppression
      AND NOT wrong_number
      AND NOT pending_prior_touch
      AND NOT active_queue_item
      AND sender_covered
    ) AS queue_eligible,
    CASE
      WHEN NOT sms_eligible THEN 'sms_ineligible'
      WHEN true_post_contact_suppression THEN 'suppressed'
      WHEN wrong_number THEN 'wrong_number'
      WHEN pending_prior_touch THEN 'pending_prior_touch'
      WHEN active_queue_item THEN 'active_queue_item'
      WHEN NOT sender_covered THEN 'no_sender_coverage'
      ELSE NULL
    END AS queue_block_reason,
    'campaign_target_graph.refresh.direct_staged' AS graph_source,
    linkage_counts,
    jsonb_build_object(
      'sms_eligible', sms_eligible,
      'true_post_contact_suppression', true_post_contact_suppression,
      'wrong_number', wrong_number,
      'pending_prior_touch', pending_prior_touch,
      'active_queue_item', active_queue_item,
      'sender_covered', sender_covered
    ) AS blocker_flags,
    jsonb_strip_nulls(jsonb_build_object(
      'property', property_data,
      'master_owner', master_owner_data,
      'prospect', prospect_data,
      'phone', phone_data,
      'suppression', suppression_data
    )) AS extra_data,
    NULLIF(source_updated_at, 'epoch'::timestamptz) AS source_updated_at,
    now() AS generated_at
  FROM target_paths
  WHERE phone_id IS NOT NULL
    AND canonical_e164 IS NOT NULL
  ON CONFLICT (graph_id) DO UPDATE SET
    graph_source = EXCLUDED.graph_source,
    generated_at = EXCLUDED.generated_at,
    source_updated_at = EXCLUDED.source_updated_at;

  GET DIAGNOSTICS v_rows_inserted = ROW_COUNT;

  SELECT COUNT(*)::integer INTO v_stage_rows FROM public.campaign_target_graph_stage;
  v_elapsed_ms := GREATEST(0, floor(EXTRACT(epoch FROM clock_timestamp() - v_started_at) * 1000)::integer);

  UPDATE public.campaign_target_graph_refresh_batches
  SET
    rows_inserted = v_rows_inserted,
    finished_at = clock_timestamp(),
    elapsed_ms = v_elapsed_ms,
    status = 'completed',
    metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
      'has_more', v_has_more,
      'stage_rows_after_batch', v_stage_rows
    )
  WHERE id = v_batch_id;

  UPDATE public.campaign_target_graph_refresh_runs
  SET metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
    'last_batch_number', v_batch_number,
    'last_batch_key', v_batch_key,
    'last_has_more', v_has_more,
    'completed_all_batches', NOT v_has_more,
    'stage_rows', v_stage_rows,
    'graph_refresh_scope', CASE WHEN v_has_more THEN 'partial' ELSE 'full' END
  )
  WHERE id = p_run_id;

  run_id := p_run_id;
  batch_number := v_batch_number;
  batch_type := v_batch_type;
  batch_key := v_batch_key;
  batch_start := v_batch_start;
  batch_end := v_batch_end;
  source_rows := v_source_rows;
  rows_inserted := v_rows_inserted;
  stage_rows := v_stage_rows;
  has_more := v_has_more;
  elapsed_ms := v_elapsed_ms;
  RETURN NEXT;
EXCEPTION WHEN OTHERS THEN
  v_elapsed_ms := GREATEST(0, floor(EXTRACT(epoch FROM clock_timestamp() - v_started_at) * 1000)::integer);

  IF v_batch_id IS NOT NULL THEN
    UPDATE public.campaign_target_graph_refresh_batches
    SET
      finished_at = clock_timestamp(),
      elapsed_ms = v_elapsed_ms,
      status = 'failed',
      error_message = SQLERRM,
      metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object('error_sqlstate', SQLSTATE)
    WHERE id = v_batch_id;
  END IF;

  UPDATE public.campaign_target_graph_refresh_runs
  SET
    status = 'failed',
    finished_at = now(),
    error_message = SQLERRM,
    metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
      'last_failed_batch_key', v_batch_key,
      'last_error_sqlstate', SQLSTATE
    )
  WHERE id = p_run_id;

  RAISE;
END;
$$;


--
-- Name: refresh_campaign_target_graph_stage_commit("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."refresh_campaign_target_graph_stage_commit"("p_run_id" "uuid") RETURNS TABLE("run_id" "uuid", "graph_rows" integer, "facet_rows" integer, "graph_refresh_scope" "text", "elapsed_ms" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_started_at timestamptz := clock_timestamp();
  v_stage_rows integer := 0;
  v_graph_rows integer := 0;
  v_facet_rows integer := 0;
  v_elapsed_ms integer := 0;
  v_scope text := 'partial';
  v_run_metadata jsonb := '{}'::jsonb;
BEGIN
  PERFORM set_config('statement_timeout', '0', true);
  PERFORM set_config('work_mem', '128MB', true);

  SELECT COALESCE(r.metadata, '{}'::jsonb)
  INTO v_run_metadata
  FROM public.campaign_target_graph_refresh_runs r
  WHERE r.id = p_run_id
    AND r.status = 'started';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'campaign target graph refresh run % is not active', p_run_id;
  END IF;

  SELECT COUNT(*)::integer INTO v_stage_rows FROM public.campaign_target_graph_stage;

  IF v_stage_rows <= 0 THEN
    UPDATE public.campaign_target_graph_refresh_runs
    SET
      status = 'failed',
      finished_at = now(),
      graph_rows = 0,
      facet_rows = 0,
      error_message = 'campaign_target_graph_stage_empty',
      metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
        'graph_refresh_scope', 'empty',
        'stage_rows', 0
      )
    WHERE id = p_run_id;

    RAISE EXCEPTION 'campaign_target_graph_stage is empty for run %', p_run_id;
  END IF;

  v_scope := CASE
    WHEN COALESCE(v_run_metadata->>'completed_all_batches', 'false') = 'true' THEN 'full'
    ELSE 'partial'
  END;

  TRUNCATE TABLE public.campaign_target_graph;

  INSERT INTO public.campaign_target_graph
  SELECT *
  FROM public.campaign_target_graph_stage;

  GET DIAGNOSTICS v_graph_rows = ROW_COUNT;

  SELECT public.refresh_campaign_target_graph_facets() INTO v_facet_rows;

  v_elapsed_ms := GREATEST(0, floor(EXTRACT(epoch FROM clock_timestamp() - v_started_at) * 1000)::integer);

  UPDATE public.campaign_target_graph_refresh_runs
  SET
    status = 'completed',
    finished_at = now(),
    graph_rows = v_graph_rows,
    facet_rows = v_facet_rows,
    metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
      'source', 'refresh_campaign_target_graph_stage_commit',
      'stage_rows', v_stage_rows,
      'graph_rows', v_graph_rows,
      'facet_rows', v_facet_rows,
      'graph_refresh_scope', v_scope,
      'fallback_enabled', false,
      'elapsed_ms_commit', v_elapsed_ms
    )
  WHERE id = p_run_id;

  run_id := p_run_id;
  graph_rows := v_graph_rows;
  facet_rows := v_facet_rows;
  graph_refresh_scope := v_scope;
  elapsed_ms := v_elapsed_ms;
  RETURN NEXT;
EXCEPTION WHEN OTHERS THEN
  UPDATE public.campaign_target_graph_refresh_runs
  SET
    status = 'failed',
    finished_at = now(),
    error_message = SQLERRM,
    metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
      'source', 'refresh_campaign_target_graph_stage_commit',
      'error_sqlstate', SQLSTATE
    )
  WHERE id = p_run_id;
  RAISE;
END;
$$;


--
-- Name: refresh_campaign_target_graph_stage_start(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."refresh_campaign_target_graph_stage_start"() RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_run_id uuid;
  v_active_run_id uuid;
  v_active_started_at timestamptz;
BEGIN
  PERFORM pg_advisory_xact_lock(hashtext('campaign_target_graph_refresh_start'));

  PERFORM public.reap_stale_campaign_target_graph_refresh_runs();

  SELECT r.id, r.started_at
    INTO v_active_run_id, v_active_started_at
    FROM public.campaign_target_graph_refresh_runs r
   WHERE r.status = 'started'
   ORDER BY r.started_at DESC
   LIMIT 1;

  IF v_active_run_id IS NOT NULL THEN
    RAISE EXCEPTION
      'campaign target graph refresh already in progress (run % started %); wait for it to finish or reap it before starting a new run',
      v_active_run_id, v_active_started_at
      USING ERRCODE = 'lock_not_available';
  END IF;

  TRUNCATE TABLE public.campaign_target_graph_stage;

  INSERT INTO public.campaign_target_graph_refresh_runs (status, metadata)
  VALUES (
    'started',
    jsonb_build_object(
      'source', 'refresh_campaign_target_graph_stage_start',
      'refresh_strategy', 'staged_property_offset_batches',
      'graph_path', 'properties_master_owners_prospects_phones',
      'graph_refresh_scope', 'partial',
      'fallback_enabled', false,
      'direct_core_only', true
    )
  )
  RETURNING id INTO v_run_id;

  RETURN v_run_id;
END;
$$;


--
-- Name: refresh_campaign_target_graph_staged(integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."refresh_campaign_target_graph_staged"("p_batch_limit" integer DEFAULT 10000, "p_max_batches" integer DEFAULT NULL::integer) RETURNS TABLE("run_id" "uuid", "batches_completed" integer, "stage_rows" integer, "graph_rows" integer, "facet_rows" integer, "graph_refresh_scope" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_run_id uuid;
  v_limit integer := LEAST(GREATEST(COALESCE(p_batch_limit, 10000), 1), 50000);
  v_offset integer := 0;
  v_batches_completed integer := 0;
  v_source_rows integer := 0;
  v_stage_rows integer := 0;
  v_has_more boolean := true;
  v_commit record;
BEGIN
  v_run_id := public.refresh_campaign_target_graph_stage_start();

  LOOP
    EXIT WHEN p_max_batches IS NOT NULL AND v_batches_completed >= p_max_batches;

    SELECT b.source_rows, b.stage_rows, b.has_more
    INTO v_source_rows, v_stage_rows, v_has_more
    FROM public.refresh_campaign_target_graph_stage_batch(v_run_id, v_limit, v_offset) b;

    v_batches_completed := v_batches_completed + 1;
    EXIT WHEN v_source_rows = 0 OR NOT v_has_more;

    v_offset := v_offset + v_limit;
  END LOOP;

  UPDATE public.campaign_target_graph_refresh_runs
  SET metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
    'completed_all_batches',
    CASE
      WHEN v_source_rows = 0 OR NOT v_has_more THEN true
      ELSE false
    END,
    'graph_refresh_scope',
    CASE
      WHEN v_source_rows = 0 OR NOT v_has_more THEN 'full'
      ELSE 'partial'
    END
  )
  WHERE id = v_run_id;

  SELECT *
  INTO v_commit
  FROM public.refresh_campaign_target_graph_stage_commit(v_run_id);

  run_id := v_run_id;
  batches_completed := v_batches_completed;
  stage_rows := v_stage_rows;
  graph_rows := v_commit.graph_rows;
  facet_rows := v_commit.facet_rows;
  graph_refresh_scope := v_commit.graph_refresh_scope;
  RETURN NEXT;
END;
$$;


--
-- Name: refresh_deal_context_index(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."refresh_deal_context_index"() RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_count integer;
  v_batch_size integer := 40000;
  v_batch_start integer := 1;
  v_batch_end integer;
  v_total_properties integer := 0;
BEGIN
  PERFORM set_config('statement_timeout', '0', true);

  TRUNCATE TABLE public.deal_context_index;

  SELECT COUNT(*)::integer
  INTO v_total_properties
  FROM public.properties;

  WHILE v_batch_start <= v_total_properties LOOP
    v_batch_end := v_batch_start + v_batch_size - 1;

    INSERT INTO public.deal_context_index (
    deal_context_id,
    context_type,
    property_id,
    master_owner_id,
    prospect_id,
    canonical_prospect_id,
    phone_id,
    email_id,
    thread_key,
    canonical_e164,
    campaign_id,
    campaign_target_id,
    queue_row_id,
    latest_message_event_id,
    latest_message_body,
    latest_message_direction,
    latest_message_at,
    last_outbound_at,
    last_inbound_at,
    owner_name,
    seller_first_name,
    property_address_full,
    property_address_city,
    property_state,
    property_zip,
    property_county_name,
    market,
    latitude,
    longitude,
    property_type,
    property_class,
    estimated_value,
    estimated_arv,
    equity_percent,
    cash_offer,
    buyer_demand_score,
    buyer_match_score,
    buyer_match_count,
    best_buyer_name,
    best_buyer_grade,
    universal_status,
    universal_stage,
    inbox_bucket,
    queue_status,
    queue_scheduled_for,
    campaign_name,
    campaign_status,
    campaign_target_status,
    suppression_status,
    suppression_type,
    final_acquisition_score,
    priority_score,
    opt_out,
    wrong_number,
    not_interested,
    needs_review,
    property_data,
    master_owner_data,
    prospect_data,
    phone_data,
    email_data,
    thread_state_data,
    campaign_data,
    queue_data,
    suppression_data,
    valuation_data,
    buyer_match_data,
    latest_message_event_data,
    created_at,
    updated_at
  )
  WITH property_rows AS (
    SELECT p_batch.*
    FROM (
      SELECT
        p.*,
        ROW_NUMBER() OVER (ORDER BY p.ctid) AS deal_context_batch_row_num
      FROM public.properties p
    ) p_batch
    WHERE p_batch.deal_context_batch_row_num BETWEEN v_batch_start AND v_batch_end
  ),
  thread_by_property AS (
    SELECT DISTINCT ON (ts.property_id) ts.*
    FROM public.deal_thread_state ts
    WHERE ts.property_id IS NOT NULL
    ORDER BY ts.property_id, COALESCE(ts.latest_message_at, ts.updated_at, ts.created_at) DESC NULLS LAST
  ),
  thread_by_owner AS (
    SELECT DISTINCT ON (ts.master_owner_id) ts.*
    FROM public.deal_thread_state ts
    WHERE ts.master_owner_id IS NOT NULL
    ORDER BY ts.master_owner_id, COALESCE(ts.latest_message_at, ts.updated_at, ts.created_at) DESC NULLS LAST
  ),
  thread_by_thread_key AS (
    SELECT DISTINCT ON (ts.thread_key) ts.*
    FROM public.deal_thread_state ts
    WHERE ts.thread_key IS NOT NULL
    ORDER BY ts.thread_key, COALESCE(ts.latest_message_at, ts.updated_at, ts.created_at) DESC NULLS LAST
  ),
  thread_by_best_phone AS (
    SELECT DISTINCT ON (ts.best_phone) ts.*
    FROM public.deal_thread_state ts
    WHERE ts.best_phone IS NOT NULL
    ORDER BY ts.best_phone, COALESCE(ts.latest_message_at, ts.updated_at, ts.created_at) DESC NULLS LAST
  ),
  message_by_thread AS (
    SELECT DISTINCT ON (me.thread_key)
      me.*,
      COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at) AS event_at
    FROM public.message_events me
    WHERE me.thread_key IS NOT NULL
    ORDER BY me.thread_key, COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at) DESC NULLS LAST, me.created_at DESC NULLS LAST
  ),
  message_by_property AS (
    SELECT DISTINCT ON (me.property_id)
      me.*,
      COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at) AS event_at
    FROM public.message_events me
    WHERE me.property_id IS NOT NULL
    ORDER BY me.property_id, COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at) DESC NULLS LAST, me.created_at DESC NULLS LAST
  ),
  message_stats_by_thread AS (
    SELECT
      me.thread_key,
      MAX(
        CASE
          WHEN LOWER(COALESCE(me.direction, '')) LIKE 'in%' THEN COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at)
          ELSE NULL
        END
      ) AS last_inbound_at,
      MAX(
        CASE
          WHEN LOWER(COALESCE(me.direction, '')) LIKE 'out%' THEN COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at)
          ELSE NULL
        END
      ) AS last_outbound_at
    FROM public.message_events me
    WHERE me.thread_key IS NOT NULL
    GROUP BY me.thread_key
  ),
  target_by_property AS (
    SELECT DISTINCT ON (ct.property_id) ct.*
    FROM public.sms_campaign_targets ct
    WHERE ct.property_id IS NOT NULL
    ORDER BY ct.property_id, COALESCE(ct.updated_at, ct.replied_at, ct.sent_at, ct.delivered_at, ct.queued_at, ct.created_at) DESC NULLS LAST
  ),
  target_by_owner AS (
    SELECT DISTINCT ON (ct.master_owner_id) ct.*
    FROM public.sms_campaign_targets ct
    WHERE ct.master_owner_id IS NOT NULL
    ORDER BY ct.master_owner_id, COALESCE(ct.updated_at, ct.replied_at, ct.sent_at, ct.delivered_at, ct.queued_at, ct.created_at) DESC NULLS LAST
  ),
  target_by_phone AS (
    SELECT DISTINCT ON (ct.canonical_e164) ct.*
    FROM public.sms_campaign_targets ct
    WHERE ct.canonical_e164 IS NOT NULL
    ORDER BY ct.canonical_e164, COALESCE(ct.updated_at, ct.replied_at, ct.sent_at, ct.delivered_at, ct.queued_at, ct.created_at) DESC NULLS LAST
  ),
  queue_by_property AS (
    SELECT DISTINCT ON (sq.property_id) sq.*
    FROM public.send_queue sq
    WHERE sq.property_id IS NOT NULL
    ORDER BY sq.property_id, COALESCE(sq.updated_at, sq.sent_at, sq.delivered_at, sq.scheduled_for_utc, sq.scheduled_for, sq.created_at) DESC NULLS LAST
  ),
  queue_by_owner AS (
    SELECT DISTINCT ON (sq.master_owner_id) sq.*
    FROM public.send_queue sq
    WHERE sq.master_owner_id IS NOT NULL
    ORDER BY sq.master_owner_id, COALESCE(sq.updated_at, sq.sent_at, sq.delivered_at, sq.scheduled_for_utc, sq.scheduled_for, sq.created_at) DESC NULLS LAST
  ),
  queue_by_thread AS (
    SELECT DISTINCT ON (sq.thread_key) sq.*
    FROM public.send_queue sq
    WHERE sq.thread_key IS NOT NULL
    ORDER BY sq.thread_key, COALESCE(sq.updated_at, sq.sent_at, sq.delivered_at, sq.scheduled_for_utc, sq.scheduled_for, sq.created_at) DESC NULLS LAST
  ),
  queue_by_phone AS (
    SELECT DISTINCT ON (sq.to_phone_number) sq.*
    FROM public.send_queue sq
    WHERE sq.to_phone_number IS NOT NULL
    ORDER BY sq.to_phone_number, COALESCE(sq.updated_at, sq.sent_at, sq.delivered_at, sq.scheduled_for_utc, sq.scheduled_for, sq.created_at) DESC NULLS LAST
  ),
  suppression_by_phone AS (
    SELECT DISTINCT ON (COALESCE(sl.phone_e164, sl.phone_number)) sl.*
    FROM public.sms_suppression_list sl
    WHERE COALESCE(sl.phone_e164, sl.phone_number) IS NOT NULL
    ORDER BY COALESCE(sl.phone_e164, sl.phone_number), COALESCE(sl.suppressed_at, sl.created_at) DESC NULLS LAST
  ),
  valuation_by_property AS (
    SELECT DISTINCT ON (v.property_id) v.*
    FROM public.property_valuation_snapshots v
    WHERE v.property_id IS NOT NULL
    ORDER BY v.property_id, COALESCE(v.updated_at, v.created_at) DESC NULLS LAST
  ),
  cash_snapshot_by_property AS (
    SELECT DISTINCT ON (c.property_id) c.*
    FROM public.property_cash_offer_snapshots c
    WHERE c.property_id IS NOT NULL
    ORDER BY c.property_id, COALESCE(c.updated_at, c.created_at) DESC NULLS LAST
  ),
  comp_summary_by_property AS (
    SELECT
      ranked.property_id,
      COUNT(*)::integer AS comp_count,
      AVG(ranked.price_off_value) AS avg_price_off_value,
      MAX(ranked.comp_confidence_score) AS max_comp_confidence_score,
      jsonb_agg(to_jsonb(ranked) ORDER BY COALESCE(ranked.updated_at, ranked.created_at) DESC NULLS LAST) AS comp_sample
    FROM (
      SELECT
        comp.*,
        ROW_NUMBER() OVER (
          PARTITION BY comp.property_id
          ORDER BY COALESCE(comp.updated_at, comp.created_at) DESC NULLS LAST
        ) AS rn
      FROM public.v_recent_sold_comps comp
      WHERE comp.property_id IS NOT NULL
    ) ranked
    WHERE ranked.rn <= 5
    GROUP BY ranked.property_id
  ),
  buyer_run_by_property AS (
    SELECT DISTINCT ON (br.property_id) br.*
    FROM public.buyer_match_runs br
    WHERE br.property_id IS NOT NULL
    ORDER BY br.property_id, COALESCE(br.updated_at, br.created_at) DESC NULLS LAST
  ),
  best_buyer_by_property AS (
    SELECT ranked.*
    FROM (
      SELECT
        candidate.*,
        ROW_NUMBER() OVER (
          PARTITION BY candidate.property_id
          ORDER BY candidate.match_score DESC NULLS LAST, COALESCE(candidate.updated_at, candidate.created_at) DESC NULLS LAST
        ) AS rn
      FROM public.buyer_match_candidates candidate
      WHERE candidate.property_id IS NOT NULL
    ) ranked
    WHERE ranked.rn = 1
  ),
  buyer_candidates_by_property AS (
    SELECT
      ranked.property_id,
      COUNT(*)::integer AS buyer_match_count,
      jsonb_agg(to_jsonb(ranked) ORDER BY ranked.match_score DESC NULLS LAST, ranked.sort_at DESC NULLS LAST) AS top_candidates
    FROM (
      SELECT
        candidate.*,
        COALESCE(candidate.updated_at, candidate.created_at) AS sort_at,
        ROW_NUMBER() OVER (
          PARTITION BY candidate.property_id
          ORDER BY candidate.match_score DESC NULLS LAST, COALESCE(candidate.updated_at, candidate.created_at) DESC NULLS LAST
        ) AS rn
      FROM public.buyer_match_candidates candidate
      WHERE candidate.property_id IS NOT NULL
    ) ranked
    WHERE ranked.rn <= 5
    GROUP BY ranked.property_id
  ),
  property_base AS (
    SELECT
      p.*,
      to_jsonb(p) AS property_json,
      mo.master_owner_id AS mo_master_owner_id,
      mo.display_name AS mo_display_name,
      mo.best_canonical_prospect_id AS mo_best_canonical_prospect_id,
      mo.priority_score AS mo_priority_score,
      mo.routing_market AS mo_routing_market,
      mo.primary_email_id AS mo_primary_email_id,
      mo.created_at AS mo_created_at,
      mo.updated_at AS mo_updated_at,
      to_jsonb(mo) AS mo_json,
      pr.prospect_id AS pr_prospect_id,
      pr.canonical_prospect_id AS pr_canonical_prospect_id,
      pr.full_name AS pr_full_name,
      pr.first_name AS pr_first_name,
      pr.best_phone AS pr_best_phone,
      pr.best_email AS pr_best_email,
      pr.primary_market AS pr_primary_market,
      pr.master_owner_priority_score AS pr_master_owner_priority_score,
      pr.created_at AS pr_created_at,
      pr.updated_at AS pr_updated_at,
      to_jsonb(pr) AS pr_json,
      ph.phone_id AS ph_phone_id,
      ph.canonical_e164 AS ph_canonical_e164,
      ph.canonical_prospect_id AS ph_canonical_prospect_id,
      ph.primary_display_name AS ph_primary_display_name,
      ph.phone_full_name AS ph_phone_full_name,
      ph.phone_first_name AS ph_phone_first_name,
      ph.primary_market AS ph_primary_market,
      ph.created_at AS ph_created_at,
      ph.updated_at AS ph_updated_at,
      to_jsonb(ph) AS ph_json,
      em.email_id AS em_email_id,
      em.created_at AS em_created_at,
      em.updated_at AS em_updated_at,
      to_jsonb(em) AS em_json
    FROM property_rows p
    LEFT JOIN public.master_owners mo
      ON mo.master_owner_id = p.master_owner_id
    LEFT JOIN LATERAL (
      SELECT pr.*
      FROM public.prospects pr
      WHERE (
        mo.best_prospect_id IS NOT NULL
        AND pr.prospect_id = mo.best_prospect_id
      ) OR (
        mo.best_canonical_prospect_id IS NOT NULL
        AND pr.canonical_prospect_id = mo.best_canonical_prospect_id
      ) OR (
        mo.master_owner_id IS NOT NULL
        AND pr.master_owner_id = mo.master_owner_id
      )
      ORDER BY
        CASE
          WHEN mo.best_prospect_id IS NOT NULL AND pr.prospect_id = mo.best_prospect_id THEN 1
          WHEN mo.best_canonical_prospect_id IS NOT NULL AND pr.canonical_prospect_id = mo.best_canonical_prospect_id THEN 2
          WHEN COALESCE(pr.is_primary_prospect, false) THEN 3
          ELSE 4
        END,
        pr.rank_position NULLS LAST,
        pr.phone_score_final DESC NULLS LAST,
        pr.contact_score_final DESC NULLS LAST,
        COALESCE(pr.updated_at, pr.created_at) DESC NULLS LAST
      LIMIT 1
    ) pr ON true
    LEFT JOIN LATERAL (
      SELECT ph.*
      FROM public.phones ph
      WHERE (
        mo.primary_phone_id IS NOT NULL
        AND ph.phone_id = mo.primary_phone_id
      ) OR (
        pr.best_phone IS NOT NULL
        AND (ph.canonical_e164 = pr.best_phone OR ph.phone = pr.best_phone)
      ) OR (
        mo.master_owner_id IS NOT NULL
        AND ph.master_owner_id = mo.master_owner_id
      ) OR (
        pr.canonical_prospect_id IS NOT NULL
        AND ph.canonical_prospect_id = pr.canonical_prospect_id
      )
      ORDER BY
        CASE
          WHEN mo.primary_phone_id IS NOT NULL AND ph.phone_id = mo.primary_phone_id THEN 1
          WHEN pr.best_phone IS NOT NULL AND (ph.canonical_e164 = pr.best_phone OR ph.phone = pr.best_phone) THEN 2
          WHEN mo.master_owner_id IS NOT NULL
            AND ph.master_owner_id = mo.master_owner_id
            AND COALESCE(ph.is_best_phone_for_owner, false) THEN 3
          WHEN pr.canonical_prospect_id IS NOT NULL AND ph.canonical_prospect_id = pr.canonical_prospect_id THEN 4
          ELSE 5
        END,
        COALESCE(ph.is_best_phone_for_slot, false) DESC,
        COALESCE(ph.is_best_phone_for_owner, false) DESC,
        ph.best_phone_score DESC NULLS LAST,
        COALESCE(ph.updated_at, ph.created_at) DESC NULLS LAST
      LIMIT 1
    ) ph ON true
    LEFT JOIN LATERAL (
      SELECT em.*
      FROM public.emails em
      WHERE (
        mo.primary_email_id IS NOT NULL
        AND em.email_id = mo.primary_email_id
      ) OR (
        pr.best_email IS NOT NULL
        AND (em.email_normalized = pr.best_email OR em.email = pr.best_email)
      ) OR (
        mo.master_owner_id IS NOT NULL
        AND em.master_owner_id = mo.master_owner_id
      ) OR (
        pr.canonical_prospect_id IS NOT NULL
        AND em.canonical_prospect_id = pr.canonical_prospect_id
      )
      ORDER BY
        CASE
          WHEN mo.primary_email_id IS NOT NULL AND em.email_id = mo.primary_email_id THEN 1
          WHEN pr.best_email IS NOT NULL AND (em.email_normalized = pr.best_email OR em.email = pr.best_email) THEN 2
          WHEN mo.master_owner_id IS NOT NULL
            AND em.master_owner_id = mo.master_owner_id
            AND COALESCE(em.is_best_email_for_owner, false) THEN 3
          WHEN pr.canonical_prospect_id IS NOT NULL AND em.canonical_prospect_id = pr.canonical_prospect_id THEN 4
          ELSE 5
        END,
        COALESCE(em.is_best_email_for_slot, false) DESC,
        COALESCE(em.is_best_email_for_owner, false) DESC,
        em.email_score_final DESC NULLS LAST,
        COALESCE(em.updated_at, em.created_at) DESC NULLS LAST
      LIMIT 1
    ) em ON true
  )
  SELECT
    COALESCE(
      NULLIF(base.property_id, ''),
      'property_export:' || COALESCE(NULLIF(base.property_export_id, ''), md5(base.property_json::text))
    ) AS deal_context_id,
    'property'::text AS context_type,
    base.property_id,
    COALESCE(base.mo_master_owner_id, base.master_owner_id) AS master_owner_id,
    base.pr_prospect_id AS prospect_id,
    COALESCE(base.pr_canonical_prospect_id, base.ph_canonical_prospect_id, base.mo_best_canonical_prospect_id) AS canonical_prospect_id,
    base.ph_phone_id AS phone_id,
    base.em_email_id AS email_id,
    COALESCE(ts_property.thread_key, ts_owner.thread_key, ts_phone.thread_key, ts_best.thread_key, sq_property.thread_key, sq_owner.thread_key, sq_phone.thread_key, me_property.thread_key, base.ph_canonical_e164) AS thread_key,
    COALESCE(base.ph_canonical_e164, ct_property.canonical_e164, ct_owner.canonical_e164, ct_phone.canonical_e164, sq_id.to_phone_number, sq_property.to_phone_number, sq_owner.to_phone_number, sq_phone.to_phone_number, ts_property.thread_key, ts_owner.thread_key, ts_phone.thread_key, ts_best.thread_key) AS canonical_e164,
    sc.id AS campaign_id,
    COALESCE(ct_property.id, ct_owner.id, ct_phone.id) AS campaign_target_id,
    COALESCE(COALESCE(ct_property.queue_row_id, ct_owner.queue_row_id, ct_phone.queue_row_id)::text, sq_id.id::text, sq_property.id::text, sq_owner.id::text, sq_thread.id::text, sq_phone.id::text) AS queue_row_id,
    COALESCE(me_thread.id::text, me_property.id::text) AS latest_message_event_id,
    COALESCE(ts_property.latest_message_body, ts_owner.latest_message_body, ts_phone.latest_message_body, ts_best.latest_message_body, me_thread.message_body, me_property.message_body) AS latest_message_body,
    COALESCE(ts_property.latest_message_direction, ts_owner.latest_message_direction, ts_phone.latest_message_direction, ts_best.latest_message_direction, me_thread.direction, me_property.direction) AS latest_message_direction,
    COALESCE(ts_property.latest_message_at, ts_owner.latest_message_at, ts_phone.latest_message_at, ts_best.latest_message_at, me_thread.event_at, me_property.event_at) AS latest_message_at,
    COALESCE(ms_thread.last_outbound_at, sq_id.sent_at, sq_property.sent_at, sq_thread.sent_at, sq_owner.sent_at, sq_phone.sent_at) AS last_outbound_at,
    ms_thread.last_inbound_at,
    COALESCE(base.mo_display_name, base.pr_full_name, base.ph_primary_display_name, base.ph_phone_full_name) AS owner_name,
    COALESCE(base.pr_first_name, base.ph_phone_first_name, split_part(COALESCE(base.pr_full_name, base.ph_phone_full_name, base.mo_display_name, ''), ' ', 1), NULL) AS seller_first_name,
    COALESCE(base.property_address_full, base.property_address, COALESCE(ct_property.property_address_full, ct_owner.property_address_full, ct_phone.property_address_full), sq_id.property_address, sq_property.property_address, sq_thread.property_address, sq_owner.property_address, sq_phone.property_address) AS property_address_full,
    COALESCE(base.property_address_city, COALESCE(ct_property.property_address_city, ct_owner.property_address_city, ct_phone.property_address_city), sq_id.property_address_city, sq_property.property_address_city, sq_owner.property_address_city, sq_phone.property_address_city) AS property_address_city,
    COALESCE(base.property_state, base.property_address_state, COALESCE(ct_property.property_address_state, ct_owner.property_address_state, ct_phone.property_address_state), sq_id.property_address_state, sq_property.property_address_state, sq_owner.property_address_state, sq_phone.property_address_state) AS property_state,
    COALESCE(base.property_zip, base.property_address_zip, COALESCE(ct_property.property_address_zip, ct_owner.property_address_zip, ct_phone.property_address_zip), sq_id.property_address_zip, sq_property.property_address_zip, sq_owner.property_address_zip, sq_phone.property_address_zip) AS property_zip,
    COALESCE(base.property_county_name, base.property_address_county_name) AS property_county_name,
    COALESCE(base.market, COALESCE(ct_property.market, ct_owner.market, ct_phone.market), sq_id.market, sq_property.market, sq_thread.market, sq_owner.market, sq_phone.market, base.mo_routing_market, base.pr_primary_market, base.ph_primary_market) AS market,
    base.latitude,
    base.longitude,
    base.property_type,
    base.property_class,
    COALESCE(base.estimated_value, valuation.estimated_value, cash_snapshot.estimated_value, COALESCE(ct_property.estimated_value, ct_owner.estimated_value, ct_phone.estimated_value)) AS estimated_value,
    valuation.estimated_arv,
    base.equity_percent,
    COALESCE(base.cash_offer, valuation.target_offer, cash_snapshot.cash_offer, COALESCE(ct_property.cash_offer, ct_owner.cash_offer, ct_phone.cash_offer)) AS cash_offer,
    COALESCE(valuation.buyer_demand_score, buyer_run.demand_score) AS buyer_demand_score,
    COALESCE(best_buyer.match_score, buyer_run.demand_score) AS buyer_match_score,
    buyer_candidates.buyer_match_count,
    best_buyer.buyer_display_name AS best_buyer_name,
    best_buyer.match_grade AS best_buyer_grade,
    COALESCE(
      NULLIF(COALESCE(ts_property.universal_status, ts_owner.universal_status, ts_phone.universal_status, ts_best.universal_status), ''),
      CASE
        WHEN COALESCE(suppression.is_active, false) OR COALESCE(ts_property.opt_out, ts_owner.opt_out, ts_phone.opt_out, ts_best.opt_out, false) THEN 'suppressed'
        WHEN LOWER(COALESCE(sq_id.queue_status, sq_property.queue_status, sq_thread.queue_status, sq_owner.queue_status, sq_phone.queue_status, '')) IN ('approval', 'queued', 'ready', 'scheduled', 'sending') THEN 'queued'
        WHEN LOWER(COALESCE(ts_property.latest_message_direction, ts_owner.latest_message_direction, ts_phone.latest_message_direction, ts_best.latest_message_direction, me_thread.direction, me_property.direction, '')) LIKE 'in%' THEN 'seller_replied'
        WHEN COALESCE(ts_property.thread_key, ts_owner.thread_key, ts_phone.thread_key, ts_best.thread_key, sq_property.thread_key, sq_owner.thread_key, sq_phone.thread_key, me_property.thread_key) IS NOT NULL THEN 'awaiting_response'
        ELSE 'not_contacted'
      END
    ) AS universal_status,
    COALESCE(
      NULLIF(COALESCE(ts_property.universal_stage, ts_owner.universal_stage, ts_phone.universal_stage, ts_best.universal_stage), ''),
      NULLIF(COALESCE(sq_id.pipeline_stage, sq_property.pipeline_stage, sq_thread.pipeline_stage, sq_owner.pipeline_stage, sq_phone.pipeline_stage), ''),
      NULLIF(COALESCE(sq_id.current_stage, sq_property.current_stage, sq_thread.current_stage, sq_owner.current_stage, sq_phone.current_stage), ''),
      CASE
        WHEN COALESCE(suppression.is_active, false) OR COALESCE(ts_property.opt_out, ts_owner.opt_out, ts_phone.opt_out, ts_best.opt_out, false) THEN 'suppressed'
        WHEN LOWER(COALESCE(ts_property.latest_message_direction, ts_owner.latest_message_direction, ts_phone.latest_message_direction, ts_best.latest_message_direction, me_thread.direction, me_property.direction, '')) LIKE 'in%' THEN 'seller_replied'
        WHEN COALESCE(ts_property.thread_key, ts_owner.thread_key, ts_phone.thread_key, ts_best.thread_key, sq_property.thread_key, sq_owner.thread_key, sq_phone.thread_key, me_property.thread_key) IS NOT NULL THEN 'awaiting_response'
        ELSE 'not_contacted'
      END
    ) AS universal_stage,
    COALESCE(
      NULLIF(COALESCE(ts_property.inbox_bucket, ts_owner.inbox_bucket, ts_phone.inbox_bucket, ts_best.inbox_bucket), ''),
      CASE
        WHEN COALESCE(suppression.is_active, false) OR COALESCE(ts_property.opt_out, ts_owner.opt_out, ts_phone.opt_out, ts_best.opt_out, false) THEN 'suppressed'
        WHEN COALESCE(ts_property.needs_review, ts_owner.needs_review, ts_phone.needs_review, ts_best.needs_review, false) THEN 'needs_review'
        WHEN LOWER(COALESCE(ts_property.latest_message_direction, ts_owner.latest_message_direction, ts_phone.latest_message_direction, ts_best.latest_message_direction, me_thread.direction, me_property.direction, '')) LIKE 'in%' THEN 'new_replies'
        WHEN COALESCE(ts_property.thread_key, ts_owner.thread_key, ts_phone.thread_key, ts_best.thread_key, sq_property.thread_key, sq_owner.thread_key, sq_phone.thread_key, me_property.thread_key) IS NOT NULL THEN 'cold'
        ELSE 'cold'
      END
    ) AS inbox_bucket,
    COALESCE(sq_id.queue_status, sq_property.queue_status, sq_thread.queue_status, sq_owner.queue_status, sq_phone.queue_status) AS queue_status,
    COALESCE(sq_id.scheduled_for_utc, sq_id.scheduled_for, sq_property.scheduled_for_utc, sq_property.scheduled_for, sq_thread.scheduled_for_utc, sq_thread.scheduled_for, sq_owner.scheduled_for_utc, sq_owner.scheduled_for, sq_phone.scheduled_for_utc, sq_phone.scheduled_for, COALESCE(ct_property.scheduled_for, ct_owner.scheduled_for, ct_phone.scheduled_for)) AS queue_scheduled_for,
    sc.campaign_name,
    sc.status AS campaign_status,
    COALESCE(ct_property.target_status, ct_owner.target_status, ct_phone.target_status) AS campaign_target_status,
    CASE
      WHEN COALESCE(suppression.is_active, false) OR COALESCE(ts_property.opt_out, ts_owner.opt_out, ts_phone.opt_out, ts_best.opt_out, false) THEN 'suppressed'
      ELSE NULL
    END AS suppression_status,
    COALESCE(suppression.suppression_type, suppression.suppression_reason) AS suppression_type,
    COALESCE(base.final_acquisition_score, COALESCE(ct_property.final_acquisition_score, ct_owner.final_acquisition_score, ct_phone.final_acquisition_score), cash_snapshot.confidence_score) AS final_acquisition_score,
    COALESCE(base.structured_motivation_score, base.mo_priority_score, base.pr_master_owner_priority_score) AS priority_score,
    COALESCE(ts_property.opt_out, ts_owner.opt_out, ts_phone.opt_out, ts_best.opt_out, false) OR COALESCE(suppression.is_active, false) AS opt_out,
    COALESCE(ts_property.wrong_number, ts_owner.wrong_number, ts_phone.wrong_number, ts_best.wrong_number, false) AS wrong_number,
    COALESCE(ts_property.not_interested, ts_owner.not_interested, ts_phone.not_interested, ts_best.not_interested, false) AS not_interested,
    COALESCE(ts_property.needs_review, ts_owner.needs_review, ts_phone.needs_review, ts_best.needs_review, false) AS needs_review,
    base.property_json AS property_data,
    base.mo_json AS master_owner_data,
    base.pr_json AS prospect_data,
    base.ph_json AS phone_data,
    base.em_json AS email_data,
    CASE
      WHEN ts_property.thread_key IS NOT NULL THEN to_jsonb(ts_property)
      WHEN ts_owner.thread_key IS NOT NULL THEN to_jsonb(ts_owner)
      WHEN ts_phone.thread_key IS NOT NULL THEN to_jsonb(ts_phone)
      WHEN ts_best.thread_key IS NOT NULL THEN to_jsonb(ts_best)
      ELSE NULL
    END AS thread_state_data,
    CASE
      WHEN COALESCE(ct_property.id, ct_owner.id, ct_phone.id) IS NOT NULL OR sc.id IS NOT NULL THEN
        jsonb_strip_nulls(
          jsonb_build_object(
            'campaign_target',
            CASE
              WHEN ct_property.id IS NOT NULL THEN to_jsonb(ct_property)
              WHEN ct_owner.id IS NOT NULL THEN to_jsonb(ct_owner)
              WHEN ct_phone.id IS NOT NULL THEN to_jsonb(ct_phone)
              ELSE NULL
            END,
            'campaign', to_jsonb(sc)
          )
        )
      ELSE NULL
    END AS campaign_data,
    CASE
      WHEN sq_id.id IS NOT NULL THEN to_jsonb(sq_id)
      WHEN sq_property.id IS NOT NULL THEN to_jsonb(sq_property)
      WHEN sq_thread.id IS NOT NULL THEN to_jsonb(sq_thread)
      WHEN sq_owner.id IS NOT NULL THEN to_jsonb(sq_owner)
      WHEN sq_phone.id IS NOT NULL THEN to_jsonb(sq_phone)
      ELSE NULL
    END AS queue_data,
    to_jsonb(suppression) AS suppression_data,
    CASE
      WHEN valuation.property_id IS NOT NULL OR cash_snapshot.property_id IS NOT NULL OR comp_summary.property_id IS NOT NULL THEN
        jsonb_strip_nulls(
          jsonb_build_object(
            'property_valuation_snapshot', to_jsonb(valuation),
            'property_cash_offer_snapshot', to_jsonb(cash_snapshot),
            'recent_comp_summary',
            CASE
              WHEN comp_summary.property_id IS NOT NULL THEN
                jsonb_strip_nulls(
                  jsonb_build_object(
                    'comp_count', comp_summary.comp_count,
                    'avg_price_off_value', comp_summary.avg_price_off_value,
                    'max_comp_confidence_score', comp_summary.max_comp_confidence_score,
                    'sample', COALESCE(comp_summary.comp_sample, '[]'::jsonb)
                  )
                )
              ELSE NULL
            END
          )
        )
      ELSE NULL
    END AS valuation_data,
    CASE
      WHEN buyer_run.property_id IS NOT NULL OR buyer_candidates.property_id IS NOT NULL THEN
        jsonb_strip_nulls(
          jsonb_build_object(
            'buyer_match_run', to_jsonb(buyer_run),
            'best_candidate', to_jsonb(best_buyer),
            'top_candidates', COALESCE(buyer_candidates.top_candidates, '[]'::jsonb)
          )
        )
      ELSE NULL
    END AS buyer_match_data,
    CASE
      WHEN me_thread.id IS NOT NULL THEN to_jsonb(me_thread)
      WHEN me_property.id IS NOT NULL THEN to_jsonb(me_property)
      ELSE NULL
    END AS latest_message_event_data,
    now() AS created_at,
    GREATEST(
      COALESCE(base.updated_at, base.created_at, now()),
      COALESCE(base.mo_updated_at, base.mo_created_at, now()),
      COALESCE(base.pr_updated_at, base.pr_created_at, now()),
      COALESCE(base.ph_updated_at, base.ph_created_at, now()),
      COALESCE(base.em_updated_at, base.em_created_at, now()),
      COALESCE(ts_property.updated_at, ts_property.created_at, ts_owner.updated_at, ts_owner.created_at, ts_phone.updated_at, ts_phone.created_at, ts_best.updated_at, ts_best.created_at, now()),
      COALESCE(sc.created_at, now()),
      COALESCE(ct_property.updated_at, ct_property.created_at, ct_owner.updated_at, ct_owner.created_at, ct_phone.updated_at, ct_phone.created_at, now()),
      COALESCE(sq_id.updated_at, sq_id.created_at, sq_property.updated_at, sq_property.created_at, sq_thread.updated_at, sq_thread.created_at, sq_owner.updated_at, sq_owner.created_at, sq_phone.updated_at, sq_phone.created_at, now()),
      COALESCE(suppression.suppressed_at, suppression.created_at, now()),
      COALESCE(valuation.updated_at, valuation.created_at, now()),
      COALESCE(cash_snapshot.updated_at, cash_snapshot.created_at, now()),
      COALESCE(buyer_run.updated_at, buyer_run.created_at, now()),
      COALESCE(best_buyer.updated_at, best_buyer.created_at, now()),
      COALESCE(me_thread.event_at, me_thread.created_at, me_property.event_at, me_property.created_at, now())
    ) AS updated_at
  FROM property_base base
  LEFT JOIN thread_by_property ts_property
    ON ts_property.property_id = base.property_id
  LEFT JOIN thread_by_owner ts_owner
    ON ts_owner.master_owner_id = base.mo_master_owner_id
  LEFT JOIN thread_by_thread_key ts_phone
    ON ts_phone.thread_key = base.ph_canonical_e164
  LEFT JOIN thread_by_best_phone ts_best
    ON ts_best.best_phone = base.ph_canonical_e164
  LEFT JOIN message_by_thread me_thread
    ON me_thread.thread_key = COALESCE(ts_property.thread_key, ts_owner.thread_key, ts_phone.thread_key, ts_best.thread_key)
  LEFT JOIN message_by_property me_property
    ON me_property.property_id = base.property_id
  LEFT JOIN message_stats_by_thread ms_thread
    ON ms_thread.thread_key = COALESCE(ts_property.thread_key, ts_owner.thread_key, ts_phone.thread_key, ts_best.thread_key)
  LEFT JOIN target_by_property ct_property
    ON ct_property.property_id = base.property_id
  LEFT JOIN target_by_owner ct_owner
    ON ct_owner.master_owner_id = base.mo_master_owner_id
  LEFT JOIN target_by_phone ct_phone
    ON ct_phone.canonical_e164 = base.ph_canonical_e164
  LEFT JOIN public.sms_campaigns sc
    ON sc.id = COALESCE(ct_property.campaign_id, ct_owner.campaign_id, ct_phone.campaign_id)
  LEFT JOIN public.send_queue sq_id
    ON sq_id.id = COALESCE(ct_property.queue_row_id, ct_owner.queue_row_id, ct_phone.queue_row_id)
  LEFT JOIN queue_by_property sq_property
    ON sq_property.property_id = base.property_id
  LEFT JOIN queue_by_thread sq_thread
    ON sq_thread.thread_key = COALESCE(ts_property.thread_key, ts_owner.thread_key, ts_phone.thread_key, ts_best.thread_key)
  LEFT JOIN queue_by_owner sq_owner
    ON sq_owner.master_owner_id = base.mo_master_owner_id
  LEFT JOIN queue_by_phone sq_phone
    ON sq_phone.to_phone_number = base.ph_canonical_e164
  LEFT JOIN suppression_by_phone suppression
    ON COALESCE(suppression.phone_e164, suppression.phone_number) = COALESCE(base.ph_canonical_e164, ct_property.canonical_e164, ct_owner.canonical_e164, ct_phone.canonical_e164, sq_id.to_phone_number, sq_property.to_phone_number, sq_thread.to_phone_number, sq_owner.to_phone_number, sq_phone.to_phone_number, ts_property.thread_key, ts_owner.thread_key, ts_phone.thread_key, ts_best.thread_key)
  LEFT JOIN valuation_by_property valuation
    ON valuation.property_id = base.property_id
  LEFT JOIN cash_snapshot_by_property cash_snapshot
    ON cash_snapshot.property_id = base.property_id
  LEFT JOIN comp_summary_by_property comp_summary
    ON comp_summary.property_id = base.property_id
  LEFT JOIN buyer_run_by_property buyer_run
    ON buyer_run.property_id = base.property_id
  LEFT JOIN best_buyer_by_property best_buyer
    ON best_buyer.property_id = base.property_id
  LEFT JOIN buyer_candidates_by_property buyer_candidates
    ON buyer_candidates.property_id = base.property_id;

    v_batch_start := v_batch_end + 1;
  END LOOP;

  INSERT INTO public.deal_context_index (
    deal_context_id,
    context_type,
    property_id,
    master_owner_id,
    prospect_id,
    canonical_prospect_id,
    phone_id,
    email_id,
    thread_key,
    canonical_e164,
    campaign_id,
    campaign_target_id,
    queue_row_id,
    latest_message_event_id,
    latest_message_body,
    latest_message_direction,
    latest_message_at,
    last_outbound_at,
    last_inbound_at,
    owner_name,
    seller_first_name,
    property_address_full,
    property_address_city,
    property_state,
    property_zip,
    property_county_name,
    market,
    latitude,
    longitude,
    property_type,
    property_class,
    estimated_value,
    estimated_arv,
    equity_percent,
    cash_offer,
    buyer_demand_score,
    buyer_match_score,
    buyer_match_count,
    best_buyer_name,
    best_buyer_grade,
    universal_status,
    universal_stage,
    inbox_bucket,
    queue_status,
    queue_scheduled_for,
    campaign_name,
    campaign_status,
    campaign_target_status,
    suppression_status,
    suppression_type,
    final_acquisition_score,
    priority_score,
    opt_out,
    wrong_number,
    not_interested,
    needs_review,
    property_data,
    master_owner_data,
    prospect_data,
    phone_data,
    email_data,
    thread_state_data,
    campaign_data,
    queue_data,
    suppression_data,
    valuation_data,
    buyer_match_data,
    latest_message_event_data,
    created_at,
    updated_at
  )
  SELECT
    'thread:' || ts.thread_key AS deal_context_id,
    'unlinked_thread'::text AS context_type,
    NULL::text AS property_id,
    COALESCE(mo.master_owner_id, ts.master_owner_id) AS master_owner_id,
    pr.prospect_id,
    COALESCE(pr.canonical_prospect_id, ph.canonical_prospect_id) AS canonical_prospect_id,
    ph.phone_id,
    em.email_id,
    ts.thread_key,
    COALESCE(ph.canonical_e164, sq.to_phone_number, ts.thread_key) AS canonical_e164,
    sc.id AS campaign_id,
    ct.id AS campaign_target_id,
    COALESCE(ct.queue_row_id::text, sq.id::text) AS queue_row_id,
    me.id::text AS latest_message_event_id,
    COALESCE(ts.latest_message_body, me.message_body) AS latest_message_body,
    COALESCE(ts.latest_message_direction, me.direction) AS latest_message_direction,
    COALESCE(ts.latest_message_at, me.event_at) AS latest_message_at,
    message_stats.last_outbound_at,
    message_stats.last_inbound_at,
    COALESCE(mo.display_name, pr.full_name, ph.primary_display_name, ph.phone_full_name) AS owner_name,
    COALESCE(
      pr.first_name,
      ph.phone_first_name,
      split_part(COALESCE(pr.full_name, ph.phone_full_name, mo.display_name, ''), ' ', 1),
      NULL
    ) AS seller_first_name,
    COALESCE(sq.property_address, ct.property_address_full) AS property_address_full,
    COALESCE(ct.property_address_city, sq.property_address_city) AS property_address_city,
    COALESCE(ct.property_address_state, sq.property_address_state) AS property_state,
    COALESCE(ct.property_address_zip, sq.property_address_zip) AS property_zip,
    NULL::text AS property_county_name,
    COALESCE(ct.market, sq.market, mo.routing_market, pr.primary_market, ph.primary_market) AS market,
    NULL::numeric AS latitude,
    NULL::numeric AS longitude,
    NULL::text AS property_type,
    NULL::text AS property_class,
    COALESCE(ct.estimated_value, valuation.estimated_value, cash_snapshot.estimated_value) AS estimated_value,
    valuation.estimated_arv,
    NULL::numeric AS equity_percent,
    COALESCE(valuation.target_offer, cash_snapshot.cash_offer, ct.cash_offer) AS cash_offer,
    COALESCE(valuation.buyer_demand_score, buyer_run.demand_score) AS buyer_demand_score,
    COALESCE(best_buyer.match_score, buyer_run.demand_score) AS buyer_match_score,
    buyer_candidates.buyer_match_count,
    best_buyer.buyer_display_name AS best_buyer_name,
    best_buyer.match_grade AS best_buyer_grade,
    COALESCE(
      NULLIF(ts.universal_status, ''),
      CASE
        WHEN COALESCE(suppression.is_active, false) OR COALESCE(ts.opt_out, false) THEN 'suppressed'
        WHEN LOWER(COALESCE(sq.queue_status, '')) IN ('approval', 'queued', 'ready', 'scheduled', 'sending') THEN 'queued'
        WHEN LOWER(COALESCE(ts.latest_message_direction, me.direction, '')) LIKE 'in%' THEN 'seller_replied'
        ELSE 'awaiting_response'
      END
    ) AS universal_status,
    COALESCE(
      NULLIF(ts.universal_stage, ''),
      NULLIF(sq.pipeline_stage, ''),
      NULLIF(sq.current_stage, ''),
      CASE
        WHEN COALESCE(suppression.is_active, false) OR COALESCE(ts.opt_out, false) THEN 'suppressed'
        WHEN LOWER(COALESCE(ts.latest_message_direction, me.direction, '')) LIKE 'in%' THEN 'seller_replied'
        ELSE 'awaiting_response'
      END
    ) AS universal_stage,
    COALESCE(
      NULLIF(ts.inbox_bucket, ''),
      CASE
        WHEN COALESCE(suppression.is_active, false) OR COALESCE(ts.opt_out, false) THEN 'suppressed'
        WHEN COALESCE(ts.needs_review, false) THEN 'needs_review'
        WHEN LOWER(COALESCE(ts.latest_message_direction, me.direction, '')) LIKE 'in%' THEN 'new_replies'
        ELSE 'unlinked'
      END
    ) AS inbox_bucket,
    sq.queue_status,
    COALESCE(sq.scheduled_for_utc, sq.scheduled_for, ct.scheduled_for) AS queue_scheduled_for,
    sc.campaign_name,
    sc.status AS campaign_status,
    ct.target_status AS campaign_target_status,
    CASE
      WHEN COALESCE(suppression.is_active, false) OR COALESCE(ts.opt_out, false) THEN 'suppressed'
      ELSE NULL
    END AS suppression_status,
    COALESCE(suppression.suppression_type, suppression.suppression_reason) AS suppression_type,
    ct.final_acquisition_score AS final_acquisition_score,
    COALESCE(mo.priority_score, pr.master_owner_priority_score) AS priority_score,
    COALESCE(ts.opt_out, false) OR COALESCE(suppression.is_active, false) AS opt_out,
    COALESCE(ts.wrong_number, false) AS wrong_number,
    COALESCE(ts.not_interested, false) AS not_interested,
    COALESCE(ts.needs_review, false) AS needs_review,
    NULL::jsonb AS property_data,
    to_jsonb(mo) AS master_owner_data,
    to_jsonb(pr) AS prospect_data,
    to_jsonb(ph) AS phone_data,
    to_jsonb(em) AS email_data,
    to_jsonb(ts) AS thread_state_data,
    CASE
      WHEN ct.id IS NOT NULL OR sc.id IS NOT NULL THEN
        jsonb_strip_nulls(
          jsonb_build_object(
            'campaign_target', to_jsonb(ct),
            'campaign', to_jsonb(sc)
          )
        )
      ELSE NULL
    END AS campaign_data,
    to_jsonb(sq) AS queue_data,
    to_jsonb(suppression) AS suppression_data,
    CASE
      WHEN valuation.property_id IS NOT NULL
        OR cash_snapshot.property_id IS NOT NULL
        OR comp_summary.property_id IS NOT NULL THEN
        jsonb_strip_nulls(
          jsonb_build_object(
            'property_valuation_snapshot', to_jsonb(valuation),
            'property_cash_offer_snapshot', to_jsonb(cash_snapshot),
            'recent_comp_summary',
            CASE
              WHEN comp_summary.property_id IS NOT NULL THEN
                jsonb_strip_nulls(
                  jsonb_build_object(
                    'comp_count', comp_summary.comp_count,
                    'avg_price_off_value', comp_summary.avg_price_off_value,
                    'max_comp_confidence_score', comp_summary.max_comp_confidence_score,
                    'sample', COALESCE(comp_summary.comp_sample, '[]'::jsonb)
                  )
                )
              ELSE NULL
            END
          )
        )
      ELSE NULL
    END AS valuation_data,
    CASE
      WHEN buyer_run.buyer_match_run_id IS NOT NULL
        OR buyer_candidates.buyer_match_count IS NOT NULL THEN
        jsonb_strip_nulls(
          jsonb_build_object(
            'buyer_match_run', to_jsonb(buyer_run),
            'best_candidate', to_jsonb(best_buyer),
            'top_candidates', COALESCE(buyer_candidates.top_candidates, '[]'::jsonb)
          )
        )
      ELSE NULL
    END AS buyer_match_data,
    to_jsonb(me) AS latest_message_event_data,
    now() AS created_at,
    GREATEST(
      COALESCE(mo.updated_at, mo.created_at, now()),
      COALESCE(pr.updated_at, pr.created_at, now()),
      COALESCE(ph.updated_at, ph.created_at, now()),
      COALESCE(em.updated_at, em.created_at, now()),
      COALESCE(ts.updated_at, ts.created_at, now()),
      COALESCE(sc.created_at, now()),
      COALESCE(ct.updated_at, ct.created_at, now()),
      COALESCE(sq.updated_at, sq.created_at, now()),
      COALESCE(suppression.suppressed_at, suppression.created_at, now()),
      COALESCE(valuation.updated_at, valuation.created_at, now()),
      COALESCE(cash_snapshot.updated_at, cash_snapshot.created_at, now()),
      COALESCE(buyer_run.updated_at, buyer_run.created_at, now()),
      COALESCE(best_buyer.updated_at, best_buyer.created_at, now()),
      COALESCE(me.event_at, me.created_at, now())
    ) AS updated_at
  FROM public.deal_thread_state ts
  LEFT JOIN public.properties p_existing
    ON p_existing.property_id = ts.property_id
  LEFT JOIN public.master_owners mo
    ON mo.master_owner_id = ts.master_owner_id
  LEFT JOIN LATERAL (
    SELECT ph.*
    FROM public.phones ph
    WHERE (ts.thread_key IS NOT NULL AND ph.canonical_e164 = ts.thread_key)
      OR (ts.best_phone IS NOT NULL AND ph.canonical_e164 = ts.best_phone)
      OR (ts.master_owner_id IS NOT NULL AND ph.master_owner_id = ts.master_owner_id)
    ORDER BY
      CASE
        WHEN ts.thread_key IS NOT NULL AND ph.canonical_e164 = ts.thread_key THEN 1
        WHEN ts.best_phone IS NOT NULL AND ph.canonical_e164 = ts.best_phone THEN 2
        WHEN ts.master_owner_id IS NOT NULL
          AND ph.master_owner_id = ts.master_owner_id
          AND COALESCE(ph.is_best_phone_for_owner, false) THEN 3
        ELSE 4
      END,
      COALESCE(ph.is_best_phone_for_slot, false) DESC,
      ph.best_phone_score DESC NULLS LAST,
      COALESCE(ph.updated_at, ph.created_at) DESC NULLS LAST
    LIMIT 1
  ) ph ON true
  LEFT JOIN LATERAL (
    SELECT pr.*
    FROM public.prospects pr
    WHERE (ph.canonical_prospect_id IS NOT NULL AND pr.canonical_prospect_id = ph.canonical_prospect_id)
      OR (ts.master_owner_id IS NOT NULL AND pr.master_owner_id = ts.master_owner_id)
      OR (ph.primary_prospect_id IS NOT NULL AND pr.prospect_id = ph.primary_prospect_id)
    ORDER BY
      CASE
        WHEN ph.canonical_prospect_id IS NOT NULL AND pr.canonical_prospect_id = ph.canonical_prospect_id THEN 1
        WHEN ph.primary_prospect_id IS NOT NULL AND pr.prospect_id = ph.primary_prospect_id THEN 2
        WHEN COALESCE(pr.is_primary_prospect, false) THEN 3
        ELSE 4
      END,
      pr.rank_position NULLS LAST,
      COALESCE(pr.updated_at, pr.created_at) DESC NULLS LAST
    LIMIT 1
  ) pr ON true
  LEFT JOIN LATERAL (
    SELECT em.*
    FROM public.emails em
    WHERE (mo.primary_email_id IS NOT NULL AND em.email_id = mo.primary_email_id)
      OR (pr.best_email IS NOT NULL AND (em.email_normalized = pr.best_email OR em.email = pr.best_email))
      OR (ts.master_owner_id IS NOT NULL AND em.master_owner_id = ts.master_owner_id)
      OR (pr.canonical_prospect_id IS NOT NULL AND em.canonical_prospect_id = pr.canonical_prospect_id)
    ORDER BY
      CASE
        WHEN mo.primary_email_id IS NOT NULL AND em.email_id = mo.primary_email_id THEN 1
        WHEN pr.best_email IS NOT NULL AND (em.email_normalized = pr.best_email OR em.email = pr.best_email) THEN 2
        WHEN ts.master_owner_id IS NOT NULL
          AND em.master_owner_id = ts.master_owner_id
          AND COALESCE(em.is_best_email_for_owner, false) THEN 3
        ELSE 4
      END,
      COALESCE(em.is_best_email_for_slot, false) DESC,
      em.email_score_final DESC NULLS LAST,
      COALESCE(em.updated_at, em.created_at) DESC NULLS LAST
    LIMIT 1
  ) em ON true
  LEFT JOIN LATERAL (
    SELECT
      me.*,
      COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at) AS event_at
    FROM public.message_events me
    WHERE (ts.thread_key IS NOT NULL AND me.thread_key = ts.thread_key)
      OR (ts.master_owner_id IS NOT NULL AND me.master_owner_id = ts.master_owner_id)
      OR (ph.canonical_e164 IS NOT NULL AND (me.to_phone_number = ph.canonical_e164 OR me.from_phone_number = ph.canonical_e164))
    ORDER BY
      CASE
        WHEN ts.thread_key IS NOT NULL AND me.thread_key = ts.thread_key THEN 1
        WHEN ts.master_owner_id IS NOT NULL AND me.master_owner_id = ts.master_owner_id THEN 2
        WHEN ph.canonical_e164 IS NOT NULL AND (me.to_phone_number = ph.canonical_e164 OR me.from_phone_number = ph.canonical_e164) THEN 3
        ELSE 4
      END,
      COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at) DESC NULLS LAST,
      me.created_at DESC NULLS LAST
    LIMIT 1
  ) me ON true
  LEFT JOIN LATERAL (
    SELECT
      MAX(
        CASE
          WHEN LOWER(COALESCE(me.direction, '')) LIKE 'in%' THEN COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at)
          ELSE NULL
        END
      ) AS last_inbound_at,
      MAX(
        CASE
          WHEN LOWER(COALESCE(me.direction, '')) LIKE 'out%' THEN COALESCE(me.event_timestamp, me.received_at, me.sent_at, me.created_at)
          ELSE NULL
        END
      ) AS last_outbound_at
    FROM public.message_events me
    WHERE (ts.thread_key IS NOT NULL AND me.thread_key = ts.thread_key)
      OR (ts.master_owner_id IS NOT NULL AND me.master_owner_id = ts.master_owner_id)
      OR (ph.canonical_e164 IS NOT NULL AND (me.to_phone_number = ph.canonical_e164 OR me.from_phone_number = ph.canonical_e164))
  ) message_stats ON true
  LEFT JOIN LATERAL (
    SELECT ct.*
    FROM public.sms_campaign_targets ct
    WHERE (ph.canonical_e164 IS NOT NULL AND ct.canonical_e164 = ph.canonical_e164)
      OR (ts.master_owner_id IS NOT NULL AND ct.master_owner_id = ts.master_owner_id)
    ORDER BY
      CASE
        WHEN ph.canonical_e164 IS NOT NULL AND ct.canonical_e164 = ph.canonical_e164 THEN 1
        WHEN ts.master_owner_id IS NOT NULL AND ct.master_owner_id = ts.master_owner_id THEN 2
        ELSE 3
      END,
      COALESCE(ct.updated_at, ct.replied_at, ct.sent_at, ct.delivered_at, ct.queued_at, ct.created_at) DESC NULLS LAST
    LIMIT 1
  ) ct ON true
  LEFT JOIN public.sms_campaigns sc
    ON sc.id = ct.campaign_id
  LEFT JOIN LATERAL (
    SELECT sq.*
    FROM public.send_queue sq
    WHERE (ct.queue_row_id IS NOT NULL AND sq.id = ct.queue_row_id)
      OR (ts.thread_key IS NOT NULL AND sq.thread_key = ts.thread_key)
      OR (ts.master_owner_id IS NOT NULL AND sq.master_owner_id = ts.master_owner_id)
      OR (ph.canonical_e164 IS NOT NULL AND sq.to_phone_number = ph.canonical_e164)
    ORDER BY
      CASE
        WHEN ct.queue_row_id IS NOT NULL AND sq.id = ct.queue_row_id THEN 1
        WHEN ts.thread_key IS NOT NULL AND sq.thread_key = ts.thread_key THEN 2
        WHEN ts.master_owner_id IS NOT NULL AND sq.master_owner_id = ts.master_owner_id THEN 3
        WHEN ph.canonical_e164 IS NOT NULL AND sq.to_phone_number = ph.canonical_e164 THEN 4
        ELSE 5
      END,
      COALESCE(sq.updated_at, sq.sent_at, sq.delivered_at, sq.scheduled_for_utc, sq.scheduled_for, sq.created_at) DESC NULLS LAST
    LIMIT 1
  ) sq ON true
  LEFT JOIN LATERAL (
    SELECT sl.*
    FROM public.sms_suppression_list sl
    WHERE COALESCE(sl.phone_e164, sl.phone_number) = COALESCE(ph.canonical_e164, sq.to_phone_number, ts.thread_key)
    ORDER BY COALESCE(sl.suppressed_at, sl.created_at) DESC NULLS LAST
    LIMIT 1
  ) suppression ON true
  LEFT JOIN LATERAL (
    SELECT v.*
    FROM public.property_valuation_snapshots v
    WHERE v.property_id = ct.property_id
    ORDER BY COALESCE(v.updated_at, v.created_at) DESC NULLS LAST
    LIMIT 1
  ) valuation ON true
  LEFT JOIN LATERAL (
    SELECT c.*
    FROM public.property_cash_offer_snapshots c
    WHERE c.property_id = ct.property_id
    ORDER BY COALESCE(c.updated_at, c.created_at) DESC NULLS LAST
    LIMIT 1
  ) cash_snapshot ON true
  LEFT JOIN comp_summary_by_property comp_summary
    ON comp_summary.property_id = ct.property_id
  LEFT JOIN LATERAL (
    SELECT br.*
    FROM public.buyer_match_runs br
    WHERE br.property_id = ct.property_id
    ORDER BY COALESCE(br.updated_at, br.created_at) DESC NULLS LAST
    LIMIT 1
  ) buyer_run ON true
  LEFT JOIN LATERAL (
    SELECT candidate.*
    FROM public.buyer_match_candidates candidate
    WHERE (
      buyer_run.buyer_match_run_id IS NOT NULL
      AND candidate.buyer_match_run_id = buyer_run.buyer_match_run_id
    ) OR (
      buyer_run.buyer_match_run_id IS NULL
      AND ct.property_id IS NOT NULL
      AND candidate.property_id = ct.property_id
    )
    ORDER BY candidate.match_score DESC NULLS LAST, COALESCE(candidate.updated_at, candidate.created_at) DESC NULLS LAST
    LIMIT 1
  ) best_buyer ON true
  LEFT JOIN LATERAL (
    SELECT
      COUNT(*)::integer AS buyer_match_count,
      jsonb_agg(to_jsonb(candidate) ORDER BY candidate.match_score DESC NULLS LAST, COALESCE(candidate.updated_at, candidate.created_at) DESC NULLS LAST) AS top_candidates
    FROM (
      SELECT candidate.*
      FROM public.buyer_match_candidates candidate
      WHERE (
        buyer_run.buyer_match_run_id IS NOT NULL
        AND candidate.buyer_match_run_id = buyer_run.buyer_match_run_id
      ) OR (
        buyer_run.buyer_match_run_id IS NULL
        AND ct.property_id IS NOT NULL
        AND candidate.property_id = ct.property_id
      )
      ORDER BY candidate.match_score DESC NULLS LAST, COALESCE(candidate.updated_at, candidate.created_at) DESC NULLS LAST
      LIMIT 5
    ) candidate
  ) buyer_candidates ON true
  WHERE p_existing.property_id IS NULL
    AND ts.thread_key IS NOT NULL;

  SELECT COUNT(*)::integer
  INTO v_count
  FROM public.deal_context_index;

  RETURN v_count;
END;
$$;


--
-- Name: reset_textgrid_daily_usage(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."reset_textgrid_daily_usage"() RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    reset_count INT;
BEGIN
    UPDATE textgrid_numbers
    SET messages_sent_today = 0,
        updated_at = NOW()
    WHERE messages_sent_today > 0;
    
    GET DIAGNOSTICS reset_count = ROW_COUNT;
    
    RETURN reset_count;
END;
$$;


--
-- Name: resolve_thread_key("text", "text", "text", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."resolve_thread_key"("p_existing_thread_key" "text" DEFAULT NULL::"text", "p_property_id" "text" DEFAULT NULL::"text", "p_master_owner_id" "text" DEFAULT NULL::"text", "p_prospect_id" "text" DEFAULT NULL::"text", "p_seller_phone" "text" DEFAULT NULL::"text", "p_our_phone" "text" DEFAULT NULL::"text", "p_provider_message_sid" "text" DEFAULT NULL::"text") RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_phone_a text;
  v_phone_b text;
  v_phones text;
BEGIN
  -- 1. existing thread_key
  IF p_existing_thread_key IS NOT NULL AND p_existing_thread_key <> '' THEN
    RETURN p_existing_thread_key;
  END IF;

  -- Normalize phones
  v_phone_a := public.normalize_phone(p_seller_phone);
  v_phone_b := public.normalize_phone(p_our_phone);
  
  -- Sort phones to ensure consistency
  IF v_phone_a IS NOT NULL AND v_phone_b IS NOT NULL THEN
    IF v_phone_a > v_phone_b THEN
      v_phones := v_phone_b || ':' || v_phone_a;
    ELSE
      v_phones := v_phone_a || ':' || v_phone_b;
    END IF;
  ELSE
    v_phones := COALESCE(v_phone_a, v_phone_b, p_provider_message_sid);
  END IF;

  -- Priority: property_id + phones, then master_owner_id + phones, then just phones
  RETURN COALESCE(p_property_id, p_master_owner_id, 'unknown') || ':' || COALESCE(v_phones, 'orphan');
END;
$$;


--
-- Name: safe_divide(numeric, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."safe_divide"("n" numeric, "d" numeric) RETURNS numeric
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select case when d is null or d = 0 then null else n / d end;
$$;


--
-- Name: select_available_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."select_available_number"() RETURNS TABLE("number_id" "uuid", "phone_number" "text", "messages_sent_today" integer)
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    tn.id,
    tn.phone_number,
    tn.messages_sent_today
  FROM textgrid_numbers tn
  WHERE tn.status = 'active'
    AND tn.messages_sent_today < tn.daily_limit
  ORDER BY 
    tn.messages_sent_today ASC,
    tn.last_used_at ASC NULLS FIRST
  LIMIT 1
  FOR UPDATE SKIP LOCKED;
END;
$$;


