--
-- Name: unlock_stale_jobs(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."unlock_stale_jobs"("stale_minutes" integer DEFAULT 10) RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    unlocked_count INT;
BEGIN
    UPDATE send_queue
    SET is_locked = false,
        locked_at = NULL,
        lock_token = NULL,
        queue_status = 'queued',
        updated_at = NOW()
    WHERE is_locked = true
      AND locked_at < NOW() - (stale_minutes || ' minutes')::INTERVAL;
    
    GET DIAGNOSTICS unlocked_count = ROW_COUNT;
    RETURN unlocked_count;
END;
$$;


--
-- Name: update_conversation_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."update_conversation_stats"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    IF NEW.direction = 'outbound' THEN
        UPDATE conversations
        SET messages_sent = messages_sent + 1,
            last_outbound_at = NEW.created_at,
            last_message_at = NEW.created_at
        WHERE id = NEW.conversation_id;
    ELSE
        UPDATE conversations
        SET messages_received = messages_received + 1,
            last_inbound_at = NEW.created_at,
            last_message_at = NEW.created_at
        WHERE id = NEW.conversation_id;
    END IF;
    
    RETURN NEW;
END;
$$;


