--
-- Name: agent_performance_kpis_v; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."agent_performance_kpis_v" AS
 WITH "enriched_messages" AS (
         SELECT "m"."id" AS "message_event_id",
            "m"."thread_key",
            "m"."direction",
            COALESCE("m"."event_timestamp", "m"."created_at") AS "event_timestamp",
            "m"."detected_intent",
            "m"."is_opt_out",
            "m"."current_stage",
                CASE
                    WHEN ("m"."direction" = 'outbound'::"text") THEN COALESCE(NULLIF("m"."sms_agent_id", ''::"text"), NULLIF(("m"."metadata" ->> 'sms_agent_id'::"text"), ''::"text"), NULLIF("q"."sms_agent_id", ''::"text"), NULLIF("q"."selected_agent_id", ''::"text"), NULLIF(("q"."metadata" ->> 'sms_agent_id'::"text"), ''::"text"), NULLIF(("t"."metadata" ->> 'agent_style_fit'::"text"), ''::"text"), NULLIF("t"."agent_persona", ''::"text"), 'unknown'::"text")
                    ELSE NULL::"text"
                END AS "out_agent_id",
                CASE
                    WHEN ("m"."direction" = 'outbound'::"text") THEN COALESCE(NULLIF("t"."agent_persona", ''::"text"), 'unknown'::"text")
                    ELSE NULL::"text"
                END AS "out_persona",
                CASE
                    WHEN ("m"."direction" = 'outbound'::"text") THEN COALESCE(NULLIF(("t"."metadata" ->> 'agent_tone'::"text"), ''::"text"), 'neutral'::"text")
                    ELSE NULL::"text"
                END AS "out_tone",
                CASE
                    WHEN ("m"."direction" = 'outbound'::"text") THEN COALESCE(NULLIF("m"."language", ''::"text"), NULLIF("q"."language", ''::"text"), NULLIF("t"."language", ''::"text"), 'english'::"text")
                    ELSE NULL::"text"
                END AS "out_language",
                CASE
                    WHEN ("m"."direction" = 'outbound'::"text") THEN COALESCE(NULLIF("t"."deal_strategy", ''::"text"), 'general'::"text")
                    ELSE NULL::"text"
                END AS "out_strategy",
                CASE
                    WHEN ("m"."direction" = 'outbound'::"text") THEN COALESCE(NULLIF(("m"."metadata" ->> 'agent_name'::"text"), ''::"text"), NULLIF(("q"."metadata" ->> 'agent_name'::"text"), ''::"text"), 'Unknown Agent'::"text")
                    ELSE NULL::"text"
                END AS "out_agent_name"
           FROM (("public"."message_events" "m"
             LEFT JOIN "public"."send_queue" "q" ON ((("m"."queue_id" = "q"."id") OR (("m"."queue_id")::"text" = "q"."queue_id"))))
             LEFT JOIN "public"."sms_templates" "t" ON (("t"."template_id" = COALESCE("m"."template_id", "q"."template_id"))))
        ), "attributed" AS (
         SELECT "sub"."message_event_id",
            "sub"."thread_key",
            "sub"."direction",
            "sub"."event_timestamp",
            "sub"."detected_intent",
            "sub"."is_opt_out",
            "sub"."current_stage",
            "sub"."out_agent_id",
            "sub"."out_persona",
            "sub"."out_tone",
            "sub"."out_language",
            "sub"."out_strategy",
            "sub"."out_agent_name",
            "sub"."grp",
            COALESCE("sub"."out_agent_id", "first_value"("sub"."out_agent_id") OVER (PARTITION BY "sub"."thread_key", "sub"."grp" ORDER BY "sub"."event_timestamp"), 'unknown'::"text") AS "sms_agent_id",
            COALESCE("sub"."out_persona", "first_value"("sub"."out_persona") OVER (PARTITION BY "sub"."thread_key", "sub"."grp" ORDER BY "sub"."event_timestamp"), 'unknown'::"text") AS "persona",
            COALESCE("sub"."out_tone", "first_value"("sub"."out_tone") OVER (PARTITION BY "sub"."thread_key", "sub"."grp" ORDER BY "sub"."event_timestamp"), 'neutral'::"text") AS "tone",
            COALESCE("sub"."out_language", "first_value"("sub"."out_language") OVER (PARTITION BY "sub"."thread_key", "sub"."grp" ORDER BY "sub"."event_timestamp"), 'english'::"text") AS "language",
            COALESCE("sub"."out_strategy", "first_value"("sub"."out_strategy") OVER (PARTITION BY "sub"."thread_key", "sub"."grp" ORDER BY "sub"."event_timestamp"), 'general'::"text") AS "strategy",
            COALESCE("sub"."out_agent_name", "first_value"("sub"."out_agent_name") OVER (PARTITION BY "sub"."thread_key", "sub"."grp" ORDER BY "sub"."event_timestamp"), 'Unknown Agent'::"text") AS "agent_name",
            "lag"("sub"."event_timestamp") OVER (PARTITION BY "sub"."thread_key" ORDER BY "sub"."event_timestamp") AS "prev_timestamp",
            "lag"("sub"."direction") OVER (PARTITION BY "sub"."thread_key" ORDER BY "sub"."event_timestamp") AS "prev_direction"
           FROM ( SELECT "enriched_messages"."message_event_id",
                    "enriched_messages"."thread_key",
                    "enriched_messages"."direction",
                    "enriched_messages"."event_timestamp",
                    "enriched_messages"."detected_intent",
                    "enriched_messages"."is_opt_out",
                    "enriched_messages"."current_stage",
                    "enriched_messages"."out_agent_id",
                    "enriched_messages"."out_persona",
                    "enriched_messages"."out_tone",
                    "enriched_messages"."out_language",
                    "enriched_messages"."out_strategy",
                    "enriched_messages"."out_agent_name",
                    "count"("enriched_messages"."out_agent_id") OVER (PARTITION BY "enriched_messages"."thread_key" ORDER BY "enriched_messages"."event_timestamp") AS "grp"
                   FROM "enriched_messages") "sub"
        ), "daily_aggregates" AS (
         SELECT "attributed"."sms_agent_id",
            "attributed"."agent_name",
            "attributed"."persona",
            "attributed"."tone",
            "attributed"."language",
            "attributed"."strategy",
            ("date_trunc"('day'::"text", "attributed"."event_timestamp"))::"date" AS "time_window",
            "count"(*) FILTER (WHERE ("attributed"."direction" = 'outbound'::"text")) AS "sends",
            "count"(*) FILTER (WHERE ("attributed"."direction" = 'inbound'::"text")) AS "replies",
            "count"(*) FILTER (WHERE (("attributed"."direction" = 'inbound'::"text") AND ("attributed"."detected_intent" = ANY (ARRAY['seller_interested'::"text", 'asking_price_provided'::"text", 'asks_offer'::"text", 'ownership_confirmed'::"text", 'condition_disclosed'::"text", 'qualified_lead'::"text", 'needs_call'::"text", 'needs_email'::"text"])))) AS "positive_replies",
            "count"(*) FILTER (WHERE (("attributed"."direction" = 'inbound'::"text") AND ("attributed"."is_opt_out" OR ("attributed"."detected_intent" = 'opt_out'::"text")))) AS "opt_outs",
            "count"(*) FILTER (WHERE (("attributed"."direction" = 'inbound'::"text") AND ("attributed"."detected_intent" = 'wrong_number'::"text"))) AS "wrong_numbers",
            "count"(*) FILTER (WHERE (("attributed"."direction" = 'inbound'::"text") AND (("attributed"."detected_intent" = 'hostile'::"text") OR ("attributed"."detected_intent" = 'angry'::"text") OR ("attributed"."detected_intent" = 'not_interested_hostile'::"text")))) AS "hostile_replies",
            "count"(*) FILTER (WHERE (("attributed"."direction" = 'inbound'::"text") AND ("attributed"."detected_intent" = 'asking_price_provided'::"text"))) AS "asking_price_replies",
            "count"(*) FILTER (WHERE (("attributed"."direction" = 'inbound'::"text") AND ("attributed"."detected_intent" = 'ownership_confirmed'::"text"))) AS "ownership_confirmed",
            "count"(*) FILTER (WHERE (("attributed"."direction" = 'inbound'::"text") AND (("attributed"."detected_intent" = 'qualified_lead'::"text") OR ("attributed"."current_stage" = 'qualified'::"text")))) AS "qualified_leads",
            "avg"((EXTRACT(epoch FROM ("attributed"."event_timestamp" - "attributed"."prev_timestamp")) / 3600.0)) FILTER (WHERE (("attributed"."direction" = 'inbound'::"text") AND ("attributed"."prev_direction" = 'outbound'::"text"))) AS "avg_response_hours"
           FROM "attributed"
          GROUP BY "attributed"."sms_agent_id", "attributed"."agent_name", "attributed"."persona", "attributed"."tone", "attributed"."language", "attributed"."strategy", (("date_trunc"('day'::"text", "attributed"."event_timestamp"))::"date")
        )
 SELECT "sms_agent_id",
    "agent_name",
    "persona",
    "tone",
    "language",
    "strategy",
    "time_window",
    "sends",
    "replies",
    "positive_replies",
    "opt_outs",
    "wrong_numbers",
    "hostile_replies",
    "asking_price_replies",
    "ownership_confirmed",
    "qualified_leads",
    "avg_response_hours",
        CASE
            WHEN ("sends" > 0) THEN ((("replies")::numeric / ("sends")::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS "reply_rate_pct",
        CASE
            WHEN ("sends" > 0) THEN ((("positive_replies")::numeric / ("sends")::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS "positive_rate_pct",
        CASE
            WHEN ("sends" > 0) THEN ((("opt_outs")::numeric / ("sends")::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS "opt_out_rate_pct",
        CASE
            WHEN ("sends" > 0) THEN ((("wrong_numbers")::numeric / ("sends")::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS "wrong_number_rate_pct",
        CASE
            WHEN ("sends" > 0) THEN ((("qualified_leads")::numeric / ("sends")::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS "qualification_rate_pct",
        CASE
            WHEN ("sends" > 0) THEN ((("positive_replies")::numeric / ("sends")::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS "stage_advance_rate_pct",
    1.0 AS "current_volume_weight",
        CASE
            WHEN (("sends" > 50) AND ((("positive_replies")::numeric / ("sends")::numeric) > 0.05)) THEN 1.5
            WHEN (("sends" > 50) AND ((("opt_outs")::numeric / ("sends")::numeric) > 0.05)) THEN 0.5
            ELSE 1.0
        END AS "recommended_volume_weight",
        CASE
            WHEN (("sends" > 50) AND ((("positive_replies")::numeric / ("sends")::numeric) > 0.05)) THEN 'scale_up'::"text"
            WHEN (("sends" > 50) AND ((("opt_outs")::numeric / ("sends")::numeric) > 0.05)) THEN 'scale_down'::"text"
            ELSE 'maintain'::"text"
        END AS "recommended_status",
    (("sends" > 100) AND ((("opt_outs")::numeric / ("sends")::numeric) > 0.08)) AS "auto_pause_candidate",
        CASE
            WHEN ("sends" < 25) THEN 'low_data'::"text"
            WHEN ("sends" < 100) THEN 'learning'::"text"
            ELSE 'high_confidence'::"text"
        END AS "confidence_bucket"
   FROM "daily_aggregates";


--
-- Name: agent_attribution_metrics_v; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."agent_attribution_metrics_v" AS
 WITH "counts" AS (
         SELECT "count"(*) AS "total_events",
            "count"(*) FILTER (WHERE (("agent_performance_kpis_v"."sms_agent_id" <> 'unknown'::"text") AND ("agent_performance_kpis_v"."sms_agent_id" IS NOT NULL))) AS "attributed_events"
           FROM "public"."agent_performance_kpis_v"
        )
 SELECT "total_events",
    "attributed_events",
    ("total_events" - "attributed_events") AS "unknown_events",
        CASE
            WHEN ("total_events" > 0) THEN ((("attributed_events")::numeric / ("total_events")::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS "attribution_coverage_pct",
        CASE
            WHEN ("total_events" > 0) THEN (((("total_events" - "attributed_events"))::numeric / ("total_events")::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS "unknown_agent_pct",
        CASE
            WHEN ("total_events" > 1000) THEN 'high'::"text"
            WHEN ("total_events" > 100) THEN 'medium'::"text"
            ELSE 'low'::"text"
        END AS "agent_attribution_confidence"
   FROM "counts";


