    "max_purchase_price",
    "avg_sqft",
    "avg_units",
    "purchase_count_total",
    "purchase_count_6mo",
    "purchase_count_12mo",
    "first_purchase_date",
    "last_purchase_date",
    "velocity_score",
    "market_focus_score",
    "price_band_score",
    "asset_fit_score",
    "cash_buyer_score",
    "corporate_strength_score",
    "dispo_priority_score",
    "confidence_score",
    "buy_box_summary",
    "buyer_summary",
    "recommended_action",
    "source",
    "raw_payload",
    "created_at",
    "updated_at",
    "avg_ppsf",
    "median_ppsf",
    "avg_ppu",
    "median_ppu",
    "avg_ppbd_bed",
    "preferred_sqft_range",
    "preferred_price_band",
    "preferred_unit_band",
    "preferred_bed_band",
    "dominant_comp_profile_hash",
    "dominant_renovation_level",
    "avg_discount_to_value",
    "avg_potential_spread",
    "buy_box_confidence_score",
    "resale_margin_score",
    "investor_fit_score",
    "avg_ppbd",
    "sqft_range_focus",
    "avg_price_off_value",
    "avg_percent_off",
    "buyer_velocity_score",
    "cash_buyer_strength",
    "flip_likelihood",
    "rental_likelihood",
    "multifamily_operator_flag",
    "institutional_scale_flag",
    "portfolio_growth_rate",
    "buy_box_signature",
    "median_hold_time_days",
    "average_rehab_level",
    "buyer_exit_strategy",
    "comp_confidence_score",
    "deal_grade",
    "target_margin_percent",
    COALESCE("buyer_velocity_score", (LEAST(100, ((COALESCE("purchase_count_6mo", 0) * 15) + (COALESCE("purchase_count_12mo", 0) * 5))))::numeric) AS "calc_buyer_velocity_score",
    COALESCE("cash_buyer_strength", LEAST((100)::numeric, (((COALESCE("corporate_strength_score", (0)::numeric) * 0.45) + (COALESCE("velocity_score", (0)::numeric) * 0.35)) + (COALESCE("dispo_priority_score", (0)::numeric) * 0.20)))) AS "calc_cash_buyer_strength",
    COALESCE("institutional_scale_flag", ((COALESCE("purchase_count_12mo", 0) >= 10) OR (COALESCE("max_purchase_price", (0)::numeric) >= (1000000)::numeric))) AS "calc_institutional_scale_flag",
    COALESCE("multifamily_operator_flag", (EXISTS ( SELECT 1
           FROM "unnest"(COALESCE("bp"."property_type_focus", ARRAY[]::"text"[])) "x"("x")
          WHERE (("lower"("x"."x") ~~ '%multi%'::"text") OR ("lower"("x"."x") ~~ '%apart%'::"text"))))) AS "calc_multifamily_operator_flag",
    COALESCE("flip_likelihood", (
        CASE
            WHEN ("lower"(COALESCE("average_rehab_level", ''::"text")) = ANY (ARRAY['cosmetic'::"text", 'moderate'::"text", 'heavy'::"text", 'structural'::"text"])) THEN 75
            ELSE 45
        END)::numeric) AS "calc_flip_likelihood",
    COALESCE("rental_likelihood", (
        CASE
            WHEN ((COALESCE("avg_units", (0)::numeric) >= (2)::numeric) OR (COALESCE("avg_purchase_price", (0)::numeric) < (250000)::numeric)) THEN 75
            ELSE 50
        END)::numeric) AS "calc_rental_likelihood"
   FROM "public"."buyer_profiles" "bp";


