--
-- Name: buyer_property_matches_computed; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."buyer_property_matches_computed" AS
 SELECT "bpm"."id",
    "bpm"."match_key",
    "bpm"."buyer_key",
    "bpm"."buyer_profile_id",
    "bpm"."property_id",
    "bpm"."master_owner_id",
    "bpm"."owner_key",
    "bpm"."property_address_full",
    "bpm"."property_address_city",
    "bpm"."property_address_state",
    "bpm"."property_address_zip",
    "bpm"."market",
    "bpm"."property_type",
    "bpm"."target_price",
    "bpm"."estimated_value",
    "bpm"."estimated_repair_cost",
    "bpm"."potential_spread",
    "bpm"."match_score",
    "bpm"."market_fit_score",
    "bpm"."price_fit_score",
    "bpm"."asset_fit_score",
    "bpm"."velocity_score",
    "bpm"."confidence",
    "bpm"."reason_for_match",
    "bpm"."recommended_action",
    "bpm"."disposition_strategy",
    "bpm"."match_status",
    "bpm"."source",
    "bpm"."raw_payload",
    "bpm"."created_at",
    "bpm"."updated_at",
    "bpm"."comp_search_profile_hash",
    "bpm"."renovation_level_classification",
    "bpm"."ppbd_bed",
    "bpm"."ppu",
    "bpm"."ppsf",
    "bpm"."sqft_range",
    "bpm"."sqft_per_unit",
    "bpm"."beds_per_unit",
    "bpm"."price_off_value",
    "bpm"."percent_off",
    "bpm"."purchase_info",
    "bpm"."buyer_buy_box_fit_score",
    "bpm"."buyer_price_band_fit_score",
    "bpm"."buyer_margin_fit_score",
    "bpm"."ppbd",
    "bpm"."arv_estimate",
    "bpm"."arv_ppsf",
    "bpm"."buyer_velocity_score",
    "bpm"."cash_buyer_strength",
    "bpm"."flip_likelihood",
    "bpm"."rental_likelihood",
    "bpm"."multifamily_operator_flag",
    "bpm"."institutional_scale_flag",
    "bpm"."buy_box_signature",
    "bpm"."buyer_exit_strategy",
    "bpm"."comp_confidence_score",
    "bpm"."deal_grade",
    "bpm"."target_margin_percent",
    "bp"."buyer_name",
    "bp"."buyer_tier",
    "bp"."buy_box_summary",
    COALESCE("bpm"."buyer_velocity_score", "bp"."buyer_velocity_score", "bp"."velocity_score") AS "calc_buyer_velocity_score",
    COALESCE("bpm"."cash_buyer_strength", "bp"."cash_buyer_strength", "bp"."cash_buyer_score") AS "calc_cash_buyer_strength",
    COALESCE("bpm"."buy_box_signature", "bp"."buy_box_signature") AS "calc_buy_box_signature",
    COALESCE("bpm"."buyer_exit_strategy", "bp"."buyer_exit_strategy") AS "calc_buyer_exit_strategy",
    COALESCE("bpm"."arv_estimate", "bpm"."estimated_value") AS "calc_arv_estimate",
    COALESCE("bpm"."arv_ppsf", "public"."safe_divide"(COALESCE("bpm"."arv_estimate", "bpm"."estimated_value"), NULLIF("bpm"."target_price", (0)::numeric))) AS "calc_arv_ppsf"
   FROM ("public"."buyer_property_matches" "bpm"
     LEFT JOIN "public"."buyer_profiles" "bp" ON (("bp"."id" = "bpm"."buyer_profile_id")));


