--
-- Name: conversation_detail_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."conversation_detail_view" WITH ("security_invoker"='true') AS
 SELECT COALESCE(NULLIF("thread_key", ''::"text"),
        CASE
            WHEN ("lower"(COALESCE("direction", ''::"text")) ~~ 'in%'::"text") THEN NULLIF(("from_phone_number")::"text", ''::"text")
            ELSE NULLIF(("to_phone_number")::"text", ''::"text")
        END, NULLIF(("to_phone_number")::"text", ''::"text"), NULLIF(("from_phone_number")::"text", ''::"text")) AS "thread_key",
    ("id")::"text" AS "message_id",
    "message_event_key",
    "provider_message_sid",
    "direction",
        CASE
            WHEN ("lower"(COALESCE("direction", ''::"text")) ~~ 'in%'::"text") THEN 'inbound'::"text"
            WHEN ("lower"(COALESCE("direction", ''::"text")) ~~ 'out%'::"text") THEN 'outbound'::"text"
            ELSE 'unknown'::"text"
        END AS "normalized_direction",
    "message_body",
    COALESCE("event_timestamp", "received_at", "sent_at", "delivered_at", "created_at") AS "timeline_at",
    "created_at",
    "sent_at",
    "received_at",
    "delivered_at",
    "failed_at",
    "delivery_status",
    "provider_delivery_status",
    "raw_carrier_status",
    "error_message",
    "from_phone_number",
    "to_phone_number",
        CASE
            WHEN ("lower"(COALESCE("direction", ''::"text")) ~~ 'in%'::"text") THEN "from_phone_number"
            ELSE "to_phone_number"
        END AS "canonical_e164",
    "phone_number_id",
    "prospect_id",
    "property_id",
    "master_owner_id",
    "textgrid_number_id",
    "sms_agent_id",
    "queue_id",
    "template_id",
    "market_id",
    "stage_before",
    "stage_after",
    "metadata",
    "jsonb_strip_nulls"("jsonb_build_object"('id', "id", 'threadKey', COALESCE(NULLIF("thread_key", ''::"text"),
        CASE
            WHEN ("lower"(COALESCE("direction", ''::"text")) ~~ 'in%'::"text") THEN NULLIF(("from_phone_number")::"text", ''::"text")
            ELSE NULLIF(("to_phone_number")::"text", ''::"text")
        END), 'direction', "direction", 'body', "message_body", 'timelineAt', COALESCE("event_timestamp", "received_at", "sent_at", "delivered_at", "created_at"), 'deliveryStatus', COALESCE("delivery_status", "provider_delivery_status", "raw_carrier_status"), 'fromNumber', "from_phone_number", 'toNumber', "to_phone_number", 'propertyId', "property_id", 'prospectId', "prospect_id", 'ownerId', "master_owner_id", 'phoneId', "phone_number_id", 'queueId', "queue_id")) AS "message_entity"
   FROM "public"."message_events" "me";


