    "c"."preview",
    "c"."display_name",
    "c"."display_address",
    "c"."display_phone",
    "c"."display_market",
    "c"."display_status",
    "c"."display_score",
    "c"."inbox_category",
    COALESCE(NULLIF("p"."market", ''::"text"), 'Unknown'::"text") AS "filter_market",
        CASE
            WHEN ("c"."is_suppressed" OR ("c"."ui_intent" = ANY (ARRAY['opt_out'::"text", 'wrong_number'::"text", 'hostile_or_legal'::"text"]))) THEN 'dead_suppressed'::"text"
            WHEN ("c"."stage" = 'dead'::"text") THEN 'dead_suppressed'::"text"
            WHEN ("c"."ui_intent" = 'asking_price_provided'::"text") THEN 'price_discovery'::"text"
            WHEN ("c"."ui_intent" = ANY (ARRAY['seller_interested'::"text", 'ownership_confirmed'::"text", 'needs_call'::"text", 'tenant_occupancy'::"text"])) THEN 'interest_probe'::"text"
            WHEN ("c"."inbound_count" > 0) THEN 'active_communication'::"text"
            WHEN ("c"."outbound_count" > 1) THEN 'interest_probe'::"text"
            WHEN (("c"."outbound_count" = 1) OR ("c"."pending_queue_count" > 0)) THEN 'ownership_check'::"text"
            ELSE 'ownership_check'::"text"
        END AS "pipeline_stage",
        CASE
            WHEN ("c"."is_suppressed" OR ("c"."ui_intent" = 'opt_out'::"text")) THEN 'suppressed'::"text"
            WHEN ("c"."ui_intent" = 'wrong_number'::"text") THEN 'wrong_number'::"text"
            WHEN ("c"."ui_intent" = 'hostile_or_legal'::"text") THEN 'blocked'::"text"
            WHEN ("c"."stage" = 'dead'::"text") THEN 'dead'::"text"
            WHEN ("c"."ui_intent" = 'asking_price_provided'::"text") THEN 'asking_price_provided'::"text"
            WHEN ("c"."ui_intent" = ANY (ARRAY['seller_interested'::"text", 'ownership_confirmed'::"text", 'needs_call'::"text", 'tenant_occupancy'::"text"])) THEN 'positive_intent'::"text"
            WHEN (("c"."inbound_count" > 0) AND (NOT "c"."is_read")) THEN 'new_reply'::"text"
            WHEN ("c"."inbound_count" > 0) THEN 'seller_replied'::"text"
            WHEN "c"."is_hot_lead" THEN 'hot'::"text"
            WHEN ("c"."outbound_count" > 1) THEN 'awaiting_response'::"text"
            WHEN (("c"."outbound_count" = 1) OR ("c"."pending_queue_count" > 0)) THEN 'queued'::"text"
            ELSE 'not_contacted'::"text"
        END AS "seller_state",
        CASE
            WHEN ("c"."is_suppressed" OR ("c"."ui_intent" = 'opt_out'::"text")) THEN 'suppressed'::"text"
            WHEN ("c"."ui_intent" = 'wrong_number'::"text") THEN 'wrong_number'::"text"
            WHEN ("c"."ui_intent" = 'hostile_or_legal'::"text") THEN 'auto_blocked'::"text"
            WHEN (("c"."stage" = 'dead'::"text") AND ("c"."ui_intent" <> ALL (ARRAY['opt_out'::"text", 'wrong_number'::"text", 'hostile_or_legal'::"text"]))) THEN 'review_required'::"text"
            WHEN ("c"."ui_intent" = 'asking_price_provided'::"text") THEN 'asking_price_provided'::"text"
            WHEN ("c"."ui_intent" = ANY (ARRAY['seller_interested'::"text", 'ownership_confirmed'::"text", 'needs_call'::"text", 'tenant_occupancy'::"text"])) THEN 'positive_intent'::"text"
            WHEN (("c"."inbound_count" > 0) AND ("c"."follow_up_at" IS NOT NULL) AND ("c"."follow_up_at" < "now"())) THEN 'needs_follow_up'::"text"
            WHEN ("c"."inbound_count" > 0) THEN 'seller_replied'::"text"
            WHEN ("c"."outbound_count" > 1) THEN 'awaiting_response'::"text"
            WHEN (("c"."outbound_count" = 1) OR ("c"."pending_queue_count" > 0)) THEN 'ownership_check_sent'::"text"
            ELSE 'not_contacted'::"text"
        END AS "seller_status",
        CASE
            WHEN ("c"."is_suppressed" OR ("c"."ui_intent" = ANY (ARRAY['opt_out'::"text", 'wrong_number'::"text"]))) THEN 'blocked'::"text"
            WHEN ("c"."pending_queue_count" > 0) THEN 'scheduled'::"text"
            WHEN ("c"."latest_message_at" IS NOT NULL) THEN 'sent'::"text"
            ELSE 'none'::"text"
        END AS "execution_state",
    "c"."state" AS "filter_state",
    "c"."city" AS "filter_city",
    "c"."zip" AS "filter_zip",
    "c"."property_type" AS "filter_property_type"
   FROM ("public"."inbox_command_center_v" "c"
     LEFT JOIN "public"."properties" "p" ON (("p"."property_id" = "c"."property_id")));


--
-- Name: inbox_category_counts; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."inbox_category_counts" AS
 SELECT "v_inbox_enriched"."inbox_category",
    "count"(*) AS "count"
   FROM "public"."v_inbox_enriched"
  GROUP BY "v_inbox_enriched"."inbox_category"
UNION ALL
 SELECT 'all'::"text" AS "inbox_category",
    "count"(*) AS "count"
   FROM "public"."v_inbox_enriched";


--
-- Name: inbox_chat_timeline_hydrated; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."inbox_chat_timeline_hydrated" AS
 WITH "raw_events" AS (
         SELECT "m"."id",
            "m"."message_event_key",
            "m"."provider_message_sid",
            "m"."direction",
            "m"."event_type",
            "m"."message_body",
            "m"."to_phone_number",
            "m"."from_phone_number",
            "m"."phone_number_id",
            "m"."queue_id",
            "m"."metadata",
            "m"."created_at",
            "m"."sent_at",
            "m"."received_at",
            "m"."delivered_at",
            "m"."failed_at",
            "m"."error_message",
            "m"."property_address",
            "m"."message_id",
            "m"."event_timestamp",
            "m"."message_variant",
            "m"."master_owner_id",
            "m"."prospect_id",
            "m"."property_id",
            "m"."textgrid_number_id",
            "m"."sms_agent_id",
            "m"."template_id",
            "m"."conversation_brain_id",
            "m"."market_id",
            "m"."ai_route",
            "m"."processed_by",
            "m"."source_app",
            "m"."trigger_name",
            "m"."ai_output",
            "m"."character_count",
            "m"."delivery_status",
            "m"."raw_carrier_status",
            "m"."is_final_failure",
            "m"."failure_bucket",
            "m"."latency_ms",
            "m"."processing_delay_seconds",
            "m"."provider_delivery_status",
            "m"."failure_code",
            "m"."failure_reason",
            "m"."is_opt_out",
            "m"."opt_out_keyword",
            "m"."opt_out_message",
            "m"."segment_count",
            "m"."prior_message_id",
            "m"."triggered_by",
            "m"."response_to_message_id",
            "m"."stage_before",
            "m"."stage_after",
            "m"."stage_changed_by",
            "m"."stage_change_reason",
            "m"."podio_sync_status",
            "m"."podio_message_event_id",
            "m"."podio_synced_at",
            "m"."podio_sync_error",
            "m"."podio_sync_attempts",
            "m"."updated_at",
            "m"."thread_key",
            "m"."seller_display_name",
            "m"."market",
            "m"."detected_intent",
            "m"."routing_allowed",
            "m"."safety_status",
            "m"."priority",
            "m"."risk",
            "m"."type",
            "m"."language",
            "m"."classification_confidence",
            "m"."current_stage",
                CASE
                    WHEN ("m"."direction" = 'inbound'::"text") THEN "m"."from_phone_number"
                    ELSE "m"."to_phone_number"
                END AS "seller_phone"
           FROM "public"."deduped_message_events" "m"
          WHERE ("m"."thread_key" IS NOT NULL)
        ), "resolved_links" AS (
         SELECT "r_1"."id" AS "message_id",
            COALESCE("r_1"."prospect_id", "ph"."primary_prospect_id", "ph"."canonical_prospect_id") AS "best_prospect_id",
            COALESCE("r_1"."master_owner_id", "ph"."master_owner_id") AS "best_master_owner_id",
            "ph"."phone_owner" AS "carrier"
           FROM ("raw_events" "r_1"
             LEFT JOIN "public"."phones" "ph" ON (("ph"."canonical_e164" = ("r_1"."seller_phone")::"text")))
        )
 SELECT "r"."id",
    "r"."message_event_key",
    "r"."provider_message_sid",
    "r"."direction",
    "r"."event_type",
    "r"."message_body",
    "r"."to_phone_number",
    "r"."from_phone_number",
    "r"."seller_phone",
        CASE
            WHEN ("r"."direction" = 'inbound'::"text") THEN "r"."to_phone_number"
            ELSE "r"."from_phone_number"
        END AS "our_number",
    "r"."delivery_status",
    "r"."provider_delivery_status",
    "r"."raw_carrier_status",
    "r"."event_timestamp",
    "r"."created_at",
    "r"."sent_at",
    "r"."received_at",
    "r"."delivered_at",
    "r"."failed_at",
    COALESCE("r"."delivered_at", "r"."sent_at", "r"."received_at", "r"."event_timestamp", "r"."created_at") AS "message_created_at",
    "r"."thread_key",
    "r"."seller_display_name",
    "r"."master_owner_id",
    "r"."prospect_id",
    "r"."property_id",
    "r"."market",
    "r"."detected_intent",
    "r"."language",
    "r"."classification_confidence",
    "r"."safety_status",
    "r"."current_stage",
    "r"."stage_before",
    "r"."stage_after",
    "r"."failure_bucket",
    "r"."failure_reason",
    "r"."error_message",
    "r"."metadata",
    ("date_part"('year'::"text", CURRENT_DATE) - ((NULLIF("substring"("pr"."mob", 1, 4), ''::"text"))::integer)::double precision) AS "prospect_age",
    "pr"."est_household_income",
    "pr"."net_asset_value",
    "pr"."buying_power",
    "pr"."education_model" AS "marital_status",
    "pr"."marital_status" AS "education_model",
    "mo"."best_language",
    "l"."carrier" AS "phone_carrier"
   FROM ((("raw_events" "r"
     JOIN "resolved_links" "l" ON (("l"."message_id" = "r"."id")))
     LEFT JOIN "public"."prospects" "pr" ON (("pr"."prospect_id" = "l"."best_prospect_id")))
     LEFT JOIN "public"."master_owners" "mo" ON (("mo"."master_owner_id" = "l"."best_master_owner_id")));


