            "c"."seller_state",
            "c"."seller_status",
            "c"."execution_state",
            "c"."filter_state",
            "c"."filter_city",
            "c"."filter_zip",
            "c"."filter_property_type",
            "c"."_direction",
            "c"."_category",
            "c"."_intent",
            "c"."_stage",
            "c"."_status",
            "c"."resolved_latest_message_direction",
            "c"."resolved_opt_out",
            "c"."resolved_wrong_number",
            "c"."resolved_not_interested",
            "c"."resolved_needs_review",
            "c"."resolved_priority",
                CASE
                    WHEN "c"."resolved_opt_out" THEN 'suppressed'::"text"
                    WHEN ("c"."resolved_wrong_number" OR "c"."resolved_not_interested" OR ("c"."_category" = ANY (ARRAY['dead'::"text", 'wrong_number'::"text"])) OR ("c"."_stage" = 'dead'::"text")) THEN 'dead'::"text"
                    WHEN ("c"."_category" = 'hot_leads'::"text") THEN 'priority'::"text"
                    WHEN ("c"."_category" = 'new_inbound'::"text") THEN 'new_replies'::"text"
                    WHEN ("c"."_category" = 'automated'::"text") THEN 'needs_review'::"text"
                    WHEN ("c"."_category" = 'outbound_active'::"text") THEN 'follow_up'::"text"
                    WHEN ("c"."_category" = 'cold_no_response'::"text") THEN 'cold'::"text"
                    WHEN "c"."resolved_needs_review" THEN 'needs_review'::"text"
                    WHEN "c"."resolved_priority" THEN 'priority'::"text"
                    WHEN ("c"."resolved_latest_message_direction" = 'inbound'::"text") THEN 'new_replies'::"text"
                    WHEN ("c"."_category" = ANY (ARRAY['outbound_active'::"text", 'follow_up'::"text", 'follow_up_due'::"text"])) THEN 'follow_up'::"text"
                    WHEN ("c"."last_inbound_at" IS NOT NULL) THEN 'follow_up'::"text"
                    ELSE 'cold'::"text"
                END AS "resolved_inbox_bucket"
           FROM "classified" "c"
        )
 SELECT "thread_key" AS "canonical_thread_key",
    "thread_key",
    "thread_key" AS "id",
    1 AS "thread_row_number",
    'v_inbox_enriched'::"text" AS "latest_message_source",
    NULL::"text" AS "latest_message_event_id",
    COALESCE("property_id", "final_property_id") AS "property_id",
    COALESCE("master_owner_id", "final_master_owner_id") AS "master_owner_id",
    "final_prospect_id" AS "prospect_id",
    COALESCE("property_id", "final_property_id") AS "selected_property_id",
    COALESCE("property_id", "final_property_id") AS "thread_property_id",
    COALESCE("master_owner_id", "final_master_owner_id") AS "thread_master_owner_id",
    "final_prospect_id" AS "thread_prospect_id",
    COALESCE("best_phone", "seller_phone", "display_phone", "thread_key") AS "canonical_e164",
    COALESCE("seller_phone", "best_phone", "display_phone", "thread_key") AS "seller_phone",
    COALESCE("best_phone", "seller_phone", "display_phone", "thread_key") AS "best_phone",
    COALESCE("best_phone", "seller_phone", "display_phone", "thread_key") AS "phone",
    COALESCE("display_phone", "best_phone", "seller_phone", "thread_key") AS "display_phone",
    NULL::"text" AS "our_number",
    "latest_message_at",
    "latest_message_at" AS "latest_activity_at",
    "latest_message_at" AS "last_message_at",
    COALESCE("latest_message_body", "preview") AS "latest_message_body",
    "resolved_latest_message_direction" AS "latest_message_direction",
    "resolved_latest_message_direction" AS "direction",
    NULL::"text" AS "delivery_status",
    NULL::"text" AS "provider_delivery_status",
    NULL::"text" AS "latest_delivery_status",
    NULL::"text" AS "latest_provider_delivery_status",
    NULL::timestamp with time zone AS "latest_delivered_at",
    NULL::timestamp with time zone AS "latest_failed_at",
    NULL::"text" AS "latest_failure_reason",
    "last_outbound_at",
    "last_inbound_at",
    "automation_status" AS "auto_reply_status",
    COALESCE(NULLIF("stage", ''::"text"), 'ownership_check'::"text") AS "current_stage",
    COALESCE(NULLIF("detected_intent", ''::"text"), NULLIF("ui_intent", ''::"text")) AS "detected_intent",
    "resolved_inbox_bucket" AS "inbox_bucket",
        CASE
            WHEN ("resolved_inbox_bucket" = 'suppressed'::"text") THEN 'suppressed'::"text"
            WHEN ("resolved_inbox_bucket" = 'dead'::"text") THEN 'dead'::"text"
            WHEN ("resolved_inbox_bucket" = 'needs_review'::"text") THEN 'needs_review'::"text"
            WHEN ("resolved_latest_message_direction" = 'outbound'::"text") THEN 'awaiting_response'::"text"
            ELSE 'active'::"text"
        END AS "universal_status",
    COALESCE(NULLIF("stage", ''::"text"), 'ownership_check'::"text") AS "universal_stage",
    COALESCE(NULLIF("stage", ''::"text"), 'ownership_check'::"text") AS "conversation_stage",
    COALESCE("owner_display_name", "display_name", "event_seller_display_name") AS "owner_name",
    "split_part"(COALESCE("owner_display_name", "display_name", "event_seller_display_name", ''::"text"), ' '::"text", 1) AS "seller_first_name",
    COALESCE("display_name", "owner_display_name", "event_seller_display_name") AS "seller_display_name",
    COALESCE("property_address_full", "display_address", "event_property_address") AS "property_address_full",
    "city" AS "property_address_city",
    "state" AS "property_state",
    "zip" AS "property_zip",
    NULL::"text" AS "property_county_name",
    COALESCE("display_market", "market") AS "market",
    "latitude",
    "longitude",
    COALESCE("property_type", "filter_property_type") AS "property_type",
    NULL::"text" AS "property_class",
    "estimated_value",
    NULL::numeric AS "estimated_arv",
    NULL::numeric AS "equity_percent",
    "cash_offer",
    "final_acquisition_score",
    "priority_score",
        CASE
            WHEN ("resolved_inbox_bucket" = 'priority'::"text") THEN 'hot'::"text"
            WHEN ("resolved_latest_message_direction" = 'inbound'::"text") THEN 'warm'::"text"
            WHEN ("last_inbound_at" IS NOT NULL) THEN 'neutral'::"text"
            ELSE 'cold'::"text"
        END AS "lead_temperature",
    COALESCE(NULLIF("detected_intent", ''::"text"), NULLIF("ui_intent", ''::"text")) AS "reply_intent",
    (COALESCE("message_count", (0)::bigint))::integer AS "message_count",
    (COALESCE("inbound_count", (0)::bigint))::integer AS "inbound_count",
    (COALESCE("outbound_count", (0)::bigint))::integer AS "outbound_count",
        CASE
            WHEN (("resolved_latest_message_direction" = 'inbound'::"text") AND (COALESCE("is_read", false) = false) AND ("resolved_inbox_bucket" <> ALL (ARRAY['dead'::"text", 'suppressed'::"text"]))) THEN 1
            ELSE 0
        END AS "unread_count",
    "resolved_opt_out" AS "opt_out",
    "resolved_wrong_number" AS "wrong_number",
    "resolved_not_interested" AS "not_interested",
    "resolved_needs_review" AS "needs_review",
    "automation_status" AS "queue_status",
        CASE
            WHEN ("resolved_inbox_bucket" = 'suppressed'::"text") THEN 'suppressed'::"text"
            ELSE NULL::"text"
        END AS "suppression_status",
        CASE
            WHEN ("resolved_inbox_bucket" = 'suppressed'::"text") THEN COALESCE(NULLIF("ui_intent", ''::"text"), 'suppressed'::"text")
            ELSE NULL::"text"
        END AS "suppression_type",
    NULL::timestamp with time zone AS "suppression_until",
    NULL::integer AS "touch_count",
    NULL::timestamp with time zone AS "last_touch_at",
        CASE
            WHEN ("property_id" IS NOT NULL) THEN 'v_inbox_enriched.property_id'::"text"
            WHEN ("final_property_id" IS NOT NULL) THEN 'v_inbox_enriched.final_property_id'::"text"
            ELSE 'no_property_match'::"text"
        END AS "selected_property_reason",
    1 AS "duplicate_property_count",
    'v_inbox_enriched'::"text" AS "enrichment_match_strategy",
    "jsonb_strip_nulls"("jsonb_build_object"('property_id', COALESCE("property_id", "final_property_id"), 'property_address_full', COALESCE("property_address_full", "display_address", "event_property_address"), 'market', COALESCE("display_market", "market"), 'property_type', COALESCE("property_type", "filter_property_type"), 'estimated_value', "estimated_value", 'cash_offer', "cash_offer", 'final_acquisition_score', "final_acquisition_score")) AS "property_data",
    "jsonb_strip_nulls"("jsonb_build_object"('master_owner_id', COALESCE("master_owner_id", "final_master_owner_id"), 'display_name', COALESCE("owner_display_name", "display_name", "event_seller_display_name"), 'priority_score', "owner_priority_score")) AS "master_owner_data",
    "jsonb_strip_nulls"("jsonb_build_object"('prospect_id', "final_prospect_id", 'display_name', COALESCE("prospect_full_name", "display_name"), 'first_name', "prospect_first_name", 'best_phone', COALESCE("prospect_best_phone", "best_phone", "seller_phone"))) AS "prospect_data",
    "jsonb_strip_nulls"("jsonb_build_object"('best_phone', "best_phone", 'seller_phone', "seller_phone", 'display_phone', "display_phone", 'carrier', "phone_carrier")) AS "phone_data",
    NULL::"jsonb" AS "email_data",
    "jsonb_strip_nulls"("jsonb_build_object"('is_read', "is_read", 'is_starred', "is_starred", 'is_pinned', "is_pinned", 'is_archived', "is_archived", 'follow_up_at', "follow_up_at")) AS "thread_state_data",
    NULL::"jsonb" AS "campaign_data",
    "jsonb_strip_nulls"("jsonb_build_object"('pending_queue_count', "pending_queue_count", 'automation_status', "automation_status", 'queue_status', "automation_status")) AS "queue_data",
        CASE
            WHEN ("resolved_inbox_bucket" = 'suppressed'::"text") THEN "jsonb_build_object"('status', 'suppressed')
            ELSE NULL::"jsonb"
        END AS "suppression_data",
    NULL::"jsonb" AS "valuation_data",
    NULL::"jsonb" AS "buyer_match_data",
    "jsonb_strip_nulls"("jsonb_build_object"('thread_key', "thread_key", 'latest_message_at', "latest_message_at", 'latest_direction', "latest_direction", 'latest_message_body', COALESCE("latest_message_body", "preview"), 'detected_intent', COALESCE(NULLIF("detected_intent", ''::"text"), NULLIF("ui_intent", ''::"text")), 'latest_delivery_status', NULL::"text", 'latest_provider_delivery_status', NULL::"text", 'latest_delivered_at', NULL::timestamp with time zone, 'latest_failed_at', NULL::timestamp with time zone, 'latest_failure_reason', NULL::"text")) AS "latest_message_event_data",
    COALESCE("latest_message_at", "last_inbound_at", "last_outbound_at") AS "created_at",
    COALESCE("latest_message_at", "last_inbound_at", "last_outbound_at") AS "updated_at",
    "preview",
    "inbox_category",
    "status" AS "display_status",
    "stage",
    "show_in_priority_inbox",
    "is_suppressed",
    "is_read",
    "is_starred",
    "is_pinned",
    "is_archived",
    "is_hot_lead",
    "event_seller_display_name",
    "owner_display_name",
    "display_name",
    "display_address",
    "display_market",
    "filter_property_type",
    "follow_up_at",
    "pending_queue_count"
   FROM "bucketed" "b";


