--
-- Name: nexus_notifications_v; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."nexus_notifications_v" AS
 SELECT "id",
    "notification_key",
        CASE
            WHEN ("notification_type" ~~* '%queue%'::"text") THEN 'Queue'::"text"
            WHEN ("notification_type" ~~* '%sms%'::"text") THEN 'SMS'::"text"
            WHEN ("notification_type" ~~* '%offer%'::"text") THEN 'Offers'::"text"
            WHEN ("notification_type" ~~* '%contract%'::"text") THEN 'Contracts'::"text"
            WHEN ("notification_type" ~~* '%title%'::"text") THEN 'Title'::"text"
            WHEN ("notification_type" ~~* '%buyer%'::"text") THEN 'Buyers'::"text"
            WHEN ("notification_type" ~~* '%property%'::"text") THEN 'Properties'::"text"
            WHEN ("notification_type" ~~* '%owner%'::"text") THEN 'Owners'::"text"
            WHEN ("severity" = ANY (ARRAY['error'::"text", 'critical'::"text"])) THEN 'Errors'::"text"
            ELSE 'System'::"text"
        END AS "command_space",
    "notification_type",
    "severity",
    "title",
    "message" AS "body",
    "status",
    "source",
    "campaign_key",
    "market",
    "asset_type",
    "strategy",
    "metrics",
    "recommended_action",
    "created_at",
    "updated_at",
    "acknowledged_at",
    "resolved_at",
        CASE
            WHEN ("acknowledged_at" IS NULL) THEN true
            ELSE false
        END AS "is_unread",
        CASE
            WHEN ("resolved_at" IS NULL) THEN true
            ELSE false
        END AS "is_open"
   FROM "public"."ops_notifications"
  ORDER BY "created_at" DESC;


--
-- Name: nexus_queue_health_v; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."nexus_queue_health_v" AS
 SELECT "count"(*) AS "total_queue_rows",
    "count"(*) FILTER (WHERE ("queue_status" = 'queued'::"text")) AS "queued_count",
    "count"(*) FILTER (WHERE ("queue_status" = 'scheduled'::"text")) AS "scheduled_count",
    "count"(*) FILTER (WHERE ("queue_status" = 'sent'::"text")) AS "sent_count",
    "count"(*) FILTER (WHERE ("queue_status" = 'failed'::"text")) AS "failed_count",
    "count"(*) FILTER (WHERE ("queue_status" = 'blocked'::"text")) AS "blocked_count",
    "count"(*) FILTER (WHERE ("queue_status" ~~ 'paused%'::"text")) AS "paused_count",
    "count"(*) FILTER (WHERE (("queue_status" = ANY (ARRAY['queued'::"text", 'scheduled'::"text"])) AND ("scheduled_for" <= "now"()))) AS "due_now_count",
    "count"(*) FILTER (WHERE (("queue_status" = ANY (ARRAY['queued'::"text", 'scheduled'::"text"])) AND ("scheduled_for" > "now"()))) AS "future_scheduled_count",
    "min"("scheduled_for") FILTER (WHERE ("queue_status" = ANY (ARRAY['queued'::"text", 'scheduled'::"text"]))) AS "oldest_pending_scheduled_for",
    "max"("sent_at") AS "latest_sent_at",
    "max"("created_at") AS "latest_created_at",
    "count"(*) FILTER (WHERE ("retry_count" >= "max_retries")) AS "max_retry_count",
    "jsonb_object_agg"("queue_status", "status_count") AS "by_status"
   FROM ( SELECT "sq_1"."id",
            "sq_1"."queue_key",
            "sq_1"."queue_status",
            "sq_1"."scheduled_for",
            "sq_1"."send_priority",
            "sq_1"."is_locked",
            "sq_1"."locked_at",
            "sq_1"."lock_token",
            "sq_1"."retry_count",
            "sq_1"."max_retries",
            "sq_1"."next_retry_at",
            "sq_1"."message_body",
            "sq_1"."phone_number_id",
            "sq_1"."to_phone_number",
            "sq_1"."from_phone_number",
            "sq_1"."metadata",
            "sq_1"."created_at",
            "sq_1"."updated_at",
            "sq_1"."property_address",
            "sq_1"."queue_id",
            "sq_1"."queue_sequence",
            "sq_1"."property_type",
            "sq_1"."owner_type",
            "sq_1"."scheduled_for_local",
            "sq_1"."scheduled_for_utc",
            "sq_1"."timezone",
            "sq_1"."contact_window",
            "sq_1"."sent_at",
            "sq_1"."delivered_at",
            "sq_1"."failed_reason",
            "sq_1"."delivery_confirmed",
            "sq_1"."master_owner_id",
            "sq_1"."prospect_id",
            "sq_1"."property_id",
            "sq_1"."market_id",
            "sq_1"."sms_agent_id",
            "sq_1"."textgrid_number_id",
            "sq_1"."template_id",
            "sq_1"."touch_number",
            "sq_1"."dnc_check",
            "sq_1"."current_stage",
            "sq_1"."message_type",
            "sq_1"."use_case_template",
            "sq_1"."message_text",
            "sq_1"."personalization_tags_used",
            "sq_1"."character_count",
            "sq_1"."provider_message_id",
            "sq_1"."local_send_date",
            "sq_1"."local_send_hour",
            "sq_1"."paused_reason",
            "sq_1"."last_guard_checked_at",
            "sq_1"."dedupe_key",
            "sq_1"."seller_first_name",
            "sq_1"."seller_display_name",
            "count"(*) OVER (PARTITION BY "sq_1"."queue_status") AS "status_count"
           FROM "public"."send_queue" "sq_1") "sq";


--
-- Name: nexus_thread_messages_v; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."nexus_thread_messages_v" AS
 SELECT "me"."id",
    COALESCE(NULLIF(("me"."metadata" ->> 'thread_key'::"text"), ''::"text"),
        CASE
            WHEN ("me"."direction" = 'inbound'::"text") THEN ('phone:'::"text" || (COALESCE("me"."from_phone_number", ''::character varying))::"text")
            ELSE ('phone:'::"text" || (COALESCE("me"."to_phone_number", ''::character varying))::"text")
        END) AS "thread_key",
    "me"."message_event_key",
    "me"."provider_message_sid",
    "me"."message_id",
    "me"."queue_id",
    "me"."direction",
    "me"."event_type",
    "me"."message_body",
    "me"."to_phone_number",
    "me"."from_phone_number",
    "me"."master_owner_id",
    "me"."prospect_id",
    "me"."property_id",
    "me"."textgrid_number_id",
    "me"."sms_agent_id",
    "me"."template_id",
    "me"."conversation_brain_id",
    "me"."delivery_status",
    "me"."provider_delivery_status",
    "me"."raw_carrier_status",
    "me"."failed_at",
    "me"."failure_code",
    "me"."failure_reason",
    "me"."error_message",
    "me"."is_final_failure",
    "me"."is_opt_out",
    "me"."opt_out_keyword",
    "me"."opt_out_message",
    "me"."stage_before",
    "me"."stage_after",
    "me"."stage_changed_by",
    "me"."stage_change_reason",
    COALESCE("me"."event_timestamp", "me"."received_at", "me"."sent_at", "me"."created_at") AS "timeline_at",
    "me"."created_at",
    "me"."sent_at",
    "me"."received_at",
    "me"."delivered_at",
    "sq"."queue_status",
    "sq"."scheduled_for",
    "sq"."sent_at" AS "queue_sent_at",
    "sq"."delivered_at" AS "queue_delivered_at",
    "sq"."failed_reason" AS "queue_failed_reason",
    "sq"."use_case_template",
    "sq"."current_stage",
    "sq"."touch_number",
    "sq"."seller_first_name",
    "sq"."seller_display_name",
    "st"."template_name",
    "st"."use_case" AS "template_use_case",
    "st"."stage_code" AS "template_stage_code",
    "st"."language" AS "template_language",
    "me"."metadata"
   FROM (("public"."message_events" "me"
     LEFT JOIN "public"."send_queue" "sq" ON (("sq"."id" = "me"."queue_id")))
     LEFT JOIN "public"."sms_templates" "st" ON ((("st"."template_id" = "me"."template_id") OR ("st"."podio_template_id" = "me"."template_id"))))
  WHERE (COALESCE("me"."from_phone_number", "me"."to_phone_number") IS NOT NULL);


