--
-- Name: number_performance_kpis_v; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."number_performance_kpis_v" AS
 WITH "windows" AS (
         SELECT 'today'::"text" AS "time_window",
            "date_trunc"('day'::"text", "now"()) AS "start_at"
        UNION ALL
         SELECT '24h'::"text",
            ("now"() - '24:00:00'::interval)
        UNION ALL
         SELECT '7d'::"text",
            ("now"() - '7 days'::interval)
        UNION ALL
         SELECT '30d'::"text",
            ("now"() - '30 days'::interval)
        UNION ALL
         SELECT 'all_time'::"text",
            '1970-01-01 00:00:00'::timestamp without time zone AS "timestamp"
        ), "base_stats" AS (
         SELECT "w"."time_window",
            "m"."textgrid_number_key",
            "count"(*) AS "sends",
            "count"(*) FILTER (WHERE (("m"."direction" = 'outbound'::"text") AND ("m"."delivery_status" = 'delivered'::"text"))) AS "delivered",
            "count"(*) FILTER (WHERE (("m"."direction" = 'outbound'::"text") AND ("m"."delivery_status" = 'failed'::"text"))) AS "failed",
            "count"(*) FILTER (WHERE ("m"."direction" = 'inbound'::"text")) AS "replies_total",
            "count"(*) FILTER (WHERE "m"."is_positive_reply") AS "positive_replies",
            "count"(*) FILTER (WHERE "m"."is_opt_out_reply") AS "opt_outs",
            "count"(*) FILTER (WHERE ("m"."detected_intent" = 'wrong_number'::"text")) AS "wrong_numbers"
           FROM ("windows" "w"
             CROSS JOIN "public"."message_attribution_events_v" "m")
          WHERE ("m"."event_timestamp" >= "w"."start_at")
          GROUP BY "w"."time_window", "m"."textgrid_number_key"
        ), "calculated" AS (
         SELECT "b"."time_window",
            "b"."textgrid_number_key",
            "b"."sends",
            "b"."delivered",
            "b"."failed",
            "b"."replies_total",
            "b"."positive_replies",
            "b"."opt_outs",
            "b"."wrong_numbers",
            ((("b"."replies_total")::double precision / (NULLIF("b"."delivered", 0))::double precision) * (100)::double precision) AS "reply_rate_pct",
            ((("b"."positive_replies")::double precision / (NULLIF("b"."replies_total", 0))::double precision) * (100)::double precision) AS "positive_rate_pct",
            ((("b"."opt_outs")::double precision / (NULLIF("b"."delivered", 0))::double precision) * (100)::double precision) AS "opt_out_rate_pct",
            ((("b"."wrong_numbers")::double precision / (NULLIF("b"."replies_total", 0))::double precision) * (100)::double precision) AS "wrong_number_rate_pct",
            ((("b"."delivered")::double precision / (NULLIF("b"."sends", 0))::double precision) * (100)::double precision) AS "delivery_rate_pct",
            ((("b"."failed")::double precision / (NULLIF("b"."sends", 0))::double precision) * (100)::double precision) AS "failure_rate_pct"
           FROM "base_stats" "b"
        )
 SELECT "c"."time_window",
    "c"."textgrid_number_key",
    "c"."sends",
    "c"."delivered",
    "c"."failed",
    "c"."replies_total",
    "c"."positive_replies",
    "c"."opt_outs",
    "c"."wrong_numbers",
    "c"."reply_rate_pct",
    "c"."positive_rate_pct",
    "c"."opt_out_rate_pct",
    "c"."wrong_number_rate_pct",
    "c"."delivery_rate_pct",
    "c"."failure_rate_pct",
    (((COALESCE("c"."delivery_rate_pct", (100)::double precision) * (0.4)::double precision) + (((100)::double precision - COALESCE(("c"."opt_out_rate_pct" * (10)::double precision), (0)::double precision)) * (0.4)::double precision)) + (((100)::double precision - COALESCE(("c"."failure_rate_pct" * (2)::double precision), (0)::double precision)) * (0.2)::double precision)) AS "health_score",
        CASE
            WHEN ("c"."sends" < 50) THEN 'insufficient_data'::"text"
            WHEN ((((100)::double precision - COALESCE(("c"."opt_out_rate_pct" * (10)::double precision), (0)::double precision)) < (40)::double precision) OR (COALESCE("c"."delivery_rate_pct", (100)::double precision) < (70)::double precision)) THEN 'burned'::"text"
            WHEN ((((100)::double precision - COALESCE(("c"."opt_out_rate_pct" * (10)::double precision), (0)::double precision)) < (60)::double precision) OR (COALESCE("c"."delivery_rate_pct", (100)::double precision) < (85)::double precision)) THEN 'risky'::"text"
            WHEN (((100)::double precision - COALESCE(("c"."opt_out_rate_pct" * (10)::double precision), (0)::double precision)) < (80)::double precision) THEN 'watch'::"text"
            ELSE 'healthy'::"text"
        END AS "health_label",
    "tn"."market",
    "tn"."friendly_name",
    "tn"."status" AS "textgrid_status"
   FROM ("calculated" "c"
     LEFT JOIN "public"."textgrid_numbers" "tn" ON ((("c"."textgrid_number_key" = ("tn"."id")::"text") OR ("c"."textgrid_number_key" = "tn"."phone_number"))));


