-- Name: queue_command_center_v; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."queue_command_center_v" AS
 SELECT "sq"."id",
    "sq"."queue_id",
    "sq"."queue_key",
    "sq"."queue_status",
    "sq"."scheduled_for",
    "sq"."scheduled_for_local",
    "sq"."timezone",
    "sq"."to_phone_number",
    "sq"."from_phone_number",
    "sq"."message_body",
    "sq"."message_text",
    "sq"."message_type",
    "sq"."use_case_template",
    "sq"."touch_number",
    "sq"."retry_count",
    "sq"."max_retries",
    "sq"."failed_reason",
    "sq"."risk_level",
    "sq"."ai_confidence",
    "sq"."estimated_cost",
    "sq"."sent_at",
    "sq"."delivered_at",
    "sq"."approved_at",
    "sq"."held_at",
    "sq"."language",
    "sq"."priority",
    "sq"."master_owner_id",
    "sq"."property_id",
    "sq"."prospect_id",
    "sq"."thread_key",
    "sq"."selected_agent_id",
    "sq"."selected_template_id",
    "sq"."market" AS "queue_market",
    "sq"."metadata",
    "mo"."display_name" AS "seller_name",
    "mo"."portfolio_total_value",
    "p"."property_address",
    "p"."property_address_city" AS "city",
    "p"."property_address_state" AS "state",
    "p"."property_address_zip" AS "zip",
    COALESCE("p"."market", "sq"."market") AS "market",
    "pr"."full_name" AS "prospect_name",
    "tai"."deal_temperature",
    "tai"."current_stage",
    "tai"."next_best_action",
    "st"."template_name",
    "st"."agent_persona"
   FROM ((((("public"."send_queue" "sq"
     LEFT JOIN "public"."master_owners" "mo" ON (("sq"."master_owner_id" = "mo"."master_owner_id")))
     LEFT JOIN "public"."properties" "p" ON (("sq"."property_id" = "p"."property_id")))
     LEFT JOIN "public"."prospects" "pr" ON (("sq"."prospect_id" = "pr"."prospect_id")))
     LEFT JOIN "public"."thread_ai_state" "tai" ON (("tai"."thread_key" = (((("sq"."property_id" || ':'::"text") || ("sq"."to_phone_number")::"text") || ':'::"text") || ("sq"."from_phone_number")::"text"))))
     LEFT JOIN "public"."sms_templates" "st" ON ((("sq"."selected_template_id" = "st"."template_id") OR ("sq"."template_id" = "st"."template_id"))))
  ORDER BY "sq"."scheduled_for" DESC;


