            "send_queue"."scheduled_for",
            "send_queue"."metadata",
            "send_queue"."retry_count",
            "send_queue"."max_retries",
            "send_queue"."master_owner_id",
            "send_queue"."property_id",
            "send_queue"."prospect_id",
            (("send_queue"."from_phone_number" IS NOT NULL) AND ("send_queue"."textgrid_number_id" IS NOT NULL) AND ("send_queue"."to_phone_number" IS NOT NULL) AND ("send_queue"."message_body" IS NOT NULL) AND ("send_queue"."scheduled_for" IS NOT NULL) AND ("send_queue"."thread_key" IS NOT NULL)) AS "has_required_fields"
           FROM "public"."send_queue"
        )
 SELECT "id",
    "queue_status",
    "from_phone_number",
    "textgrid_number_id",
    "to_phone_number",
    "seller_first_name",
    "seller_display_name",
    "message_body",
    "template_id",
    "selected_template_id",
    "market",
    "current_stage",
    "thread_key",
    "dedupe_key",
    "created_at",
    "scheduled_for",
    "metadata",
    "retry_count",
    "max_retries",
    "master_owner_id",
    "property_id",
    "prospect_id",
    "has_required_fields",
        CASE
            WHEN ("queue_status" = 'paused_name_missing'::"text") THEN 'missing_name'::"text"
            WHEN ("queue_status" = 'paused_invalid_queue_row'::"text") THEN 'invalid_payload'::"text"
            WHEN ((("from_phone_number" IS NULL) OR ("textgrid_number_id" IS NULL)) AND ("queue_status" <> ALL (ARRAY['sent'::"text", 'delivered'::"text"]))) THEN 'missing_route'::"text"
            WHEN (("template_id" IS NULL) AND ("selected_template_id" IS NULL) AND ("queue_status" <> ALL (ARRAY['sent'::"text", 'delivered'::"text"]))) THEN 'missing_template'::"text"
            WHEN (("current_stage" IS NULL) AND ("queue_status" <> ALL (ARRAY['sent'::"text", 'delivered'::"text"]))) THEN 'missing_stage'::"text"
            WHEN (("message_body" IS NULL) AND ("queue_status" <> ALL (ARRAY['sent'::"text", 'delivered'::"text"]))) THEN 'missing_body'::"text"
            WHEN ("queue_status" = 'paused_duplicate'::"text") THEN 'duplicate'::"text"
            WHEN ("queue_status" = 'paused_global_lock'::"text") THEN 'global_lock'::"text"
            WHEN (("queue_status" = 'paused_max_retries'::"text") OR ("retry_count" >= "max_retries")) THEN 'max_retries'::"text"
            WHEN (("queue_status" = 'queued'::"text") AND "has_required_fields") THEN 'ready'::"text"
            ELSE 'other'::"text"
        END AS "validation_bucket",
        CASE
            WHEN ("queue_status" = 'paused_name_missing'::"text") THEN 'Seller first name is missing but required for template'::"text"
            WHEN ("queue_status" = 'paused_invalid_queue_row'::"text") THEN 'Invalid queue payload structure'::"text"
            WHEN (("from_phone_number" IS NULL) OR ("textgrid_number_id" IS NULL)) THEN 'Outbound routing not assigned'::"text"
            WHEN (("template_id" IS NULL) AND ("selected_template_id" IS NULL)) THEN 'No template resolved'::"text"
            WHEN ("current_stage" IS NULL) THEN 'Thread stage unknown'::"text"
            WHEN ("message_body" IS NULL) THEN 'Message body is empty'::"text"
            WHEN ("queue_status" = 'paused_duplicate'::"text") THEN 'Duplicate send detected'::"text"
            WHEN ("queue_status" = 'paused_global_lock'::"text") THEN 'Global sending lock active'::"text"
            WHEN ("queue_status" = 'paused_max_retries'::"text") THEN 'Maximum retry attempts reached'::"text"
            ELSE NULL::"text"
        END AS "validation_reason",
    (("queue_status" = ANY (ARRAY['paused_name_missing'::"text", 'paused_invalid_queue_row'::"text"])) AND ("to_phone_number" IS NOT NULL) AND (("master_owner_id" IS NOT NULL) OR ("property_id" IS NOT NULL) OR ("prospect_id" IS NOT NULL) OR ("thread_key" IS NOT NULL))) AS "repairable",
        CASE
            WHEN (NOT "has_required_fields") THEN "concat_ws"(', '::"text",
            CASE
                WHEN ("from_phone_number" IS NULL) THEN 'from_phone_number'::"text"
                ELSE NULL::"text"
            END,
            CASE
                WHEN ("textgrid_number_id" IS NULL) THEN 'textgrid_number_id'::"text"
                ELSE NULL::"text"
            END,
            CASE
                WHEN ("to_phone_number" IS NULL) THEN 'to_phone_number'::"text"
                ELSE NULL::"text"
            END,
            CASE
                WHEN ("message_body" IS NULL) THEN 'message_body'::"text"
                ELSE NULL::"text"
            END,
            CASE
                WHEN ("scheduled_for" IS NULL) THEN 'scheduled_for'::"text"
                ELSE NULL::"text"
            END,
            CASE
                WHEN ("thread_key" IS NULL) THEN 'thread_key'::"text"
                ELSE NULL::"text"
            END)
            ELSE NULL::"text"
        END AS "missing_fields"
   FROM "validation" "v";


