--
-- Name: recently_sold_properties_computed; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."recently_sold_properties_computed" AS
 SELECT "id",
    "source_file",
    "source_row_number",
    "property_id",
    "apn_parcel_id",
    "property_address_full",
    "property_address_city",
    "property_address_state",
    "property_address_zip",
    "property_address_county_name",
    "market",
    "property_type",
    "property_class",
    "county_land_use_code",
    "owner_id",
    "owner_name",
    "owner_name_clean",
    "owner_type",
    "is_corporate_owner",
    "out_of_state_owner",
    "owner_address_full",
    "owner_address_city",
    "owner_address_state",
    "owner_address_zip",
    "buyer_name",
    "buyer_name_clean",
    "sale_date",
    "recording_date",
    "sale_price",
    "estimated_value",
    "assessed_total_value",
    "assessed_land_value",
    "assessed_improvement_value",
    "equity_amount",
    "equity_percent",
    "estimated_repair_cost",
    "building_square_feet",
    "units_count",
    "total_bedrooms",
    "total_baths",
    "year_built",
    "effective_year_built",
    "renovation_level_classification",
    "comp_search_profile_hash",
    "price_per_sqft",
    "price_per_unit",
    "price_per_bed",
    "price_off_value",
    "percent_off",
    "potential_spread",
    "mls_current_listing_price",
    "mls_market_status",
    "mls_sold_date",
    "mls_sold_price",
    "market_status_label",
    "market_status_value",
    "market_sub_status_label",
    "market_sub_status_value",
    "latitude",
    "longitude",
    "raw_payload",
    "created_at",
    "updated_at",
    "ppbd_bed",
    "ppu",
    "ppsf",
    "sqft_range",
    "sqft_per_unit",
    "beds_per_unit",
    "purchase_info",
    "buyer_entity_strength",
    "buyer_buy_box_signal",
    "buyer_activity_signal",
    "comp_quality_score",
    "resale_margin_score",
    "investor_fit_score",
    "ppbd",
    "arv_estimate",
    "arv_ppsf",
    "year_built_bucket",
    "comp_confidence_score",
    "deal_grade",
    "target_margin_percent",
    COALESCE("ppsf", "public"."safe_divide"("sale_price", NULLIF("building_square_feet", (0)::numeric))) AS "calc_ppsf",
    COALESCE("ppu", "public"."safe_divide"("sale_price", NULLIF("units_count", (0)::numeric))) AS "calc_ppu",
    COALESCE("ppbd", "public"."safe_divide"("sale_price", NULLIF("total_bedrooms", (0)::numeric))) AS "calc_ppbd",
    COALESCE("sqft_range", "public"."calc_sqft_range"("building_square_feet")) AS "calc_sqft_range",
    COALESCE("sqft_per_unit", "public"."safe_divide"("building_square_feet", NULLIF("units_count", (0)::numeric))) AS "calc_sqft_per_unit",
    COALESCE("beds_per_unit", "public"."safe_divide"("total_bedrooms", NULLIF("units_count", (0)::numeric))) AS "calc_beds_per_unit",
    COALESCE("price_off_value", ("estimated_value" - "sale_price")) AS "calc_price_off_value",
    COALESCE("percent_off", "public"."safe_divide"((("estimated_value" - "sale_price") * (100)::numeric), NULLIF("estimated_value", (0)::numeric))) AS "calc_percent_off",
    COALESCE("potential_spread", (("estimated_value" - COALESCE("estimated_repair_cost", (0)::numeric)) - COALESCE("sale_price", (0)::numeric))) AS "calc_potential_spread",
    COALESCE("arv_estimate", "estimated_value", "mls_sold_price", "mls_current_listing_price") AS "calc_arv_estimate",
    COALESCE("arv_ppsf", "public"."safe_divide"(COALESCE("arv_estimate", "estimated_value", "mls_sold_price"), NULLIF("building_square_feet", (0)::numeric))) AS "calc_arv_ppsf",
    COALESCE("year_built_bucket", "public"."calc_year_bucket"("year_built")) AS "calc_year_built_bucket",
    COALESCE("renovation_level_classification", "public"."calc_rehab_level"("estimated_repair_cost", "building_square_feet", NULL::"text")) AS "calc_renovation_level_classification",
    COALESCE("comp_search_profile_hash", "encode"("extensions"."digest"(((((((((((((COALESCE("market", ''::"text") || '|'::"text") || COALESCE("property_type", ''::"text")) || '|'::"text") || "public"."calc_sqft_range"("building_square_feet")) || '|'::"text") || COALESCE(("total_bedrooms")::"text", ''::"text")) || '|'::"text") || COALESCE(("total_baths")::"text", ''::"text")) || '|'::"text") || "public"."calc_year_bucket"("year_built")) || '|'::"text") || COALESCE("public"."calc_rehab_level"("estimated_repair_cost", "building_square_feet", NULL::"text"), ''::"text")), 'sha256'::"text"), 'hex'::"text")) AS "calc_comp_search_profile_hash",
    COALESCE("target_margin_percent", "public"."safe_divide"((((COALESCE("estimated_value", (0)::numeric) - COALESCE("estimated_repair_cost", (0)::numeric)) - COALESCE("sale_price", (0)::numeric)) * (100)::numeric), NULLIF("estimated_value", (0)::numeric))) AS "calc_target_margin_percent",
    COALESCE("comp_confidence_score", (LEAST(100, (((((
        CASE
            WHEN ("market" IS NOT NULL) THEN 15
            ELSE 0
        END +
        CASE
            WHEN (("sale_price" IS NOT NULL) AND ("sale_price" > (0)::numeric)) THEN 20
            ELSE 0
        END) +
        CASE
            WHEN (("estimated_value" IS NOT NULL) AND ("estimated_value" > (0)::numeric)) THEN 20
            ELSE 0
        END) +
        CASE
            WHEN (("building_square_feet" IS NOT NULL) AND ("building_square_feet" > (0)::numeric)) THEN 15
            ELSE 0
        END) +
        CASE
            WHEN ("property_type" IS NOT NULL) THEN 10
            ELSE 0
        END) +
        CASE
            WHEN ("sale_date" IS NOT NULL) THEN 20
            ELSE 0
        END)))::numeric) AS "calc_comp_confidence_score",
    "public"."calc_deal_grade"("public"."safe_divide"((((COALESCE("estimated_value", (0)::numeric) - COALESCE("estimated_repair_cost", (0)::numeric)) - COALESCE("sale_price", (0)::numeric)) * (100)::numeric), NULLIF("estimated_value", (0)::numeric)), ((COALESCE("estimated_value", (0)::numeric) - COALESCE("estimated_repair_cost", (0)::numeric)) - COALESCE("sale_price", (0)::numeric)), COALESCE("comp_confidence_score", (0)::numeric)) AS "calc_deal_grade"
   FROM "public"."recently_sold_properties" "rsp";


