--
-- Name: template_number_combo_kpis_v; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."template_number_combo_kpis_v" AS
 WITH "windows" AS (
         SELECT 'today'::"text" AS "time_window",
            "date_trunc"('day'::"text", "now"()) AS "start_at"
        UNION ALL
         SELECT '24h'::"text",
            ("now"() - '24:00:00'::interval)
        UNION ALL
         SELECT '7d'::"text",
            ("now"() - '7 days'::interval)
        UNION ALL
         SELECT '30d'::"text",
            ("now"() - '30 days'::interval)
        UNION ALL
         SELECT 'all_time'::"text",
            '1970-01-01 00:00:00'::timestamp without time zone AS "timestamp"
        ), "attributed_replies" AS (
         SELECT "o"."message_event_id",
            "o"."template_key",
            "o"."textgrid_number_key",
            "o"."market",
            "o"."language",
            "o"."event_timestamp" AS "sent_at",
            "o"."delivery_status",
            "r"."message_event_id" AS "reply_id",
            "r"."detected_intent" AS "reply_intent",
            "r"."is_opt_out" AS "reply_opt_out",
            "row_number"() OVER (PARTITION BY "o"."message_event_id" ORDER BY "r"."event_timestamp") AS "reply_rank"
           FROM ("public"."message_attribution_events_v" "o"
             LEFT JOIN "public"."message_attribution_events_v" "r" ON ((("o"."thread_key" = "r"."thread_key") AND ("r"."direction" = 'inbound'::"text") AND ("r"."event_timestamp" > "o"."event_timestamp") AND ("r"."event_timestamp" <= ("o"."event_timestamp" + '14 days'::interval)))))
          WHERE ("o"."direction" = 'outbound'::"text")
        ), "first_replies" AS (
         SELECT "attributed_replies"."message_event_id",
            "attributed_replies"."template_key",
            "attributed_replies"."textgrid_number_key",
            "attributed_replies"."market",
            "attributed_replies"."language",
            "attributed_replies"."sent_at",
            "attributed_replies"."delivery_status",
            "attributed_replies"."reply_id",
            "attributed_replies"."reply_intent",
            "attributed_replies"."reply_opt_out",
            "attributed_replies"."reply_rank"
           FROM "attributed_replies"
          WHERE ("attributed_replies"."reply_rank" = 1)
        ), "base_stats" AS (
         SELECT "w"."time_window",
            "f"."template_key",
            "f"."textgrid_number_key",
            "f"."market",
            "f"."language",
            "count"(*) AS "sends",
            "count"(*) FILTER (WHERE ("f"."delivery_status" = 'delivered'::"text")) AS "delivered",
            "count"(*) FILTER (WHERE ("f"."reply_id" IS NOT NULL)) AS "replies",
            "count"(*) FILTER (WHERE ("f"."reply_intent" = ANY (ARRAY['seller_interested'::"text", 'asking_price_provided'::"text", 'asks_offer'::"text", 'ownership_confirmed'::"text", 'condition_disclosed'::"text", 'needs_call'::"text", 'needs_email'::"text"]))) AS "positives",
            "count"(*) FILTER (WHERE (("f"."reply_intent" = 'opt_out'::"text") OR ("f"."reply_opt_out" = true))) AS "opt_outs",
            "count"(*) FILTER (WHERE ("f"."reply_intent" = 'wrong_number'::"text")) AS "wrong_numbers",
            "count"(*) FILTER (WHERE ("f"."delivery_status" = 'failed'::"text")) AS "failed"
           FROM ("windows" "w"
             CROSS JOIN "first_replies" "f")
          WHERE ("f"."sent_at" >= "w"."start_at")
          GROUP BY "w"."time_window", "f"."template_key", "f"."textgrid_number_key", "f"."market", "f"."language"
        )
 SELECT "time_window",
    "template_key",
    "textgrid_number_key",
    "market",
    "language",
    "sends",
    "delivered",
    "replies",
    "positives",
    "opt_outs",
    "wrong_numbers",
    "failed",
    ((("replies")::double precision / (NULLIF("delivered", 0))::double precision) * (100)::double precision) AS "reply_rate_pct",
    ((("positives")::double precision / (NULLIF("replies", 0))::double precision) * (100)::double precision) AS "positive_rate_pct",
    ((("opt_outs")::double precision / (NULLIF("delivered", 0))::double precision) * (100)::double precision) AS "opt_out_rate_pct",
    ((("failed")::double precision / (NULLIF("sends", 0))::double precision) * (100)::double precision) AS "failure_rate_pct",
        CASE
            WHEN (("sends" >= 20) AND (((("positives")::double precision / (NULLIF("replies", 0))::double precision) * (100)::double precision) >= (15)::double precision)) THEN 'high_performer'::"text"
            WHEN (("sends" >= 20) AND (((("opt_outs")::double precision / (NULLIF("delivered", 0))::double precision) * (100)::double precision) >= (4)::double precision)) THEN 'high_opt_out'::"text"
            WHEN (("sends" >= 20) AND (((("failed")::double precision / (NULLIF("sends", 0))::double precision) * (100)::double precision) >= (20)::double precision)) THEN 'high_failure'::"text"
            ELSE 'normal'::"text"
        END AS "combo_label"
   FROM "base_stats";


--
-- Name: template_performance_kpis_v; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."template_performance_kpis_v" AS
 WITH "windows" AS (
         SELECT 'today'::"text" AS "time_window",
            "date_trunc"('day'::"text", "now"()) AS "start_at"
        UNION ALL
         SELECT '24h'::"text",
            ("now"() - '24:00:00'::interval)
        UNION ALL
         SELECT '7d'::"text",
            ("now"() - '7 days'::interval)
        UNION ALL
         SELECT '30d'::"text",
            ("now"() - '30 days'::interval)
        UNION ALL
         SELECT 'all_time'::"text",
            '1970-01-01 00:00:00'::timestamp without time zone AS "timestamp"
        ), "attributed_replies" AS (
         SELECT "o"."message_event_id",
            "o"."template_key",
            "o"."textgrid_number_key",
            "o"."event_timestamp" AS "sent_at",
            "o"."delivery_status",
            "r"."message_event_id" AS "reply_id",
            "r"."event_timestamp" AS "replied_at",
            "r"."detected_intent" AS "reply_intent",
            "r"."is_opt_out" AS "reply_opt_out",
            "r"."is_positive_reply",
            "row_number"() OVER (PARTITION BY "o"."message_event_id" ORDER BY "r"."event_timestamp") AS "reply_rank"
           FROM ("public"."message_attribution_events_v" "o"
             LEFT JOIN "public"."message_attribution_events_v" "r" ON ((("o"."thread_key" = "r"."thread_key") AND ("r"."direction" = 'inbound'::"text") AND ("r"."event_timestamp" > "o"."event_timestamp") AND ("r"."event_timestamp" <= ("o"."event_timestamp" + '14 days'::interval)))))
          WHERE ("o"."direction" = 'outbound'::"text")
        ), "first_replies" AS (
         SELECT "attributed_replies"."message_event_id",
            "attributed_replies"."template_key",
            "attributed_replies"."textgrid_number_key",
            "attributed_replies"."sent_at",
            "attributed_replies"."delivery_status",
            "attributed_replies"."reply_id",
            "attributed_replies"."replied_at",
            "attributed_replies"."reply_intent",
            "attributed_replies"."reply_opt_out",
            "attributed_replies"."is_positive_reply",
            "attributed_replies"."reply_rank"
           FROM "attributed_replies"
          WHERE ("attributed_replies"."reply_rank" = 1)
        ), "base_stats" AS (
         SELECT "w"."time_window",
            "f"."template_key",
            "count"(*) AS "sends",
            "count"(*) FILTER (WHERE ("f"."delivery_status" = 'delivered'::"text")) AS "delivered",
            "count"(*) FILTER (WHERE ("f"."delivery_status" = 'failed'::"text")) AS "failed",
            "count"(*) FILTER (WHERE ("f"."reply_id" IS NOT NULL)) AS "replies_attributed",
            "count"(*) FILTER (WHERE "f"."is_positive_reply") AS "positive_replies",
            "count"(*) FILTER (WHERE (("f"."reply_intent" = 'opt_out'::"text") OR "f"."reply_opt_out")) AS "opt_outs",
            "count"(*) FILTER (WHERE ("f"."reply_intent" = 'wrong_number'::"text")) AS "wrong_numbers",
            "avg"((EXTRACT(epoch FROM ("f"."replied_at" - "f"."sent_at")) / (3600)::numeric)) FILTER (WHERE ("f"."reply_id" IS NOT NULL)) AS "avg_response_hours"
           FROM ("windows" "w"
             CROSS JOIN "first_replies" "f")
          WHERE ("f"."sent_at" >= "w"."start_at")
          GROUP BY "w"."time_window", "f"."template_key"
        ), "calculated" AS (
         SELECT "base_stats"."time_window",
            "base_stats"."template_key",
            "base_stats"."sends",
            "base_stats"."delivered",
            "base_stats"."failed",
            "base_stats"."replies_attributed",
            "base_stats"."positive_replies",
            "base_stats"."opt_outs",
            "base_stats"."wrong_numbers",
            "base_stats"."avg_response_hours",
            ((("base_stats"."replies_attributed")::double precision / (NULLIF("base_stats"."delivered", 0))::double precision) * (100)::double precision) AS "reply_rate_pct",
            ((("base_stats"."positive_replies")::double precision / (NULLIF("base_stats"."replies_attributed", 0))::double precision) * (100)::double precision) AS "positive_rate_pct",
            ((("base_stats"."opt_outs")::double precision / (NULLIF("base_stats"."delivered", 0))::double precision) * (100)::double precision) AS "opt_out_rate_pct",
            ((("base_stats"."wrong_numbers")::double precision / (NULLIF("base_stats"."replies_attributed", 0))::double precision) * (100)::double precision) AS "wrong_number_rate_pct",
            ((("base_stats"."delivered")::double precision / (NULLIF("base_stats"."sends", 0))::double precision) * (100)::double precision) AS "delivery_rate_pct",
            ((("base_stats"."failed")::double precision / (NULLIF("base_stats"."sends", 0))::double precision) * (100)::double precision) AS "failure_rate_pct"
           FROM "base_stats"
        )
 SELECT "time_window",
    "template_key",
    "sends",
    "delivered",
    "failed",
    "replies_attributed",
    "positive_replies",
    "opt_outs",
    "wrong_numbers",
    "avg_response_hours",
    "reply_rate_pct",
    "positive_rate_pct",
    "opt_out_rate_pct",
    "wrong_number_rate_pct",
    "delivery_rate_pct",
    "failure_rate_pct",
    "sends" AS "sample_size",
        CASE
            WHEN ("sends" < 10) THEN 'insufficient_data'::"text"
            WHEN ("sends" < 30) THEN 'low_confidence'::"text"
            WHEN ("sends" < 100) THEN 'medium_confidence'::"text"
            ELSE 'high_confidence'::"text"
        END AS "confidence_bucket",
        CASE
            WHEN ("sends" < 10) THEN 'insufficient_data'::"text"
            WHEN (("sends" >= 30) AND ("positive_rate_pct" >= (12)::double precision) AND ("opt_out_rate_pct" <= (2.5)::double precision) AND ("reply_rate_pct" >= (8)::double precision)) THEN 'winner'::"text"
            WHEN ((("sends" >= 30) AND ("opt_out_rate_pct" >= (5)::double precision)) OR ("failure_rate_pct" >= (20)::double precision)) THEN 'pause_candidate'::"text"
            WHEN (("sends" >= 30) AND ("opt_out_rate_pct" >= (4)::double precision)) THEN 'risky'::"text"
            WHEN (("sends" >= 30) AND ("reply_rate_pct" < (5)::double precision)) THEN 'watch'::"text"
            WHEN ("positive_rate_pct" > (10)::double precision) THEN 'rising'::"text"
            ELSE 'stable'::"text"
        END AS "performance_label"
   FROM "calculated";


--
-- Name: textgrid_numbers_dashboard; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."textgrid_numbers_dashboard" AS
 SELECT "phone_number",
    "status",
    "messages_sent_today",
    "daily_limit",
    ("daily_limit" - "messages_sent_today") AS "remaining_today",
    "round"((((("messages_sent_today")::double precision / ("daily_limit")::double precision) * (100)::double precision))::numeric, 2) AS "usage_percentage",
    "health_score",
    "last_used_at",
        CASE
            WHEN ("messages_sent_today" >= "daily_limit") THEN 'at_limit'::"text"
            WHEN (("messages_sent_today")::numeric >= (("daily_limit")::numeric * 0.9)) THEN 'near_limit'::"text"
            WHEN ("status" = 'paused'::"text") THEN 'paused'::"text"
            ELSE 'available'::"text"
        END AS "availability_status"
   FROM "public"."textgrid_numbers"
  ORDER BY "messages_sent_today" DESC;


