--
-- Name: v_buyer_entity_purchases; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_buyer_entity_purchases" WITH ("security_invoker"='true') AS
 WITH "source_rows" AS (
         SELECT "b"."id" AS "comp_id",
            "b"."property_id",
            COALESCE(NULLIF(TRIM(BOTH FROM "b"."owner_name"), ''::"text"), NULLIF(TRIM(BOTH FROM "b"."owner_1_name"), ''::"text"), NULLIF(TRIM(BOTH FROM "b"."owner_2_name"), ''::"text")) AS "raw_buyer_name",
            NULLIF(TRIM(BOTH FROM "b"."owner_name"), ''::"text") AS "owner_name",
            NULLIF(TRIM(BOTH FROM "b"."owner_1_name"), ''::"text") AS "owner_1_name",
            NULLIF(TRIM(BOTH FROM "b"."owner_2_name"), ''::"text") AS "owner_2_name",
            NULLIF(TRIM(BOTH FROM "b"."owner_address_full"), ''::"text") AS "owner_address_full",
            NULLIF(TRIM(BOTH FROM "b"."owner_address_city"), ''::"text") AS "owner_address_city",
            NULLIF(TRIM(BOTH FROM "b"."owner_address_state"), ''::"text") AS "owner_address_state",
            NULLIF(TRIM(BOTH FROM "b"."owner_address_zip"), ''::"text") AS "owner_address_zip",
            COALESCE("b"."is_corporate_owner", false) AS "is_corporate_buyer",
            "b"."sale_date",
            COALESCE("b"."sale_price", "b"."mls_sold_price") AS "sale_price",
            "b"."mls_sold_date",
            "b"."mls_sold_price",
            NULLIF(TRIM(BOTH FROM "b"."property_address_full"), ''::"text") AS "property_address_full",
            NULLIF(TRIM(BOTH FROM "b"."property_address_city"), ''::"text") AS "property_address_city",
            NULLIF(TRIM(BOTH FROM "b"."property_address_state"), ''::"text") AS "property_address_state",
            NULLIF(TRIM(BOTH FROM "b"."property_address_zip"), ''::"text") AS "property_address_zip",
            COALESCE(NULLIF(TRIM(BOTH FROM "p"."market"), ''::"text"), NULLIF(TRIM(BOTH FROM "concat_ws"(', '::"text", "b"."property_address_city", "b"."property_address_state")), ''::"text"), NULLIF(TRIM(BOTH FROM "concat_ws"(', '::"text", "p"."property_address_city", "p"."property_address_state")), ''::"text")) AS "market",
            NULLIF(TRIM(BOTH FROM "b"."normalized_asset_class"), ''::"text") AS "normalized_asset_class",
            NULLIF(TRIM(BOTH FROM "b"."property_type"), ''::"text") AS "property_type",
            "b"."building_square_feet",
            "b"."total_bedrooms",
            "b"."total_baths",
            "b"."year_built",
            "b"."latitude",
            "b"."longitude"
           FROM ("public"."buyer_comp_raw_v2" "b"
             LEFT JOIN "public"."properties" "p" ON (("p"."property_id" = "b"."property_id")))
          WHERE (("b"."sale_date" IS NOT NULL) AND (COALESCE("b"."sale_price", "b"."mls_sold_price") IS NOT NULL) AND (COALESCE("b"."sale_price", "b"."mls_sold_price") > (0)::numeric))
        ), "normalized_rows" AS (
         SELECT "source_rows"."comp_id",
            "source_rows"."property_id",
            "source_rows"."raw_buyer_name",
            "source_rows"."owner_name",
            "source_rows"."owner_1_name",
            "source_rows"."owner_2_name",
            "source_rows"."owner_address_full",
            "source_rows"."owner_address_city",
            "source_rows"."owner_address_state",
            "source_rows"."owner_address_zip",
            "source_rows"."is_corporate_buyer",
            "source_rows"."sale_date",
            "source_rows"."sale_price",
            "source_rows"."property_address_full",
            "source_rows"."property_address_city",
            "source_rows"."property_address_state",
            "source_rows"."property_address_zip",
            "source_rows"."market",
            "source_rows"."normalized_asset_class",
            "source_rows"."property_type",
            "source_rows"."building_square_feet",
            "source_rows"."total_bedrooms",
            "source_rows"."total_baths",
            "source_rows"."year_built",
            "source_rows"."latitude",
            "source_rows"."longitude",
            "public"."normalize_buyer_entity_name"("source_rows"."raw_buyer_name") AS "normalized_buyer_name",
            "public"."normalize_buyer_entity_text"("source_rows"."owner_address_full") AS "normalized_owner_address",
            ((COALESCE("source_rows"."mls_sold_price", (0)::numeric) > (0)::numeric) OR ("source_rows"."mls_sold_date" IS NOT NULL)) AS "is_mls_purchase"
           FROM "source_rows"
        )
 SELECT "comp_id",
    "property_id",
    COALESCE("normalized_buyer_name", "concat"('unknown buyer ', COALESCE("normalized_owner_address", "property_id", ("comp_id")::"text"))) AS "buyer_entity_key",
    COALESCE("raw_buyer_name", "owner_1_name", "owner_2_name", 'Unknown Buyer'::"text") AS "buyer_display_name",
    "is_corporate_buyer",
    "owner_name",
    "owner_1_name",
    "owner_2_name",
    "owner_address_full",
    "owner_address_city",
    "owner_address_state",
    "owner_address_zip",
    "sale_date",
    "sale_price",
    "property_address_full",
    "property_address_city",
    "property_address_state",
    "property_address_zip",
    "market",
    "normalized_asset_class",
    "property_type",
    "building_square_feet",
    "total_bedrooms",
    "total_baths",
    "year_built",
    "latitude",
    "longitude",
    "is_mls_purchase",
    (NOT "is_mls_purchase") AS "is_off_market_purchase"
   FROM "normalized_rows";


--
-- Name: v_buyer_entities_from_comps; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_buyer_entities_from_comps" WITH ("security_invoker"='true') AS
 WITH "purchase_base" AS (
         SELECT "v_buyer_entity_purchases"."comp_id",
            "v_buyer_entity_purchases"."property_id",
            "v_buyer_entity_purchases"."buyer_entity_key",
            "v_buyer_entity_purchases"."buyer_display_name",
            "v_buyer_entity_purchases"."is_corporate_buyer",
            "v_buyer_entity_purchases"."owner_name",
            "v_buyer_entity_purchases"."owner_1_name",
            "v_buyer_entity_purchases"."owner_2_name",
            "v_buyer_entity_purchases"."owner_address_full",
            "v_buyer_entity_purchases"."owner_address_city",
            "v_buyer_entity_purchases"."owner_address_state",
            "v_buyer_entity_purchases"."owner_address_zip",
            "v_buyer_entity_purchases"."sale_date",
            "v_buyer_entity_purchases"."sale_price",
            "v_buyer_entity_purchases"."property_address_full",
            "v_buyer_entity_purchases"."property_address_city",
            "v_buyer_entity_purchases"."property_address_state",
            "v_buyer_entity_purchases"."property_address_zip",
            "v_buyer_entity_purchases"."market",
            "v_buyer_entity_purchases"."normalized_asset_class",
            "v_buyer_entity_purchases"."property_type",
            "v_buyer_entity_purchases"."building_square_feet",
            "v_buyer_entity_purchases"."total_bedrooms",
            "v_buyer_entity_purchases"."total_baths",
            "v_buyer_entity_purchases"."year_built",
            "v_buyer_entity_purchases"."latitude",
            "v_buyer_entity_purchases"."longitude",
            "v_buyer_entity_purchases"."is_mls_purchase",
            "v_buyer_entity_purchases"."is_off_market_purchase"
           FROM "public"."v_buyer_entity_purchases"
        ), "dominant_attributes" AS (
         SELECT DISTINCT ON ("purchase_base"."buyer_entity_key") "purchase_base"."buyer_entity_key",
            "purchase_base"."buyer_display_name",
            "purchase_base"."owner_address_full",
            "purchase_base"."owner_address_city",
            "purchase_base"."owner_address_state",
            "purchase_base"."owner_address_zip"
           FROM "purchase_base"
          ORDER BY "purchase_base"."buyer_entity_key", ("purchase_base"."buyer_display_name" <> 'Unknown Buyer'::"text") DESC, ("purchase_base"."owner_address_full" IS NOT NULL) DESC, "purchase_base"."sale_date" DESC, ("length"("purchase_base"."buyer_display_name")) DESC
        ), "zip_activity" AS (
         SELECT "ranked"."buyer_entity_key",
            "max"("ranked"."zip_purchase_count") AS "max_zip_purchase_count"
           FROM ( SELECT "purchase_base"."buyer_entity_key",
                    "purchase_base"."property_address_zip",
                    "count"(*) AS "zip_purchase_count"
                   FROM "purchase_base"
                  WHERE ("purchase_base"."property_address_zip" IS NOT NULL)
                  GROUP BY "purchase_base"."buyer_entity_key", "purchase_base"."property_address_zip") "ranked"
          GROUP BY "ranked"."buyer_entity_key"
        ), "rollup" AS (
         SELECT "p"."buyer_entity_key",
            "d"."buyer_display_name",
            "bool_or"("p"."is_corporate_buyer") AS "is_corporate_buyer",
            "d"."owner_address_full",
            "d"."owner_address_city",
            "d"."owner_address_state",
            "d"."owner_address_zip",
            "count"(*) FILTER (WHERE ("p"."sale_date" >= (CURRENT_DATE - '6 mons'::interval))) AS "purchase_count_6mo",
            "count"(*) FILTER (WHERE ("p"."sale_date" >= (CURRENT_DATE - '1 year'::interval))) AS "purchase_count_12mo",
            COALESCE("sum"("p"."sale_price") FILTER (WHERE ("p"."sale_date" >= (CURRENT_DATE - '6 mons'::interval))), (0)::numeric) AS "total_purchase_volume_6mo",
            ("percentile_cont"((0.5)::double precision) WITHIN GROUP (ORDER BY (("p"."sale_price")::double precision)))::numeric AS "median_purchase_price",
            "avg"("p"."sale_price") AS "avg_purchase_price",
            "min"("p"."sale_price") AS "min_purchase_price",
            "max"("p"."sale_price") AS "max_purchase_price",
            "max"("p"."sale_date") AS "last_purchase_date",
            "min"("p"."sale_date") AS "first_purchase_date",
            "count"(DISTINCT "p"."market") FILTER (WHERE ("p"."market" IS NOT NULL)) AS "markets_active_count",
            "count"(DISTINCT "p"."property_address_zip") FILTER (WHERE ("p"."property_address_zip" IS NOT NULL)) AS "zips_active_count",
            "count"(DISTINCT "p"."property_address_state") FILTER (WHERE ("p"."property_address_state" IS NOT NULL)) AS "states_active_count",
            COALESCE("array_agg"(DISTINCT "p"."normalized_asset_class" ORDER BY "p"."normalized_asset_class") FILTER (WHERE ("p"."normalized_asset_class" IS NOT NULL)), '{}'::"text"[]) AS "asset_classes_bought",
            COALESCE("array_agg"(DISTINCT "p"."property_type" ORDER BY "p"."property_type") FILTER (WHERE ("p"."property_type" IS NOT NULL)), '{}'::"text"[]) AS "property_types_bought",
            "avg"("p"."building_square_feet") AS "avg_sqft",
            "avg"("p"."total_bedrooms") AS "avg_beds",
            "avg"("p"."total_baths") AS "avg_baths",
            "avg"("p"."year_built") AS "avg_year_built",
            "count"(*) FILTER (WHERE "p"."is_mls_purchase") AS "mls_purchase_count",
            "count"(*) FILTER (WHERE "p"."is_off_market_purchase") AS "off_market_purchase_count",
            ("max"(
                CASE
                    WHEN ("p"."buyer_display_name" <> 'Unknown Buyer'::"text") THEN 1
                    ELSE 0
                END) = 1) AS "has_buyer_name",
            ("max"(
                CASE
                    WHEN ("p"."owner_address_full" IS NOT NULL) THEN 1
                    ELSE 0
                END) = 1) AS "has_owner_address"
           FROM ("purchase_base" "p"
             JOIN "dominant_attributes" "d" ON (("d"."buyer_entity_key" = "p"."buyer_entity_key")))
          GROUP BY "p"."buyer_entity_key", "d"."buyer_display_name", "d"."owner_address_full", "d"."owner_address_city", "d"."owner_address_state", "d"."owner_address_zip"
        ), "scored" AS (
         SELECT "r"."buyer_entity_key",
            "r"."buyer_display_name",
            "r"."is_corporate_buyer",
            "r"."owner_address_full",
            "r"."owner_address_city",
            "r"."owner_address_state",
            "r"."owner_address_zip",
            "r"."purchase_count_6mo",
            "r"."purchase_count_12mo",
            "r"."total_purchase_volume_6mo",
            "r"."median_purchase_price",
            "r"."avg_purchase_price",
            "r"."min_purchase_price",
            "r"."max_purchase_price",
            "r"."last_purchase_date",
            "r"."first_purchase_date",
            "r"."markets_active_count",
            "r"."zips_active_count",
            "r"."states_active_count",
            "r"."asset_classes_bought",
            "r"."property_types_bought",
            "r"."avg_sqft",
            "r"."avg_beds",
            "r"."avg_baths",
            "r"."avg_year_built",
            "r"."mls_purchase_count",
            "r"."off_market_purchase_count",
            "r"."has_buyer_name",
            "r"."has_owner_address",
            COALESCE("z"."max_zip_purchase_count", (0)::bigint) AS "max_zip_purchase_count",
            (GREATEST((0)::numeric, LEAST((100)::numeric, ("round"((((((((((((10 + LEAST((28)::bigint, ("r"."purchase_count_12mo" * 8))) + LEAST((12)::bigint, ("r"."purchase_count_6mo" * 4))) +
                CASE
                    WHEN "r"."is_corporate_buyer" THEN 8
                    ELSE 0
                END) +
                CASE
                    WHEN ("r"."last_purchase_date" >= (CURRENT_DATE - '45 days'::interval)) THEN 12
                    WHEN ("r"."last_purchase_date" >= (CURRENT_DATE - '90 days'::interval)) THEN 8
                    WHEN ("r"."last_purchase_date" >= (CURRENT_DATE - '180 days'::interval)) THEN 4
                    ELSE 0
                END) + LEAST((10)::bigint, (COALESCE("z"."max_zip_purchase_count", (0)::bigint) * 2))) + LEAST((8)::bigint, ("r"."off_market_purchase_count" * 2))) +
                CASE
                    WHEN ("r"."total_purchase_volume_6mo" >= (2000000)::numeric) THEN 10
                    WHEN ("r"."total_purchase_volume_6mo" >= (1000000)::numeric) THEN 8
                    WHEN ("r"."total_purchase_volume_6mo" >= (500000)::numeric) THEN 5
                    WHEN ("r"."total_purchase_volume_6mo" >= (250000)::numeric) THEN 3
                    ELSE 0
                END) -
                CASE
                    WHEN (("r"."purchase_count_12mo" = 1) AND (NOT "r"."is_corporate_buyer")) THEN 18
                    ELSE 0
                END) -
                CASE
                    WHEN (NOT "r"."has_buyer_name") THEN 15
                    ELSE 0
                END) -
                CASE
                    WHEN (NOT "r"."has_owner_address") THEN 8
                    ELSE 0
                END))::double precision))::numeric)))::integer AS "buyer_confidence_score"
           FROM ("rollup" "r"
             LEFT JOIN "zip_activity" "z" ON (("z"."buyer_entity_key" = "r"."buyer_entity_key")))
        )
 SELECT "buyer_entity_key",
    "buyer_display_name",
    "is_corporate_buyer",
    "owner_address_full",
    "owner_address_city",
    "owner_address_state",
    "owner_address_zip",
    "purchase_count_6mo",
    "purchase_count_12mo",
    "total_purchase_volume_6mo",
    "median_purchase_price",
    "avg_purchase_price",
    "min_purchase_price",
    "max_purchase_price",
    "last_purchase_date",
    "first_purchase_date",
    "markets_active_count",
    "zips_active_count",
    "states_active_count",
    "asset_classes_bought",
    "property_types_bought",
    "avg_sqft",
    "avg_beds",
    "avg_baths",
    "avg_year_built",
    "mls_purchase_count",
    "off_market_purchase_count",
    "buyer_confidence_score",
        CASE
            WHEN (("buyer_confidence_score" >= 90) AND ("purchase_count_12mo" >= 4)) THEN 'A+'::"text"
            WHEN (("buyer_confidence_score" >= 75) AND ("purchase_count_12mo" >= 2)) THEN 'A'::"text"
            WHEN ("buyer_confidence_score" >= 55) THEN 'B'::"text"
            WHEN ("buyer_confidence_score" >= 35) THEN 'Watchlist'::"text"
            ELSE 'Noise'::"text"
        END AS "buyer_grade",
    "concat_ws"(' • '::"text",
        CASE
            WHEN ("purchase_count_6mo" > 0) THEN (("purchase_count_6mo")::"text" || ' buys in 6mo'::"text")
            ELSE (("purchase_count_12mo")::"text" || ' buys in 12mo'::"text")
        END,
        CASE
            WHEN ("off_market_purchase_count" > 0) THEN (("off_market_purchase_count")::"text" || ' off-market'::"text")
            ELSE (("mls_purchase_count")::"text" || ' MLS'::"text")
        END,
        CASE
            WHEN ("markets_active_count" > 1) THEN (("markets_active_count")::"text" || ' active markets'::"text")
            WHEN ("zips_active_count" > 1) THEN (("zips_active_count")::"text" || ' active ZIPs'::"text")
            ELSE 'Focused buy box'::"text"
        END,
        CASE
            WHEN "is_corporate_buyer" THEN 'Corporate buyer'::"text"
            ELSE 'Individual buyer'::"text"
        END,
        CASE
            WHEN ("last_purchase_date" IS NOT NULL) THEN (('Last buy '::"text" || ((CURRENT_DATE - "last_purchase_date"))::"text") || 'd ago'::"text")
            ELSE NULL::"text"
        END) AS "buyer_signal_summary"
   FROM "scored" "s";


--
-- Name: v_buyer_entity_leaderboard; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_buyer_entity_leaderboard" WITH ("security_invoker"='true') AS
 WITH "market_counts" AS (
         SELECT "p"."buyer_entity_key",
            "p"."market",
            "count"(*) AS "purchase_count"
           FROM "public"."v_buyer_entity_purchases" "p"
          WHERE ("p"."market" IS NOT NULL)
          GROUP BY "p"."buyer_entity_key", "p"."market"
        ), "market_ranked" AS (
         SELECT "m"."buyer_entity_key",
            "m"."market",
            "m"."purchase_count",
            "row_number"() OVER (PARTITION BY "m"."buyer_entity_key" ORDER BY "m"."purchase_count" DESC, "m"."market") AS "market_rank"
           FROM "market_counts" "m"
        ), "market_summary" AS (
         SELECT "market_ranked"."buyer_entity_key",
            "array_agg"("market_ranked"."market" ORDER BY "market_ranked"."purchase_count" DESC, "market_ranked"."market") FILTER (WHERE ("market_ranked"."market_rank" <= 5)) AS "top_markets"
           FROM "market_ranked"
          GROUP BY "market_ranked"."buyer_entity_key"
        ), "zip_counts" AS (
         SELECT "p"."buyer_entity_key",
            "p"."property_address_zip" AS "zip_code",
            "count"(*) AS "purchase_count"
           FROM "public"."v_buyer_entity_purchases" "p"
          WHERE ("p"."property_address_zip" IS NOT NULL)
          GROUP BY "p"."buyer_entity_key", "p"."property_address_zip"
        ), "zip_ranked" AS (
         SELECT "z"."buyer_entity_key",
            "z"."zip_code",
            "z"."purchase_count",
            "row_number"() OVER (PARTITION BY "z"."buyer_entity_key" ORDER BY "z"."purchase_count" DESC, "z"."zip_code") AS "zip_rank"
           FROM "zip_counts" "z"
        ), "zip_summary" AS (
         SELECT "zip_ranked"."buyer_entity_key",
            "array_agg"("zip_ranked"."zip_code" ORDER BY "zip_ranked"."purchase_count" DESC, "zip_ranked"."zip_code") FILTER (WHERE ("zip_ranked"."zip_rank" <= 5)) AS "top_zips"
           FROM "zip_ranked"
          GROUP BY "zip_ranked"."buyer_entity_key"
        ), "state_counts" AS (
         SELECT "p"."buyer_entity_key",
            "p"."property_address_state",
            "count"(*) AS "purchase_count"
           FROM "public"."v_buyer_entity_purchases" "p"
          WHERE ("p"."property_address_state" IS NOT NULL)
          GROUP BY "p"."buyer_entity_key", "p"."property_address_state"
        ), "state_ranked" AS (
         SELECT "s"."buyer_entity_key",
            "s"."property_address_state",
            "s"."purchase_count",
            "row_number"() OVER (PARTITION BY "s"."buyer_entity_key" ORDER BY "s"."purchase_count" DESC, "s"."property_address_state") AS "state_rank"
           FROM "state_counts" "s"
        ), "state_summary" AS (
         SELECT "state_ranked"."buyer_entity_key",
            "array_agg"("state_ranked"."property_address_state" ORDER BY "state_ranked"."purchase_count" DESC, "state_ranked"."property_address_state") FILTER (WHERE ("state_ranked"."state_rank" <= 5)) AS "top_states"
           FROM "state_ranked"
          GROUP BY "state_ranked"."buyer_entity_key"
        )
 SELECT "e"."buyer_entity_key",
    "e"."buyer_display_name",
    "e"."is_corporate_buyer",
    "e"."owner_address_full",
    "e"."owner_address_city",
    "e"."owner_address_state",
    "e"."owner_address_zip",
    "e"."purchase_count_6mo",
    "e"."purchase_count_12mo",
    "e"."total_purchase_volume_6mo",
    "e"."median_purchase_price",
    "e"."avg_purchase_price",
    "e"."min_purchase_price",
    "e"."max_purchase_price",
    "e"."last_purchase_date",
    "e"."first_purchase_date",
    "e"."markets_active_count",
    "e"."zips_active_count",
    "e"."states_active_count",
    "e"."asset_classes_bought",
    "e"."property_types_bought",
    "e"."avg_sqft",
    "e"."avg_beds",
    "e"."avg_baths",
    "e"."avg_year_built",
    "e"."mls_purchase_count",
    "e"."off_market_purchase_count",
    "e"."buyer_confidence_score",
    "e"."buyer_grade",
    "e"."buyer_signal_summary",
    COALESCE("ms"."top_markets", '{}'::"text"[]) AS "top_markets",
    COALESCE("zs"."top_zips", '{}'::"text"[]) AS "top_zips",
    COALESCE("ss"."top_states", '{}'::"text"[]) AS "top_states",
    ("e"."purchase_count_12mo" >= 2) AS "is_repeat_buyer",
    ("e"."buyer_grade" = ANY (ARRAY['A+'::"text", 'A'::"text", 'B'::"text"])) AS "is_real_buyer",
    ("e"."off_market_purchase_count" > 0) AS "is_off_market_buyer",
    (("e"."owner_address_state" IS NOT NULL) AND (EXISTS ( SELECT 1
           FROM "state_ranked" "s"
          WHERE (("s"."buyer_entity_key" = "e"."buyer_entity_key") AND ("s"."state_rank" = 1) AND ("s"."property_address_state" = "e"."owner_address_state"))))) AS "is_local_buyer",
    ("e"."buyer_grade" = ANY (ARRAY['Noise'::"text", 'Watchlist'::"text"])) AS "is_retail_or_noise"
   FROM ((("public"."v_buyer_entities_from_comps" "e"
     LEFT JOIN "market_summary" "ms" ON (("ms"."buyer_entity_key" = "e"."buyer_entity_key")))
     LEFT JOIN "zip_summary" "zs" ON (("zs"."buyer_entity_key" = "e"."buyer_entity_key")))
     LEFT JOIN "state_summary" "ss" ON (("ss"."buyer_entity_key" = "e"."buyer_entity_key")));


--
-- Name: v_buyer_property_matches_unified; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_buyer_property_matches_unified" AS
 SELECT "buyer_property_matches_v2"."id",
    "buyer_property_matches_v2"."subject_property_id" AS "property_id",
    "buyer_property_matches_v2"."buyer_key",
    "buyer_property_matches_v2"."fit_score" AS "match_score",
    "buyer_property_matches_v2"."geo_fit_score" AS "market_fit_score",
    "buyer_property_matches_v2"."asset_fit_score",
    "buyer_property_matches_v2"."price_fit_score",
    "buyer_property_matches_v2"."velocity_fit_score" AS "velocity_score",
    "buyer_property_matches_v2"."reason",
    "buyer_property_matches_v2"."nearest_purchase_distance_miles",
    "buyer_property_matches_v2"."last_matched_purchase_date",
    "buyer_property_matches_v2"."created_at",
    "buyer_property_matches_v2"."updated_at"
   FROM "public"."buyer_property_matches_v2"
UNION ALL
 SELECT "buyer_property_matches"."id",
    "buyer_property_matches"."property_id",
    "buyer_property_matches"."buyer_key",
    "buyer_property_matches"."match_score",
    "buyer_property_matches"."market_fit_score",
    "buyer_property_matches"."asset_fit_score",
    "buyer_property_matches"."price_fit_score",
    "buyer_property_matches"."velocity_score",
    "buyer_property_matches"."reason_for_match" AS "reason",
    NULL::numeric AS "nearest_purchase_distance_miles",
    NULL::"date" AS "last_matched_purchase_date",
    "buyer_property_matches"."created_at",
    "buyer_property_matches"."updated_at"
   FROM "public"."buyer_property_matches"
  WHERE (NOT (EXISTS ( SELECT 1
           FROM "public"."buyer_property_matches_v2" "v2"
          WHERE (("v2"."buyer_key" = "buyer_property_matches"."buyer_key") AND ("v2"."subject_property_id" = "buyer_property_matches"."property_id")))));


--
-- Name: v_property_lead_command; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_property_lead_command" AS
 SELECT "p"."property_export_id",
    "p"."upsert_key" AS "property_upsert_key",
    "p"."property_id",
    "p"."apn_parcel_id",
    "p"."master_owner_id",
    "p"."master_key",
    "p"."owner_id",
    "p"."property_address_full",
    "p"."property_address_city",
    "p"."property_address_state",
    "p"."property_address_zip",
    "p"."property_address_county_name",
    "p"."market",
    "p"."latitude",
    "p"."longitude",
    "p"."property_type",
    "p"."property_class",
    "p"."year_built",
    "p"."building_square_feet",
    "p"."total_bedrooms",
    "p"."total_baths",
    "p"."units_count",
    "p"."estimated_value",
    "p"."equity_amount",
    "p"."equity_percent",
    "p"."total_loan_balance",
    "p"."total_loan_payment",
    "p"."tax_amt",
    "p"."cash_offer",
    "p"."estimated_repair_cost",
    "p"."estimated_repair_cost_per_sqft",
    "p"."ai_score",
    "p"."structured_motivation_score",
    "p"."deal_strength_score",
    "p"."tag_distress_score",
    "p"."final_acquisition_score",
    "p"."podio_tags",
    "p"."rehab_level",
    "p"."offer_vs_loan",
    "p"."offer_vs_sale_price",
    "p"."options",
    "p"."contact_status",
    "p"."search_profile_hash",
    "p"."sale_date",
    "p"."recording_date",
    "p"."ownership_years",
    "mo"."display_name" AS "owner_display_name",
    "mo"."primary_owner_address",
    "mo"."owner_type_guess",
    "mo"."priority_tier",
    "mo"."follow_up_cadence",
    "mo"."best_channel",
    "mo"."agent_persona",
    "mo"."agent_family",
    "mo"."best_language",
    "pr"."first_name" AS "prospect_first_name",
    "pr"."full_name" AS "prospect_display_name",
    "pr"."prospect_id" AS "primary_prospect_id",
    "ph"."phone_id" AS "best_phone_id",
    "ph"."phone" AS "best_phone",
    "ph"."canonical_e164" AS "best_phone_e164",
    "ph"."phone_type",
    "ph"."best_phone_score",
        CASE
            WHEN (("ph"."canonical_e164" IS NOT NULL) AND ("ph"."phone_type" = 'W'::"text") AND (COALESCE("ph"."activity_status", ''::"text") ~~* '%active%'::"text") AND (COALESCE("ph"."activity_status", ''::"text") !~~* '%inactive%'::"text")) THEN true
            ELSE false
        END AS "sms_eligible",
    "ph"."activity_status",
    "ph"."usage_12_months",
    "ph"."usage_2_months",
    "ph"."contact_window",
    "ph"."timezone",
    "em"."email_id" AS "best_email_id",
    "em"."email" AS "best_email",
    "em"."email_score_final"
   FROM (((("public"."properties" "p"
     LEFT JOIN "public"."master_owners" "mo" ON (("mo"."master_owner_id" = "p"."master_owner_id")))
     LEFT JOIN "public"."prospects" "pr" ON (("pr"."prospect_id" = "mo"."best_prospect_id")))
     LEFT JOIN LATERAL ( SELECT "ph_1"."phone_id",
            "ph_1"."master_owner_id",
            "ph_1"."master_key",
            "ph_1"."canonical_e164",
            "ph_1"."phone_raw",
            "ph_1"."phone",
            "ph_1"."sort_rank",
            "ph_1"."best_phone_score",
            "ph_1"."phone_type",
            "ph_1"."phone_owner",
            "ph_1"."activity_status",
            "ph_1"."usage_12_months",
            "ph_1"."usage_2_months",
            "ph_1"."primary_prospect_id",
            "ph_1"."canonical_prospect_id",
            "ph_1"."best_slot",
            "ph_1"."contact_rank_position",
            "ph_1"."contact_score_final",
            "ph_1"."linked_source_slots_text",
            "ph_1"."linked_source_slots_json",
            "ph_1"."linked_prospect_ids_text",
            "ph_1"."linked_prospect_ids_json",
            "ph_1"."linked_individual_keys_text",
            "ph_1"."linked_individual_keys_json",
            "ph_1"."linked_languages_text",
            "ph_1"."linked_languages_json",
            "ph_1"."is_best_phone_for_slot",
            "ph_1"."is_best_phone_for_owner",
            "ph_1"."owner_display_name",
            "ph_1"."primary_market",
            "ph_1"."timezone",
            "ph_1"."contact_window",
            "ph_1"."sending_priority_tier",
            "ph_1"."upsert_key",
            "ph_1"."source_system",
            "ph_1"."export_version",
            "ph_1"."exported_at_utc",
            "ph_1"."row_hash",
            "ph_1"."created_at",
            "ph_1"."updated_at"
           FROM "public"."phones" "ph_1"
          WHERE ("ph_1"."master_owner_id" = "p"."master_owner_id")
          ORDER BY "ph_1"."is_best_phone_for_owner" DESC NULLS LAST, "ph_1"."best_phone_score" DESC NULLS LAST, "ph_1"."sort_rank"
         LIMIT 1) "ph" ON (true))
     LEFT JOIN LATERAL ( SELECT "em_1"."email_id",
            "em_1"."master_owner_id",
            "em_1"."master_key",
            "em_1"."email",
            "em_1"."email_normalized",
            "em_1"."sort_rank",
            "em_1"."email_linkage_score_raw",
            "em_1"."email_score_final",
            "em_1"."email_rank",
            "em_1"."email_role",
            "em_1"."primary_prospect_id",
            "em_1"."canonical_prospect_id",
            "em_1"."best_slot",
            "em_1"."contact_rank_position",
            "em_1"."contact_score_final",
            "em_1"."linked_source_slots_text",
            "em_1"."linked_source_slots_json",
            "em_1"."linked_prospect_ids_text",
            "em_1"."linked_prospect_ids_json",
            "em_1"."linked_individual_keys_text",
            "em_1"."linked_individual_keys_json",
            "em_1"."linked_languages_text",
            "em_1"."linked_languages_json",
            "em_1"."is_best_email_for_slot",
            "em_1"."is_best_email_for_owner",
            "em_1"."owner_display_name",
            "em_1"."primary_market",
            "em_1"."timezone",
            "em_1"."sending_priority_tier",
            "em_1"."email_eligible",
            "em_1"."upsert_key",
            "em_1"."source_system",
            "em_1"."export_version",
            "em_1"."exported_at_utc",
            "em_1"."row_hash",
            "em_1"."created_at",
            "em_1"."updated_at"
           FROM "public"."emails" "em_1"
          WHERE ("em_1"."master_owner_id" = "p"."master_owner_id")
          ORDER BY "em_1"."is_best_email_for_owner" DESC NULLS LAST, "em_1"."email_score_final" DESC NULLS LAST, "em_1"."sort_rank"
         LIMIT 1) "em" ON (true));


--
-- Name: v_sms_campaign_queue_candidates; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_sms_campaign_queue_candidates" AS
 SELECT DISTINCT ON ("best_phone_e164") "property_export_id",
    "property_id",
    "property_address_full",
    "property_address_city",
    "property_address_state",
    "property_address_zip",
    "property_address_county_name",
    "market",
    "master_owner_id",
    "master_key",
    "owner_display_name",
    "prospect_first_name",
    "prospect_display_name",
    "primary_prospect_id",
    "primary_owner_address",
    "best_phone_id",
    "best_phone",
    "best_phone_e164",
    "phone_type",
    "best_phone_score",
    "sms_eligible",
    "activity_status",
    "contact_window",
    "timezone",
    "best_email_id",
    "best_email",
    "priority_tier",
    "agent_persona",
    "agent_family",
    "best_language",
    "cash_offer",
    "estimated_value",
    "equity_amount",
    "equity_percent",
    "estimated_repair_cost",
    "final_acquisition_score",
    "podio_tags",
    "rehab_level",
    "offer_vs_loan",
    "offer_vs_sale_price",
    "options",
    "contact_status",
    "ownership_years"
   FROM "public"."v_property_lead_command"
  WHERE (("sms_eligible" = true) AND ("best_phone_e164" IS NOT NULL) AND ("master_owner_id" IS NOT NULL))
  ORDER BY "best_phone_e164",
        CASE "priority_tier"
            WHEN 'TIER_1'::"text" THEN 1
            WHEN 'TIER_2'::"text" THEN 2
            WHEN 'TIER_3'::"text" THEN 3
            ELSE 9
        END, "final_acquisition_score" DESC NULLS LAST, "equity_percent" DESC NULLS LAST, "estimated_value" DESC NULLS LAST;


--
-- Name: v_outbound_candidate_freshness; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_outbound_candidate_freshness" AS
 SELECT "c"."property_export_id",
    "c"."property_id",
    "c"."property_address_full",
    "c"."property_address_city",
    "c"."property_address_state",
    "c"."property_address_zip",
    "c"."property_address_county_name",
    "c"."market",
    "c"."master_owner_id",
    "c"."master_key",
    "c"."owner_display_name",
    "c"."prospect_first_name",
    "c"."prospect_display_name",
    "c"."primary_prospect_id",
    "c"."primary_owner_address",
    "c"."best_phone_id",
    "c"."best_phone",
    "c"."best_phone_e164",
    "c"."phone_type",
    "c"."best_phone_score",
    "c"."sms_eligible",
    "c"."activity_status",
    "c"."contact_window",
    "c"."timezone",
    "c"."best_email_id",
    "c"."best_email",
    "c"."priority_tier",
    "c"."agent_persona",
    "c"."agent_family",
    "c"."best_language",
    "c"."cash_offer",
    "c"."estimated_value",
    "c"."equity_amount",
    "c"."equity_percent",
    "c"."estimated_repair_cost",
    "c"."final_acquisition_score",
    "c"."podio_tags",
    "c"."rehab_level",
    "c"."offer_vs_loan",
    "c"."offer_vs_sale_price",
    "c"."options",
    "c"."contact_status",
    "c"."ownership_years",
    "p"."property_type",
    "p"."property_class",
    "s"."last_sms_at",
    "s"."last_outbound_at",
    "s"."next_allowed_sms_at",
    "s"."current_touch_number",
    "s"."is_paused",
    "s"."pause_reason",
    (COALESCE("s"."last_sms_at", "s"."last_outbound_at") IS NULL) AS "never_contacted",
        CASE
            WHEN ("s"."last_sms_at" IS NULL) THEN (100)::numeric
            ELSE GREATEST((0)::numeric, ((100)::numeric - EXTRACT(days FROM ("now"() - "s"."last_sms_at"))))
        END AS "freshness_score"
   FROM (("public"."v_sms_campaign_queue_candidates" "c"
     LEFT JOIN "public"."v_property_lead_command" "p" ON (("c"."property_id" = "p"."property_id")))
     LEFT JOIN "public"."contact_outreach_state" "s" ON ((("c"."master_owner_id" = "s"."podio_master_owner_id") AND ("c"."best_phone_e164" = "s"."to_phone_number"))));


--
-- Name: v_candidate_exhaustion_metrics; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_candidate_exhaustion_metrics" AS
 SELECT "market",
    "priority_tier",
    "count"(*) AS "total_candidates",
    "count"(*) FILTER (WHERE ("never_contacted" = true)) AS "never_contacted_count",
    "count"(*) FILTER (WHERE ("last_sms_at" IS NOT NULL)) AS "contacted_count",
    "count"(*) FILTER (WHERE ("next_allowed_sms_at" > "now"())) AS "suppressed_count",
    "round"("avg"("final_acquisition_score"), 2) AS "avg_score"
   FROM "public"."v_outbound_candidate_freshness"
  GROUP BY "market", "priority_tier";


--
-- Name: v_feeder_candidates_fast; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_feeder_candidates_fast" AS
 SELECT "c"."property_export_id",
    "c"."property_id",
    "c"."property_address_full",
    "c"."property_address_city",
    "c"."property_address_state",
    "c"."property_address_zip",
    "c"."property_address_county_name",
    "c"."market",
    "c"."master_owner_id",
    "c"."master_key",
    "c"."owner_display_name",
    "c"."prospect_first_name",
    "c"."prospect_display_name",
    "c"."primary_prospect_id",
    "c"."primary_owner_address",
    "c"."best_phone_id",
    "c"."best_phone",
    "c"."best_phone_e164",
    "c"."phone_type",
    "c"."best_phone_score",
    "c"."sms_eligible",
    "c"."activity_status",
    "c"."contact_window",
    "c"."timezone",
    "c"."best_email_id",
    "c"."best_email",
    "c"."priority_tier",
    "c"."agent_persona",
    "c"."agent_family",
    "c"."best_language",
    "c"."cash_offer",
    "c"."estimated_value",
    "c"."equity_amount",
    "c"."equity_percent",
    "c"."estimated_repair_cost",
    "c"."final_acquisition_score",
    "c"."podio_tags",
    "c"."rehab_level",
    "c"."offer_vs_loan",
    "c"."offer_vs_sale_price",
    "c"."options",
    "c"."contact_status",
    "c"."ownership_years",
    "cos"."last_sms_at",
    "cos"."last_outbound_at",
    "cos"."next_allowed_sms_at",
    "cos"."first_outbound_at",
    "cos"."last_touch_at",
    COALESCE("cos"."touch_count", 0) AS "touch_count",
    COALESCE("cos"."current_touch_number", 0) AS "current_touch_number",
    "cos"."suppression_until",
    "cos"."suppression_reason",
    "cos"."is_paused",
    "cos"."pause_reason",
    (("cos"."podio_master_owner_id" IS NULL) OR ("cos"."last_sms_at" IS NULL)) AS "never_contacted",
    COALESCE("cos"."touch_count", 0) AS "freshness_score",
    "pr"."prospect_id" AS "canonical_prospect_id",
    "pr"."full_name" AS "prospect_full_name",
    "pr"."matching_flags",
    "pr"."matching_flags" AS "prospect_matching_flags",
    "pr"."person_flags_text",
    "pr"."likely_owner",
    "pr"."likely_renting"
   FROM (("public"."v_sms_campaign_queue_candidates" "c"
     LEFT JOIN LATERAL ( SELECT "p"."prospect_id",
            "p"."full_name",
            "p"."matching_flags",
            "p"."person_flags_text",
            "p"."likely_owner",
            "p"."likely_renting"
           FROM "public"."prospects" "p"
          WHERE ("p"."master_owner_id" = "c"."master_owner_id")
          ORDER BY (("p"."matching_flags" IS NOT NULL) AND ("p"."matching_flags" <> ''::"text")) DESC, "p"."is_primary_prospect" DESC NULLS LAST, "p"."phone_score_final" DESC NULLS LAST, "p"."prospect_id"
         LIMIT 1) "pr" ON (true))
     LEFT JOIN "public"."contact_outreach_state" "cos" ON ((("cos"."podio_master_owner_id" = "c"."master_owner_id") AND ("cos"."to_phone_number" = "c"."best_phone_e164"))))
  WHERE (("c"."sms_eligible" = true) AND ("c"."best_phone_e164" IS NOT NULL) AND ("c"."master_owner_id" IS NOT NULL) AND ("c"."property_id" IS NOT NULL) AND (("cos"."suppression_until" IS NULL) OR ("cos"."suppression_until" <= "now"())) AND (("cos"."is_paused" IS NULL) OR ("cos"."is_paused" = false)) AND (("cos"."dnc" IS NULL) OR ("cos"."dnc" = false)))
  ORDER BY
        CASE
            WHEN (("cos"."podio_master_owner_id" IS NULL) OR ("cos"."last_sms_at" IS NULL)) THEN 0
            ELSE 1
        END, COALESCE("cos"."touch_count", 0), "c"."final_acquisition_score" DESC NULLS LAST, "c"."best_phone_score" DESC NULLS LAST, "c"."equity_percent" DESC NULLS LAST;


--
-- Name: v_identity_guard_metrics; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_identity_guard_metrics" AS
 SELECT "market",
    "count"(*) AS "total_quarantined",
    "count"(*) FILTER (WHERE ("identity_alignment_status" = 'verified'::"text")) AS "verified_count",
    "count"(*) FILTER (WHERE ("identity_alignment_status" = 'probable'::"text")) AS "probable_count",
    "count"(*) FILTER (WHERE ("identity_alignment_status" = 'weak'::"text")) AS "weak_count",
    "count"(*) FILTER (WHERE ("identity_alignment_status" = 'unknown'::"text")) AS "unknown_count",
    "count"(*) FILTER (WHERE ("identity_alignment_status" = 'mismatch'::"text")) AS "mismatch_count",
    "count"(*) FILTER (WHERE ("identity_alignment_status" = 'mismatch'::"text")) AS "hard_block_count",
    "round"(((("count"(*) FILTER (WHERE ("identity_alignment_status" = 'mismatch'::"text")))::numeric / (NULLIF("count"(*), 0))::numeric) * (100)::numeric), 2) AS "mismatch_rate",
    "count"(*) FILTER (WHERE (("identity_alignment_status" = 'mismatch'::"text") AND ((("metadata" ->> 'best_phone_score'::"text"))::integer >= 70))) AS "high_risk_mismatch_count",
    "max"("blocked_at") AS "last_blocked_at",
    "now"() AS "updated_at"
   FROM "public"."outbound_identity_quarantine"
  GROUP BY "market";


