            "e"."calculated_total_value",
            "e"."calculated_land_value",
            "e"."calculated_improvement_value",
            "e"."sale_price",
            "e"."sale_date",
            "e"."recording_date",
            "e"."last_sale_doc_type",
            "e"."past_due_amount",
            "e"."ai_score",
            "e"."is_corporate_owner",
            "e"."out_of_state_owner",
            "e"."detected_intent",
            "e"."queue_stage",
            "e"."automation_state",
            "e"."last_message_iso",
            "e"."preview",
            "e"."display_name",
            "e"."display_address",
            "e"."display_phone",
            "e"."display_market",
            "e"."display_status",
            "e"."display_score",
            "e"."inbox_category",
            "e"."filter_market",
            "e"."pipeline_stage",
            "e"."seller_state",
            "e"."seller_status",
            "e"."execution_state",
            "e"."filter_state",
            "e"."filter_city",
            "e"."filter_zip",
            "e"."filter_property_type",
            "e"."_direction",
            "e"."_category",
            "e"."_intent",
            "e"."_stage",
            "e"."_status",
                CASE
                    WHEN ("e"."_direction" ~~ 'in%'::"text") THEN 'inbound'::"text"
                    WHEN ("e"."_direction" ~~ 'out%'::"text") THEN 'outbound'::"text"
                    ELSE NULLIF("e"."latest_direction", ''::"text")
                END AS "latest_message_direction",
            (COALESCE("e"."is_suppressed", false) OR ("e"."_category" = ANY (ARRAY['dnc_opt_out'::"text", 'suppressed'::"text"])) OR ("e"."_intent" = ANY (ARRAY['opt_out'::"text", 'stop'::"text", 'unsubscribe'::"text", 'dnc'::"text", 'do_not_contact'::"text"]))) AS "resolved_opt_out",
            (("e"."_intent" = ANY (ARRAY['wrong_number'::"text", 'wrong_person'::"text", 'deceased'::"text"])) OR ("e"."_status" = 'wrong_number'::"text") OR ("e"."_stage" = 'wrong_number'::"text")) AS "resolved_wrong_number",
            (("e"."_intent" = ANY (ARRAY['not_interested'::"text", 'negative'::"text", 'hostile'::"text", 'hostile_or_legal'::"text"])) OR ("e"."_status" = 'not_interested'::"text") OR ("e"."_stage" = 'not_interested'::"text")) AS "resolved_not_interested",
            (("e"."_category" = ANY (ARRAY['automated'::"text", 'needs_review'::"text", 'manual_review'::"text"])) OR ("e"."_status" = ANY (ARRAY['needs_review'::"text", 'review_required'::"text"])) OR ("e"."_stage" = ANY (ARRAY['needs_review'::"text", 'review_required'::"text"])) OR ("e"."_intent" = ANY (ARRAY['property_correction'::"text", 'unclear'::"text"]))) AS "resolved_needs_review",
            (("e"."_category" = ANY (ARRAY['hot_leads'::"text", 'priority'::"text"])) OR COALESCE("e"."show_in_priority_inbox", false) OR COALESCE("e"."is_hot_lead", false) OR ("e"."_intent" = ANY (ARRAY['seller_interested'::"text", 'qualified_lead'::"text", 'asking_price_provided'::"text", 'asks_offer'::"text", 'wants_offer'::"text", 'offer_requested'::"text", 'contract_ready'::"text", 'price_anchor'::"text", 'ownership_confirmed'::"text", 'needs_call'::"text", 'callback_requested'::"text", 'latent_interest'::"text"]))) AS "resolved_priority"
           FROM "enriched" "e"
        ), "bucketed" AS (
         SELECT "c"."latest_message_direction",
            COALESCE("c"."property_id", "c"."final_property_id") AS "property_id",
            1 AS "duplicate_property_count",
                CASE
                    WHEN "c"."resolved_opt_out" THEN 'suppressed'::"text"
                    WHEN ("c"."resolved_wrong_number" OR "c"."resolved_not_interested" OR ("c"."_category" = ANY (ARRAY['dead'::"text", 'wrong_number'::"text"])) OR ("c"."_stage" = 'dead'::"text")) THEN 'dead'::"text"
                    WHEN ("c"."_category" = 'hot_leads'::"text") THEN 'priority'::"text"
                    WHEN ("c"."_category" = 'new_inbound'::"text") THEN 'new_replies'::"text"
                    WHEN ("c"."_category" = 'automated'::"text") THEN 'needs_review'::"text"
                    WHEN ("c"."_category" = 'outbound_active'::"text") THEN 'follow_up'::"text"
                    WHEN ("c"."_category" = 'cold_no_response'::"text") THEN 'cold'::"text"
                    WHEN "c"."resolved_needs_review" THEN 'needs_review'::"text"
                    WHEN "c"."resolved_priority" THEN 'priority'::"text"
                    WHEN ("c"."latest_message_direction" = 'inbound'::"text") THEN 'new_replies'::"text"
                    WHEN ("c"."_category" = ANY (ARRAY['outbound_active'::"text", 'follow_up'::"text", 'follow_up_due'::"text"])) THEN 'follow_up'::"text"
                    WHEN ("c"."last_inbound_at" IS NOT NULL) THEN 'follow_up'::"text"
                    ELSE 'cold'::"text"
                END AS "inbox_bucket"
           FROM "classified" "c"
        )
 SELECT "count"(*) AS "all",
    "count"(*) AS "all_messages",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'priority'::"text")) AS "priority",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'priority'::"text")) AS "hot_leads",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'new_replies'::"text")) AS "new_replies",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'new_replies'::"text")) AS "new_inbound",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'new_replies'::"text")) AS "needs_reply",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'needs_review'::"text")) AS "needs_review",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'needs_review'::"text")) AS "manual_review",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'needs_review'::"text")) AS "automated",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'follow_up'::"text")) AS "follow_up",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'follow_up'::"text")) AS "outbound_active",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'cold'::"text")) AS "cold",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'cold'::"text")) AS "cold_no_response",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'dead'::"text")) AS "dead",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'suppressed'::"text")) AS "suppressed",
    "count"(*) FILTER (WHERE ("inbox_bucket" = 'suppressed'::"text")) AS "dnc_opt_out",
    "count"(*) FILTER (WHERE ("inbox_bucket" = ANY (ARRAY['priority'::"text", 'new_replies'::"text", 'needs_review'::"text", 'follow_up'::"text"]))) AS "active",
    "count"(*) FILTER (WHERE (("latest_message_direction" = 'outbound'::"text") AND ("inbox_bucket" <> ALL (ARRAY['dead'::"text", 'suppressed'::"text"])))) AS "waiting",
    "count"(*) FILTER (WHERE (("latest_message_direction" = 'outbound'::"text") AND ("inbox_bucket" <> ALL (ARRAY['dead'::"text", 'suppressed'::"text"])))) AS "waiting_on_seller",
    "count"(*) FILTER (WHERE ("property_id" IS NULL)) AS "unlinked",
    "count"(*) FILTER (WHERE ("duplicate_property_count" > 1)) AS "duplicate_property_threads"
   FROM "bucketed";


--
-- Name: v_map_property_pins; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_map_property_pins" AS
 SELECT "d"."thread_key",
    "p"."property_id",
    "p"."latitude",
    "p"."longitude",
    "p"."property_address_full" AS "property_address",
    "o"."display_name" AS "owner_name",
    "d"."last_message_body",
    "d"."inbox_status",
    "d"."conversation_stage"
   FROM (("public"."deal_thread_state" "d"
     JOIN "public"."property_universe_state" "p" ON (("d"."property_id" = "p"."property_id")))
     LEFT JOIN "public"."master_owners" "o" ON (("d"."master_owner_id" = "o"."master_owner_id")))
  WHERE (("p"."latitude" IS NOT NULL) AND ("p"."longitude" IS NOT NULL));


--
-- Name: v_market_fresh_inventory; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_market_fresh_inventory" AS
 SELECT "market",
    "count"(*) AS "fresh_count",
    "count"(*) FILTER (WHERE ("final_acquisition_score" > (80)::numeric)) AS "high_score_fresh_count"
   FROM "public"."v_outbound_candidate_freshness"
  WHERE ("never_contacted" = true)
  GROUP BY "market"
  ORDER BY ("count"(*)) DESC;


--
-- Name: v_nexus_active_dashboard; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_nexus_active_dashboard" AS
 SELECT "ct"."id" AS "thread_id",
    "ct"."seller_id",
    "ct"."status",
    "ct"."last_message_at",
    "sh"."base_score" AS "heat_score",
    "an"."stage" AS "negotiation_stage",
    "he"."status" AS "escalation_status"
   FROM ((("public"."conversation_threads" "ct"
     LEFT JOIN "public"."seller_heat_scores" "sh" ON (("ct"."seller_id" = "sh"."seller_id")))
     LEFT JOIN "public"."active_negotiations" "an" ON (("ct"."id" = "an"."thread_id")))
     LEFT JOIN "public"."human_escalations" "he" ON (("ct"."id" = "he"."thread_id")))
  WHERE (("ct"."status")::"text" = 'active'::"text");


--
-- Name: v_operator_inbox_threads; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_operator_inbox_threads" AS
 WITH "me_with_joins" AS (
         SELECT "me"."id" AS "message_event_id",
            "me"."thread_key" AS "me_thread_key",
            "me"."queue_id" AS "me_queue_id",
            "me"."provider_message_sid",
            "me"."to_phone_number",
            "me"."from_phone_number",
            "me"."direction",
            "me"."message_body",
            "me"."created_at" AS "message_created_at",
            "me"."event_type",
            "me"."property_id" AS "me_property_id",
            "me"."master_owner_id" AS "me_master_owner_id",
            "me"."phone_number_id" AS "me_phone_number_id",
            "me"."market_id" AS "me_market_id",
            "me"."metadata" AS "me_metadata",
            "sq"."thread_key" AS "sq_thread_key",
            "sq"."id" AS "sq_id",
            "sq"."property_id" AS "sq_property_id",
            "sq"."master_owner_id" AS "sq_master_owner_id",
            "sq"."phone_number_id" AS "sq_phone_number_id",
            "sq"."market_id" AS "sq_market_id",
            "sq"."queue_key",
            "sq"."queue_status",
            "sq"."type" AS "queue_type",
            "sq"."scheduled_for",
            "sq"."sent_at" AS "sq_sent_at",
            "sq"."delivered_at" AS "sq_delivered_at",
            NULL::timestamp with time zone AS "sq_failed_at",
            "sq"."current_stage" AS "thread_stage",
            "sq"."detected_intent" AS "last_intent",
            "sq"."ai_confidence" AS "classification_confidence",
            (((LEAST("me"."to_phone_number", "me"."from_phone_number"))::"text" || ':'::"text") || (GREATEST("me"."to_phone_number", "me"."from_phone_number"))::"text") AS "phone_pair",
            "p"."property_id" AS "p_id",
            "p"."property_address_full" AS "p_address_full",
            "p"."property_address_city" AS "p_city",
            "p"."property_address_state" AS "p_state",
            "p"."property_address_zip" AS "p_zip",
            "p"."market" AS "p_market",
            "mo"."master_owner_id" AS "mo_id",
            "mo"."display_name" AS "mo_full_name",
            "pr"."prospect_id" AS "pr_id",
            "pr"."full_name" AS "pr_name",
            "pr"."first_name" AS "pr_first_name",
            "ph"."phone_id" AS "ph_id",
            "ph"."canonical_e164" AS "ph_phone_number"
           FROM ((((("public"."message_events" "me"
             LEFT JOIN "public"."send_queue" "sq" ON (("me"."queue_id" = "sq"."id")))
             LEFT JOIN "public"."properties" "p" ON (("p"."property_id" = COALESCE("me"."property_id", "sq"."property_id"))))
             LEFT JOIN "public"."master_owners" "mo" ON (("mo"."master_owner_id" = COALESCE("me"."master_owner_id", "sq"."master_owner_id", "p"."master_owner_id"))))
             LEFT JOIN "public"."prospects" "pr" ON ((("pr"."master_owner_id" = COALESCE("me"."master_owner_id", "sq"."master_owner_id", "p"."master_owner_id")) OR (("pr"."best_phone" = ("me"."to_phone_number")::"text") OR ("pr"."best_phone" = ("me"."from_phone_number")::"text")))))
             LEFT JOIN "public"."phones" "ph" ON ((("ph"."phone_id" = (COALESCE("me"."phone_number_id", "sq"."phone_number_id"))::"text") OR (("ph"."canonical_e164" = ("me"."to_phone_number")::"text") OR ("ph"."canonical_e164" = ("me"."from_phone_number")::"text")))))
        ), "resolved_threads" AS (
         SELECT "me_with_joins"."message_event_id",
            "me_with_joins"."me_thread_key",
            "me_with_joins"."me_queue_id",
            "me_with_joins"."provider_message_sid",
            "me_with_joins"."to_phone_number",
            "me_with_joins"."from_phone_number",
            "me_with_joins"."direction",
            "me_with_joins"."message_body",
            "me_with_joins"."message_created_at",
            "me_with_joins"."event_type",
            "me_with_joins"."me_property_id",
            "me_with_joins"."me_master_owner_id",
            "me_with_joins"."me_phone_number_id",
            "me_with_joins"."me_market_id",
            "me_with_joins"."me_metadata",
            "me_with_joins"."sq_thread_key",
            "me_with_joins"."sq_id",
            "me_with_joins"."sq_property_id",
            "me_with_joins"."sq_master_owner_id",
            "me_with_joins"."sq_phone_number_id",
            "me_with_joins"."sq_market_id",
            "me_with_joins"."queue_key",
            "me_with_joins"."queue_status",
            "me_with_joins"."queue_type",
            "me_with_joins"."scheduled_for",
            "me_with_joins"."sq_sent_at",
            "me_with_joins"."sq_delivered_at",
            "me_with_joins"."sq_failed_at",
            "me_with_joins"."thread_stage",
            "me_with_joins"."last_intent",
            "me_with_joins"."classification_confidence",
            "me_with_joins"."phone_pair",
            "me_with_joins"."p_id",
            "me_with_joins"."p_address_full",
            "me_with_joins"."p_city",
            "me_with_joins"."p_state",
            "me_with_joins"."p_zip",
            "me_with_joins"."p_market",
            "me_with_joins"."mo_id",
            "me_with_joins"."mo_full_name",
            "me_with_joins"."pr_id",
            "me_with_joins"."pr_name",
            "me_with_joins"."pr_first_name",
            "me_with_joins"."ph_id",
            "me_with_joins"."ph_phone_number",
            COALESCE("me_with_joins"."me_thread_key", "me_with_joins"."sq_thread_key", ("me_with_joins"."me_queue_id")::"text", "me_with_joins"."provider_message_sid", "me_with_joins"."phone_pair", "concat"(COALESCE("me_with_joins"."me_property_id", "me_with_joins"."sq_property_id"), ':', COALESCE("me_with_joins"."me_master_owner_id", "me_with_joins"."sq_master_owner_id")), ("me_with_joins"."message_event_id")::"text") AS "resolved_thread_key"
           FROM "me_with_joins"
        ), "thread_aggregates" AS (
         SELECT "resolved_threads"."resolved_thread_key" AS "thread_key",
            "max"("resolved_threads"."message_created_at") AS "latest_message_at",
            ("array_agg"("resolved_threads"."message_body" ORDER BY "resolved_threads"."message_created_at" DESC))[1] AS "latest_message_body",
            ("array_agg"("resolved_threads"."direction" ORDER BY "resolved_threads"."message_created_at" DESC))[1] AS "latest_direction",
            ("array_agg"("resolved_threads"."event_type" ORDER BY "resolved_threads"."message_created_at" DESC))[1] AS "latest_message_status",
            "count"(*) AS "message_count",
            "count"(*) FILTER (WHERE ("resolved_threads"."direction" = 'inbound'::"text")) AS "inbound_count",
            "count"(*) FILTER (WHERE ("resolved_threads"."direction" = 'outbound'::"text")) AS "outbound_count",
            "count"(*) FILTER (WHERE ("resolved_threads"."event_type" = 'failed'::"text")) AS "failed_count",
            "count"(*) FILTER (WHERE ("resolved_threads"."event_type" = 'delivered'::"text")) AS "delivered_count",
            "count"(*) FILTER (WHERE ("resolved_threads"."event_type" = 'sent'::"text")) AS "sent_count",
            ("array_agg"("resolved_threads"."message_created_at" ORDER BY "resolved_threads"."message_created_at" DESC) FILTER (WHERE ("resolved_threads"."direction" = 'inbound'::"text")))[1] AS "latest_inbound_at",
            ("array_agg"("resolved_threads"."message_created_at" ORDER BY "resolved_threads"."message_created_at" DESC) FILTER (WHERE ("resolved_threads"."direction" = 'outbound'::"text")))[1] AS "latest_outbound_at",
            COALESCE("max"("resolved_threads"."me_property_id"), "max"("resolved_threads"."sq_property_id"), "max"("resolved_threads"."p_id")) AS "resolved_property_id",
            COALESCE("max"("resolved_threads"."me_master_owner_id"), "max"("resolved_threads"."sq_master_owner_id"), "max"("resolved_threads"."mo_id")) AS "resolved_master_owner_id",
            "max"(("resolved_threads"."to_phone_number")::"text") AS "to_phone_number",
            "max"(("resolved_threads"."from_phone_number")::"text") AS "from_phone_number",
                CASE
                    WHEN ("max"("resolved_threads"."direction") = 'inbound'::"text") THEN "max"(("resolved_threads"."from_phone_number")::"text")
                    ELSE "max"(("resolved_threads"."to_phone_number")::"text")
                END AS "seller_phone",
                CASE
                    WHEN ("max"("resolved_threads"."direction") = 'outbound'::"text") THEN "max"(("resolved_threads"."from_phone_number")::"text")
                    ELSE "max"(("resolved_threads"."to_phone_number")::"text")
                END AS "selected_textgrid_number",
            "max"("resolved_threads"."thread_stage") AS "thread_stage",
            "max"("resolved_threads"."last_intent") AS "detected_intent",
            "max"("resolved_threads"."classification_confidence") AS "ai_state",
            "bool_or"((("resolved_threads"."message_body" ~~* ANY (ARRAY['%stop%'::"text", '%unsubscribe%'::"text", '%wrong number%'::"text", '%wrong person%'::"text", '%do not text%'::"text", '%lawyer%'::"text", '%attorney%'::"text", '%legal%'::"text", '%harassment%'::"text", '%not interested%'::"text"])) OR (("resolved_threads"."me_metadata" ->> 'intent'::"text") = ANY (ARRAY['stop'::"text", 'unsubscribe'::"text", 'dnc'::"text"])))) AS "is_suppressed_auto",
            "bool_or"(((("resolved_threads"."me_metadata" ->> 'intent'::"text") = ANY (ARRAY['stop'::"text", 'unsubscribe'::"text", 'dnc'::"text"])) OR ("resolved_threads"."message_body" ~~* ANY (ARRAY['%stop%'::"text", '%unsubscribe%'::"text"])))) AS "opt_out_auto",
            "bool_or"(("resolved_threads"."message_body" ~~* ANY (ARRAY['%wrong number%'::"text", '%wrong person%'::"text"]))) AS "wrong_number_auto",
            "bool_or"(("resolved_threads"."message_body" ~~* ANY (ARRAY['%not interested%'::"text"]))) AS "not_interested_auto",
            "bool_or"((("resolved_threads"."message_body" ~~* ANY (ARRAY['%yes%'::"text", '%interested%'::"text", '%offer%'::"text", '%cash%'::"text", '%how much%'::"text", '%price%'::"text", '%asking price%'::"text", '%call me%'::"text", '%open to selling%'::"text", '%maybe%'::"text", '%depends%'::"text", '%what can you offer%'::"text"])) OR (("resolved_threads"."me_metadata" ->> 'intent'::"text") = ANY (ARRAY['interested'::"text", 'hot_lead'::"text"])))) AS "positive_reply_auto",
            "bool_or"((("resolved_threads"."me_metadata" ->> 'intent'::"text") = 'asking_price_provided'::"text")) AS "asking_price_detected_auto",
            "bool_or"((("resolved_threads"."me_metadata" ->> 'intent'::"text") = 'ownership_confirmed'::"text")) AS "ownership_confirmed_auto",
            "bool_or"(((("resolved_threads"."me_metadata" ->> 'needs_review'::"text") = 'true'::"text") OR ("resolved_threads"."classification_confidence" < (0.5)::double precision))) AS "needs_review_auto",
            "max"("resolved_threads"."p_address_full") AS "p_address_full",
            "max"("resolved_threads"."p_city") AS "p_city",
            "max"("resolved_threads"."p_state") AS "p_state",
            "max"("resolved_threads"."p_zip") AS "p_zip",
            "max"("resolved_threads"."p_market") AS "p_market",
            "max"("resolved_threads"."mo_full_name") AS "mo_full_name",
            "max"("resolved_threads"."pr_name") AS "pr_name",
            "max"("resolved_threads"."pr_first_name") AS "pr_first_name"
           FROM "resolved_threads"
          GROUP BY "resolved_threads"."resolved_thread_key"
        )
 SELECT "ta"."thread_key",
    "ta"."seller_phone" AS "canonical_e164",
    "ta"."seller_phone",
    COALESCE("ta"."mo_full_name", "ta"."pr_name", 'Unknown Seller'::"text") AS "seller_name",
    COALESCE("ta"."pr_first_name", "split_part"("ta"."mo_full_name", ' '::"text", 1)) AS "seller_first_name",
    "ta"."mo_full_name" AS "owner_name",
    "ta"."resolved_master_owner_id" AS "master_owner_id",
    "ta"."resolved_property_id" AS "property_id",
    "ta"."p_address_full" AS "property_address_full",
    "ta"."p_city" AS "property_city",
    "ta"."p_state" AS "property_state",
    "ta"."p_zip" AS "property_zip",
    "ta"."p_market" AS "market",
    NULL::"text" AS "timezone",
    NULL::"text" AS "campaign_id",
    NULL::"text" AS "campaign_name",
    NULL::"text" AS "campaign_target_id",
    "ta"."latest_message_at",
    "ta"."latest_message_body",
    "ta"."latest_direction",
    "ta"."latest_message_status",
    "ta"."detected_intent" AS "latest_intent",
    "ta"."ai_state" AS "latest_classification",
    NULL::"text" AS "latest_template_id",
    "ta"."from_phone_number",
    "ta"."to_phone_number",
    "ta"."selected_textgrid_number",
    COALESCE("ots"."inbox_bucket",
        CASE
            WHEN ("ta"."is_suppressed_auto" OR "ta"."opt_out_auto" OR "ta"."wrong_number_auto") THEN 'suppressed'::"text"
            WHEN ("ta"."positive_reply_auto" OR "ta"."asking_price_detected_auto" OR ("ta"."detected_intent" = ANY (ARRAY['seller_interested'::"text", 'ownership_confirmed'::"text", 'asking_price_provided'::"text", 'condition_disclosed'::"text", 'property_interest'::"text"]))) THEN 'priority'::"text"
            WHEN (("ta"."latest_direction" = 'inbound'::"text") AND "ta"."needs_review_auto") THEN 'needs_review'::"text"
            WHEN ("ta"."latest_direction" = 'inbound'::"text") THEN 'new_replies'::"text"
            WHEN (("ta"."latest_direction" = 'outbound'::"text") AND ("ta"."inbound_count" = 0)) THEN 'cold'::"text"
            ELSE 'all'::"text"
        END) AS "inbox_bucket",
    COALESCE("ots"."lead_temperature",
        CASE
            WHEN "ta"."positive_reply_auto" THEN 'hot'::"text"
            WHEN ("ta"."inbound_count" > 0) THEN 'warm'::"text"
            ELSE 'cold'::"text"
        END) AS "lead_temperature",
    COALESCE("ots"."seller_stage", "ta"."thread_stage", 'S1 Ownership Check'::"text") AS "seller_stage",
    COALESCE("ots"."conversation_stage", 'ownership_check'::"text") AS "conversation_stage",
    COALESCE("ots"."review_status",
        CASE
            WHEN "ta"."needs_review_auto" THEN 'needs_review'::"text"
            ELSE 'reviewed'::"text"
        END) AS "review_status",
    "ots"."follow_up_at",
    "ots"."suppression_status" AS "suppression_type",
    "ta"."is_suppressed_auto" AS "is_suppressed",
    "ta"."opt_out_auto" AS "opt_out",
    "ta"."wrong_number_auto" AS "wrong_number",
    "ta"."not_interested_auto" AS "not_interested",
    "ta"."needs_review_auto" AS "needs_review",
    "ta"."positive_reply_auto" AS "positive_reply",
    "ta"."asking_price_detected_auto" AS "asking_price_detected",
    "ta"."ownership_confirmed_auto" AS "ownership_confirmed",
        CASE
            WHEN ("ta"."latest_direction" = 'inbound'::"text") THEN 1
            ELSE 0
        END AS "unread_count",
    "ta"."inbound_count",
    "ta"."outbound_count",
    "ta"."delivered_count",
    "ta"."failed_count",
    "ta"."latest_outbound_at" AS "last_outbound_at",
    "ta"."latest_inbound_at" AS "last_inbound_at",
    "min"("ta"."latest_message_at") OVER (PARTITION BY "ta"."thread_key") AS "created_at",
    "max"("ta"."latest_message_at") OVER (PARTITION BY "ta"."thread_key") AS "updated_at",
    "ots"."metadata"
   FROM ("thread_aggregates" "ta"
     LEFT JOIN "public"."operator_thread_state" "ots" ON (("ta"."thread_key" = "ots"."thread_key")));


