--
-- Name: v_recent_sold_comps; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_recent_sold_comps" AS
 SELECT "id",
    "batch_id",
    "source_record_id",
    "source_deal_id",
    "property_id",
    "normalized_asset_class",
    "comp_search_profile_hash",
    "renovation_level_classification",
    "sqft_range",
    "sqft_per_unit",
    "beds_per_unit",
    "year_built_bucket",
    "purchase_info",
    "ppbd",
    "ppu",
    "ppsf",
    "price_off_value",
    "percent_off",
    "potential_spread",
    "arv_estimate",
    "arv_ppsf",
    "comp_confidence_score",
    "deal_grade",
    "target_margin_percent",
    "property_address_full",
    "property_address",
    "property_address_city",
    "property_address_state",
    "property_address_zip",
    "property_address_county_name",
    "latitude",
    "longitude",
    "sale_date",
    COALESCE("sale_price", "saleprice", "mls_sold_price") AS "sale_price",
    "mls_sold_date",
    "mls_sold_price",
    "estimated_value",
    "estimated_repair_cost",
    "estimated_repair_cost_per_sqft",
    "equity_amount",
    "equity_percent",
    "total_bedrooms",
    "total_baths",
    "building_square_feet",
    "lot_square_feet",
    "lot_acreage",
    "units_count",
    "year_built",
    "effective_year_built",
    "construction_type",
    "building_condition",
    "property_type",
    "property_class",
    "streetview_image",
    "satellite_image",
    "property_flags_json",
    "property_flags_text",
    "created_at",
    "updated_at",
        CASE
            WHEN ("mls_sold_price" IS NOT NULL) THEN 'MLS Sold'::"text"
            WHEN (("sale_price" IS NOT NULL) OR ("saleprice" IS NOT NULL)) THEN 'Public Record Sold'::"text"
            ELSE 'Off-Market Sold'::"text"
        END AS "sale_source",
        CASE
            WHEN ((COALESCE("sale_price", "saleprice", "mls_sold_price") IS NOT NULL) AND (NULLIF("building_square_feet", (0)::numeric) IS NOT NULL)) THEN "round"((COALESCE("sale_price", "saleprice", "mls_sold_price") / NULLIF("building_square_feet", (0)::numeric)), 2)
            ELSE "ppsf"
        END AS "computed_ppsf",
        CASE
            WHEN ("sale_date" >= (CURRENT_DATE - '6 mons'::interval)) THEN true
            ELSE false
        END AS "is_recent_6_months",
        CASE
            WHEN ((COALESCE("sale_price", "saleprice", "mls_sold_price") IS NOT NULL) AND ("sale_date" IS NOT NULL) AND ("latitude" IS NOT NULL) AND ("longitude" IS NOT NULL) AND ("property_address_full" IS NOT NULL) AND ("property_address_zip" IS NOT NULL)) THEN true
            ELSE false
        END AS "is_usable_comp"
   FROM "public"."buyer_comp_raw_v2"
  WHERE ("import_status" IS DISTINCT FROM 'rejected'::"text");


--
-- Name: v_sms_ready_contacts; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_sms_ready_contacts" AS
 SELECT "p"."property_export_id",
    "p"."property_id",
    "p"."property_address_full",
    "p"."property_address_city",
    "p"."property_address_state",
    "p"."property_address_zip",
    "p"."property_county_name" AS "property_address_county_name",
    "p"."market",
    COALESCE((NULLIF(("to_jsonb"("p".*) ->> 'cash_offer'::"text"), ''::"text"))::numeric, NULL::numeric) AS "cash_offer",
    "p"."estimated_value",
    "p"."equity_amount",
    "p"."equity_percent",
    COALESCE((NULLIF(("to_jsonb"("p".*) ->> 'final_acquisition_score'::"text"), ''::"text"))::numeric, (NULLIF(("to_jsonb"("mo".*) ->> 'priority_score'::"text"), ''::"text"))::numeric, NULL::numeric) AS "final_acquisition_score",
    "p"."seller_tags_text" AS "podio_tags",
    "mo"."master_owner_id",
    "mo"."master_key",
    "mo"."display_name",
    "mo"."primary_owner_address",
    "mo"."priority_tier",
    "mo"."follow_up_cadence",
    "mo"."agent_persona",
    "mo"."agent_family",
    "mo"."best_language",
    COALESCE(NULLIF("mo"."primary_phone_id", ''::"text"), NULLIF("mo"."best_phone_1", ''::"text")) AS "best_phone_id",
    COALESCE("ph"."phone_id", COALESCE(NULLIF("mo"."primary_phone_id", ''::"text"), NULLIF("mo"."best_phone_1", ''::"text"))) AS "phone_id",
    "ph"."phone",
    "ph"."canonical_e164",
    "ph"."best_phone_score",
    "ph"."phone_type",
    "ph"."activity_status",
    "ph"."usage_12_months",
    "ph"."usage_2_months",
    "ph"."contact_window",
    COALESCE("ph"."timezone", "mo"."routing_timezone") AS "timezone",
    "ph"."primary_prospect_id",
    "ph"."canonical_prospect_id",
    "pr"."prospect_id" AS "matched_prospect_id",
    "pr"."matching_flags",
    "pr"."matching_flags" AS "prospect_matching_flags",
    "pr"."person_flags_text",
    "pr"."person_flags_json",
    "pr"."likely_owner",
    ((COALESCE("ph"."canonical_e164", "ph"."phone") IS NOT NULL) AND ("ph"."phone_contact_status" IS DISTINCT FROM 'wrong_number'::"text")) AS "sms_eligible",
    "ph"."phone_first_name",
    "ph"."phone_full_name",
    "ph"."primary_display_name",
    COALESCE(NULLIF("ph"."phone_first_name", ''::"text"), "split_part"(NULLIF("ph"."phone_full_name", ''::"text"), ' '::"text", 1)) AS "seller_first_name",
    COALESCE(NULLIF("ph"."phone_full_name", ''::"text"), NULLIF("ph"."primary_display_name", ''::"text")) AS "seller_full_name",
    'properties.master_owner_id'::"text" AS "joined_property_source"
   FROM ((("public"."master_owners" "mo"
     LEFT JOIN "public"."phones" "ph" ON (("ph"."phone_id" = COALESCE(NULLIF("mo"."primary_phone_id", ''::"text"), NULLIF("mo"."best_phone_1", ''::"text")))))
     LEFT JOIN LATERAL ( SELECT "pr0"."prospect_id",
            "pr0"."matching_flags",
            "pr0"."person_flags_text",
            "pr0"."person_flags_json",
            "pr0"."likely_owner",
            "pr0"."is_primary_prospect",
            "pr0"."phone_score_final"
           FROM "public"."prospects" "pr0"
          WHERE ("pr0"."master_owner_id" = "mo"."master_owner_id")
          ORDER BY (("pr0"."matching_flags" IS NOT NULL) AND ("pr0"."matching_flags" <> ''::"text")) DESC, "pr0"."is_primary_prospect" DESC NULLS LAST, "pr0"."phone_score_final" DESC NULLS LAST, "pr0"."prospect_id"
         LIMIT 1) "pr" ON (true))
     LEFT JOIN "public"."properties" "p" ON (("p"."master_owner_id" = "mo"."master_owner_id")));


--
-- Name: v_sms_ready_contacts_clean; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_sms_ready_contacts_clean" AS
 SELECT "property_export_id",
    "property_id",
    "property_address_full",
    "property_address_city",
    "property_address_state",
    "property_address_zip",
    "property_address_county_name",
    "market",
    "cash_offer",
    "estimated_value",
    "equity_amount",
    "equity_percent",
    "final_acquisition_score",
    "podio_tags",
    "master_owner_id",
    "master_key",
    "display_name",
    "primary_owner_address",
    "priority_tier",
    "follow_up_cadence",
    "agent_persona",
    "agent_family",
    "best_language",
    "best_phone_id",
    "phone_id",
    "phone",
    "canonical_e164",
    "best_phone_score",
    "phone_type",
    "activity_status",
    "usage_12_months",
    "usage_2_months",
    "contact_window",
    "timezone",
    "primary_prospect_id",
    "canonical_prospect_id",
    "matched_prospect_id",
    "matching_flags",
    "prospect_matching_flags",
    "person_flags_text",
    "person_flags_json",
    "likely_owner",
    "sms_eligible",
    "phone_first_name",
    "phone_full_name",
    "primary_display_name",
    "seller_first_name",
    "seller_full_name",
    "joined_property_source"
   FROM ( SELECT DISTINCT ON ("c"."canonical_e164") "c"."property_export_id",
            "c"."property_id",
            "c"."property_address_full",
            "c"."property_address_city",
            "c"."property_address_state",
            "c"."property_address_zip",
            "c"."property_address_county_name",
            "c"."market",
            "c"."cash_offer",
            "c"."estimated_value",
            "c"."equity_amount",
            "c"."equity_percent",
            "c"."final_acquisition_score",
            "c"."podio_tags",
            "c"."master_owner_id",
            "c"."master_key",
            "c"."display_name",
            "c"."primary_owner_address",
            "c"."priority_tier",
            "c"."follow_up_cadence",
            "c"."agent_persona",
            "c"."agent_family",
            "c"."best_language",
            "c"."best_phone_id",
            "c"."phone_id",
            "c"."phone",
            "c"."canonical_e164",
            "c"."best_phone_score",
            "c"."phone_type",
            "c"."activity_status",
            "c"."usage_12_months",
            "c"."usage_2_months",
            "c"."contact_window",
            "c"."timezone",
            "c"."primary_prospect_id",
            "c"."canonical_prospect_id",
            "c"."matched_prospect_id",
            "c"."matching_flags",
            "c"."prospect_matching_flags",
            "c"."person_flags_text",
            "c"."person_flags_json",
            "c"."likely_owner",
            "c"."sms_eligible",
            "c"."phone_first_name",
            "c"."phone_full_name",
            "c"."primary_display_name",
            "c"."seller_first_name",
            "c"."seller_full_name",
            "c"."joined_property_source"
           FROM ("public"."v_sms_ready_contacts" "c"
             LEFT JOIN "public"."sms_suppression_list" "s" ON ((("s"."phone_e164" = "c"."canonical_e164") AND ("s"."is_active" = true))))
          WHERE ("s"."phone_e164" IS NULL)
          ORDER BY "c"."canonical_e164", "c"."final_acquisition_score" DESC) "t"
  ORDER BY ("random"());


--
-- Name: v_sms_ready_contacts_expanded; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_sms_ready_contacts_expanded" AS
 SELECT "p"."property_export_id",
    "p"."property_id",
    "p"."property_address_full",
    "p"."property_address_city",
    "p"."property_address_state",
    "p"."property_address_zip",
    "p"."property_county_name" AS "property_address_county_name",
    "p"."market",
    COALESCE((NULLIF(("to_jsonb"("p".*) ->> 'cash_offer'::"text"), ''::"text"))::numeric, NULL::numeric) AS "cash_offer",
    "p"."estimated_value",
    "p"."equity_amount",
    "p"."equity_percent",
    COALESCE((NULLIF(("to_jsonb"("p".*) ->> 'final_acquisition_score'::"text"), ''::"text"))::numeric, (NULLIF(("to_jsonb"("mo".*) ->> 'priority_score'::"text"), ''::"text"))::numeric, NULL::numeric) AS "final_acquisition_score",
    "p"."seller_tags_text" AS "podio_tags",
    "mo"."master_owner_id",
    "mo"."master_key",
    "mo"."display_name",
    "mo"."primary_owner_address",
    "mo"."priority_tier",
    "mo"."follow_up_cadence",
    "mo"."agent_persona",
    "mo"."agent_family",
    "mo"."best_language",
    "ph"."phone_id" AS "best_phone_id",
    "ph"."phone_id",
    "ph"."phone",
    "ph"."canonical_e164",
    "ph"."best_phone_score",
    "ph"."phone_type",
    "ph"."activity_status",
    "ph"."usage_12_months",
    "ph"."usage_2_months",
    "ph"."contact_window",
    COALESCE("ph"."timezone", "mo"."routing_timezone") AS "timezone",
    "ph"."primary_prospect_id",
    "ph"."canonical_prospect_id",
    ("ph"."phone_contact_status" IS DISTINCT FROM 'wrong_number'::"text") AS "sms_eligible",
    "ph"."phone_first_name",
    "ph"."phone_full_name",
    "ph"."primary_display_name",
    COALESCE(NULLIF("ph"."phone_first_name", ''::"text"), "split_part"(NULLIF("ph"."phone_full_name", ''::"text"), ' '::"text", 1)) AS "seller_first_name",
    COALESCE(NULLIF("ph"."phone_full_name", ''::"text"), NULLIF("ph"."primary_display_name", ''::"text")) AS "seller_full_name",
    'properties.master_owner_id'::"text" AS "joined_property_source",
    "row_number"() OVER (PARTITION BY "p"."property_id", "mo"."master_owner_id" ORDER BY COALESCE("ph"."best_phone_score", 0) DESC NULLS LAST, COALESCE("ph"."contact_score_final", 0) DESC NULLS LAST, "ph"."sort_rank") AS "phone_rank",
    (COALESCE("ph"."best_phone_score", 0) + COALESCE("ph"."contact_score_final", 0)) AS "candidate_confidence_score"
   FROM (("public"."master_owners" "mo"
     JOIN "public"."phones" "ph" ON (("ph"."master_owner_id" = "mo"."master_owner_id")))
     JOIN "public"."properties" "p" ON (("p"."master_owner_id" = "mo"."master_owner_id")))
  WHERE (("ph"."canonical_e164" IS NOT NULL) AND (("ph"."phone_type" = ANY (ARRAY['Mobile'::"text", 'VoIP'::"text"])) OR ("ph"."phone_type" IS NULL) OR ("ph"."phone_type" = 'Unknown'::"text")));


--
-- Name: v_template_coverage_audit; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_template_coverage_audit" AS
 SELECT "market",
    "property_type",
    "count"(*) AS "total_candidate_count",
    "count"(*) FILTER (WHERE ("never_contacted" = true)) AS "fresh_candidate_count",
    ( SELECT "count"(*) AS "count"
           FROM "public"."sms_templates" "t"
          WHERE (("t"."is_active" = true) AND (("t"."property_type_scope" IS NULL) OR ("t"."property_type_scope" = ''::"text") OR ("t"."property_type_scope" ~~* (('%'::"text" || "c"."property_type") || '%'::"text"))))) AS "applicable_template_count"
   FROM "public"."v_outbound_candidate_freshness" "c"
  GROUP BY "market", "property_type";


--
-- Name: v_universal_inbox_threads; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_universal_inbox_threads" AS
 SELECT "d"."thread_key",
    "d"."master_owner_id",
    "d"."property_id",
    "d"."latest_message_at" AS "last_message_at",
    "d"."latest_message_body" AS "last_message_body",
    "d"."latest_message_direction" AS "direction",
    "d"."inbox_bucket" AS "inbox_category",
    "d"."universal_status" AS "inbox_status",
    "d"."universal_stage" AS "conversation_stage",
    "d"."unread_count",
    "d"."best_phone",
    "o"."display_name" AS "owner_name",
    "p"."property_address_full" AS "property_address",
    "p"."market",
    "d"."inbox_bucket",
    "d"."universal_status",
    "d"."universal_stage",
    "d"."latest_message_direction",
    "d"."latest_message_body",
    "d"."latest_message_at",
    "d"."reply_intent",
    "d"."lead_temperature",
    "d"."suppression_status",
    "d"."opt_out",
    "d"."wrong_number",
    "d"."not_interested",
    "d"."needs_review",
    "d"."created_at",
    "d"."updated_at"
   FROM (("public"."deal_thread_state" "d"
     LEFT JOIN "public"."master_owners" "o" ON (("d"."master_owner_id" = "o"."master_owner_id")))
     LEFT JOIN "public"."property_universe_state" "p" ON (("d"."property_id" = "p"."property_id")));


