    CONSTRAINT "workflows_live_send_draft_guard" CHECK ((("live_send_enabled" IS FALSE) OR ("status" = 'active'::"text"))),
    CONSTRAINT "workflows_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'active'::"text", 'paused'::"text", 'archived'::"text"]))),
    CONSTRAINT "workflows_type_check" CHECK (("workflow_type" = ANY (ARRAY['outbound'::"text", 'follow_up'::"text", 'auto_reply'::"text", 'nurture'::"text", 'reactivation'::"text", 'deal_execution'::"text"])))
);


--
-- Name: TABLE "workflows"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE "public"."workflows" IS 'Workflow Studio draft/active workflow definitions. live_send_enabled defaults false.';


